INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000001', 'Which type of error is one-directional, repeats with the same sign and magnitude under the same conditions, and can be removed by applying a correction formula?', 'multiple_choice', '["Random error","Systematic error","Gross error (blunder)","Standard error"]'::jsonb, 'Systematic error', 'Systematic errors follow physical/instrumental laws (e.g., tape too long, atmospheric refraction). They accumulate in one direction and are corrected by formula or procedure, unlike random errors (treated statistically) or blunders (detected and removed).', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000002', 'A measurement is described as ''precise but not accurate.'' What does this mean?', 'multiple_choice', '["Repeated measurements cluster tightly together but are centered away from the true value","A single measurement happens to equal the true value","Repeated measurements scatter widely but average to the true value","The measurement has many significant figures"]'::jsonb, 'Repeated measurements cluster tightly together but are centered away from the true value', 'Precision is repeatability (tight clustering). Accuracy is closeness to truth. A tight cluster offset from the bullseye is precise but inaccurate, typically caused by an uncorrected systematic error.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000003', 'In the sample standard deviation formula σ = √(Σv²/(n−1)), why is the denominator (n−1) rather than n?', 'multiple_choice', '["To make the result larger and more conservative","Because one degree of freedom is consumed computing the mean","Because one observation is always a blunder","To convert variance to standard deviation"]'::jsonb, 'Because one degree of freedom is consumed computing the mean', 'The residuals are taken about the computed mean, which uses up one degree of freedom. Dividing by (n−1) gives an unbiased estimate of the population variance from a sample.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000004', 'A line is measured 10 times and the standard deviation of a single observation is σ = 0.030 ft. What is the standard error of the mean?', 'multiple_choice', '["0.0095 ft","0.030 ft","0.095 ft","0.300 ft"]'::jsonb, '0.0095 ft', 'σ_m = σ/√n = 0.030/√10 = 0.030/3.1623 = 0.0095 ft. The standard error of the mean is always smaller than the standard deviation of a single observation by a factor of √n.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000005', 'A distance is taped in 4 equal segments, each with a random error of ±0.012 ft. What is the expected random error in the total distance?', 'multiple_choice', '["±0.012 ft","±0.024 ft","±0.048 ft","±0.144 ft"]'::jsonb, '±0.024 ft', 'For a series of n equal independent errors, E = e·√n = 0.012·√4 = 0.012·2 = 0.024 ft. Random errors combine in quadrature, not by simple addition (which would give 0.048 ft).', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000006', 'A rectangular parcel measures 200.00 ± 0.05 ft by 300.00 ± 0.06 ft. What is the standard error in the computed area?', 'multiple_choice', '["±10.0 ft²","±18.0 ft²","±20.8 ft²","±28.0 ft²"]'::jsonb, '±20.8 ft²', 'For a product A = a·b, σ_A = √((b·σ_a)² + (a·σ_b)²) = √((300·0.05)² + (200·0.06)²) = √(15² + 12²) = √(225+144) = √369 = 20.8 ft².', 'hard', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000007', 'According to the 68-95-99.7 rule for a normal distribution, approximately what percentage of random errors fall within ±2σ of the mean?', 'multiple_choice', '["68.3%","90.0%","95.4%","99.7%"]'::jsonb, '95.4%', '±1σ contains ~68.3%, ±2σ contains ~95.4%, and ±3σ contains ~99.7% of observations in a normal distribution. (The 95% confidence multiplier of exactly 1.96σ is slightly less than 2σ.)', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000008', 'A traverse has a perimeter of 3,300 ft and a linear misclosure of 0.33 ft. What is the relative precision?', 'multiple_choice', '["1:1,000","1:5,000","1:10,000","1:33,000"]'::jsonb, '1:10,000', 'Relative precision = perimeter/misclosure expressed as 1:N = 3300/0.33 = 10,000, reported as 1:10,000.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000009', 'When forming a weighted mean of several measurements with differing standard deviations, the weight of each measurement is proportional to:', 'multiple_choice', '["σ","σ²","1/σ","1/σ²"]'::jsonb, '1/σ²', 'Weight is inversely proportional to variance: w ∝ 1/σ². The most precise measurement (smallest σ) receives the largest weight and dominates the weighted mean.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000010', 'The probable error E₅₀ (the bound containing 50% of random errors) equals which multiple of the standard deviation?', 'multiple_choice', '["0.6745σ","1.0000σ","1.6449σ","1.9600σ"]'::jsonb, '0.6745σ', 'The probable error is E₅₀ = 0.6745σ — half of all random errors are smaller than this value. The 90% and 95% multipliers are 1.6449 and 1.9600 respectively.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000011', 'Before applying statistical analysis (mean, standard deviation) to a set of observations, the surveyor must first ensure the data is free of:', 'multiple_choice', '["All random errors","Blunders and uncorrected systematic errors","Significant figures","Any rounding"]'::jsonb, 'Blunders and uncorrected systematic errors', 'Statistics describe random error only. A blunder or an uncorrected systematic error invalidates the statistical estimates, so blunders must be detected/removed and systematic errors corrected first.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000012', 'How many significant figures are in the measurement 0.04060 m?', 'multiple_choice', '["3","4","5","6"]'::jsonb, '4', 'Leading zeros are not significant (0.0...). The digits 4, 0, 6, and the trailing 0 (after the decimal) are significant → 4060 → four significant figures.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000013', 'A distance of 2,640.00 US survey feet is to be expressed in international feet. Which statement is correct?', 'multiple_choice', '["The two values are identical because a foot is a foot","The international-foot value is slightly larger by about 2 ppm","The international-foot value is slightly smaller by about 5%","Conversion is impossible without the latitude"]'::jsonb, 'The international-foot value is slightly larger by about 2 ppm', '1 US survey ft = 0.3048006096 m vs 1 international ft = 0.3048 m exactly. A US survey foot is slightly longer, so the same physical distance expressed in international feet is a slightly larger number — about 2 ppm difference, which matters for state-plane coordinates.', 'hard', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000014', 'What is the most probable value of a set of equally-weighted direct observations?', 'multiple_choice', '["The median","The mode","The arithmetic mean","The midrange"]'::jsonb, 'The arithmetic mean', 'For equally-weighted direct observations the most probable value (MPV) is the arithmetic mean, x̄ = Σxᵢ/n. This is the value that minimizes the sum of squared residuals.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000015', 'An angle is measured with a standard deviation of 5″. A surveyor needs the standard error of the mean to be ≤ 1″. Approximately how many repetitions are required?', 'multiple_choice', '["5","10","25","50"]'::jsonb, '25', 'σ_m = σ/√n ≤ 1 → √n ≥ σ/1 = 5 → n ≥ 25. Because of the √n relationship, reducing the standard error of the mean by a factor of 5 requires 25 times the observations.', 'hard', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000016', 'Convert 50.0 chains to feet (US survey/Gunter''s chain).', 'numeric_input', '[]'::jsonb, '3300', '1 chain = 66 ft, so 50.0 chains × 66 ft/chain = 3,300 ft.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000017', 'A parcel contains 87,120 ft². How many acres is this?', 'numeric_input', '[]'::jsonb, '2', '1 acre = 43,560 ft². 87,120 / 43,560 = 2.0 acres.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000018', 'True or False: The standard error of the mean is always larger than the standard deviation of a single observation.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. σ_m = σ/√n, so for n > 1 the standard error of the mean is always SMALLER than σ. Averaging more observations sharpens the estimate of the mean.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000019', 'True or False: Random errors are equally likely to be positive or negative and tend to cancel as the number of observations increases.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. Random (accidental) errors follow the normal distribution, are symmetric about zero, and partially cancel — which is why repeated observations and least-squares adjustment improve results.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000020', 'Two independent distances are measured: AB = 450.00 ± 0.03 ft and BC = 300.00 ± 0.04 ft. What is the standard error of the total distance AC = AB + BC?', 'multiple_choice', '["±0.01 ft","±0.05 ft","±0.07 ft","±0.50 ft"]'::jsonb, '±0.05 ft', 'For a sum of independent quantities, errors add in quadrature: E = √(0.03² + 0.04²) = √(0.0009 + 0.0016) = √0.0025 = 0.05 ft.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000021', 'Five angle observations have residuals (seconds) of +2, −3, +1, −1, +1 about their mean. What is Σv² used in the standard deviation calculation?', 'multiple_choice', '["0","8","16","16 (with sign)"]'::jsonb, '16', 'Σv² = 2² + 3² + 1² + 1² + 1² = 4 + 9 + 1 + 1 + 1 = 16. Squaring removes the signs; this feeds σ = √(Σv²/(n−1)) = √(16/4) = 2″.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000022', 'Which of the following is the correct value of the 95% confidence multiplier (two-tailed Z value) for a normal distribution?', 'multiple_choice', '["1.2816","1.6449","1.9600","2.5758"]'::jsonb, '1.9600', 'The two-tailed Z value is 1.6449 for 90%, 1.9600 for 95%, and 2.5758 for 99%. These appear in the FS Reference Handbook unit-normal table.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000023', 'A measured value is 1234.567 and is to be rounded to 5 significant figures. What is the rounded result?', 'multiple_choice', '["1234.5","1234.6","1234.57","1235.0"]'::jsonb, '1234.6', 'Five significant figures of 1234.567 are 1,2,3,4,5; the next digit (6) rounds the fifth digit up: 1234.6.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb013000-0000-0000-0000-000000000024', 'The product of two measured quantities, each known to 3 significant figures, should be reported to how many significant figures?', 'multiple_choice', '["2","3","5","6"]'::jsonb, '3', 'In multiplication/division, the result carries the same number of significant figures as the least precise factor — here 3 significant figures.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000001', 'A distance is measured {{n}} times. The standard deviation of a single observation is σ = {{sigma:f3}} ft. Compute the standard error of the mean (ft).', 'numeric_input', '[]'::jsonb, '0', 'The standard error of the mean is σ_m = σ/√n = {{sigma:f3}}/√{{n}} = {{_answer}} ft. It is always smaller than the single-observation σ by the factor √n.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000001', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000002', 'A line is taped in {{n}} equal segments. Each segment carries an independent random error of ±{{e:f3}} ft. Compute the expected random error in the total length (ft).', 'numeric_input', '[]'::jsonb, '0', 'For n equal independent errors, they combine in quadrature: E = e·√n = {{e:f3}}·√{{n}} = {{_answer}} ft. This is NOT the linear sum n·e.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000002', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000003', 'Three independent distances are added end to end. Their standard errors are ±{{e1:f3}} ft, ±{{e2:f3}} ft, and ±{{e3:f3}} ft. Compute the standard error of the total distance (ft).', 'numeric_input', '[]'::jsonb, '0', 'For a sum of independent quantities, errors add in quadrature: E = √(e1²+e2²+e3²) = {{_answer}} ft.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000003', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000004', 'A traverse has a perimeter of {{perimeter:f2}} ft and a linear misclosure of {{misclosure:f3}} ft. Express the relative precision as 1:N — report N (rounded to the nearest whole number).', 'numeric_input', '[]'::jsonb, '0', 'Relative precision = misclosure/perimeter reduced to a unit numerator: N = perimeter/misclosure = {{perimeter:f2}}/{{misclosure:f3}} = {{_answer}}, reported as 1:{{_answer}}.', 'easy', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000004', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000005', 'A quantity is observed {{n}} times. The sum of the squared residuals about the mean is Σv² = {{sv2:f4}}. Compute the sample standard deviation σ = √(Σv²/(n−1)).', 'numeric_input', '[]'::jsonb, '0', 'σ = √(Σv²/(n−1)) = √({{sv2:f4}}/({{n}}−1)) = {{_answer}}. Use n−1 (degrees of freedom) because the mean consumed one degree of freedom.', 'medium', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000005', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb016000-0000-0000-0000-000000000006', 'A distance is measured two ways: method 1 gives {{m1:f3}} ft with σ₁ = ±{{s1:f3}} ft; method 2 gives {{m2:f3}} ft with σ₂ = ±{{s2:f3}} ft. Compute the weighted mean (ft), using weights ∝ 1/σ².', 'numeric_input', '[]'::jsonb, '0', 'Weights are inverse variances: w1 = 1/σ₁², w2 = 1/σ₂². The weighted mean = Σ(w·x)/Σw = {{_answer}} ft, pulled toward the more precise (smaller-σ) measurement.', 'hard', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb015000-0000-0000-0000-000000000006', 0.005);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000001', 'A line is observed 8 times with a single-observation standard deviation of 0.024 ft. What is the standard error of the mean?', 'multiple_choice', '["0.0085 ft","0.0240 ft","0.0680 ft","0.1920 ft"]'::jsonb, '0.0085 ft', 'σ_m = σ/√n = 0.024/√8 = 0.024/2.828 = 0.0085 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000002', 'Which error type must be detected and removed (never statistically adjusted) before any analysis?', 'multiple_choice', '["Random error","Systematic error","Gross error (blunder)","Probable error"]'::jsonb, 'Gross error (blunder)', 'Blunders (mistakes) are large, sporadic, and must be found via checks/redundancy and removed. Systematic errors are corrected by formula; random errors are treated statistically.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000003', 'Four independent distances with standard errors ±0.02, ±0.02, ±0.03, and ±0.04 ft are added. The standard error of the total is most nearly:', 'multiple_choice', '["±0.06 ft","±0.11 ft","±0.055 ft","±0.02 ft"]'::jsonb, '±0.055 ft', 'E = √(0.02²+0.02²+0.03²+0.04²) = √(0.0004+0.0004+0.0009+0.0016) = √0.0033 = 0.0574 ≈ 0.055 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000004', 'A rectangular lot is 100.00 ± 0.03 ft by 250.00 ± 0.05 ft. The standard error of its area is most nearly:', 'multiple_choice', '["±5.6 ft²","±9.0 ft²","±13.5 ft²","±16.0 ft²"]'::jsonb, '±9.0 ft²', 'σ_A = √((b·σ_a)² + (a·σ_b)²) = √((250·0.03)² + (100·0.05)²) = √(7.5² + 5²) = √(56.25+25) = √81.25 = 9.0 ft².', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000005', 'In a normal distribution of random errors, approximately 99.7% of observations fall within:', 'multiple_choice', '["±1σ","±2σ","±3σ","±0.6745σ"]'::jsonb, '±3σ', 'The 68-95-99.7 rule: ±1σ ≈ 68.3%, ±2σ ≈ 95.4%, ±3σ ≈ 99.7%.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000006', 'Weight assigned to an observation in a weighted mean is proportional to:', 'multiple_choice', '["The standard deviation σ","The variance σ²","The inverse of the variance 1/σ²","The number of observations"]'::jsonb, 'The inverse of the variance 1/σ²', 'More precise measurements (smaller σ) receive more weight: w ∝ 1/σ².', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000007', 'A surveyor''s tape is 0.02 ft too long and this length is used for every measurement along a line. This is an example of:', 'multiple_choice', '["A random error","A systematic error","A blunder","A standard error"]'::jsonb, 'A systematic error', 'A tape standardization error repeats with the same sign and magnitude each tape length and accumulates — the definition of a systematic error, correctable by formula.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000008', 'A traverse perimeter is 4,000 ft with a linear misclosure of 0.40 ft. The relative precision is:', 'multiple_choice', '["1:1,000","1:4,000","1:10,000","1:40,000"]'::jsonb, '1:10,000', 'N = perimeter/misclosure = 4000/0.40 = 10,000 → 1:10,000.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000009', 'How many feet are in 3.5 Gunter''s chains?', 'multiple_choice', '["210 ft","231 ft","350 ft","168 ft"]'::jsonb, '231 ft', '1 chain = 66 ft → 3.5 × 66 = 231 ft.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000010', 'The arithmetic mean of a set of equally-weighted observations is best described as the:', 'multiple_choice', '["Probable error","Most probable value","Standard error","Residual"]'::jsonb, 'Most probable value', 'For equally-weighted direct observations, the mean is the most probable value (MPV) — the value that minimizes Σv².', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000011', 'A measurement has a precision described as ''tight repeatability but a consistent offset from the true value.'' The most likely cause is:', 'multiple_choice', '["Large random errors","An uncorrected systematic error","Too few observations","Excess significant figures"]'::jsonb, 'An uncorrected systematic error', 'A consistent offset (bias) with tight repeatability indicates a systematic error — precise but not accurate.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000012', 'An angle is turned with σ = 6″. To reduce the standard error of the mean to 2″, how many repetitions are required?', 'multiple_choice', '["3","9","18","36"]'::jsonb, '9', 'σ_m = σ/√n ≤ 2 → √n ≥ 6/2 = 3 → n ≥ 9.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000013', 'How many acres are in a parcel of 130,680 ft²?', 'multiple_choice', '["2.5 acres","3.0 acres","3.5 acres","4.0 acres"]'::jsonb, '3.0 acres', '130,680 / 43,560 = 3.0 acres (1 acre = 43,560 ft²).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000014', 'Which statement about random errors is correct?', 'multiple_choice', '["They are always positive","They are equally likely positive or negative and follow the normal curve","They can be eliminated by a correction formula","They are the same as blunders"]'::jsonb, 'They are equally likely positive or negative and follow the normal curve', 'Random (accidental) errors are symmetric about zero, follow the normal distribution, and partially cancel with redundancy.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000015', 'The probable error E₅₀ equals 0.6745σ. If σ = 0.04 ft, the probable error is most nearly:', 'multiple_choice', '["±0.020 ft","±0.027 ft","±0.040 ft","±0.067 ft"]'::jsonb, '±0.027 ft', 'E₅₀ = 0.6745 × 0.04 = 0.0270 ft — half of all errors are smaller than this.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb017000-0000-0000-0000-000000000016', 'A result computed by multiplying two quantities, each measured to 4 significant figures, should be reported to how many significant figures?', 'multiple_choice', '["2","4","6","8"]'::jsonb, '4', 'In multiplication, the product carries the significant figures of the least precise factor — 4 significant figures.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m1','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000001', 'In differential leveling using the height-of-instrument method, a backsight (BS) is:', 'multiple_choice', '["A rod reading on a point of known elevation, added to that elevation to get the HI","A rod reading on a point of unknown elevation, subtracted from the HI","The horizontal distance from the instrument to the benchmark","The vertical angle measured to a distant target"]'::jsonb, 'A rod reading on a point of known elevation, added to that elevation to get the HI', 'A backsight (plus sight) is taken on a point of known elevation. HI = Elev + BS. A foresight is the minus sight taken on a point being determined.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000002', 'Which equation gives the elevation of a new point from the height of instrument?', 'multiple_choice', '["Elev = HI − FS","Elev = HI + FS","Elev = HI − BS","Elev = FS − HI"]'::jsonb, 'Elev = HI − FS', 'The foresight is subtracted from the line-of-sight elevation (HI): Elev = HI − FS. The backsight is what was added to form the HI.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000003', 'BM-A has elevation 318.40 ft. The level reads a backsight of 6.12 ft on BM-A. What is the height of instrument (HI)?', 'multiple_choice', '["324.52 ft","312.28 ft","6.12 ft","330.64 ft"]'::jsonb, '324.52 ft', 'HI = Elev + BS = 318.40 + 6.12 = 324.52 ft.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000004', 'With an HI of 324.52 ft, a foresight of 9.30 ft is read on point P. The elevation of P is:', 'multiple_choice', '["315.22 ft","333.82 ft","309.10 ft","9.30 ft"]'::jsonb, '315.22 ft', 'Elev_P = HI − FS = 324.52 − 9.30 = 315.22 ft.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000005', 'Over a level run, ΣBS = 18.42 ft and ΣFS = 22.05 ft. The net change in elevation from the first to the last point is:', 'multiple_choice', '["−3.63 ft","+3.63 ft","+40.47 ft","−40.47 ft"]'::jsonb, '−3.63 ft', 'ΔElev = ΣBS − ΣFS = 18.42 − 22.05 = −3.63 ft. The endpoint is lower than the start.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000006', 'The arithmetic (page) check on a level note verifies that:', 'multiple_choice', '["ΣBS − ΣFS equals the last elevation minus the first elevation","The instrument is in collimation","Curvature and refraction have been removed","No field blunders occurred in reading the rod"]'::jsonb, 'ΣBS − ΣFS equals the last elevation minus the first elevation', 'The check confirms the bookkeeping: ΣBS − ΣFS must equal Elev_last − Elev_first. It does not detect field reading blunders or systematic errors.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000007', 'A point used to transfer the line of sight from one instrument setup to the next, on which both a foresight and the following backsight are read, is called a:', 'multiple_choice', '["Turning point (TP)","Benchmark (BM)","Backsight station","Datum point"]'::jsonb, 'Turning point (TP)', 'A turning point is a temporary, well-defined point used to carry elevation forward. A benchmark is a permanent point of published elevation.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000008', 'For a level sight of 4,000 ft, the combined curvature-and-refraction correction (rod reading, ft) is most nearly:', 'multiple_choice', '["0.33 ft","0.082 ft","3.3 ft","0.021 ft"]'::jsonb, '0.33 ft', 'F = 4000/1000 = 4. C_R = 0.0206·F² = 0.0206 × 16 = 0.330 ft.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000009', 'In differential leveling, the effect of curvature and refraction is essentially eliminated by:', 'multiple_choice', '["Balancing (equalizing) backsight and foresight distances","Using a longer rod","Reading only the middle crosshair","Leveling only downhill"]'::jsonb, 'Balancing (equalizing) backsight and foresight distances', 'When BS and FS distances are equal, the curvature-and-refraction (and collimation) errors are the same magnitude on both sights and cancel in the difference.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000010', 'Earth curvature causes a level rod reading at a long distance to appear:', 'multiple_choice', '["Too high (larger than true)","Too low (smaller than true)","Unchanged","Negative"]'::jsonb, 'Too high (larger than true)', 'Curvature drops the earth''s surface away from the horizontal line of sight, so the line strikes the rod higher, reading too high. Refraction partially offsets this.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000011', 'A field test that detects collimation error (a line of sight not truly horizontal) is the:', 'multiple_choice', '["Two-peg test","Three-wire test","Stadia test","Compass rule test"]'::jsonb, 'Two-peg test', 'The two-peg test compares an equal-distance (cancelling) setup against an unequal-distance setup to isolate the collimation error per unit distance.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000012', 'From station A (Elev 600.00 ft) a total station measures a horizontal distance of 500.0 ft to a target at vertical angle +6°00′ (instrument and target heights equal). The elevation of the target is most nearly:', 'multiple_choice', '["652.6 ft","547.4 ft","549.7 ft","650.3 ft"]'::jsonb, '652.6 ft', 'ΔElev = d·tan V = 500.0 × tan(6°) = 500.0 × 0.10510 = 52.55 ft. Elev = 600.00 + 52.55 = 652.55 ≈ 652.6 ft.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000013', 'If a total station reads a zenith angle z (measured from the vertical/zenith) and slope distance S, the elevation difference is:', 'multiple_choice', '["ΔElev = S·cos(z)","ΔElev = S·sin(z)","ΔElev = S·tan(z)","ΔElev = S/cos(z)"]'::jsonb, 'ΔElev = S·cos(z)', 'A zenith angle is measured down from vertical, so the vertical component is S·cos(z). (For a vertical angle V from horizontal, ΔElev = S·sin V.)', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000014', 'The current official vertical datum for the conterminous United States is:', 'multiple_choice', '["NAVD88","NAD83","NGVD29","WGS84"]'::jsonb, 'NAVD88', 'NAVD88 is the current US vertical datum (orthometric heights). NGVD29 is its predecessor; NAD83 and WGS84 are horizontal/3-D datums.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000015', 'Reciprocal leveling (reading both ends from each bank) is used primarily to:', 'multiple_choice', '["Cancel curvature, refraction, and collimation across a wide obstacle such as a river","Speed up leveling by halving the number of setups","Convert ellipsoid heights to orthometric heights","Eliminate the need for a level rod"]'::jsonb, 'Cancel curvature, refraction, and collimation across a wide obstacle such as a river', 'Because equal-distance balancing is impossible across a river, reciprocal observations from each bank are averaged: Δh = ½[(a₁−b₁)+(a₂−b₂)], cancelling the systematic errors.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000016', 'In three-wire leveling, the rod reading used for the computation is taken as:', 'multiple_choice', '["The mean of the upper, middle, and lower crosshair readings","The upper crosshair only","The difference of the upper and lower readings","The lower crosshair only"]'::jsonb, 'The mean of the upper, middle, and lower crosshair readings', 'Reading = (U + M + L)/3, with the half-interval check (U − M) ≈ (M − L). The stadia interval also gives the sight distance ≈ 100·(U − L).', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000017', 'A level loop closes with a misclosure of +0.06 ft over a total distance of 1.5 miles. The allowable third-order closure is 0.05·√(miles). Does the loop meet third-order accuracy?', 'multiple_choice', '["Yes — allowable is 0.061 ft, so 0.06 ft is within tolerance","No — allowable is 0.05 ft","Yes — allowable is 0.075 ft","No — allowable is 0.033 ft"]'::jsonb, 'Yes — allowable is 0.061 ft, so 0.06 ft is within tolerance', 'Allowable = 0.05·√1.5 = 0.05 × 1.225 = 0.061 ft. The 0.06 ft misclosure is just within the limit.', 'hard', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000018', 'When distributing a level loop misclosure, the correction at each point is proportional to:', 'multiple_choice', '["The distance leveled (or number of setups) to that point","The square of the elevation","The backsight reading at that point","The latitude of the point"]'::jsonb, 'The distance leveled (or number of setups) to that point', 'Random leveling error accumulates with distance, so the correction is distributed in proportion to cumulative distance (or setup count) along the run.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000019', 'A backsight of 2.55 ft is read on BM-1 (Elev 410.20 ft) and a foresight of 8.40 ft is read on BM-2. The elevation of BM-2 is:', 'multiple_choice', '["404.35 ft","421.15 ft","416.05 ft","399.25 ft"]'::jsonb, '404.35 ft', 'HI = 410.20 + 2.55 = 412.75 ft; Elev_BM-2 = 412.75 − 8.40 = 404.35 ft.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000020', 'Orthometric height H (the elevation obtained by leveling) is related to the GPS ellipsoid height h and geoid height N by:', 'multiple_choice', '["H = h − N","H = h + N","H = N − h","H = h × N"]'::jsonb, 'H = h − N', 'Leveling yields orthometric heights referenced to the geoid: H = h − N, where h is the ellipsoid height from GPS and N is the geoid undulation.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000021', 'Profile leveling is performed primarily to:', 'multiple_choice', '["Determine elevations of points along a route for plotting a profile and designing grades","Establish horizontal control coordinates","Measure angles between two benchmarks","Convert bearings to azimuths"]'::jsonb, 'Determine elevations of points along a route for plotting a profile and designing grades', 'Profile leveling collects ground elevations along a centerline (with intermediate foresights) to plot the profile used for vertical-curve and grade design.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000022', 'True or False: In differential leveling, intermediate sights (other than turning points) are included in the ΣBS − ΣFS arithmetic check.', 'true_false', '["True","False"]'::jsonb, 'False', 'Only the plus sights (BS) and the turning-point/closing minus sights (FS) carry the line of sight forward and enter ΣBS − ΣFS. Intermediate foresights (e.g., in profile leveling) give point elevations but are not part of the running check.', 'hard', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000023', 'A sight distance of 1,500 ft gives a curvature-only correction (C = 0.0240·F²) of most nearly:', 'multiple_choice', '["0.054 ft","0.36 ft","0.046 ft","0.012 ft"]'::jsonb, '0.054 ft', 'F = 1.5; C = 0.0240 × 1.5² = 0.0240 × 2.25 = 0.054 ft.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb023000-0000-0000-0000-000000000024', 'Which statement about the HI method versus the rise-and-fall method of reducing levels is correct?', 'multiple_choice', '["The HI method computes a line-of-sight elevation (HI) then subtracts foresights; the rise-and-fall method differences successive readings directly","The two methods give different final elevations","The HI method cannot use turning points","The rise-and-fall method ignores backsights"]'::jsonb, 'The HI method computes a line-of-sight elevation (HI) then subtracts foresights; the rise-and-fall method differences successive readings directly', 'Both yield identical elevations. The HI method (HI = Elev + BS, Elev = HI − FS) is faster for many intermediate sights; rise-and-fall provides an extra per-leg check.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000001', 'A level is set up and reads a backsight of {{bs:f2}} ft on benchmark BM-A, whose elevation is {{elevBM:f2}} ft. Compute the height of instrument (HI), in ft.', 'numeric_input', '[]'::jsonb, '0', 'The backsight is a plus sight added to the known benchmark elevation: HI = {{elevBM:f2}} + {{bs:f2}} = {{_answer}} ft.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000002', 'Benchmark BM-A has elevation {{elevBM:f2}} ft. The level reads a backsight of {{bs:f2}} ft on BM-A, then a foresight of {{fs:f2}} ft on point P. Compute the elevation of point P, in ft.', 'numeric_input', '[]'::jsonb, '0', 'HI = {{elevBM:f2}} + {{bs:f2}} = {{hi:f2}} ft, then Elev_P = HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft.', 'easy', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000002', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000003', 'A differential level run starts on BM-1 (elevation {{elevBM:f2}} ft). Over the run the sum of backsights is ΣBS = {{sumBS:f2}} ft and the sum of foresights is ΣFS = {{sumFS:f2}} ft. Compute the elevation of the closing point, in ft.', 'numeric_input', '[]'::jsonb, '0', 'ΔElev = ΣBS − ΣFS = {{sumBS:f2}} − {{sumFS:f2}} = {{dElev:f2}} ft. Closing elevation = {{elevBM:f2}} + {{dElev:f2}} = {{_answer}} ft.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000003', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000004', 'A level sight is {{distFt}} ft long. Using the combined curvature-and-refraction relation C_R = 0.0206·F² (F in thousands of feet), compute the correction to the rod reading, in ft.', 'numeric_input', '[]'::jsonb, '0', 'With F = {{distFt}}/1000 = {{F:f2}} thousand ft, C_R = 0.0206·F² = {{_answer}} ft. This correction is subtracted from a long foresight; balancing BS and FS distances cancels it.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000004', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000005', 'From station A (elevation {{elevA:f2}} ft) a total station measures a horizontal distance of {{dist:f1}} ft to a prism at a vertical angle of {{vAngle:dms}} above horizontal. Instrument and prism heights are equal. Compute the elevation of the prism point, in ft.', 'numeric_input', '[]'::jsonb, '0', 'With equal instrument and prism heights, ΔElev = d·tan(V) = {{dist:f1}} × tan({{vAngle:dms}}) = {{dElev:f2}} ft, so the prism elevation = {{elevA:f2}} + {{dElev:f2}} = {{_answer}} ft.', 'medium', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000005', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb026000-0000-0000-0000-000000000006', 'A level loop starts on BM-100 (elevation {{elevStart:f3}} ft) and is run to BM-101, whose published elevation is {{elevKnown:f3}} ft. The notes give ΣBS = {{sumBS:f3}} ft and ΣFS = {{sumFS:f3}} ft. Compute the loop misclosure (observed closing elevation − published elevation), in ft.', 'numeric_input', '[]'::jsonb, '0', 'Observed closing elevation = {{elevStart:f3}} + ΣBS − ΣFS = {{obsClose:f3}} ft. Misclosure = observed − published = {{obsClose:f3}} − {{elevKnown:f3}} = {{_answer}} ft; the correction (opposite sign) is distributed in proportion to distance leveled.', 'hard', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb025000-0000-0000-0000-000000000006', 0.002);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000001', 'A backsight of 4.78 ft is taken on a benchmark at elevation 521.36 ft; a foresight of 6.90 ft is then read on a turning point. The elevation of the turning point is most nearly:', 'multiple_choice', '["519.24 ft","523.48 ft","513.68 ft","532.04 ft"]'::jsonb, '519.24 ft', 'HI = 521.36 + 4.78 = 526.14 ft; Elev_TP = 526.14 − 6.90 = 519.24 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000002', 'In a differential level run, ΣBS = 27.65 ft and ΣFS = 24.10 ft. The closing point relative to the starting benchmark is:', 'multiple_choice', '["3.55 ft higher","3.55 ft lower","51.75 ft higher","Unchanged in elevation"]'::jsonb, '3.55 ft higher', 'ΔElev = ΣBS − ΣFS = 27.65 − 24.10 = +3.55 ft, so the closing point is 3.55 ft higher.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000003', 'The combined curvature-and-refraction correction for a 5,000-ft sight (C_R = 0.0206·F², F in thousands of ft) is most nearly:', 'multiple_choice', '["0.52 ft","0.10 ft","5.2 ft","0.026 ft"]'::jsonb, '0.52 ft', 'F = 5; C_R = 0.0206 × 25 = 0.515 ≈ 0.52 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000004', 'From a station at elevation 740.00 ft, a horizontal distance of 800.0 ft is measured to a target at a vertical angle of +2°30′ (equal instrument and target heights). The target elevation is most nearly:', 'multiple_choice', '["774.9 ft","705.1 ft","769.9 ft","740.0 ft"]'::jsonb, '774.9 ft', 'ΔElev = 800.0 × tan(2.5°) = 800.0 × 0.043661 = 34.93 ft; Elev = 740.00 + 34.93 = 774.93 ≈ 774.9 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000005', 'Why are backsight and foresight distances kept approximately equal in differential leveling?', 'multiple_choice', '["To cancel curvature, refraction, and collimation errors","To reduce the number of turning points","To make the rod readings smaller","To convert orthometric heights to ellipsoid heights"]'::jsonb, 'To cancel curvature, refraction, and collimation errors', 'Equal sight distances make the systematic errors equal on the BS and FS so they cancel in the difference.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000006', 'Which field test is used to determine whether a level''s line of sight is truly horizontal when the bubble is centered?', 'multiple_choice', '["The two-peg test","The stadia test","The collimation traverse","The compass rule"]'::jsonb, 'The two-peg test', 'The two-peg test isolates collimation error by comparing an equal-distance setup with an unequal-distance setup.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000007', 'The current official vertical datum used for orthometric elevations in the conterminous United States is:', 'multiple_choice', '["NAVD88","NGVD29","NAD83","WGS84"]'::jsonb, 'NAVD88', 'NAVD88 is the current US vertical datum; NGVD29 is its predecessor; NAD83 and WGS84 are horizontal/3-D datums.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000008', 'A level loop is run 2.0 miles and closes with a misclosure of 0.08 ft. If the third-order allowable closure is 0.05·√(miles), the loop:', 'multiple_choice', '["Fails — allowable is about 0.071 ft","Passes — allowable is about 0.10 ft","Passes — allowable is about 0.16 ft","Fails — allowable is about 0.025 ft"]'::jsonb, 'Fails — allowable is about 0.071 ft', 'Allowable = 0.05·√2.0 = 0.05 × 1.414 = 0.071 ft. The 0.08-ft misclosure exceeds this, so the loop fails third-order.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000009', 'In three-wire leveling the rod reading used in the reduction is:', 'multiple_choice', '["The mean of the upper, middle, and lower crosshair readings","The middle crosshair only","The sum of all three readings","The upper minus the lower reading"]'::jsonb, 'The mean of the upper, middle, and lower crosshair readings', 'Reading = (U + M + L)/3, providing redundancy and a check (U − M ≈ M − L); the interval also yields the sight distance ≈ 100·(U − L).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000010', 'A level note shows ΣBS − ΣFS = +12.43 ft and the starting and closing elevations differ by +12.40 ft. The +0.03-ft difference indicates:', 'multiple_choice', '["An arithmetic or accumulated leveling error to be checked/distributed","That curvature was not corrected","A horizontal angle blunder","That the datum is NGVD29"]'::jsonb, 'An arithmetic or accumulated leveling error to be checked/distributed', 'ΣBS − ΣFS should equal the elevation difference exactly; a small residual is misclosure (accumulated error) to be verified and, if within tolerance, distributed.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000011', 'Reciprocal leveling is most appropriate when:', 'multiple_choice', '["A wide river or canyon prevents equal backsight and foresight distances","The benchmark elevation is unknown","Only one rod is available","The line of sight is exactly horizontal"]'::jsonb, 'A wide river or canyon prevents equal backsight and foresight distances', 'When sights cannot be balanced, reading both points from each side and averaging cancels curvature, refraction, and collimation.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000012', 'Leveling produces orthometric heights (H). To convert a GPS-derived ellipsoid height (h) to an orthometric height you apply the geoid height (N) using:', 'multiple_choice', '["H = h − N","H = h + N","H = N − h","H = h · N"]'::jsonb, 'H = h − N', 'Orthometric height equals ellipsoid height minus geoid undulation: H = h − N.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000013', 'A surveyor must establish the elevation of a point 0.6 mile from the nearest benchmark, with intermediate ground shots for a road profile. The most appropriate procedure is:', 'multiple_choice', '["Differential and profile leveling carrying turning points from the benchmark","A single trigonometric sight with no benchmark tie","GPS RTK without a geoid model","Taping the slope distance only"]'::jsonb, 'Differential and profile leveling carrying turning points from the benchmark', 'Differential leveling carries control from the benchmark via turning points; profile leveling adds the intermediate ground shots for the road profile.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb027000-0000-0000-0000-000000000014', 'For a 3,000-ft sight, the earth-curvature-only correction (C = 0.0240·F², F in thousands of ft) is most nearly:', 'multiple_choice', '["0.216 ft","0.185 ft","0.072 ft","2.16 ft"]'::jsonb, '0.216 ft', 'F = 3; C = 0.0240 × 9 = 0.216 ft. (Combined with refraction it would be 0.0206 × 9 = 0.185 ft.)', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m2','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000001', 'A steel tape is standardized at 68°F. The coefficient of thermal expansion for steel used on the FS is most nearly:', 'multiple_choice', '["0.00000645 per °F","0.0000645 per °F","0.00000116 per °F","0.0000116 per °F"]'::jsonb, '0.00000645 per °F', 'For steel, α ≈ 6.45×10⁻⁶ per °F (the value 11.6×10⁻⁶ is the per-°C coefficient). The temperature correction is Ct = 0.00000645·(T − 68)·L.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000002', 'A 100.00-ft measured distance is taped at 103°F with a tape standardized at 68°F. The temperature correction is most nearly:', 'multiple_choice', '["+0.023 ft","+0.045 ft","+0.090 ft","−0.023 ft"]'::jsonb, '+0.023 ft', 'Ct = 0.00000645·(103 − 68)·100.00 = 0.00000645·35·100 = +0.0226 ft. Positive because the warm tape reads short.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000003', 'The sag correction applied to a tape suspended only at its ends is:', 'multiple_choice', '["Always negative (the tape reads long)","Always positive (the tape reads short)","Zero if tension equals the standard pull","Equal in magnitude to the slope correction"]'::jsonb, 'Always negative (the tape reads long)', 'An unsupported tape hangs as a catenary, so the measured distance is longer than the true horizontal chord; the correction Cs = −w²L³/(24P²) is always subtractive.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000004', 'A slope distance of 250.00 ft is measured along a grade with a zenith angle of 92°00′00″. The horizontal distance is most nearly:', 'multiple_choice', '["249.85 ft","250.15 ft","248.48 ft","250.00 ft"]'::jsonb, '249.85 ft', 'H = S·sin(Z) = 250.00·sin(92°) = 250.00·0.999391 = 249.85 ft.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000005', 'A zenith angle of 90°00′00″ corresponds to a vertical angle of:', 'multiple_choice', '["0°00′00″","90°00′00″","180°00′00″","45°00′00″"]'::jsonb, '0°00′00″', 'Z = 90° − α, so a level sight (Z = 90°) is a vertical angle of 0°.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000006', 'Which best describes the purpose of observing an angle in both direct and reverse (face-left and face-right) positions?', 'multiple_choice', '["It cancels instrumental errors such as collimation and horizontal-axis tilt","It eliminates the need for a back-azimuth","It corrects for magnetic declination","It reduces a slope distance to horizontal"]'::jsonb, 'It cancels instrumental errors such as collimation and horizontal-axis tilt', 'Meaning the direct and reverse observations cancels systematic instrumental errors (collimation, trunnion-axis tilt, vertical-circle index). It has nothing to do with declination or slope reduction.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000007', 'An EDM is rated ±(3 mm + 2 ppm). For a 2,000-m line, the standard error is most nearly:', 'multiple_choice', '["7 mm","5 mm","3 mm","23 mm"]'::jsonb, '7 mm', 'ppm term = 2 ppm × 2.000 km = 4 mm; total e = 3 + 4 = 7 mm. (2 ppm of 2,000,000 mm = 4 mm.)', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000008', 'Approximately what change in conditions produces a 10-ppm atmospheric correction to an EDM distance?', 'multiple_choice', '["A 10°C temperature change or a 1 in Hg pressure change","A 1°C temperature change or a 10 in Hg pressure change","A 100°C temperature change","Any change in the prism constant"]'::jsonb, 'A 10°C temperature change or a 1 in Hg pressure change', 'As a rule of thumb, roughly a 10°C temperature difference, or a 1 in Hg (≈25 mm Hg) pressure difference, corresponds to about 10 ppm of distance correction.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000009', 'Convert the azimuth 312°20′00″ to a bearing.', 'multiple_choice', '["N 47°40′00″ W","S 47°40′00″ W","N 47°40′00″ E","S 47°40′00″ E"]'::jsonb, 'N 47°40′00″ W', '312° is in Quadrant IV (270°–360°, NW), so bearing = 360° − Az = 360° − 312°20′ = 47°40′, written N 47°40′00″ W.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000010', 'Convert the bearing S 23°15′00″ E to an azimuth.', 'multiple_choice', '["156°45′00″","203°15′00″","23°15′00″","336°45′00″"]'::jsonb, '156°45′00″', 'SE quadrant: Az = 180° − bearing = 180° − 23°15′ = 156°45′00″.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000011', 'The azimuth of a line is 73°10′00″. Its back-azimuth is:', 'multiple_choice', '["253°10′00″","106°50′00″","286°50′00″","163°10′00″"]'::jsonb, '253°10′00″', 'Az < 180°, so Back-Az = Az + 180° = 73°10′ + 180° = 253°10′00″.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000012', 'Convert 41°27′36″ to decimal degrees.', 'multiple_choice', '["41.4600°","41.2736°","41.4536°","41.4760°"]'::jsonb, '41.4600°', 'dd = 41 + 27/60 + 36/3600 = 41 + 0.45 + 0.01 = 41.4600°.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000013', 'Add the angles 38°52′40″ + 16°19′35″. The sum is:', 'multiple_choice', '["55°12′15″","55°11′75″","54°12′15″","55°12′05″"]'::jsonb, '55°12′15″', 'Seconds: 40+35=75″ = 1′15″. Minutes: 52+19+1 = 72′ = 1°12′. Degrees: 38+16+1 = 55°. Sum = 55°12′15″.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000014', 'An old deed calls a line N 18°00′ W (magnetic) where the declination was 6°30′ West at the time of the survey. The true bearing is:', 'multiple_choice', '["N 24°30′ W","N 11°30′ W","N 18°00′ W","S 24°30′ E"]'::jsonb, 'N 24°30′ W', 'For a NW-quadrant magnetic bearing, west declination rotates the magnetic meridian west of true, so the true bearing swings further from north: N (18°00′ + 6°30′) W = N 24°30′ W. (Carefully reason the geometry; a west declination is subtracted for an east bearing but increases a west bearing.)', 'hard', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000015', 'A total station outputs which set of raw values directly?', 'multiple_choice', '["Horizontal angle, zenith angle, and slope distance","Latitude, departure, and area","Northing, easting, and elevation only","Magnetic bearing and declination"]'::jsonb, 'Horizontal angle, zenith angle, and slope distance', 'A total station marries an electronic theodolite (horizontal + zenith angles) to an EDM (slope distance); it then computes H, V, and coordinates internally.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000016', 'A reflectorless total station differs from a conventional total station primarily in that it:', 'multiple_choice', '["Measures distance to a surface without a prism","Cannot measure vertical angles","Requires two operators","Uses a steel tape for backup"]'::jsonb, 'Measures distance to a surface without a prism', 'Reflectorless EDM returns the signal from the target surface itself, eliminating the prism for points that are hard or unsafe to occupy.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000017', 'The instrument (additive) constant of an EDM is best described as:', 'multiple_choice', '["A fixed offset, in mm, independent of the distance measured","An error proportional to the distance","The atmospheric ppm correction","The prism height above the point"]'::jsonb, 'A fixed offset, in mm, independent of the distance measured', 'The additive/zero constant is a constant offset (in mm) regardless of distance; the ppm/scale term is the distance-proportional part.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000018', 'A line is taped down a uniform 8% grade as a slope length of 300.00 ft. The horizontal distance is most nearly (use the approximate slope correction Ch ≈ −h²/2L):', 'multiple_choice', '["299.04 ft","300.96 ft","298.10 ft","300.00 ft"]'::jsonb, '299.04 ft', 'h = 0.08·300 = 24.0 ft. Ch ≈ −h²/(2L) = −(24²)/(2·300) = −576/600 = −0.96 ft. H ≈ 300.00 − 0.96 = 299.04 ft.', 'hard', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000019', 'Which calculator function most directly converts a distance and azimuth into a latitude (ΔN) and departure (ΔE)?', 'multiple_choice', '["Polar-to-rectangular (P▸R / Rec)","Rectangular-to-polar (R▸P / Pol)","DMS-to-decimal (▸DD)","Reciprocal (1/x)"]'::jsonb, 'Polar-to-rectangular (P▸R / Rec)', 'P▸R converts (distance, azimuth) into the rectangular components (ΔE, ΔN). R▸P does the inverse (components → distance and azimuth).', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000020', 'True or False: A vertical angle is measured up or down from the horizontal plane, while a zenith angle is measured down from the upward vertical.', 'true_false', '["True","False"]'::jsonb, 'True', 'Correct. Vertical angle α = 0° at the horizon; zenith angle Z = 0° straight up and 90° at the horizon, so Z = 90° − α.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000021', 'True or False: The temperature correction Ct = 0.00000645·(T − 68)·L is negative when the tape is colder than 68°F.', 'true_false', '["True","False"]'::jsonb, 'True', 'When T < 68°F, (T − 68) is negative, so Ct is negative — a cold tape has contracted and reads long, so the true measured distance is slightly shorter.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000022', 'A slope distance of 180.00 ft is observed with a vertical angle of +3°30′00″. The horizontal distance is most nearly:', 'numeric_input', '[]'::jsonb, '179.67', 'H = S·cos(α) = 180.00·cos(3.5°) = 180.00·0.998135 = 179.66 ≈ 179.67 ft.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000023', 'Express 218°43′52″ in total seconds of arc.', 'numeric_input', '[]'::jsonb, '787432', 'Total seconds = 218·3600 + 43·60 + 52 = 784,800 + 2,580 + 52 = 787,432″.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000024', 'The ''2C'' value used as a collimation check is computed as:', 'multiple_choice', '["(Direct + Reverse) − 360°","(Direct − Reverse) / 2","Direct + Reverse","90° − vertical angle"]'::jsonb, '(Direct + Reverse) − 360°', 'For a pointing, the reverse reading should differ from the direct by 180°; 2C = (Direct + Reverse) − 360° gives twice the collimation error and should be small and consistent.', 'hard', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000025', 'For the most accurate EDM measurement over a long line on a hot day, the surveyor should primarily:', 'multiple_choice', '["Record temperature and pressure to apply the atmospheric (ppm) correction","Replace the tripod","Use an umbrella to shade the instrument battery","Avoid measuring near power lines"]'::jsonb, 'Record temperature and pressure to apply the atmospheric (ppm) correction', 'The dominant variable error over a long EDM line is the atmospheric (ppm) correction, which depends on temperature and pressure; recording them lets you apply the correct ppm.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb033000-0000-0000-0000-000000000026', 'A line measured with an EDM reads 1,402.118 m. The instrument''s additive (prism) constant is −0.030 m. The corrected distance is:', 'multiple_choice', '["1,402.088 m","1,402.148 m","1,402.118 m","1,372.118 m"]'::jsonb, '1,402.088 m', 'Apply the additive constant: 1,402.118 + (−0.030) = 1,402.088 m.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000001', 'Convert the angle {{D}}°{{M}}′{{S}}″ to decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'Decimal degrees = {{D}} + {{M}}/60 + {{S}}/3600 = {{_answer}}°. On the TI-36X Pro enter the angle with the °’” key and toggle to decimal with 2nd °’”.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000001', 0.001);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000002', 'Express the angle {{D}}°{{M}}′{{S}}″ in total seconds of arc.', 'numeric_input', '[]'::jsonb, '0', 'Total seconds = {{D}}·3600 + {{M}}·60 + {{S}} = {{_answer}}″.', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000002', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000003', 'A line has azimuth {{az:f4}}°, which lies in the SW quadrant. Give the bearing angle (degrees from south, toward west).', 'numeric_input', '[]'::jsonb, '0', 'For an azimuth in the SW quadrant (180°–270°), bearing = Az − 180° = {{az:f4}} − 180 = {{_answer}}°, written S {{_answer}}° W.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000003', 0.001);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000004', 'A line bears N {{brg:f4}}° W. Compute its azimuth (clockwise from north, 0°–360°).', 'numeric_input', '[]'::jsonb, '0', 'For a NW-quadrant bearing, azimuth = 360° − bearing = 360 − {{brg:f4}} = {{_answer}}°.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000004', 0.001);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000005', 'The forward azimuth of a line is {{az:f4}}°. Compute its back-azimuth (0°–360°).', 'numeric_input', '[]'::jsonb, '0', 'Back-azimuth = Az ± 180° = {{_answer}}° (add 180° when Az < 180°, subtract 180° when Az ≥ 180°).', 'easy', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000005', 0.001);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000006', 'A distance of {{L:f2}} ft is measured with a steel tape standardized at 68°F. The field temperature is {{T}}°F. Compute the corrected length (ft). Use Ct = 0.00000645·(T − 68)·L.', 'numeric_input', '[]'::jsonb, '0', 'Ct = 0.00000645·({{T}}−68)·{{L:f2}} = {{Ct:f3}} ft; corrected length = {{L:f2}} + {{Ct:f3}} = {{_answer}} ft. The correction is positive when T > 68°F (hot tape reads short).', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000006', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000007', 'A total station measures a slope distance of {{S:f3}} ft with a zenith angle of {{Zd}}°{{Zm}}′{{Zs}}″. Compute the horizontal distance (ft). Use H = S·sin(Z).', 'numeric_input', '[]'::jsonb, '0', 'Convert the zenith angle to {{Zdd:f4}}°, then H = S·sin(Z) = {{S:f3}}·sin({{Zdd:f4}}°) = {{_answer}} ft. Enter the angle in DMS and keep the calculator in DEG mode.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000007', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb036000-0000-0000-0000-000000000008', 'An EDM is rated ±({{a}} mm + {{b}} ppm). For a measured distance of {{Dm}} m, compute the worst-case standard error (mm).', 'numeric_input', '[]'::jsonb, '0', 'ppm error (mm) = b·D(km) = {{b}}·{{Dkm:f3}} = {{ppmTerm:f2}} mm; total e = a + ppm term = {{a}} + {{ppmTerm:f2}} = {{_answer}} mm. Always convert the distance to km before multiplying by the ppm rating.', 'medium', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb035000-0000-0000-0000-000000000008', 0.05);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000001', 'A 500.00-ft distance is taped at 38°F with a steel tape standardized at 68°F. Using Ct = 0.00000645·(T−68)·L, the corrected length is most nearly:', 'multiple_choice', '["499.90 ft","500.10 ft","499.97 ft","500.03 ft"]'::jsonb, '499.90 ft', 'Ct = 0.00000645·(38−68)·500 = 0.00000645·(−30)·500 = −0.097 ft. Corrected = 500.00 − 0.097 ≈ 499.90 ft (cold tape contracts and reads long).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000002', 'A slope distance of 326.40 ft is measured with a zenith angle of 85°30′00″. The horizontal distance is most nearly:', 'multiple_choice', '["325.44 ft","326.40 ft","324.20 ft","326.00 ft"]'::jsonb, '325.44 ft', 'H = S·sin(Z) = 326.40·sin(85°30′) = 326.40·0.997045 = 325.44 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000003', 'The azimuth 248°15′00″ expressed as a bearing is:', 'multiple_choice', '["S 68°15′00″ W","N 68°15′00″ W","S 68°15′00″ E","N 68°15′00″ E"]'::jsonb, 'S 68°15′00″ W', '248° is in Quadrant III (SW); bearing = Az − 180° = 68°15′, written S 68°15′00″ W.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000004', 'An EDM rated ±(2 mm + 3 ppm) measures a 1,500-m line. The expected standard error is most nearly:', 'multiple_choice', '["6.5 mm","4.5 mm","2.0 mm","11.0 mm"]'::jsonb, '6.5 mm', 'ppm term = 3 × 1.500 km = 4.5 mm; total = 2 + 4.5 = 6.5 mm.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000005', 'Observing a horizontal angle in both face-left and face-right and meaning the results primarily serves to:', 'multiple_choice', '["Cancel instrumental (collimation, axis) errors","Reduce slope distance to horizontal","Convert magnetic bearings to true","Eliminate atmospheric ppm error"]'::jsonb, 'Cancel instrumental (collimation, axis) errors', 'Direct-and-reverse observation cancels systematic instrumental errors; it does nothing for slope, declination, or atmospheric corrections.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000006', 'A zenith angle is measured from the upward vertical. The corresponding vertical angle for a zenith reading of 96°00′00″ is:', 'multiple_choice', '["−6°00′00″","+6°00′00″","+96°00′00″","−96°00′00″"]'::jsonb, '−6°00′00″', 'α = 90° − Z = 90° − 96° = −6° (a depression angle, sighting downhill).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000007', 'Which instrument directly combines an electronic theodolite and an EDM with onboard computation of coordinates?', 'multiple_choice', '["Total station","Automatic level","Plane table","Magnetic compass"]'::jsonb, 'Total station', 'A total station integrates an electronic theodolite (angles) and EDM (distance) with a processor that computes H, V, and coordinates.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000008', 'An 1870 deed line reads N 30°00′ E (magnetic); the declination then was 5°00′ East. The true bearing is:', 'multiple_choice', '["N 35°00′ E","N 25°00′ E","S 35°00′ W","N 30°00′ E"]'::jsonb, 'N 35°00′ E', 'For an east-quadrant bearing, east declination is added: N (30°00′ + 5°00′) E = N 35°00′ E.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000009', 'The sag correction for a tape supported only at its ends is:', 'multiple_choice', '["Negative (the unsupported tape reads long)","Positive (the tape reads short)","Zero regardless of tension","Equal to the temperature correction"]'::jsonb, 'Negative (the unsupported tape reads long)', 'The catenary sag makes the measured chord longer than the true horizontal distance, so the correction Cs = −w²L³/(24P²) is subtractive.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000010', 'Convert 127°36′18″ to decimal degrees (most nearly):', 'multiple_choice', '["127.6050°","127.3618°","127.6018°","127.6500°"]'::jsonb, '127.6050°', '127 + 36/60 + 18/3600 = 127 + 0.6 + 0.005 = 127.6050°.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000011', 'The sum of 64°48′50″ and 25°22′40″ is:', 'multiple_choice', '["90°11′30″","90°10′90″","89°11′30″","90°11′90″"]'::jsonb, '90°11′30″', 'Seconds: 50+40=90″=1′30″. Minutes: 48+22+1=71′=1°11′. Degrees: 64+25+1=90°. Sum = 90°11′30″.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000012', 'The most direct way to reduce a slope distance S to a horizontal distance H given the vertical angle α is:', 'multiple_choice', '["H = S·cos(α)","H = S·sin(α)","H = S·tan(α)","H = S/cos(α)"]'::jsonb, 'H = S·cos(α)', 'With the vertical angle measured from horizontal, the horizontal component is H = S·cos(α). (Using the zenith angle Z it is H = S·sin(Z).)', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000013', 'For best long-line EDM accuracy, the field crew should mainly record:', 'multiple_choice', '["Temperature and barometric pressure","The battery voltage","Wind speed and humidity only","Tripod leg length"]'::jsonb, 'Temperature and barometric pressure', 'The atmospheric (ppm) correction depends on temperature and pressure; recording them lets the crew apply the correct first-velocity correction.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb037000-0000-0000-0000-000000000014', 'The back-azimuth of a line whose forward azimuth is 200°00′00″ is:', 'multiple_choice', '["20°00′00″","380°00′00″","160°00′00″","20°00′00″ S"]'::jsonb, '20°00′00″', 'Az ≥ 180°, so back-azimuth = 200° − 180° = 20°00′00″.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m3','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000001', 'A closed-loop traverse returns to its starting point. In the absence of error, what must be true of the latitudes and departures of its courses?', 'multiple_choice', '["ΣLat = 0 and ΣDep = 0","ΣLat = ΣDep","ΣLat = perimeter and ΣDep = 0","ΣLat and ΣDep each equal the misclosure"]'::jsonb, 'ΣLat = 0 and ΣDep = 0', 'A loop traverse starts and ends at the same point, so the north–south components (latitudes) must net to zero and the east–west components (departures) must net to zero. Nonzero sums are the closure in latitude and departure, whose vector sum is the linear misclosure.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000002', 'The latitude of a course is computed as:', 'multiple_choice', '["L · cos(azimuth)","L · sin(azimuth)","L · tan(azimuth)","L / cos(azimuth)"]'::jsonb, 'L · cos(azimuth)', 'Latitude is the north–south (Northing) component of a course: Lat = L·cos(Az). The departure is the east–west component, L·sin(Az). Remember ''Latitude–cosine, Departure–sine.''', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000003', 'A course has length 250.00 ft and azimuth 120°00′00″. What are its latitude and departure?', 'multiple_choice', '["Lat = −125.00 ft, Dep = +216.51 ft","Lat = +125.00 ft, Dep = +216.51 ft","Lat = +216.51 ft, Dep = −125.00 ft","Lat = −216.51 ft, Dep = +125.00 ft"]'::jsonb, 'Lat = −125.00 ft, Dep = +216.51 ft', 'Lat = 250·cos120° = 250·(−0.5) = −125.00 ft (south). Dep = 250·sin120° = 250·(0.8660) = +216.51 ft (east). Azimuth 120° is in the SE quadrant, so latitude is negative and departure positive.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000004', 'Which traverse type starts and ends on two DIFFERENT known control points and is checked against the known coordinate difference?', 'multiple_choice', '["Closed-connecting (link) traverse","Closed-loop (polygon) traverse","Open traverse","Radial traverse"]'::jsonb, 'Closed-connecting (link) traverse', 'A closed-connecting or ''link'' traverse begins on one known point and closes on a second known point; the computed coordinate difference is compared with the known difference to assess closure. A loop returns to its start; an open traverse has no closure check.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000005', 'Linear misclosure of a closed traverse is computed from the closure in latitude (ΣLat) and departure (ΣDep) as:', 'multiple_choice', '["e = √((ΣLat)² + (ΣDep)²)","e = ΣLat + ΣDep","e = (ΣLat)² + (ΣDep)²","e = |ΣLat − ΣDep|"]'::jsonb, 'e = √((ΣLat)² + (ΣDep)²)', 'The misclosure is the magnitude of the closure vector: e = √((ΣLat)² + (ΣDep)²) = hypot(ΣLat, ΣDep). On a calculator it is the R▸P distance of (ΣDep, ΣLat).', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000006', 'A traverse has a perimeter of 2,400.00 ft and a linear misclosure of 0.20 ft. The relative precision is most nearly:', 'multiple_choice', '["1:12,000","1:480","1:2,400","1:24,000"]'::jsonb, '1:12,000', 'RP = perimeter / misclosure = 2400 / 0.20 = 12,000, reported as 1:12,000. The larger the denominator, the better the precision.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000007', 'Under the compass (Bowditch) rule, the correction applied to a course''s latitude is proportional to:', 'multiple_choice', '["the length of that course relative to the perimeter","the magnitude of that course''s latitude relative to Σ|Lat|","the number of courses in the traverse","the area enclosed by the traverse"]'::jsonb, 'the length of that course relative to the perimeter', 'The Bowditch (compass) rule distributes the misclosure in proportion to course length: C_lat,i = −(ΣLat)·(Lᵢ/P). The transit rule instead uses the magnitude of the latitude/departure of each course.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000008', 'Which statement best distinguishes the compass (Bowditch) rule from the transit rule?', 'multiple_choice', '["Bowditch weights corrections by course length; the transit rule weights by latitude/departure magnitude","Bowditch weights by latitude/departure magnitude; the transit rule weights by course length","Both distribute the misclosure equally to every course","Bowditch applies only to angles and the transit rule only to distances"]'::jsonb, 'Bowditch weights corrections by course length; the transit rule weights by latitude/departure magnitude', 'The Bowditch rule assumes angles and distances are equally precise and distributes the closure by course length. The transit rule assumes angles are more precise than distances and distributes by the magnitude of each course''s latitude (or departure).', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000009', 'Point A is (N 1,000.00, E 1,000.00) and point B is (N 1,300.00, E 1,400.00). The horizontal distance A→B is:', 'multiple_choice', '["500.00 ft","700.00 ft","350.00 ft","412.31 ft"]'::jsonb, '500.00 ft', 'ΔN = 300, ΔE = 400. D = √(300² + 400²) = √(90000 + 160000) = √250000 = 500.00 ft (the classic 3-4-5 triangle).', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000010', 'For the inverse from A(N 1,000, E 1,000) to B(N 1,300, E 1,400), the azimuth A→B is most nearly:', 'multiple_choice', '["53°08′","36°52′","126°52′","306°52′"]'::jsonb, '53°08′', 'Az = atan2(ΔE, ΔN) = atan2(400, 300) = 53.13° ≈ 53°08′. Both ΔN and ΔE are positive (NE quadrant), so the azimuth equals the bearing angle N 53°08′ E.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000011', 'Why are ΔE entered as x and ΔN entered as y when using the calculator''s rectangular→polar function for a survey inverse?', 'multiple_choice', '["Azimuth is measured clockwise from north (the y-axis), so the angle returned is the azimuth directly","It does not matter; the result is the same either way","Because departure is always larger than latitude","To force the calculator into radian mode"]'::jsonb, 'Azimuth is measured clockwise from north (the y-axis), so the angle returned is the azimuth directly', 'Survey azimuth is referenced to north. By placing ΔN on the y-axis and ΔE on the x-axis, the polar angle the calculator returns (measured from +y for atan2(x,y)) is the azimuth. Swapping them reflects the angle and gives the wrong direction.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000012', 'A bearing of S 40°00′ W expressed as an azimuth from north is:', 'multiple_choice', '["220°00′","140°00′","320°00′","040°00′"]'::jsonb, '220°00′', 'In the SW quadrant, Az = 180° + bearing angle = 180° + 40° = 220°.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000013', 'The back-azimuth of a line whose forward azimuth is 245°30′ is:', 'multiple_choice', '["65°30′","114°30′","425°30′","155°30′"]'::jsonb, '65°30′', 'Back-azimuth = forward azimuth ± 180°. 245°30′ − 180° = 65°30′ (subtract because the result must stay in 0°–360°).', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000014', 'Forward computation: from P(N 2,000.00, E 3,000.00), a course of azimuth 60°00′00″ and length 400.00 ft reaches point Q. The northing of Q is most nearly:', 'multiple_choice', '["2,200.00 ft","2,346.41 ft","1,800.00 ft","3,346.41 ft"]'::jsonb, '2,200.00 ft', 'Lat = 400·cos60° = 400·0.5 = +200.00 ft. N_Q = 2000 + 200 = 2,200.00 ft. (The easting would be 3000 + 400·sin60° = 3000 + 346.41 = 3,346.41 ft.)', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000015', 'The area by coordinates (shoelace) of a closed polygon is computed as:', 'multiple_choice', '["A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|","A = Σ (Xᵢ + Yᵢ)","A = ½·Σ (Xᵢ · Yᵢ)","A = perimeter² / 4π"]'::jsonb, 'A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|', 'The shoelace (coordinate) formula sums the cross-products of successive vertices, halves the magnitude, and the polygon must be closed (last vertex connects to the first). It equals the handbook form A = ½|ΣXᵢ(Y_{i+1} − Y_{i−1})|.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000016', 'A parcel computes to 217,800 ft² by coordinates. Its area in acres is:', 'multiple_choice', '["5.00 acres","2.50 acres","10.00 acres","0.50 acres"]'::jsonb, '5.00 acres', '1 acre = 43,560 ft². 217,800 / 43,560 = 5.00 acres.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000017', 'After applying the compass rule, the sum of the corrected (adjusted) latitudes of a closed-loop traverse should equal:', 'multiple_choice', '["0","the original ΣLat","the perimeter","the linear misclosure"]'::jsonb, '0', 'Adjustment forces closure: the corrections are designed so that ΣLat and ΣDep of the adjusted courses each become zero, allowing the traverse to close on itself.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000018', 'Which calculator operation directly yields the distance and azimuth between two known coordinates?', 'multiple_choice', '["Rectangular→polar (R▸P), entering ΔE and ΔN","Polar→rectangular (P▸R), entering distance and azimuth","The DMS→decimal conversion","The matrix determinant function"]'::jsonb, 'Rectangular→polar (R▸P), entering ΔE and ΔN', 'R▸P converts the rectangular components (ΔE, ΔN) into polar form (distance, angle) — exactly the inverse problem. P▸R does the opposite (forward) computation: azimuth + distance into ΔE, ΔN.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000019', 'A course azimuth computed by atan2(ΔE, ΔN) comes out as −47.0°. The correct azimuth (0°–360°) is:', 'multiple_choice', '["313.0°","47.0°","133.0°","227.0°"]'::jsonb, '313.0°', 'A negative azimuth is normalized by adding 360°: −47.0° + 360° = 313.0° (a NW-quadrant direction, consistent with ΔN +, ΔE −).', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000020', 'Which intersection problem can have TWO valid solution points?', 'multiple_choice', '["Distance–distance (circle–circle) intersection","Bearing–bearing intersection of two non-parallel lines","An inverse between two fixed points","Forward computation from azimuth and distance"]'::jsonb, 'Distance–distance (circle–circle) intersection', 'Two circles (distance–distance) generally intersect at two points, so the surveyor must pick the geometrically correct one. Two non-parallel lines (bearing–bearing) intersect at exactly one point; the inverse and forward computations are unique.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000021', 'An open traverse is generally avoided for control work because:', 'multiple_choice', '["it provides no check on the measurements (no closure)","it cannot be computed with a calculator","its latitudes always sum to a large value","it requires least-squares adjustment"]'::jsonb, 'it provides no check on the measurements (no closure)', 'An open traverse ends at an unknown point, so there is no second known value to check against — undetected blunders propagate. Loop and link traverses both provide a closure check.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000022', 'True or False: When computing area by coordinates, the shoelace sum is taken as an absolute value because a clockwise ordering of vertices produces a negative sum.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. The signed shoelace sum is positive for counterclockwise vertex order and negative for clockwise order; the absolute value gives the physical area regardless of direction.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000023', 'A misclosure has ΣLat = −0.12 ft and ΣDep = +0.05 ft. The linear misclosure is most nearly:', 'numeric_input', '[]'::jsonb, '0.13', 'e = √((−0.12)² + (0.05)²) = √(0.0144 + 0.0025) = √0.0169 = 0.13 ft.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000024', 'True or False: The relative precision 1:8,000 represents BETTER work than 1:5,000.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. Relative precision is misclosure per unit of perimeter expressed as 1:N; a larger N means the misclosure is a smaller fraction of the perimeter, i.e., better work.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000025', 'In the handbook quadrant form Az = arctan(ΔE/ΔN) + C, the constant C for a course in the SE quadrant (ΔN negative, ΔE positive) is:', 'multiple_choice', '["180°","0°","360°","90°"]'::jsonb, '180°', 'Per the NCEES handbook, C = 0° in NE (ΔN+, ΔE+), 180° in SE and SW (ΔN negative), and 360° in NW (ΔN+, ΔE−). For SE, C = 180°.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb043000-0000-0000-0000-000000000026', 'A course of latitude +180.00 ft and departure −240.00 ft has what length?', 'numeric_input', '[]'::jsonb, '300.00', 'L = √(Lat² + Dep²) = √(180² + 240²) = √(32400 + 57600) = √90000 = 300.00 ft.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000001', 'A traverse course has a length of {{dist:f2}} ft and an azimuth of {{az:f2}}° (measured clockwise from north). Compute the LATITUDE (ΔN, north–south component) of the course in feet.', 'numeric_input', '[]'::jsonb, '0', 'The latitude is the north–south component of the course: Lat = L·cos(Az) = {{dist:f2}} × cos({{az:f2}}°) = {{_answer}} ft. Use the cosine for latitude (sine gives the departure). The sign is automatic from the azimuth.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000002', 'A traverse course has a length of {{dist:f2}} ft and an azimuth of {{az:f2}}° (clockwise from north). Compute the DEPARTURE (ΔE, east–west component) of the course in feet.', 'numeric_input', '[]'::jsonb, '0', 'The departure is the east–west component of the course: Dep = L·sin(Az) = {{dist:f2}} × sin({{az:f2}}°) = {{_answer}} ft. Use the sine for departure (cosine gives the latitude). The sign follows from the azimuth automatically.', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000003', 'Point A is at (N {{nA:f2}}, E {{eA:f2}}). Point B is at (N {{nB:f2}}, E {{eB:f2}}). Compute the horizontal distance A→B (ft).', 'numeric_input', '[]'::jsonb, '0', 'Use rectangular→polar. ΔN = {{dN:f2}}, ΔE = {{dE:f2}}; the distance is √(ΔN² + ΔE²) = {{_answer}} ft. On the TI, R▸Pr(ΔE, ΔN) returns this in one keystroke.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000003', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000004', 'Point A is at (N {{nA:f2}}, E {{eA:f2}}). Point B is at (N {{nB:f2}}, E {{eB:f2}}). Compute the azimuth (clockwise from north, 0°–360°) of the line A→B, in decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'Azimuth = atan2(ΔE, ΔN) referenced to north. Raw value = {{azRaw:f2}}°; normalized to 0°–360° gives {{_answer}}°. The signs of ΔN ({{dN:f2}}) and ΔE ({{dE:f2}}) place the line in its quadrant. On the TI, R▸Pθ(ΔE, ΔN) then add 360° if negative.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000004', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000005', 'Starting at point P (N {{n1:f2}}, E {{e1:f2}}), a course of azimuth {{az:f2}}° (clockwise from north) and length {{dist:f2}} ft is run to point Q. Compute the NORTHING (N) of point Q (ft).', 'numeric_input', '[]'::jsonb, '0', 'Forward (polar→rectangular) computation: the latitude is L·cos(Az) = {{dist:f2}} × cos({{az:f2}}°) = {{lat:f2}} ft. Add to the starting northing: N_Q = {{n1:f2}} + {{lat:f2}} = {{_answer}} ft. (The easting would use L·sin(Az).)', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000005', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000006', 'Starting at point P (N {{n1:f2}}, E {{e1:f2}}), a course of azimuth {{az:f2}}° (clockwise from north) and length {{dist:f2}} ft is run to point Q. Compute the EASTING (E) of point Q (ft).', 'numeric_input', '[]'::jsonb, '0', 'Forward (polar→rectangular) computation: the departure is L·sin(Az) = {{dist:f2}} × sin({{az:f2}}°) = {{dep:f2}} ft. Add to the starting easting: E_Q = {{e1:f2}} + {{dep:f2}} = {{_answer}} ft. (The northing would use L·cos(Az).)', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000006', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000007', 'A closed-loop traverse has a closure in latitude ΣLat = {{sumLat:f3}} ft and a closure in departure ΣDep = {{sumDep:f3}} ft. Compute the linear misclosure (ft).', 'numeric_input', '[]'::jsonb, '0', 'The linear misclosure is the magnitude of the closure vector: e = √((ΣLat)² + (ΣDep)²) = √(({{sumLat:f3}})² + ({{sumDep:f3}})²) = {{_answer}} ft. On the TI this is R▸Pr(ΣDep, ΣLat).', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000007', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000008', 'A closed traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{misc:f3}} ft. Express the relative precision as 1:N — report the value of N (rounded to the nearest whole number).', 'numeric_input', '[]'::jsonb, '0', 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{misc:f3}} = {{_answer}}, reported as 1:{{_answer}}. A larger N indicates better (tighter) work.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000008', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000009', 'A triangular parcel has corners A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), and C (N {{nC:f2}}, E {{eC:f2}}), taken in order. Compute the enclosed area by coordinates (shoelace), in square feet.', 'numeric_input', '[]'::jsonb, '0', 'Apply the shoelace formula with X = Easting, Y = Northing, vertices in order A→B→C: A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| = {{_answer}} ft². Divide by 43,560 to convert to acres. The absolute value handles clockwise vs. counterclockwise ordering.', 'medium', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000009', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb046000-0000-0000-0000-000000000010', 'A line has the quadrant bearing S {{beta:f2}}° W. Express this as an azimuth (clockwise from north, 0°–360°), in decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'For a SW-quadrant bearing, the azimuth = 180° + the bearing angle = 180° + {{beta:f2}}° = {{_answer}}°. (NE: Az = β; SE: 180 − β; SW: 180 + β; NW: 360 − β.)', 'easy', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb045000-0000-0000-0000-000000000010', 0.02);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000001', 'A traverse course is 350.00 ft long with an azimuth of 300°00′00″. Its departure (ΔE) is most nearly:', 'multiple_choice', '["−303.11 ft","+303.11 ft","+175.00 ft","−175.00 ft"]'::jsonb, '−303.11 ft', 'Dep = L·sin(Az) = 350·sin300° = 350·(−0.8660) = −303.11 ft (west, NW quadrant). The latitude would be 350·cos300° = +175.00 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000002', 'Point P (N 4,200.00, E 6,500.00) and point Q (N 3,900.00, E 6,900.00). The horizontal distance P→Q is most nearly:', 'multiple_choice', '["500.00 ft","700.00 ft","300.00 ft","412.31 ft"]'::jsonb, '500.00 ft', 'ΔN = −300, ΔE = +400. D = √(300² + 400²) = 500.00 ft (3-4-5 triangle).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000003', 'For the line from P (N 4,200, E 6,500) to Q (N 3,900, E 6,900), the azimuth P→Q is most nearly:', 'multiple_choice', '["126°52′","53°08′","306°52′","233°08′"]'::jsonb, '126°52′', 'ΔN = −300, ΔE = +400 (SE quadrant). Az = atan2(400, −300) = 126.87° ≈ 126°52′, equivalently S 53°08′ E.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000004', 'A closed-loop traverse has ΣLat = +0.18 ft and ΣDep = −0.24 ft, with a perimeter of 1,800.00 ft. The relative precision is most nearly:', 'multiple_choice', '["1:6,000","1:7,500","1:3,000","1:10,000"]'::jsonb, '1:6,000', 'Misclosure e = √(0.18² + 0.24²) = √(0.0324 + 0.0576) = √0.09 = 0.30 ft. RP = 1800 / 0.30 = 6,000 → 1:6,000.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000005', 'Using the compass (Bowditch) rule, the latitude correction for a 400.00-ft course in a traverse with perimeter 2,000.00 ft and ΣLat = +0.10 ft is:', 'multiple_choice', '["−0.02 ft","+0.02 ft","−0.05 ft","−0.10 ft"]'::jsonb, '−0.02 ft', 'C_lat = −(ΣLat)·(L/P) = −(0.10)·(400/2000) = −0.10·0.20 = −0.02 ft. The correction is negative to remove the positive closure.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000006', 'A four-corner parcel has coordinates (E, N): (0, 0), (600, 0), (600, 400), (0, 400). Its area by coordinates is:', 'multiple_choice', '["240,000 ft²","120,000 ft²","1,000 ft²","480,000 ft²"]'::jsonb, '240,000 ft²', 'This is a 600 × 400 rectangle; the shoelace formula gives ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| = 240,000 ft² = 5.51 acres.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000007', 'Which calculator function returns the coordinates of a new point directly from a course azimuth and distance?', 'multiple_choice', '["Polar→rectangular (P▸R)","Rectangular→polar (R▸P)","DMS→decimal","Solve/SOLVER"]'::jsonb, 'Polar→rectangular (P▸R)', 'P▸R converts (distance, azimuth) into rectangular components (ΔE, ΔN), which are added to the starting coordinates. R▸P performs the reverse (inverse) computation.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000008', 'The bearing N 27°15′ W expressed as an azimuth is:', 'multiple_choice', '["332°45′","207°15′","152°45′","27°15′"]'::jsonb, '332°45′', 'For a NW-quadrant bearing, Az = 360° − bearing = 360° − 27°15′ = 332°45′.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000009', 'A course has latitude −150.00 ft and departure +150.00 ft. Its length and azimuth are most nearly:', 'multiple_choice', '["212.13 ft, 135°00′","212.13 ft, 45°00′","150.00 ft, 135°00′","300.00 ft, 315°00′"]'::jsonb, '212.13 ft, 135°00′', 'L = √(150² + 150²) = 212.13 ft. Az = atan2(+150, −150) = 135° (SE quadrant: ΔN −, ΔE +), i.e. S 45°00′ E.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000010', 'Two adjoining sequential deeds are plotted by coordinates and the surveyor needs the strip area between them. The most direct computation, once all corner coordinates are known, is:', 'multiple_choice', '["Area by coordinates (shoelace) on the strip polygon","Average end area","Prismoidal formula","Degree of curve"]'::jsonb, 'Area by coordinates (shoelace) on the strip polygon', 'With all corners reduced to coordinates, the planar area of any closed figure is computed directly by the shoelace (coordinate) method. End-area and prismoidal formulas are volume methods; degree of curve is a horizontal-curve quantity.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000011', 'An open traverse differs from a closed traverse principally in that an open traverse:', 'multiple_choice', '["provides no closure check on its measurements","always encloses an area","cannot be run with a total station","must be adjusted by least squares"]'::jsonb, 'provides no closure check on its measurements', 'An open traverse ends at an unknown point, so there is no independent value to check against and blunders go undetected. This is why it is avoided for control surveys.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb047000-0000-0000-0000-000000000012', 'A closed-loop traverse has a linear misclosure of 0.40 ft over a 5,000.00-ft perimeter. The achieved relative precision, and whether it meets a 1:10,000 requirement, is:', 'multiple_choice', '["1:12,500 — meets the 1:10,000 requirement","1:2,000 — fails the 1:10,000 requirement","1:5,000 — fails the 1:10,000 requirement","1:20,000 — meets the 1:10,000 requirement"]'::jsonb, '1:12,500 — meets the 1:10,000 requirement', 'RP = perimeter / misclosure = 5,000 / 0.40 = 12,500, i.e. 1:12,500. Since 12,500 ≥ 10,000, the traverse meets the 1:10,000 standard (equivalently, the allowable misclosure is 5,000/10,000 = 0.50 ft and 0.40 ft is within it).', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m4','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000001', 'The area of a closed parcel whose every corner is known by coordinates is most directly computed by:', 'multiple_choice', '["the coordinate (shoelace) method","the trapezoidal rule","Simpson''s 1/3 rule","the prismoidal formula"]'::jsonb, 'the coordinate (shoelace) method', 'With all corners reduced to coordinates, the shoelace/coordinate method (equivalent to the DMD method) gives the planar area directly. Trapezoidal and Simpson''s rules are for irregular boundaries defined by offsets; the prismoidal formula is a volume method.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000002', 'A parcel computes to 130,680 ft² by coordinates. Its area in acres is:', 'multiple_choice', '["3.00 acres","1.50 acres","6.00 acres","0.30 acres"]'::jsonb, '3.00 acres', '1 acre = 43,560 ft². 130,680 / 43,560 = 3.00 acres.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000003', 'Offsets of 12.0, 15.0, 18.0, 14.0, and 10.0 ft are taken at a constant 25.0-ft interval. By the trapezoidal rule, the area between the baseline and the boundary is:', 'multiple_choice', '["1,450 ft²","1,725 ft²","1,375 ft²","1,500 ft²"]'::jsonb, '1,450 ft²', 'A = w·[(h₁+hₙ)/2 + Σinterior] = 25·[(12+10)/2 + 15+18+14] = 25·[11 + 47] = 25·58 = 1,450 ft².', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000004', 'Simpson''s 1/3 rule for area from offsets requires:', 'multiple_choice', '["an odd number of offsets (even number of intervals)","an even number of offsets","exactly three offsets","offsets at unequal intervals"]'::jsonb, 'an odd number of offsets (even number of intervals)', 'Simpson''s 1/3 rule fits a parabola through each successive group of three offsets, so it needs an even number of equal intervals, i.e., an odd number of offsets. For an even count, apply Simpson to all but the last strip and add that strip as a trapezoid.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000005', 'In the average-end-area method, the volume between two cross-sections of end areas A₁ and A₂ a distance L apart is:', 'multiple_choice', '["V = L·(A₁ + A₂)/2","V = L·(A₁ + A₂)","V = (A₁ + A₂)/(2L)","V = L·(A₁ + 4Aₘ + A₂)/6"]'::jsonb, 'V = L·(A₁ + A₂)/2', 'Average end area multiplies the mean of the two end areas by the distance between them: V = L·(A₁+A₂)/2. The last option is the prismoidal formula, which requires the mid-section area Aₘ.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000006', 'A cut volume computes to 13,500 ft³. Expressed in cubic yards it is:', 'multiple_choice', '["500 yd³","1,500 yd³","4,500 yd³","364,500 yd³"]'::jsonb, '500 yd³', '1 yd³ = 27 ft³. 13,500 / 27 = 500 yd³.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000007', 'Two cross-sections 100 ft apart have end areas of 150 ft² and 210 ft². The average-end-area volume in cubic yards is most nearly:', 'multiple_choice', '["667 yd³","555 yd³","778 yd³","18,000 yd³"]'::jsonb, '667 yd³', 'V = L·(A₁+A₂)/2 = 100·(150+210)/2 = 100·180 = 18,000 ft³. 18,000/27 = 666.7 ≈ 667 yd³.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000008', 'Compared with the average-end-area method for a tapering section, the prismoidal formula generally gives a volume that is:', 'multiple_choice', '["slightly smaller","slightly larger","exactly equal","twice as large"]'::jsonb, 'slightly smaller', 'Average end area slightly over-estimates volume when sections taper; the prismoidal formula (using the true mid-section area) is more accurate and the difference, the prismoidal correction, makes the prismoidal volume slightly smaller.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000009', 'The degree of curve (arc definition) for a curve of radius 1,432.40 ft is most nearly:', 'multiple_choice', '["4°00′","2°00′","5°00′","8°00′"]'::jsonb, '4°00′', 'D = 5,729.58/R = 5,729.58/1,432.40 = 4.000° = 4°00′. The degree of curve is the central angle subtending a 100-ft arc.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000010', 'A circular curve has R = 600.00 ft and deflection angle I = 30°00′. Its tangent distance T is most nearly:', 'multiple_choice', '["160.77 ft","300.00 ft","321.54 ft","155.29 ft"]'::jsonb, '160.77 ft', 'T = R·tan(I/2) = 600·tan15° = 600·0.26795 = 160.77 ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000011', 'For a curve with R = 600.00 ft and I = 30°00′, the curve length L is most nearly:', 'multiple_choice', '["314.16 ft","300.00 ft","321.54 ft","180.00 ft"]'::jsonb, '314.16 ft', 'L = R·I·(π/180) = 600·(30·π/180) = 600·0.523599 = 314.16 ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000012', 'If the PI of a curve is at station 50+00.00 and the tangent distance T = 240.00 ft, the station of the PC is:', 'multiple_choice', '["47+60.00","52+40.00","50+24.00","47+76.00"]'::jsonb, '47+60.00', 'PC = PI − T = (50+00 = 5,000 ft) − 240 = 4,760 ft = station 47+60.00. The PC always precedes the PI by the tangent distance.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000013', 'A curve has PC at station 47+60.00 and length L = 314.16 ft. The station of the PT is:', 'multiple_choice', '["50+74.16","50+00.00","44+45.84","47+91.42"]'::jsonb, '50+74.16', 'PT = PC + L = 4,760 + 314.16 = 5,074.16 ft = station 50+74.16. The PT is found by adding the arc length L (not the tangent T) to the PC.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000014', 'The external distance E of a circular curve is given by:', 'multiple_choice', '["E = R·(sec(I/2) − 1)","E = R·(1 − cos(I/2))","E = 2R·sin(I/2)","E = R·tan(I/2)"]'::jsonb, 'E = R·(sec(I/2) − 1)', 'The external distance (PI to the midpoint of the curve) is E = R·(sec(I/2) − 1) = R·(1/cos(I/2) − 1). The second option is the middle ordinate M, the third is the long chord LC, the fourth is the tangent T.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000015', 'The total deflection angle from the PC to the PT of a simple circular curve equals:', 'multiple_choice', '["I/2","I","2I","90° − I"]'::jsonb, 'I/2', 'By the inscribed-angle property, the deflection angle from the tangent at the PC to any chord is half the subtended central angle; from PC to PT the subtended angle is the full I, so the total deflection is I/2. This is a standard field check.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000016', 'An equal-tangent vertical curve has g₁ = +2.0% and g₂ = −3.0% over L = 500 ft. The rate of change of grade r per foot is:', 'multiple_choice', '["−0.0001 per ft","+0.0001 per ft","−0.01 per ft","−0.05 per ft"]'::jsonb, '−0.0001 per ft', 'r = (g₂ − g₁)/L = (−0.03 − 0.02)/500 = −0.05/500 = −0.0001 per ft (a crest curve, since the grade decreases).', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000017', 'A vertical curve has g₁ = −2.0% and g₂ = +4.0%, L = 400 ft, with PVC at elevation 500.00 ft. The elevation on the curve 200 ft from the PVC is most nearly:', 'multiple_choice', '["499.00 ft","496.00 ft","504.00 ft","503.00 ft"]'::jsonb, '499.00 ft', 'Y = Y_PVC + g₁x + [(g₂−g₁)/(2L)]x² = 500 + (−0.02)(200) + [0.06/(2·400)]·200² = 500 − 4.00 + (0.06/800)·40,000 = 500 − 4.00 + 3.00 = 499.00 ft.', 'hard', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000018', 'A vertical curve with g₁ = −3.0% and g₂ = +2.0% over L = 600 ft has its low point at what distance from the PVC?', 'multiple_choice', '["360 ft","240 ft","300 ft","600 ft"]'::jsonb, '360 ft', 'x_m = −g₁·L/(g₂ − g₁) = −(−0.03)(600)/(0.02 − (−0.03)) = 18/0.05 = 360 ft. Because g₁ and g₂ have opposite signs (sag curve), the low point lies on the curve.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000019', 'On a vertical curve, a true high or low point exists on the curve only when:', 'multiple_choice', '["g₁ and g₂ have opposite signs","g₁ and g₂ have the same sign","g₁ equals g₂","the curve is longer than 500 ft"]'::jsonb, 'g₁ and g₂ have opposite signs', 'The turning point is where the curve grade passes through zero; this happens within the curve only if the grade changes sign, i.e., g₁ and g₂ have opposite signs. If both grades are the same sign, the high/low point falls outside the curve.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000020', 'The long chord of a circular curve with R = 800.00 ft and I = 40°00′ is most nearly:', 'multiple_choice', '["547.23 ft","291.13 ft","558.46 ft","279.23 ft"]'::jsonb, '547.23 ft', 'LC = 2R·sin(I/2) = 2·800·sin20° = 1,600·0.34202 = 547.23 ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000021', 'The middle ordinate M of a curve with R = 500.00 ft and I = 60°00′ is most nearly:', 'multiple_choice', '["66.99 ft","433.01 ft","288.68 ft","77.35 ft"]'::jsonb, '66.99 ft', 'M = R·(1 − cos(I/2)) = 500·(1 − cos30°) = 500·(1 − 0.86603) = 500·0.13397 = 66.99 ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000022', 'True or False: In the prismoidal formula V = L·(A₁ + 4Aₘ + A₂)/6, the term Aₘ is the average of the two end areas, (A₁ + A₂)/2.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. Aₘ is the area of the section taken midway between the two ends, computed from that section''s own (mid) dimensions. Substituting the average (A₁+A₂)/2 merely reproduces the average-end-area result and defeats the purpose of the prismoidal correction.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000023', 'A 4.0-acre tract equals how many square feet?', 'numeric_input', '[]'::jsonb, '174240', '4.0 acres × 43,560 ft²/acre = 174,240 ft².', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000024', 'A circular curve is to have a curve length L = 600.00 ft for a deflection angle I = 24°00′. The required radius R is most nearly:', 'numeric_input', '[]'::jsonb, '1432.39', 'L = R·I·(π/180) → R = L/(I·π/180) = 600/(24·π/180) = 600/0.418879 = 1,432.39 ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000025', 'True or False: The station of the PT of a simple curve is obtained by adding the tangent distance T to the PC station.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. PT = PC + L, where L is the arc (curve) length. Adding the tangent distance T instead is a common and serious stationing error.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb053000-0000-0000-0000-000000000026', 'Five offsets 0, 8.0, 11.0, 9.0, and 0 ft are measured at a 20.0-ft interval. By Simpson''s 1/3 rule the area is most nearly:', 'multiple_choice', '["600 ft²","560 ft²","1,120 ft²","287 ft²"]'::jsonb, '600 ft²', 'A = (w/3)·[h₁ + h₅ + 4(h₂ + h₄) + 2(h₃)] = (20/3)·[0 + 0 + 4(8+9) + 2(11)] = (20/3)·[68 + 22] = (20/3)·90 = 600 ft². Ends ×1, interior odd-position offsets (2nd, 4th) ×4, interior even-position offset (3rd) ×2.', 'hard', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000001', 'A four-corner parcel has corners, in order, A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), C (N {{nC:f2}}, E {{eC:f2}}), and D (N {{nD:f2}}, E {{eD:f2}}). Compute the enclosed area by coordinates (shoelace) and report it in ACRES.', 'numeric_input', '[]'::jsonb, '0', 'Apply the shoelace formula with X = Easting, Y = Northing, vertices in order A→B→C→D, take the absolute value, then divide by 43,560 ft²/acre. Area = {{_answer}} acres.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000001', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000002', 'Perpendicular offsets from a straight baseline to an irregular boundary are measured at a constant interval of {{w:f1}} ft: h₁={{h1:f1}}, h₂={{h2:f1}}, h₃={{h3:f1}}, h₄={{h4:f1}}, h₅={{h5:f1}} ft. Using the TRAPEZOIDAL rule, compute the area (ft²) between the baseline and the boundary.', 'numeric_input', '[]'::jsonb, '0', 'The trapezoidal rule averages the two end offsets and adds the interior offsets, all times the interval: A = w·[(h₁+hₙ)/2 + Σinterior] = {{w:f1}}·[({{h1:f1}}+{{h5:f1}})/2 + {{h2:f1}}+{{h3:f1}}+{{h4:f1}}] = {{_answer}} ft².', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000002', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000003', 'Five offsets at a constant interval of {{w:f1}} ft are h₁={{h1:f1}}, h₂={{h2:f1}}, h₃={{h3:f1}}, h₄={{h4:f1}}, h₅={{h5:f1}} ft. Using SIMPSON''S 1/3 rule, compute the area (ft²) between the baseline and the boundary.', 'numeric_input', '[]'::jsonb, '0', 'Simpson''s 1/3 rule weights the ends ×1, the interior odd-position offsets (2nd, 4th) ×4, and the interior even-position offset (3rd) ×2, all times w/3: A = ({{w:f1}}/3)·[{{h1:f1}}+{{h5:f1}} + 4({{h2:f1}}+{{h4:f1}}) + 2({{h3:f1}})] = {{_answer}} ft².', 'hard', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000003', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000004', 'Two adjacent cross-sections {{L:f1}} ft apart have end areas A₁ = {{a1:f1}} ft² and A₂ = {{a2:f1}} ft². Using the average-end-area method, compute the earthwork volume in CUBIC YARDS.', 'numeric_input', '[]'::jsonb, '0', 'Average end area: V = L·(A₁+A₂)/2 = {{L:f1}}·({{a1:f1}}+{{a2:f1}})/2 = {{vft3:f1}} ft³. Divide by 27 ft³/yd³ → {{_answer}} yd³.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000004', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000005', 'A simple circular curve has radius R = {{R:f2}} ft and deflection (central) angle I = {{I:f2}}°. Compute the tangent distance T (ft).', 'numeric_input', '[]'::jsonb, '0', 'The tangent distance from the PI to the PC (and to the PT) is T = R·tan(I/2) = {{R:f2}}·tan({{I:f2}}°/2) = {{_answer}} ft. Set the calculator to DEGREE mode and use I/2.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000005', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000006', 'A circular curve has radius R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. Compute the curve (arc) length L (ft).', 'numeric_input', '[]'::jsonb, '0', 'The arc length is L = R·I·(π/180) = {{R:f2}}·toRad({{I:f2}}°) = {{_answer}} ft. Equivalently, L = (I/D)·100 if the degree of curve D is known.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000006', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000007', 'A circular curve has radius R = {{R:f2}} ft. Compute the degree of curve D (arc definition), in decimal degrees.', 'numeric_input', '[]'::jsonb, '0', 'The arc-definition degree of curve is D = 5,729.58/R = 5,729.58/{{R:f2}} = {{_answer}}°. It is the central angle that subtends a 100-ft arc.', 'easy', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000007', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000008', 'A circular curve has radius R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. Compute the external distance E (ft) from the PI to the midpoint of the curve.', 'numeric_input', '[]'::jsonb, '0', 'The external distance is E = R·(sec(I/2) − 1) = R·(1/cos(I/2) − 1) = {{R:f2}}·(1/cos({{I:f2}}°/2) − 1) = {{_answer}} ft. There is no sec key — type 1/cos(I/2).', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000008', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000009', 'An equal-tangent vertical curve of length L = {{L:f1}} ft has back grade g₁ = {{g1:f2}}% and forward grade g₂ = {{g2:f2}}%. The PVC is at elevation {{ypvc:f2}} ft. Compute the elevation on the curve at a distance x = {{x:f1}} ft from the PVC (ft).', 'numeric_input', '[]'::jsonb, '0', 'Convert grades to decimals, then Y = Y_PVC + g₁·x + [(g₂−g₁)/(2L)]·x². With g₁={{g1:f2}}%, g₂={{g2:f2}}%, L={{L:f1}} ft, x={{x:f1}} ft: Y = {{_answer}} ft.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000009', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb056000-0000-0000-0000-000000000010', 'An equal-tangent vertical curve of length L = {{L:f1}} ft has back grade g₁ = {{g1:f2}}% and forward grade g₂ = {{g2:f2}}% (opposite signs, so a turning point exists). Compute the distance x from the PVC to the high/low point (ft).', 'numeric_input', '[]'::jsonb, '0', 'The high/low point is where the curve grade is zero: x_m = −g₁·L/(g₂ − g₁). The percent signs cancel in the ratio, so x_m = −({{g1:f2}})·{{L:f1}}/({{g2:f2}} − {{g1:f2}}) = {{_answer}} ft from the PVC.', 'medium', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb055000-0000-0000-0000-000000000010', 0.1);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000001', 'A rectangular parcel is 660.0 ft by 330.0 ft. Its area is most nearly:', 'multiple_choice', '["5.00 acres","2.50 acres","10.00 acres","0.50 acres"]'::jsonb, '5.00 acres', 'Area = 660 × 330 = 217,800 ft². 217,800 / 43,560 = 5.00 acres (660 ft = 10 chains, 330 ft = 5 chains → 50 sq chains = 5 acres).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000002', 'Offsets 6.0, 9.0, 12.0, 10.0, 7.0 ft are taken at a 30.0-ft interval. By the trapezoidal rule the area is most nearly:', 'multiple_choice', '["1,125 ft²","1,050 ft²","1,320 ft²","990 ft²"]'::jsonb, '1,125 ft²', 'A = 30·[(6+7)/2 + 9+12+10] = 30·[6.5 + 31] = 30·37.5 = 1,125 ft².', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000003', 'Two cross-sections 100 ft apart have cut end areas of 90 ft² and 150 ft². The volume between them in cubic yards is most nearly:', 'multiple_choice', '["444 yd³","555 yd³","333 yd³","12,000 yd³"]'::jsonb, '444 yd³', 'V = 100·(90+150)/2 = 100·120 = 12,000 ft³; 12,000/27 = 444.4 ≈ 444 yd³.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000004', 'A circular curve has R = 1,000.00 ft and I = 36°00′. Its tangent distance T is most nearly:', 'multiple_choice', '["324.92 ft","300.00 ft","618.03 ft","293.89 ft"]'::jsonb, '324.92 ft', 'T = R·tan(I/2) = 1,000·tan18° = 1,000·0.32492 = 324.92 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000005', 'For a curve with R = 1,000.00 ft and I = 36°00′, the curve length L is most nearly:', 'multiple_choice', '["628.32 ft","600.00 ft","649.84 ft","314.16 ft"]'::jsonb, '628.32 ft', 'L = R·I·(π/180) = 1,000·(36·π/180) = 1,000·0.628319 = 628.32 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000006', 'The PI of a curve is at station 80+00.00 and T = 324.92 ft. The PC station and (with L = 628.32 ft) the PT station are:', 'multiple_choice', '["PC 76+75.08, PT 83+03.40","PC 83+24.92, PT 89+53.24","PC 76+75.08, PT 80+00.00","PC 80+00.00, PT 86+28.32"]'::jsonb, 'PC 76+75.08, PT 83+03.40', 'PC = PI − T = 8,000 − 324.92 = 7,675.08 = 76+75.08. PT = PC + L = 7,675.08 + 628.32 = 8,303.40 = 83+03.40 (add the arc length, not T).', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000007', 'The degree of curve (arc definition) of a 2,864.79-ft radius curve is most nearly:', 'multiple_choice', '["2°00′","4°00′","1°00′","5°00′"]'::jsonb, '2°00′', 'D = 5,729.58/R = 5,729.58/2,864.79 = 2.000° = 2°00′.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000008', 'An equal-tangent vertical curve has g₁ = +1.50%, g₂ = −2.50%, L = 800 ft, PVC elevation 1,000.00 ft. The elevation 400 ft from the PVC (the PVI station) on the curve is most nearly:', 'multiple_choice', '["1,002.00 ft","1,006.00 ft","1,000.00 ft","1,004.00 ft"]'::jsonb, '1,002.00 ft', 'Y = 1000 + 0.015·400 + [(−0.025 − 0.015)/(2·800)]·400² = 1000 + 6.00 + (−0.04/1600)·160,000 = 1000 + 6.00 − 4.00 = 1,002.00 ft.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000009', 'A sag vertical curve has g₁ = −2.0% and g₂ = +1.0% over L = 600 ft. The low point lies how far from the PVC?', 'multiple_choice', '["400 ft","200 ft","300 ft","600 ft"]'::jsonb, '400 ft', 'x_m = −g₁·L/(g₂ − g₁) = −(−0.02)(600)/(0.01 − (−0.02)) = 12/0.03 = 400 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000010', 'Which formula gives the most accurate earthwork volume between two cross-sections when the mid-section area is measured?', 'multiple_choice', '["Prismoidal: V = L·(A₁ + 4Aₘ + A₂)/6","Average end area: V = L·(A₁ + A₂)/2","V = L·Aₘ","V = (A₁ + A₂)/(2L)"]'::jsonb, 'Prismoidal: V = L·(A₁ + 4Aₘ + A₂)/6', 'The prismoidal formula uses the true mid-section area Aₘ and models the solid as a prismoid, giving a more accurate volume than the average-end-area approximation.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000011', 'A surveyor must lay out the midpoint of a circular curve in the field. The deflection angle from the PC to the curve''s midpoint equals:', 'multiple_choice', '["I/4","I/2","I","90° − I/2"]'::jsonb, 'I/4', 'The total PC-to-PT deflection is I/2; the midpoint of the curve is half of that arc, so its deflection from the PC is (I/2)/2 = I/4.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000012', 'A subdivision plat reports a lot as 1.250 acres. Converted to square feet this is:', 'multiple_choice', '["54,450 ft²","43,560 ft²","62,500 ft²","27,225 ft²"]'::jsonb, '54,450 ft²', '1.250 × 43,560 = 54,450 ft². Acreage-to-square-foot conversion uses the exact 43,560 ft²/acre.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb057000-0000-0000-0000-000000000013', 'Cut end areas at three cross-sections spaced 100 ft apart are 120, 160, and 200 ft². The total cut volume between sections 1 and 3 by the average-end-area method is most nearly:', 'multiple_choice', '["1,185 yd³","1,000 yd³","1,333 yd³","32,000 yd³"]'::jsonb, '1,185 yd³', 'Section 1→2: 100·(120+160)/2 = 14,000 ft³. Section 2→3: 100·(160+200)/2 = 18,000 ft³. Total = 32,000 ft³ ÷ 27 = 1,185.2 ≈ 1,185 yd³.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m5','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000001', 'The relationship among ellipsoidal height (h), orthometric height (H), and geoid undulation (N) is:', 'multiple_choice', '["H = h − N","H = h + N","N = h + H","h = H − N"]'::jsonb, 'H = h − N', 'GNSS measures ellipsoidal height h; orthometric height (elevation) H = h − N, where N is the geoid undulation (separation of geoid below/above the ellipsoid). Equivalently h = H + N.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000002', 'A GNSS receiver, by itself, directly measures which type of height?', 'multiple_choice', '["Ellipsoidal height (h)","Orthometric height (H)","Dynamic height","Geoid undulation (N)"]'::jsonb, 'Ellipsoidal height (h)', 'GNSS positions are referenced to the ellipsoid, so the raw vertical result is an ellipsoidal height. A geoid model is needed to convert it to an orthometric elevation: H = h − N.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000003', 'The geoid is best described as:', 'multiple_choice', '["An equipotential gravity surface approximating mean sea level","A smooth mathematical ellipsoid of revolution","The physical topographic surface of the earth","The orbit plane of the GPS satellites"]'::jsonb, 'An equipotential gravity surface approximating mean sea level', 'The geoid is the equipotential surface of the earth''s gravity field that best fits mean sea level; it is everywhere perpendicular to the plumb line. The ellipsoid is the smooth mathematical reference; the two are separated by the undulation N.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000004', 'An ellipsoidal height h = 980.00 ft is observed where the geoid undulation N = −27.00 ft. The orthometric elevation H is:', 'multiple_choice', '["1,007.00 ft","953.00 ft","−27.00 ft","27.00 ft"]'::jsonb, '1,007.00 ft', 'H = h − N = 980.00 − (−27.00) = 1,007.00 ft. Because N is negative, the orthometric height is larger than the ellipsoidal height.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000005', 'Which GNSS error source is largely eliminated by using a dual-frequency (L1/L2) receiver?', 'multiple_choice', '["Ionospheric delay","Multipath","Receiver clock drift relative to the antenna","Tropospheric delay"]'::jsonb, 'Ionospheric delay', 'Ionospheric delay is frequency-dependent, so combining two carrier frequencies cancels most of it. Multipath is site-specific (not removed by differencing or dual-frequency); tropospheric delay is not frequency-dependent and is modeled instead.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000006', 'Lower values of Dilution of Precision (DOP) indicate:', 'multiple_choice', '["Stronger satellite geometry and a smaller position error","Weaker satellite geometry and a larger position error","More multipath","A larger number of cycle slips"]'::jsonb, 'Stronger satellite geometry and a smaller position error', 'DOP scales ranging error into position error: σ_pos ≈ UERE × DOP. Well-distributed satellites give a low DOP and a small position error; clustered satellites give a high DOP.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000007', 'With a user-equivalent range error (UERE) of 2.0 m and a PDOP of 4.0, the expected 3-D position error is most nearly:', 'multiple_choice', '["8.0 m","2.0 m","0.5 m","16.0 m"]'::jsonb, '8.0 m', 'σ_pos = UERE × PDOP = 2.0 × 4.0 = 8.0 m. PDOP applies to the 3-D position; HDOP and VDOP would give the horizontal and vertical components.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000008', 'The combined scale factor (CSF) used to reduce ground distances to State Plane grid distances is:', 'multiple_choice', '["Scale factor × elevation factor","Scale factor + elevation factor","Scale factor / elevation factor","Elevation factor − scale factor"]'::jsonb, 'Scale factor × elevation factor', 'CSF = SF × EF. The scale factor reduces ellipsoid distance to grid; the elevation (sea-level) factor reduces ground distance to the ellipsoid. Their product converts ground directly to grid.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000009', 'A ground distance of 1,500.00 ft is to be placed on the State Plane grid where CSF = 0.9999000. The grid distance is most nearly:', 'multiple_choice', '["1,499.85 ft","1,500.15 ft","1,500.00 ft","1,350.00 ft"]'::jsonb, '1,499.85 ft', 'Grid = ground × CSF = 1,500.00 × 0.9999000 = 1,499.85 ft. To go from ground to grid you multiply by the combined factor (here slightly less than 1, so the grid distance is shorter).', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000010', 'A State Plane grid distance of 2,000.00 ft must be staked on the ground where CSF = 0.9998500. The ground distance is most nearly:', 'multiple_choice', '["2,000.30 ft","1,999.70 ft","2,000.00 ft","2,003.00 ft"]'::jsonb, '2,000.30 ft', 'Ground = grid / CSF = 2,000.00 / 0.9998500 = 2,000.30 ft. To recover the ground distance you divide by the combined factor; the ground value is longer when CSF < 1.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000011', 'The elevation (sea-level) factor for reducing a ground distance to the ellipsoid is approximately:', 'multiple_choice', '["EF = R / (R + H + N)","EF = (R + H) / R","EF = R × (R + H)","EF = (R + N) / (R + H)"]'::jsonb, 'EF = R / (R + H + N)', 'EF = R/(R + H + N) ≈ R/(R + h), with R ≈ 20,906,000 ft. Higher elevations make EF smaller, shrinking the ground distance toward the ellipsoid.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000012', 'The State Plane Coordinate System uses the Lambert Conformal Conic projection for states (or zones) that are elongated:', 'multiple_choice', '["East–west","North–south","Diagonally","Only at the poles"]'::jsonb, 'East–west', 'Lambert Conformal Conic suits zones long in the east–west direction (e.g., Texas, Pennsylvania). Transverse Mercator is used for zones long north–south (e.g., Illinois).', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000013', 'The Transverse Mercator projection is best suited to State Plane zones that are elongated:', 'multiple_choice', '["North–south","East–west","Equatorially","Circularly"]'::jsonb, 'North–south', 'Transverse Mercator (a transverse cylinder) keeps distortion low along a north–south band, so it is used for tall, narrow zones. Lambert Conformal Conic handles wide east–west zones.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000014', 'State Plane zones are designed so that the maximum scale distortion is kept to about:', 'multiple_choice', '["1 part in 10,000","1 part in 100","1 part in 1,000,000","1 part in 50"]'::jsonb, '1 part in 10,000', 'SPCS zones are limited in width so scale distortion stays near 1:10,000. UTM, with wider 6° zones and a 0.9996 central scale factor, allows larger distortion, which is why SPCS is preferred for local surveys.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000015', 'The central-meridian scale factor of the Universal Transverse Mercator (UTM) system is:', 'multiple_choice', '["0.9996","1.0000","0.9999","1.0004"]'::jsonb, '0.9996', 'UTM fixes the scale factor at 0.9996 along each zone''s central meridian (a secant cylinder), spreading distortion across the 6°-wide zone. SPCS zones use values closer to 1 because they are narrower.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000016', 'The horizontal datum currently used for U.S. geodetic surveying, based on the GRS80 ellipsoid, is:', 'multiple_choice', '["NAD83","NAVD88","WGS84","NAD27"]'::jsonb, 'NAD83', 'NAD83 (North American Datum of 1983) is the horizontal datum, realized on the GRS80 ellipsoid. NAVD88 is the vertical (orthometric) datum; WGS84 is the GPS broadcast datum; NAD27 is the superseded Clarke-1866 datum.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000017', 'Convergence (the mapping angle, γ) on a map projection is the angle between:', 'multiple_choice', '["Grid north and geodetic (true) north","Magnetic north and true north","Grid north and magnetic north","The ellipsoid normal and the plumb line"]'::jsonb, 'Grid north and geodetic (true) north', 'Convergence is the difference between grid north and geodetic north; it is zero on the central meridian and grows with distance east or west of it. The plumb-line/normal difference is the deflection of the vertical (a different quantity).', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000018', 'OPUS (the NGS Online Positioning User Service) processes a submitted GNSS data set by:', 'multiple_choice', '["Differencing it against the CORS network to return published datum coordinates","Averaging autonomous code positions in real time","Applying a magnetic declination correction","Converting the ellipsoid to a Lambert projection"]'::jsonb, 'Differencing it against the CORS network to return published datum coordinates', 'OPUS post-processes a static occupation against nearby Continuously Operating Reference Stations (CORS) and returns NAD83 and ITRF coordinates for a single receiver, with an accuracy report.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000019', 'Real-time kinematic (RTK) surveying achieves centimeter accuracy primarily by:', 'multiple_choice', '["Carrier-phase differencing between a base of known position and a rover","Averaging many autonomous code positions","Using a single-frequency receiver with WAAS","Increasing the satellite elevation mask to 45°"]'::jsonb, 'Carrier-phase differencing between a base of known position and a rover', 'RTK resolves carrier-phase ambiguities and differences the rover against a base (or network) of known coordinates in real time, canceling correlated errors and yielding 1–3 cm positions.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000020', 'A real-time network (RTN) or VRS solution lets a surveyor perform RTK without:', 'multiple_choice', '["Setting up their own base station on a known point","Using carrier-phase observations","Any cellular or radio data link","Resolving integer ambiguities"]'::jsonb, 'Setting up their own base station on a known point', 'An RTN models corrections from a network of CORS and delivers them (often as a virtual reference station) to the rover, so the surveyor needs only one receiver and a data link — no local base.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000021', 'Which best describes multipath error in GNSS?', 'multiple_choice', '["Signal reflecting off nearby surfaces before reaching the antenna","Frequency-dependent delay in the ionosphere","Drift of the satellite atomic clocks","Error in the broadcast orbit (ephemeris)"]'::jsonb, 'Signal reflecting off nearby surfaces before reaching the antenna', 'Multipath is reflected signal arriving along with the direct signal, biasing the range. It is site-specific and is mitigated by antenna design (choke ring) and good siting, not by differencing.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000022', 'The NGS 2022 datum modernization replaces NAD83 and NAVD88 with new reference frames realized primarily through:', 'multiple_choice', '["GNSS and the CORS network (time-dependent terrestrial reference frames)","A new nationwide network of passive brass monuments","Magnetic observatory data","Optical leveling loops only"]'::jsonb, 'GNSS and the CORS network (time-dependent terrestrial reference frames)', 'The 2022 frames (e.g., NATRF2022 horizontal, NAPGD2022 vertical with GEOID2022) are plate-fixed, epoch-dependent and realized by GNSS/CORS rather than passive marks — a shift away from monument-based datums.', 'hard', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000023', 'For a GNSS baseline specified as 5 mm + 1 ppm, the expected error on a 20 km baseline is most nearly:', 'numeric_input', '[]'::jsonb, '25', 'σ = a + b·L = 5 mm + (1 ppm)(20 km) = 5 + 20 = 25 mm. One ppm equals 1 mm per km, so the distance-dependent term is 20 mm.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000024', 'True or False: WGS84 and NAD83 are identical datums and their coordinates can be used interchangeably for survey-grade work.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. WGS84 (GPS broadcast / essentially ITRF) and NAD83 differ by 1–2 m because of plate motion and origin definition. They must not be treated as interchangeable at survey accuracy.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000025', 'At an elevation of 6,000 ft (geoid undulation neglected), the elevation factor EF = R/(R+H), with R = 20,906,000 ft, is most nearly:', 'numeric_input', '[]'::jsonb, '0.99971', 'EF = 20,906,000 / (20,906,000 + 6,000) = 20,906,000 / 20,912,000 = 0.999713. Higher ground means a smaller EF, shrinking ground distances toward the ellipsoid.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000026', 'True or False: To convert a State Plane grid distance to a ground distance, you divide the grid distance by the combined scale factor.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. Grid = ground × CSF, so ground = grid ÷ CSF. When CSF < 1 the ground distance comes out longer than the grid distance.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb063000-0000-0000-0000-000000000027', 'The reference ellipsoid associated with NAD83 is:', 'multiple_choice', '["GRS80","Clarke 1866","WGS72","Bessel 1841"]'::jsonb, 'GRS80', 'NAD83 uses the GRS80 ellipsoid (a = 6,378,137 m, 1/f = 298.257222101). Clarke 1866 underlies the older NAD27; WGS84 uses an ellipsoid essentially identical to GRS80.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000001', 'A GNSS survey returns an ellipsoidal height h = {{h:f2}} ft at a station. The geoid model gives a geoid undulation N = {{N:f2}} ft. Compute the orthometric height (elevation) H, in feet.', 'numeric_input', '[]'::jsonb, '0', 'The orthometric height is H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} ft. Because the geoid undulation N is negative, subtracting it makes H larger than the ellipsoidal height h.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000001', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000002', 'A benchmark has a published orthometric elevation H = {{H:f2}} ft. A static GNSS occupation gives an ellipsoidal height h = {{h:f2}} ft. Compute the geoid undulation N at the mark, in feet.', 'numeric_input', '[]'::jsonb, '0', 'From h = H + N, the geoid undulation is N = h − H = {{h:f2}} − {{H:f2}} = {{_answer}} ft. A negative N (typical of the conterminous U.S.) means the geoid lies below the ellipsoid here.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000002', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000003', 'A station is at elevation H = {{H:f2}} ft (geoid undulation neglected). Using a mean earth radius R = 20,906,000 ft, compute the elevation (sea-level) factor EF = R/(R + H). Report to 6 decimal places.', 'numeric_input', '[]'::jsonb, '0', 'EF = R/(R + H) = 20,906,000 / (20,906,000 + {{H:f2}}) = {{_answer}}. A higher elevation gives a smaller EF, reducing the ground distance toward the ellipsoid.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000003', 0.000002);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000004', 'At a project site the projection scale factor SF = {{SF:f7}} and the station elevation is H = {{H:f2}} ft (geoid undulation neglected, R = 20,906,000 ft). Compute the combined scale factor CSF. Report to 7 decimal places.', 'numeric_input', '[]'::jsonb, '0', 'First EF = R/(R + H) = {{EF:f7}}. Then CSF = SF × EF = {{SF:f7}} × {{EF:f7}} = {{_answer}}. Multiply a ground distance by this combined factor to obtain the State Plane grid distance.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000004', 5e-7);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000005', 'A ground distance of {{dist:f2}} ft is to be placed on the State Plane grid where the combined scale factor CSF = {{csf:f7}}. Compute the grid distance, in feet.', 'numeric_input', '[]'::jsonb, '0', 'To go from ground to grid, multiply by the combined factor: D_grid = {{dist:f2}} × {{csf:f7}} = {{_answer}} ft. With CSF < 1 the grid distance is shorter than the measured ground distance.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000005', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000006', 'A State Plane inverse gives a grid distance of {{dist:f2}} ft. The combined scale factor for the area is CSF = {{csf:f7}}. Compute the ground distance to stake, in feet.', 'numeric_input', '[]'::jsonb, '0', 'To recover the ground distance, divide the grid distance by the combined factor: D_ground = {{dist:f2}} / {{csf:f7}} = {{_answer}} ft. With CSF < 1 the ground distance is longer than the grid distance.', 'medium', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000006', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000007', 'A GNSS receiver pair is specified at {{a:f1}} mm + {{b:f1}} ppm. For a baseline of {{km:f2}} km, compute the expected horizontal uncertainty, in millimeters.', 'numeric_input', '[]'::jsonb, '0', 'The baseline error is σ = a + b·L = {{a:f1}} mm + {{b:f1}} ppm × {{km:f2}} km = {{_answer}} mm. One ppm equals 1 mm per km, so the distance-dependent term is b·L millimeters.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000007', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb066000-0000-0000-0000-000000000008', 'A GNSS observation has a user-equivalent range error UERE = {{uere:f2}} m and a PDOP of {{pdop:f2}}. Compute the expected 3-D position error, in meters.', 'numeric_input', '[]'::jsonb, '0', 'Position error scales the ranging error by the geometry: σ_pos = UERE × PDOP = {{uere:f2}} × {{pdop:f2}} = {{_answer}} m. A lower DOP (stronger geometry) gives a smaller position error.', 'easy', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb065000-0000-0000-0000-000000000008', 0.02);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000001', 'GNSS measures ellipsoidal height h. To obtain the orthometric elevation H needed for engineering, the surveyor applies the geoid undulation N using:', 'multiple_choice', '["H = h − N","H = h + N","H = N − h","H = h × N"]'::jsonb, 'H = h − N', 'Orthometric height H = h − N, where N comes from a geoid model. With N negative across most of the U.S., H is larger than h.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000002', 'Which surface is the reference for orthometric heights (elevations) obtained by spirit leveling?', 'multiple_choice', '["The geoid","The GRS80 ellipsoid","The WGS84 ellipsoid","The topographic surface"]'::jsonb, 'The geoid', 'Orthometric heights are referenced to the geoid (the equipotential ''mean sea level'' surface). GNSS heights are referenced to the ellipsoid; the two differ by the undulation N.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000003', 'A ground distance of 3,200.00 ft is reduced to grid with a combined factor of 0.9999200. The grid distance is most nearly:', 'multiple_choice', '["3,199.74 ft","3,200.26 ft","3,200.00 ft","3,197.44 ft"]'::jsonb, '3,199.74 ft', 'Grid = ground × CSF = 3,200.00 × 0.9999200 = 3,199.74 ft. Multiply ground by the combined factor to get grid (shorter, since CSF < 1).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000004', 'A State Plane grid distance of 1,000.00 ft is to be staked where CSF = 0.9998000. The ground distance is most nearly:', 'multiple_choice', '["1,000.20 ft","999.80 ft","1,000.00 ft","1,002.00 ft"]'::jsonb, '1,000.20 ft', 'Ground = grid / CSF = 1,000.00 / 0.9998000 = 1,000.20 ft. Divide grid by the combined factor to recover the longer ground distance.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000005', 'For which State Plane zone shape is the Lambert Conformal Conic projection appropriate?', 'multiple_choice', '["A zone elongated east–west","A zone elongated north–south","A circular zone","A polar zone"]'::jsonb, 'A zone elongated east–west', 'Lambert Conformal Conic minimizes distortion across east–west bands; Transverse Mercator is used for north–south bands.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000006', 'The Universal Transverse Mercator system applies a scale factor along the central meridian of each zone equal to:', 'multiple_choice', '["0.9996","1.0000","0.9999","1.0004"]'::jsonb, '0.9996', 'UTM uses 0.9996 at the central meridian of each 6° zone, distributing distortion across the zone. SPCS zones keep distortion nearer 1:10,000 by being narrower.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000007', 'Which GNSS error is reduced by combining two carrier frequencies (L1/L2)?', 'multiple_choice', '["Ionospheric delay","Multipath","Tropospheric delay","Antenna setup error"]'::jsonb, 'Ionospheric delay', 'Ionospheric delay is frequency-dependent and is largely canceled by a dual-frequency solution. Tropospheric delay is modeled; multipath is mitigated by siting and antenna design.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000008', 'A surveyor wants the smallest GNSS position error. The most favorable condition is:', 'multiple_choice', '["A low PDOP (well-distributed satellites)","A high PDOP","Satellites clustered overhead","A short observation with few satellites"]'::jsonb, 'A low PDOP (well-distributed satellites)', 'σ_pos ≈ UERE × DOP, so a low DOP from good satellite geometry minimizes position error. High DOP means poor geometry and larger error.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000009', 'NGS''s OPUS service is best described as a tool to:', 'multiple_choice', '["Post-process a single static GNSS occupation against the CORS network","Provide real-time RTK corrections in the field","Compute magnetic declination","Draft a Lambert projection from field data"]'::jsonb, 'Post-process a single static GNSS occupation against the CORS network', 'OPUS returns published NAD83/ITRF coordinates for one receiver by differencing the data against nearby CORS — an office (post-processing) tool, not a real-time service.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000010', 'The horizontal datum currently in use for U.S. geodetic control, built on GRS80, is:', 'multiple_choice', '["NAD83","NAD27","NAVD88","WGS72"]'::jsonb, 'NAD83', 'NAD83 on the GRS80 ellipsoid is the U.S. horizontal datum. NAVD88 is the vertical datum; NAD27 (Clarke 1866) is superseded.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000011', 'Convergence (the mapping angle) at a State Plane station is:', 'multiple_choice', '["Zero on the central meridian and increases away from it","Constant everywhere in the zone","Largest on the central meridian","Equal to the magnetic declination"]'::jsonb, 'Zero on the central meridian and increases away from it', 'Convergence — the angle between grid north and geodetic north — is zero on the central meridian and grows with east–west distance from it. It is unrelated to magnetic declination.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000012', 'The 2022 NGS datum modernization (NATRF2022 / NAPGD2022) differs from NAD83/NAVD88 chiefly in that the new frames are:', 'multiple_choice', '["Time-dependent and realized by GNSS/CORS rather than passive monuments","Based on the Clarke 1866 ellipsoid","Defined only for the state of Texas","Independent of any geoid model"]'::jsonb, 'Time-dependent and realized by GNSS/CORS rather than passive monuments', 'The 2022 frames are plate-fixed, epoch-dependent and realized through GNSS and the CORS network, with GEOID2022 supplying N — a move away from passive monument-based datums.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000013', 'A GNSS baseline processor reports 5 mm + 1 ppm accuracy. Over a 15 km baseline the expected uncertainty is most nearly:', 'multiple_choice', '["20 mm","15 mm","6.5 mm","75 mm"]'::jsonb, '20 mm', 'σ = a + b·L = 5 mm + (1 ppm)(15 km) = 5 + 15 = 20 mm (1 ppm = 1 mm per km).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb067000-0000-0000-0000-000000000014', 'RTK and network-RTK (RTN/VRS) surveys reach centimeter accuracy by:', 'multiple_choice', '["Carrier-phase differencing against a base or modeled network","Averaging thousands of autonomous code positions","Using only the L1 C/A code","Raising the elevation mask to exclude all low satellites"]'::jsonb, 'Carrier-phase differencing against a base or modeled network', 'Both resolve carrier-phase ambiguities and difference the rover against a known base (RTK) or a modeled network/VRS (RTN), canceling correlated errors for 1–3 cm results.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m6','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000001', 'In the Public Land Survey System, the lines running east–west and numbered north or south of the base line define:', 'multiple_choice', '["Townships","Ranges","Sections","Aliquot parts"]'::jsonb, 'Townships', 'Township rows run east–west and are numbered north/south of the base line (e.g., T2N). Ranges run north–south, numbered east/west of the principal meridian (e.g., R3E). A township (6×6 mi) sits at the intersection of a township row and a range column.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000002', 'A standard PLSS township contains how many sections, and a standard section contains how many acres?', 'multiple_choice', '["36 sections; 640 acres","16 sections; 160 acres","36 sections; 160 acres","640 sections; 36 acres"]'::jsonb, '36 sections; 640 acres', 'A township is 6 mi × 6 mi = 36 sq mi, divided into 36 sections. A standard section is 1 mi × 1 mi = 1 sq mile = 640 acres.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000003', 'Within a standard township, Section 1 and Section 36 are located, respectively, in the:', 'multiple_choice', '["NE corner and the SE corner","NW corner and the SE corner","SE corner and the NW corner","NE corner and the SW corner"]'::jsonb, 'NE corner and the SE corner', 'Section numbering is a serpentine (boustrophedon): Section 1 is in the NE corner, numbering runs west to 6, drops to 7, runs east to 12, and so on, ending at Section 36 in the SE corner.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000004', 'What is the area of the NE¼ of the SW¼ of a regular section?', 'multiple_choice', '["40 acres","160 acres","80 acres","20 acres"]'::jsonb, '40 acres', 'A quarter-quarter (the classic ''forty'') = ¼ × ¼ × 640 = 40 acres. Read right-to-left: the SW¼ is 160 ac, and its NE¼ is 40 ac.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000005', 'What is the area of the N½ of the NW¼ of a regular section?', 'multiple_choice', '["80 acres","40 acres","160 acres","120 acres"]'::jsonb, '80 acres', 'N½ of NW¼ = ½ × ¼ × 640 = 80 acres. (The whole NW¼ is 160 ac; the north half is 80 ac.)', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000006', 'What is the area of the S½ of the SE¼ of the NW¼ of a regular section?', 'multiple_choice', '["20 acres","40 acres","10 acres","80 acres"]'::jsonb, '20 acres', 'S½ × SE¼ × NW¼ × 640 = ½ × ¼ × ¼ × 640 = (1/32) × 640 = 20 acres. On a calculator: 640 ÷ 2 ÷ 4 ÷ 4 = 20.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000007', 'A regular quarter-quarter section (''forty'') is nominally how many feet on a side?', 'multiple_choice', '["1,320 ft","2,640 ft","660 ft","5,280 ft"]'::jsonb, '1,320 ft', 'A forty is ¼ mile on a side = 20 chains = 20 × 66 = 1,320 ft. Check: 1,320² = 1,742,400 ft² ÷ 43,560 = 40 acres.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000008', 'A PLSS corner whose original monument is gone but whose position can be recovered from collateral evidence such as a bearing tree, occupation lines, and credible testimony is classified as:', 'multiple_choice', '["Obliterated","Lost","Existent","Witness"]'::jsonb, 'Obliterated', 'An obliterated corner has lost its monument but is recoverable from acceptable collateral evidence; it is NOT lost. A lost corner cannot be recovered from any evidence and must be restored by proportionate measurement. An existent corner still has its monument or undisturbed accessories.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000009', 'Proportionate measurement may be used to restore a PLSS corner only when the corner is:', 'multiple_choice', '["Lost (not recoverable from any acceptable evidence)","Obliterated but recoverable from a bearing tree","Existent with an undisturbed original monument","Merely inconvenient to reach"]'::jsonb, 'Lost (not recoverable from any acceptable evidence)', 'Proportioning is the last resort, used only for a truly lost corner. Existent corners control absolutely, and obliterated corners are recovered from collateral evidence — never proportioned if any acceptable evidence locates them.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000010', 'Which restoration method is used for a lost interior section corner that is controlled in two directions by the nearest found corners to the north, south, east, and west?', 'multiple_choice', '["Double proportionate measurement","Single proportionate measurement","Compass (Bowditch) rule","Random line and true line"]'::jsonb, 'Double proportionate measurement', 'A corner controlled in two directions (the typical interior section corner common to four sections) is restored by double proportion: proportion independently in the N–S and E–W directions and combine. Single proportion is for a corner lying on a single line between two found corners.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000011', 'A lost quarter corner is recorded 40.00 chains from each adjacent section corner. The full line between the two existent section corners measures 80.50 chains. By single proportionate measurement, the restored quarter corner is set how far from the first section corner?', 'multiple_choice', '["40.25 chains","40.00 chains","40.50 chains","80.50 chains"]'::jsonb, '40.25 chains', 'd'' = D_record × (L_measured / L_record) = 40.00 × (80.50 / 80.00) = 40.25 chains. The 0.50-ch surplus splits equally (0.25 each) because the record split was 40/40.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000012', 'When the calls in a single deed conflict, which class of call has the HIGHEST dignity (controls)?', 'multiple_choice', '["A call for a natural monument","A call for a bearing (course)","A call for a distance","A call for quantity (acreage)"]'::jsonb, 'A call for a natural monument', 'The dignity of calls ranks natural monuments highest, then artificial monuments, adjoinder, course, distance, and quantity (weakest). The hierarchy is a rule of construction that yields to the parties'' intent and the original surveyor''s footsteps.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000013', 'A deed call reads ''…thence N 80°20′ E, 800.28 feet to a 12-inch oak tree blazed and recorded as the corner.'' On the ground the oak is found at 815 feet. Which call controls?', 'multiple_choice', '["The oak tree (a natural monument)","The bearing N 80°20′ E","The distance 800.28 feet","The stated acreage of the parcel"]'::jsonb, 'The oak tree (a natural monument)', 'A found, identified natural monument outranks course and distance. The line runs to the oak even though the measured distance differs from the record — monuments control over course-and-distance (Stafford v. King).', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000014', 'The cardinal principle that a retracing surveyor must locate a boundary where the original surveyor actually ran it on the ground — even against later, more precise measurements — is called:', 'multiple_choice', '["Following the footsteps of the original surveyor","The rule of apportionment","The doctrine of accretion","The race-notice rule"]'::jsonb, 'Following the footsteps of the original surveyor', 'The footsteps doctrine holds that the original survey, as actually run and monumented, governs the location of the boundary; the dignity-of-calls hierarchy is invoked only when those footsteps cannot be retraced.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000015', 'A grantor conveys Parcel A in 2005 and the adjoining Parcel B in 2010 by separate metes-and-bounds deeds carved from a larger tract. A 3-foot overlap is later discovered. How is it resolved?', 'multiple_choice', '["The senior deed (Parcel A) prevails; Parcel B is cut back to the remainder","The overlap is split equally between the two parcels","The junior deed (Parcel B) prevails because it is more recent","The overlap is apportioned in proportion to each parcel''s record area"]'::jsonb, 'The senior deed (Parcel A) prevails; Parcel B is cut back to the remainder', 'These are sequential conveyances, so senior/junior rights govern. The senior (earlier) deed takes the full measure of its description; the junior takes only the remainder and absorbs the conflict. There is no proration between sequential conveyances.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000016', 'A recorded subdivision plat creates 10 equal lots in a block. The measured distance between the controlling block-corner monuments exceeds the platted total by 2.00 feet. How is the excess handled?', 'multiple_choice', '["Apportioned among the lots in proportion to their record dimensions","Given entirely to the first lot sold (the senior lot)","Discarded, because the plat dimensions are conclusive","Given entirely to the last lot in the block"]'::jsonb, 'Apportioned among the lots in proportion to their record dimensions', 'Lots in a recorded plat are a simultaneous conveyance — no lot is senior. Excess or deficiency between controlling monuments is apportioned proportionately among the lots. (Equal lots here would each get 0.20 ft.)', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000017', 'A river forms a property boundary. Over many years the river slowly and imperceptibly deposits soil, building out the bank. The boundary:', 'multiple_choice', '["Moves with the new bank (the owner gains land by accretion)","Is fixed at its former location","Moves to the centerline of the new channel only if navigable","Reverts to the state regardless of the change"]'::jsonb, 'Moves with the new bank (the owner gains land by accretion)', 'Accretion is the gradual, imperceptible addition of alluvion; the boundary moves with the water and the riparian owner gains the new land. (Sudden avulsive change, by contrast, fixes the boundary at its former location.)', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000018', 'A flood suddenly cuts a new channel, abruptly relocating a stream that served as a boundary. The boundary:', 'multiple_choice', '["Remains fixed at the former location of the stream (avulsion)","Moves to the new channel immediately","Is split equally between the old and new channels","Is extinguished entirely"]'::jsonb, 'Remains fixed at the former location of the stream (avulsion)', 'Avulsion is a sudden, perceptible change. Title does not shift merely because the water moved suddenly; the boundary is fixed at the former location of the watercourse.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000019', 'On a navigable stream, the bed below the ordinary high-water mark is generally:', 'multiple_choice', '["Owned by the State, held in trust for the public","Owned by the adjoining upland owner to the centerline","Unowned until claimed by adverse possession","Owned equally by both abutting owners"]'::jsonb, 'Owned by the State, held in trust for the public', 'On navigable waters the State owns the bed under the public-trust doctrine; private title typically stops at the high-water mark. On a non-navigable stream the abutting owner generally takes to the centerline (thread).', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000020', 'Which set of elements must a claimant prove to acquire title by common-law adverse possession?', 'multiple_choice', '["Actual, open and notorious, exclusive, hostile, and continuous for the statutory period","Recorded, surveyed, platted, and taxed","Permissive, shared, occasional, and good-faith","Granted, written, acknowledged, and delivered"]'::jsonb, 'Actual, open and notorious, exclusive, hostile, and continuous for the statutory period', 'Common-law adverse possession requires possession that is actual, open and notorious, exclusive, hostile (under a claim of right adverse to the true owner), and continuous for the statutory limitation period. Permissive use can never ripen into title.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000021', 'An easement is best described as:', 'multiple_choice', '["A non-possessory right to use another person''s land for a specified purpose","A complete (fee-simple) ownership of the servient land","A lien securing payment of a debt","A restrictive covenant limiting building height"]'::jsonb, 'A non-possessory right to use another person''s land for a specified purpose', 'An easement is a limited, non-possessory interest in another''s land. It may be appurtenant (running with the land) or in gross (personal), and may be created expressly, by implication, by necessity, or by prescription.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000022', 'In a pure ''notice'' recording jurisdiction, a later bona-fide purchaser for value without notice of a prior unrecorded deed:', 'multiple_choice', '["Prevails over the prior grantee even if the BFP records second (or never records)","Prevails only if the BFP records before the prior grantee","Loses to the prior grantee because the prior conveyance was first in time","Must re-record annually to keep priority"]'::jsonb, 'Prevails over the prior grantee even if the BFP records second (or never records)', 'In a notice state, a subsequent BFP for value without notice takes free of a prior unrecorded conveyance regardless of recording order — there is no race requirement. (In a race-notice state, that same BFP would also have to record first.)', 'hard', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000023', 'A quitclaim deed:', 'multiple_choice', '["Conveys only whatever interest the grantor has, with no warranty of title","Guarantees clear title against all defects in the chain","Is the same as a general warranty deed","Automatically makes the grantee a bona-fide purchaser"]'::jsonb, 'Conveys only whatever interest the grantor has, with no warranty of title', 'A quitclaim conveys the grantor''s interest, if any, without warranties. A general warranty deed, by contrast, warrants title against all defects back through the chain.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000024', 'The three principal systems of legal land description in the United States are:', 'multiple_choice', '["Metes-and-bounds, lot-and-block (platted), and PLSS (rectangular/aliquot)","State plane, geographic, and UTM","Deed, patent, and easement","Bearing, distance, and elevation"]'::jsonb, 'Metes-and-bounds, lot-and-block (platted), and PLSS (rectangular/aliquot)', 'Land is described by metes-and-bounds (a perimeter of calls), lot-and-block (reference to a recorded subdivision plat), or PLSS aliquot parts (e.g., the SE¼ of Sec. 14, T2N, R3E). The other lists are coordinate or instrument categories, not description systems.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000025', 'Texas land is distinctive because, unlike most western states, it:', 'multiple_choice', '["Was never federal public domain, so most of Texas has no PLSS township-range grid","Uses a denser PLSS grid with half-mile sections","Was surveyed entirely by the federal BLM","Has no recorded land descriptions at all"]'::jsonb, 'Was never federal public domain, so most of Texas has no PLSS township-range grid', 'Texas retained its public lands at annexation; its titles flow from the State (via the GLO), not the federal government. Most of Texas therefore has no PLSS grid — land is described by metes-and-bounds keyed to an original GLO survey + abstract number, historically measured in varas.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000026', 'One Texas vara equals 33⅓ inches. A field-note call of 540 varas is most nearly how many feet?', 'numeric_input', '[]'::jsonb, '1500', '1 vara = 33⅓ in = 2.7778 ft, so 540 × 2.7778 = 1,500.0 ft (equivalently 540 ÷ 0.36 = 1,500). Recall 36 varas = exactly 100 ft, so 540 vrs = 15 × 100 = 1,500 ft.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000027', 'True or False: When the dignity of calls cannot resolve a conflict, the stated quantity (acreage) of the parcel is the call given the greatest weight.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. Quantity/area is the WEAKEST call — a check, not a control. When the hierarchy cannot resolve a conflict, the parties'' intent (read in light of the surrounding circumstances) governs, not the acreage.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000028', 'An appurtenant easement that benefits a dominant estate is generally:', 'multiple_choice', '["Transferred automatically with the dominant land and cannot be conveyed separately","Personal to the original holder and ends when the land is sold","A possessory fee interest in the servient land","Valid only if it appears on a recorded plat"]'::jsonb, 'Transferred automatically with the dominant land and cannot be conveyed separately', 'An appurtenant easement runs with the land — it passes automatically to successive owners of the dominant estate and cannot be severed and conveyed apart from that land. An easement in gross, by contrast, is personal.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000029', 'A surveyor retraces a section line and finds the original quarter-corner monument, undisturbed, set by the government surveyor. The record distance to it differs from the surveyor''s measurement by 1.2 ft. The surveyor should:', 'multiple_choice', '["Hold the original monument (an existent corner controls absolutely)","Reset the corner at the record distance","Proportion the corner between the section corners","Average the record and measured positions"]'::jsonb, 'Hold the original monument (an existent corner controls absolutely)', 'An existent original monument controls over record course-and-distance. The found monument is the corner; you do not move it to fit a measurement, and proportioning is improper when an existent (or obliterated-but-recoverable) corner is available.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000030', 'Which professional-ethics principle most directly governs a surveyor who discovers that an existing fence does not match the true deeded boundary?', 'multiple_choice', '["Report the professional analysis honestly and without bias, even if it is unwelcome to the client","Set the corners to match the fence so the client is satisfied","Conceal the discrepancy to avoid a dispute","Defer to the neighbor''s preference"]'::jsonb, 'Report the professional analysis honestly and without bias, even if it is unwelcome to the client', 'The surveyor''s canons require communicating professional analysis and opinion truthfully and without bias or personal interest, and holding the public welfare paramount. The surveyor reports the true boundary relationship to the fence; the boundary is not moved to please a client.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb073000-0000-0000-0000-000000000031', 'Reading right-to-left, the description ''the W½ of the SW¼ of the NE¼'' of a regular section describes a parcel of:', 'numeric_input', '[]'::jsonb, '20', 'W½ × SW¼ × NE¼ × 640 = ½ × ¼ × ¼ × 640 = 20 acres. (NE¼ = 160 ac; its SW¼ = 40 ac; the W half of that = 20 ac.)', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000001', 'A regular PLSS section contains 640 acres. Compute the area, in acres, of an aliquot part formed by applying a {{f1:choice}}, then a {{f2:choice}}, then a {{f3:choice}} (e.g., ''the {{f3:choice}} of the {{f2:choice}} of the {{f1:choice}}''). Each ''half'' divides the area by 2 and each ''quarter'' divides it by 4.', 'numeric_input', '[]'::jsonb, '0', 'Aliquot area = 640 ÷ (product of the divisors). A ''half'' divides by 2, a ''quarter'' by 4. Here 640 ÷ {{d1}} ÷ {{d2}} ÷ {{d3}} = {{_answer}} acres. Read the description right-to-left to nest the parts.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000001', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000002', 'Compute the area, in acres, of {{frac:choice}} of a regular 640-acre section.', 'numeric_input', '[]'::jsonb, '0', 'A quarter = 640/4 = 160 ac; a half = 640/2 = 320 ac; a quarter-quarter = 640/16 = 40 ac; a half-quarter = 640/8 = 80 ac. For this part, 640 ÷ {{div}} = {{_answer}} acres.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000002', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000003', 'A lost corner lies on a single straight line between two existent corners. Its RECORD distance from the first corner is {{dRec:f2}} ft on a RECORD total line length of {{lRec:f2}} ft. You remeasure the full line between the two existent corners and obtain {{lMeas:f2}} ft. By single proportionate measurement, compute the CORRECTED distance (ft) from the first corner at which to set the restored corner.', 'numeric_input', '[]'::jsonb, '0', 'Single proportion distributes the measured-vs-record difference uniformly along the single line: d'' = D_record × (L_measured / L_record) = {{dRec:f2}} × ({{lMeas:f2}} ÷ {{lRec:f2}}) = {{_answer}} ft. The restored corner keeps the same record fraction of the corrected line.', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000004', 'Existent corner 1 is at (N {{n1:f2}}, E {{e1:f2}}) and existent corner 2 is at (N {{n2:f2}}, E {{e2:f2}}). A lost corner lies between them on the line, with a RECORD distance of {{dRec:f2}} ft from corner 1 on a record line total of {{lRec:f2}} ft. By single proportion (linear interpolation), compute the restored EASTING (ft) of the lost corner.', 'numeric_input', '[]'::jsonb, '0', 'Single proportion in coordinate form is a linear interpolation by the record fraction f = D_record/L_record = {{dRec:f2}}/{{lRec:f2}}. Restored easting E = E₁ + (E₂ − E₁)·f = {{e1:f2}} + ({{e2:f2}} − {{e1:f2}})·f = {{_answer}} ft. (The northing interpolates the same way.)', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000004', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000005', 'A described rectangular parcel measures {{a:f2}} ft along its north and south lines and {{b:f2}} ft along its east and west lines. Compute the parcel''s area in ACRES (1 acre = 43,560 ft²).', 'numeric_input', '[]'::jsonb, '0', 'Area = length × width = {{a:f2}} × {{b:f2}} = {{sqft:f2}} ft². Divide by 43,560 ft²/acre: {{_answer}} acres. (For a non-rectangular described parcel, reduce the corners to coordinates and use the shoelace area, then convert.)', 'medium', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000005', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb076000-0000-0000-0000-000000000006', 'A Texas GLO field note gives a call of {{vrs:f1}} varas. Using the Texas legal vara of 33⅓ in = 2.7778 ft, convert the distance to FEET.', 'numeric_input', '[]'::jsonb, '0', '1 vara = 33⅓ in = 2.7778 ft (equivalently feet = varas ÷ 0.36). So {{vrs:f1}} vrs × 2.7778 = {{_answer}} ft. Recall 36 varas = exactly 100 ft. A retracing surveyor must also reconcile the historic (often magnetic) bearing basis to a modern datum.', 'easy', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb075000-0000-0000-0000-000000000006', 0.2);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000001', 'In a standard PLSS township, which section is in the SE corner?', 'multiple_choice', '["Section 36","Section 1","Section 6","Section 31"]'::jsonb, 'Section 36', 'Numbering snakes from Section 1 in the NE corner and ends at Section 36 in the SE corner. (Section 6 is the NW corner; Section 31 is the SW corner.)', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000002', 'The area of the SE¼ of the NW¼ of a regular section is:', 'multiple_choice', '["40 acres","160 acres","80 acres","20 acres"]'::jsonb, '40 acres', 'Quarter-quarter = ¼ × ¼ × 640 = 40 acres. The NW¼ is 160 ac; its SE¼ is 40 ac.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000003', 'A lost corner cannot be recovered from any acceptable evidence. The proper method to restore an interior section corner controlled in two directions is:', 'multiple_choice', '["Double proportionate measurement","Single proportionate measurement","Hold the nearest fence","Adopt the record bearing and distance from one neighbor"]'::jsonb, 'Double proportionate measurement', 'An interior section corner is controlled by found corners in four directions; restore it by proportioning independently N–S and E–W (double proportion). Single proportion is for a corner on a single line between two found corners.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000004', 'When deed calls conflict, the correct order of dignity (highest to lowest) is:', 'multiple_choice', '["Natural monuments, artificial monuments, course, distance, quantity","Quantity, distance, course, artificial monuments, natural monuments","Course, distance, natural monuments, artificial monuments, quantity","Distance, course, quantity, monuments"]'::jsonb, 'Natural monuments, artificial monuments, course, distance, quantity', 'The dignity of calls ranks natural monuments highest and quantity (acreage) lowest, with adjoinder typically inserted between artificial monuments and course. The hierarchy yields to intent and the original surveyor''s footsteps.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000005', 'Two parcels are carved sequentially from a larger tract by separate deeds five years apart, and a gap is later found between them. The discrepancy is resolved by:', 'multiple_choice', '["Senior/junior rights — the senior deed takes its full description, the junior the remainder","Equal apportionment of the gap between the two parcels","Proration in proportion to each parcel''s acreage","Awarding the gap to whichever owner recorded last"]'::jsonb, 'Senior/junior rights — the senior deed takes its full description, the junior the remainder', 'Sequential conveyances are governed by senior/junior rights, not proration. The earlier (senior) deed gets the full measure of its description; the later (junior) deed takes only what remains.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000006', 'A lake gradually recedes, permanently uncovering a strip of land along the shore of a littoral owner''s parcel. This process is called and its effect is:', 'multiple_choice', '["Reliction — the boundary moves and the owner gains the uncovered land","Avulsion — the boundary is fixed","Accretion — the owner loses land","Erosion — the owner gains land"]'::jsonb, 'Reliction — the boundary moves and the owner gains the uncovered land', 'Reliction is the gradual uncovering of land by the permanent recession of water; like accretion, the boundary moves and the abutting owner gains. Avulsion (sudden change) fixes the boundary; erosion is gradual loss.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000007', 'Lots in a recorded subdivision plat are a SIMULTANEOUS conveyance. When measured block dimensions exceed the platted total, the excess is:', 'multiple_choice', '["Apportioned among the lots in proportion to their record dimensions","Given to the senior (first-sold) lot","Ignored, because plats are conclusive","Absorbed entirely by the corner lots"]'::jsonb, 'Apportioned among the lots in proportion to their record dimensions', 'No platted lot is senior to another; excess or deficiency between controlling monuments is apportioned among the lots proportionally. Senior/junior rights apply only to sequential conveyances.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000008', 'A surveyor recovers an original government quarter-corner monument, clearly the genuine, undisturbed monument, though it sits 2 ft off the record distance. The surveyor should:', 'multiple_choice', '["Hold the monument — an existent original corner controls over record measurements","Move it to the record distance","Proportion it between the section corners","Set a new corner at the average position"]'::jsonb, 'Hold the monument — an existent original corner controls over record measurements', 'Existent original monuments control absolutely; the footsteps of the original surveyor, evidenced by the genuine monument, govern over record course-and-distance. Proportioning applies only to truly lost corners.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000009', 'A prescriptive easement requires use that is, among other things:', 'multiple_choice', '["Open, notorious, continuous, and adverse (non-permissive) for the statutory period","Permissive and shared with the owner","Granted in writing and recorded","Approved by the county within one year"]'::jsonb, 'Open, notorious, continuous, and adverse (non-permissive) for the statutory period', 'A prescriptive easement arises from open, notorious, continuous, adverse (hostile, non-permissive) use for the statutory period. Permissive use can never ripen into a prescriptive right.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000010', 'A description reads ''the John Doe Survey, Abstract No. 123, Bexar County, Texas.'' This locational anchor reflects that Texas:', 'multiple_choice', '["Has no PLSS grid; land is keyed to an original GLO survey and abstract number","Uses township, range, and section like the federal system","Was surveyed by the federal BLM","Numbers its lands by latitude only"]'::jsonb, 'Has no PLSS grid; land is keyed to an original GLO survey and abstract number', 'Texas retained its public lands, so most Texas land is described by metes-and-bounds tied to an original General Land Office survey and abstract number — the spine of Texas land identification — not by the PLSS township-range-section grid.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000011', 'Under a pure ''notice'' recording act, a later good-faith purchaser for value without notice of a prior unrecorded deed:', 'multiple_choice', '["Takes free of the prior deed regardless of who records first","Wins only by recording before the prior grantee","Always loses to the earlier conveyance","Must record within 30 days"]'::jsonb, 'Takes free of the prior deed regardless of who records first', 'A notice statute protects the subsequent BFP without notice irrespective of recording order. A race-notice statute would additionally require the BFP to record first. Texas is a pure notice state.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000012', 'The stated quantity (acreage) in a deed, when it conflicts with a found monument and a course-and-distance call, is:', 'multiple_choice', '["The weakest call — it yields to monuments and to course and distance","The strongest call — it controls all others","Equal in weight to a natural monument","Controlling only on platted subdivisions"]'::jsonb, 'The weakest call — it yields to monuments and to course and distance', 'Quantity/area is the lowest-dignity call: a check, not a control. It yields to natural and artificial monuments and to course and distance, and ultimately to the parties'' intent.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000013', 'A 540-vara call in a Texas grant equals, in feet (1 vara = 2.7778 ft):', 'multiple_choice', '["1,500 ft","1,944 ft","1,080 ft","194 ft"]'::jsonb, '1,500 ft', '540 × 2.7778 = 1,500 ft (since 36 varas = 100 ft, 540 vrs = 15 × 100 = 1,500 ft). The vara is unique to Texas and former Spanish-grant areas; use Texas''s legal 33⅓-inch value.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000014', 'An LSLS or RPLS retracing a public-land boundary classifies a corner with no monument but recoverable from a recorded bearing tree and an old fence line. This corner is:', 'multiple_choice', '["Obliterated — recoverable from collateral evidence, not proportioned","Lost — must be proportioned","Existent — the monument is intact","A meander corner"]'::jsonb, 'Obliterated — recoverable from collateral evidence, not proportioned', 'An obliterated corner has lost its monument but is recoverable from collateral evidence (bearing trees, fences, testimony, adjoiner deeds). It is not lost and must not be proportioned while acceptable evidence locates it.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000015', 'A surveyor''s professional duty when a client asks that monuments be set to favor the client''s claim rather than the evidence is to:', 'multiple_choice', '["Decline and set corners per the boundary evidence, holding the public welfare paramount","Comply, since the client pays the fee","Set the corners halfway as a compromise","Refer the client to the neighbor"]'::jsonb, 'Decline and set corners per the boundary evidence, holding the public welfare paramount', 'The surveyor''s canons require unbiased professional analysis and place the public welfare first and foremost. Boundaries are located from the evidence and the original survey, not adjusted to favor a paying client.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb077000-0000-0000-0000-000000000016', 'On a non-navigable stream that forms a boundary, the abutting owner''s title generally extends to:', 'multiple_choice', '["The center thread of the channel","Only the top of the bank","The far bank","The ordinary high-water mark on the owner''s own side only"]'::jsonb, 'The center thread of the channel', 'On a non-navigable watercourse the riparian owner generally takes to the centerline (thread) of the stream. On a navigable stream the State owns the bed and private title stops at the high-water mark.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m7','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000001', 'The scale of a vertical aerial photograph is given by which relationship (f = focal length, H = flying height above datum, h = ground elevation)?', 'multiple_choice', '["S = f / (H − h)","S = (H − h) / f","S = f · (H − h)","S = f / H + h"]'::jsonb, 'S = f / (H − h)', 'For a vertical photo, scale equals focal length divided by the flying height above the ground point: S = f/(H−h). Higher ground (smaller H−h) yields a larger scale; valleys yield a smaller scale.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000002', 'A vertical photo is taken with a 0.500-ft focal length from H = 9,000 ft above a datum, over ground at elevation 1,000 ft. The photo scale is most nearly:', 'multiple_choice', '["1:16,000","1:18,000","1:8,000","1:4,500"]'::jsonb, '1:16,000', 'S = f/(H−h) = 0.500/(9,000−1,000) = 0.500/8,000 = 1/16,000.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000003', 'On a photo at scale 1:6,000, two points are 4.00 in apart. Their ground distance is most nearly:', 'multiple_choice', '["2,000 ft","1,500 ft","24,000 ft","667 ft"]'::jsonb, '2,000 ft', 'Ground = photo distance × scale denominator = 4.00 in × 6,000 = 24,000 in = 2,000 ft (÷12).', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000004', 'Relief displacement on a vertical photograph is computed as (r = radial distance from principal point, h = object height, H = flying height):', 'multiple_choice', '["d = r·h / H","d = H·h / r","d = r·H / h","d = (H − h) / r"]'::jsonb, 'd = r·h / H', 'Relief displacement d = r·h/H acts radially outward from the principal point for points above the datum, and is the basis for measuring object heights from a single photo (h = d·H/r).', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000005', 'Relief displacement on a vertical photo is directed:', 'multiple_choice', '["radially outward from the principal point for points above the datum","radially inward toward the principal point","always toward the north edge of the photo","tangent to the photo edge"]'::jsonb, 'radially outward from the principal point for points above the datum', 'Objects taller than the datum lean radially outward (away from the photo center). Both r and d are measured from the principal point. This is why buildings appear to lean outward in an aerial photo.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000006', 'Ground sample distance (GSD) for a digital aerial sensor is given by:', 'multiple_choice', '["GSD = (pixel size × H) / f","GSD = f / (pixel size × H)","GSD = (pixel size × f) / H","GSD = H / (pixel size · f)"]'::jsonb, 'GSD = (pixel size × H) / f', 'GSD is the ground footprint of one pixel: (pixel size × flying height) / focal length, with all terms in consistent units. Smaller GSD means higher resolution.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000007', 'A UAS camera has a 5.0-µm pixel and a 20-mm focal length, flown 300 m above ground. The GSD is most nearly:', 'multiple_choice', '["7.5 cm","3.0 cm","75 cm","1.5 cm"]'::jsonb, '7.5 cm', 'GSD(cm) = pixel(µm)·H(m)/[f(mm)·10] = 5.0×300/(20×10) = 1,500/200 = 7.5 cm.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000008', 'Aerial photographs for stereo mapping are typically flown with what forward overlap (endlap)?', 'multiple_choice', '["About 60%","About 10%","About 90%","0% (no overlap)"]'::jsonb, 'About 60%', 'Standard practice uses about 60% forward overlap (endlap) and about 30% sidelap so every ground point appears on at least two photos, enabling stereo viewing and parallax measurement.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000009', 'Stereoscopic parallax (p = x − x′) of a point in an aerial stereo pair is greatest for points that are:', 'multiple_choice', '["closer to the camera (higher elevation)","farther from the camera (lower elevation)","at the exact datum elevation","at the photo principal point only"]'::jsonb, 'closer to the camera (higher elevation)', 'Parallax increases as a point gets closer to the camera, i.e., higher ground produces larger parallax. Heights follow from h = H − f·B/p.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000010', 'LiDAR differs fundamentally from aerial photography in that LiDAR is:', 'multiple_choice', '["an active sensor that emits laser pulses and times their return","a passive sensor that records reflected sunlight","limited to a single visible band","incapable of producing 3-D data"]'::jsonb, 'an active sensor that emits laser pulses and times their return', 'LiDAR actively emits laser energy and measures travel time to build a dense 3-D point cloud; multiple returns can penetrate vegetation to yield a bare-earth DEM. Photography and most satellite imagers are passive.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000011', 'Which product is a BARE-EARTH representation of the terrain (objects removed)?', 'multiple_choice', '["Digital Elevation Model / Digital Terrain Model (DEM/DTM)","Digital Surface Model (DSM)","Orthomosaic","Point cloud (all returns)"]'::jsonb, 'Digital Elevation Model / Digital Terrain Model (DEM/DTM)', 'A DEM/DTM represents bare ground. A DSM includes objects such as canopy and buildings. LiDAR ground-classified (last) returns are used to build the bare-earth DEM.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000012', 'In a GIS, which data model stores discrete features (points, lines, polygons) with attributes, as opposed to a grid of cells?', 'multiple_choice', '["Vector","Raster","Metadata","Geoid"]'::jsonb, 'Vector', 'The vector model represents discrete features with geometry and attributes; the raster model stores a continuous grid of cells, each holding a value (e.g., elevation or a spectral band).', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000013', 'Two GIS layers fail to overlay correctly even though both cover the same area. The MOST likely cause is:', 'multiple_choice', '["the layers are in different or undeclared coordinate systems/projections","the monitor resolution is too low","one layer is vector and one is raster","the attribute tables have different column names"]'::jsonb, 'the layers are in different or undeclared coordinate systems/projections', 'Mismatched or undeclared projections/datums are the classic reason layers don''t line up. Each layer must declare its projection, coordinate system, and datum; metadata records this.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000014', 'Which map projection is preferred for a state with a large EAST–WEST extent (e.g., used in State Plane zones)?', 'multiple_choice', '["Lambert Conformal Conic","Transverse Mercator","Universal Polar Stereographic","Gnomonic"]'::jsonb, 'Lambert Conformal Conic', 'Lambert Conformal Conic suits states elongated east–west; Transverse Mercator suits states elongated north–south. Both are conformal projections used in the U.S. State Plane Coordinate System.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000015', 'The current standard horizontal and vertical datums used for U.S. surveying/mapping are, respectively:', 'multiple_choice', '["NAD83 (horizontal) and NAVD88 (vertical)","NAD27 (horizontal) and NGVD29 (vertical)","WGS84 (horizontal) and MSL (vertical)","SPCS (horizontal) and geoid (vertical)"]'::jsonb, 'NAD83 (horizontal) and NAVD88 (vertical)', 'NAD83 is the standard horizontal datum and NAVD88 the standard orthometric (vertical) datum for U.S. work. The geoid undulation N relates ellipsoidal height h to orthometric height H by h = H + N.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000016', 'On a 1:1,200 map, a property line measured 2.5 in long. Its ground length is:', 'multiple_choice', '["250 ft","300 ft","3,000 ft","120 ft"]'::jsonb, '250 ft', 'Ground = map distance × scale denominator = 2.5 in × 1,200 = 3,000 in = 250 ft (÷12).', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000017', 'A proposed pipe runs at a +1.5% grade. Over a horizontal distance of 400 ft, the elevation change is:', 'multiple_choice', '["+6.0 ft","+0.6 ft","+60 ft","+1.5 ft"]'::jsonb, '+6.0 ft', 'ΔElev = grade × horizontal distance = 0.015 × 400 = 6.0 ft of rise.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000018', 'At a construction station the existing ground is 102.4 and the proposed finished grade is 99.7. The required earthwork at that point is:', 'multiple_choice', '["a cut of 2.7 ft","a fill of 2.7 ft","a cut of 99.7 ft","no work needed"]'::jsonb, 'a cut of 2.7 ft', 'Cut = existing − proposed = 102.4 − 99.7 = 2.7 ft. Because existing is above proposed, material must be removed (cut).', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000019', 'Two cross-sections 100 ft apart have end areas of 150 ft² and 250 ft². By the average-end-area method the volume between them is:', 'multiple_choice', '["20,000 ft³","40,000 ft³","10,000 ft³","200 ft³"]'::jsonb, '20,000 ft³', 'V = L·(A₁+A₂)/2 = 100·(150+250)/2 = 100·200 = 20,000 ft³ (≈ 741 yd³).', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000020', 'In the prismoidal formula V = L·(A₁ + 4·A_m + A₂)/6, the quantity A_m is:', 'multiple_choice', '["the area of the mid-section (halfway between the two ends)","the average of A₁ and A₂","the larger of A₁ and A₂","the cross-section area at one-quarter point"]'::jsonb, 'the area of the mid-section (halfway between the two ends)', 'A_m is the actual cross-section area measured at the midpoint between the two ends — NOT (A₁+A₂)/2. Using the true mid-section makes the prismoidal result more accurate than average-end-area.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000021', 'To convert an earthwork volume from cubic feet to cubic yards, divide by:', 'multiple_choice', '["27","9","3","43,560"]'::jsonb, '27', '1 yd³ = 3 ft × 3 ft × 3 ft = 27 ft³, so divide cubic feet by 27 to get cubic yards. (43,560 ft² is one acre.)', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000022', 'True or False: On a single vertical aerial photo, ground at a higher elevation appears at a LARGER scale than ground in a valley.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. S = f/(H−h); higher ground has a smaller (H−h), so the scale ratio is larger (denominator smaller). Valleys (larger H−h) are at a smaller scale.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000023', 'A vertical photo with f = 6.00 in is required at a scale of 1:4,800 over flat ground at the datum. The required flying height is most nearly:', 'numeric_input', '[]'::jsonb, '2400', 'H − h = f/S = 0.500 ft × 4,800 = 2,400 ft. With h = 0 at the datum, the flying height is 2,400 ft.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000024', 'A tower images 0.30 in of relief displacement at a radial distance r = 5.00 in from the principal point; the flying height is H = 4,000 ft. The tower height is most nearly:', 'numeric_input', '[]'::jsonb, '240', 'h = d·H/r = 0.30 × 4,000 / 5.00 = 240 ft.', 'hard', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000025', 'Which statement about UAS (drone) photogrammetric mapping is correct?', 'multiple_choice', '["It uses low flying heights to achieve a small GSD over small areas, often processed by structure-from-motion","It cannot produce orthomosaics or 3-D models","It must always be flown at the same height as manned aircraft","It eliminates the need for any ground control"]'::jsonb, 'It uses low flying heights to achieve a small GSD over small areas, often processed by structure-from-motion', 'UAS platforms fly low, giving a small GSD (high resolution) over limited areas, and SfM photogrammetry generates orthomosaics, DSMs, and point clouds. Ground control (or PPK/RTK) is still used for accuracy.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb083000-0000-0000-0000-000000000026', 'True or False: A Digital Surface Model (DSM) and a Digital Terrain Model (DTM) of the same forested area are identical.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. A DSM includes the top of objects (tree canopy, rooftops), while a DTM/DEM is bare earth. They differ wherever vegetation or structures exist.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000001', 'A vertical aerial photo is taken with a focal length of {{f_ft:f3}} ft from a flying height of {{H:f0}} ft above datum, over ground at an average elevation of {{h:f0}} ft. Compute the photo SCALE denominator (report N for a scale of 1:N).', 'numeric_input', '[]'::jsonb, '0', 'Photo scale S = f/(H−h). With f = {{f_ft:f3}} ft and H−h = {{H:f0}} − {{h:f0}} ft, the scale denominator N = (H−h)/f = {{_answer}}, i.e. a scale of 1:{{_answer}}. Keep f, H, and h in the same units.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000001', 5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000002', 'On a vertical photo at scale 1:{{scale:f0}}, two features are measured {{dphoto:f2}} in apart. Compute the corresponding GROUND distance, in feet.', 'numeric_input', '[]'::jsonb, '0', 'Ground distance = photo distance × scale denominator = {{dphoto:f2}} in × {{scale:f0}} = ground inches; divide by 12 for feet → {{_answer}} ft. Scale is the ratio photo/ground, so ground = photo ÷ S.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000002', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000003', 'A digital aerial camera has a {{pix:f1}} µm pixel and a focal length of {{f_mm:f1}} mm, flown {{H:f0}} m above the ground. Compute the ground sample distance (GSD), in centimeters.', 'numeric_input', '[]'::jsonb, '0', 'Using the unit-matched shortcut GSD(cm) = pixel(µm)·H(m)/[f(mm)·10] = {{pix:f1}}·{{H:f0}}/({{f_mm:f1}}·10) = {{_answer}} cm. Smaller GSD means higher resolution.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000003', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000004', 'On a vertical photo, an object images at a radial distance r = {{r:f2}} in from the principal point. The object top is {{h:f0}} ft above the datum and the flying height is H = {{H:f0}} ft. Compute the relief displacement d, in inches.', 'numeric_input', '[]'::jsonb, '0', 'Relief displacement d = r·h/H = {{r:f2}} × {{h:f0}} / {{H:f0}} = {{_answer}} in. The displacement is radial and outward from the principal point for points above the datum.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000004', 0.005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000005', 'A mapping flight requires a photo scale of 1:{{scale:f0}} using a camera of focal length {{f_ft:f3}} ft over flat ground at the datum (h = 0). Compute the required FLYING HEIGHT above the ground, in feet.', 'numeric_input', '[]'::jsonb, '0', 'From S = f/(H−h), the flying height above ground is H−h = f × scale denominator = {{f_ft:f3}} × {{scale:f0}} = {{_answer}} ft. With h = 0 at the datum, H = {{_answer}} ft.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000005', 2);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000006', 'A ground line is {{dground:f1}} ft long. On a map at scale 1:{{scale:f0}}, how long will the line plot, in inches?', 'numeric_input', '[]'::jsonb, '0', 'Map distance = ground distance / scale denominator. Convert ground to inches: {{dground:f1}} ft × 12 = ground inches; ÷ {{scale:f0}} = {{_answer}} in on the map.', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000006', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000007', 'Two cross-sections {{L:f0}} ft apart have end areas of {{A1:f0}} ft² and {{A2:f0}} ft². Using the average-end-area method, compute the volume between them, in cubic yards.', 'numeric_input', '[]'::jsonb, '0', 'V = L·(A₁+A₂)/2 = {{L:f0}} × ({{A1:f0}}+{{A2:f0}})/2 = {{vcf:f0}} ft³. Divide by 27 to convert to cubic yards: {{_answer}} yd³.', 'medium', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000007', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb086000-0000-0000-0000-000000000008', 'A roadway is designed at a grade of {{grade:f2}}%. Over a horizontal distance of {{dist:f0}} ft, compute the change in elevation, in feet.', 'numeric_input', '[]'::jsonb, '0', 'Grade as a decimal = {{grade:f2}}/100. ΔElev = grade × horizontal distance = ({{grade:f2}}/100) × {{dist:f0}} = {{_answer}} ft of rise (or fall, for a negative grade).', 'easy', 'f5000008-0000-0000-0000-000000000008', 'FS', ARRAY['fs-buildout','fs-m8','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb085000-0000-0000-0000-000000000008', 0.05);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000001', 'A vertical photo is taken with a 0.500-ft focal length from 7,500 ft above a datum, over ground at elevation 500 ft. The photo scale is most nearly:', 'multiple_choice', '["1:14,000","1:15,000","1:7,000","1:3,500"]'::jsonb, '1:14,000', 'S = f/(H−h) = 0.500/(7,500−500) = 0.500/7,000 = 1/14,000.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000002', 'On a photo at scale 1:5,000, a runway measures 5.00 in long. Its ground length is most nearly:', 'multiple_choice', '["2,083 ft","1,500 ft","25,000 ft","1,000 ft"]'::jsonb, '2,083 ft', 'Ground = 5.00 in × 5,000 = 25,000 in = 2,083 ft (÷12).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000003', 'A digital sensor has a 6.0-µm pixel and a 30-mm focal length, flown 600 m above ground. The GSD is most nearly:', 'multiple_choice', '["12 cm","6 cm","20 cm","3 cm"]'::jsonb, '12 cm', 'GSD(cm) = pixel(µm)·H(m)/[f(mm)·10] = 6.0×600/(30×10) = 3,600/300 = 12 cm.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000004', 'A building images at radial distance r = 4.00 in; its top is 600 ft above datum and the flying height is 6,000 ft. The relief displacement is most nearly:', 'multiple_choice', '["0.40 in","0.04 in","4.0 in","0.60 in"]'::jsonb, '0.40 in', 'd = r·h/H = 4.00 × 600 / 6,000 = 0.40 in, directed radially outward from the principal point.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000005', 'Which best describes the difference between the vector and raster GIS data models?', 'multiple_choice', '["Vector stores discrete features with attributes; raster stores a grid of cells with values","Vector is always 3-D; raster is always 2-D","Vector cannot store attributes; raster can","They are identical except for file size"]'::jsonb, 'Vector stores discrete features with attributes; raster stores a grid of cells with values', 'Vector represents discrete points/lines/polygons with attributes; raster represents continuous phenomena as a grid of cells, each holding a value. Each suits different data types.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000006', 'For a U.S. State Plane zone in a state that is long in the NORTH–SOUTH direction, the projection used is typically:', 'multiple_choice', '["Transverse Mercator","Lambert Conformal Conic","Albers Equal Area","Mercator"]'::jsonb, 'Transverse Mercator', 'Transverse Mercator is used for zones elongated north–south; Lambert Conformal Conic for zones elongated east–west. Both are conformal and used in SPCS.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000007', 'LiDAR''s ability to map bare ground beneath a forest canopy depends on:', 'multiple_choice', '["multiple laser returns, with ground-classified (last) returns used for the DEM","the red band of a multispectral image","stereo parallax between two photos","the geoid undulation"]'::jsonb, 'multiple laser returns, with ground-classified (last) returns used for the DEM', 'LiDAR pulses produce multiple returns; some penetrate gaps in the canopy. Classifying the ground (often last) returns yields a bare-earth DEM, which photography alone cannot do under canopy.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000008', 'Two cross-sections 80 ft apart have end areas 200 ft² and 320 ft². The average-end-area volume is most nearly:', 'multiple_choice', '["20,800 ft³","41,600 ft³","10,400 ft³","770 ft³"]'::jsonb, '20,800 ft³', 'V = L·(A₁+A₂)/2 = 80·(200+320)/2 = 80·260 = 20,800 ft³ (≈ 770 yd³).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000009', 'A storm sewer is laid at −0.80% grade. Over 250 ft of horizontal run the invert drops by:', 'multiple_choice', '["2.0 ft","0.20 ft","20 ft","0.80 ft"]'::jsonb, '2.0 ft', 'ΔElev = grade × distance = 0.0080 × 250 = 2.0 ft of fall.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000010', 'At a construction station, existing ground is 96.2 and proposed grade is 98.9. The earthwork required is:', 'multiple_choice', '["a fill of 2.7 ft","a cut of 2.7 ft","a fill of 98.9 ft","no work"]'::jsonb, 'a fill of 2.7 ft', 'Fill = proposed − existing = 98.9 − 96.2 = 2.7 ft. Proposed is above existing, so material must be added (fill).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000011', 'Offset stakes are commonly set in construction layout because:', 'multiple_choice', '["they lie a known distance outside the work so they survive excavation while still defining line and grade","they are cheaper than hubs","they remove the need for any grade information","they must be set exactly on the construction line"]'::jsonb, 'they lie a known distance outside the work so they survive excavation while still defining line and grade', 'An offset stake is set a known horizontal distance from the feature so that grading/excavation does not destroy it; the crew transfers line and grade from the offset to the work.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000012', 'An earthwork quantity computes to 54,000 ft³. In cubic yards this is:', 'multiple_choice', '["2,000 yd³","6,000 yd³","18,000 yd³","1.24 yd³"]'::jsonb, '2,000 yd³', '54,000 ft³ ÷ 27 = 2,000 yd³ (1 yd³ = 27 ft³).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000013', 'A Digital Surface Model (DSM) over an urban area differs from a Digital Terrain Model (DTM) in that the DSM:', 'multiple_choice', '["includes the tops of buildings and vegetation, not just bare earth","is always at a coarser resolution","contains only vector data","cannot be derived from LiDAR"]'::jsonb, 'includes the tops of buildings and vegetation, not just bare earth', 'A DSM represents the first-surface elevations (canopy, rooftops), while a DTM/DEM is bare ground. Both can come from LiDAR or photogrammetry, but they differ wherever objects exist.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb087000-0000-0000-0000-000000000014', 'A mapping job requires 1:9,600 photos with a 0.500-ft focal length over ground at the datum. The flying height required is:', 'multiple_choice', '["4,800 ft","9,600 ft","2,400 ft","19,200 ft"]'::jsonb, '4,800 ft', 'H − h = f × scale denominator = 0.500 × 9,600 = 4,800 ft; with h = 0, H = 4,800 ft.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m8','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000001', 'Which calculator operation most directly gives the distance AND azimuth between two known coordinates?', 'multiple_choice', '["Rectangular-to-polar (R▸P) conversion","Polar-to-rectangular (P▸R) conversion","Decimal-to-DMS conversion","The statistics (mean/σ) mode"]'::jsonb, 'Rectangular-to-polar (R▸P) conversion', 'Feeding ΔE and ΔN into R▸P returns the distance (r) and direction (θ) in one step — exactly the inverse. P▸R does the reverse (forward) computation; the other modes are unrelated.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000002', 'Which calculator operation most directly gives the coordinates of a new point from a known azimuth and distance?', 'multiple_choice', '["Polar-to-rectangular (P▸R) conversion","Rectangular-to-polar (R▸P) conversion","DMS arithmetic","The reciprocal (x⁻¹) key"]'::jsonb, 'Polar-to-rectangular (P▸R) conversion', 'P▸R turns (distance, azimuth) into rectangular components (ΔE, ΔN), which you add to the start point. This is the forward computation ΔN = D·cos(Az), ΔE = D·sin(Az) in one operation.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000003', 'Before doing any trigonometric (curve, inverse, traverse) computation on an approved calculator, you should verify the calculator is in:', 'multiple_choice', '["DEGREE (DEG) mode","RADIAN (RAD) mode","GRADIAN (GRAD) mode","Fix-2 display mode"]'::jsonb, 'DEGREE (DEG) mode', 'Survey angles are in degrees, so the calculator must be in DEG. A calculator left in RAD or GRAD gives wildly wrong trig results with no error message — the classic silent blunder.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000004', 'Which calculators are on the NCEES approved list for 2026 exams?', 'multiple_choice', '["Casio fx-115/fx-991, HP 33s/35s, and TI-30X/TI-36X models","Any non-graphing scientific calculator","TI-84 Plus and Casio fx-9750 graphing models","Only the HP 33s and HP 35s"]'::jsonb, 'Casio fx-115/fx-991, HP 33s/35s, and TI-30X/TI-36X models', 'The 2026 list permits all Casio fx-115 and fx-991 models, only the HP 33s and HP 35s, and all TI-30X and TI-36X models. No programmable, graphing, or CAS calculators are allowed.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000005', 'Under the convention used for COGO on a scientific calculator, which axis represents ΔN (latitude)?', 'multiple_choice', '["The y-axis (north)","The x-axis (east)","The polar radius r","The z-axis"]'::jsonb, 'The y-axis (north)', 'By convention x = ΔE (Easting/departure) and y = ΔN (Northing/latitude), with the azimuth measured from north. R▸P and P▸R map between (ΔE, ΔN) and (distance, azimuth).', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000006', 'To convert the bearing S 40°00′ W to an azimuth you would compute:', 'multiple_choice', '["180° + 40° = 220°","180° − 40° = 140°","360° − 40° = 320°","40° directly"]'::jsonb, '180° + 40° = 220°', 'A southwest bearing converts by Az = 180° + β. So S 40°00′ W → 180° + 40° = 220°00′ azimuth.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000007', 'The back azimuth of a line whose forward azimuth is 312°15′ is:', 'multiple_choice', '["132°15′","192°15′","47°45′","227°45′"]'::jsonb, '132°15′', 'Back azimuth = (Az + 180°) mod 360° = 312°15′ − 180° = 132°15′ (subtract 180° when Az > 180°).', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000008', 'When entering an inverse on the calculator, the robust one-line azimuth formula uses which argument order for atan2?', 'multiple_choice', '["atan2(ΔE, ΔN) — easting first, northing second","atan2(ΔN, ΔE) — northing first, easting second","atan2(distance, azimuth)","atan2(N₂, E₂)"]'::jsonb, 'atan2(ΔE, ΔN) — easting first, northing second', 'Azimuth is measured clockwise from north (the ΔN axis), so the azimuth is atan2(ΔE, ΔN). Reversing the order gives an angle measured from east instead and produces wrong azimuths.', 'hard', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000009', 'On a TI-36X Pro / Casio fx-991, after an R▸P conversion you see the distance but need the angle. You should:', 'multiple_choice', '["press the [x⇄y] (swap) key to read θ","re-enter both values","switch to RAD mode","press the reciprocal x⁻¹ key"]'::jsonb, 'press the [x⇄y] (swap) key to read θ', 'R▸P returns both r and θ; the swap key (or reading the second output field) displays the angle without re-entering the coordinates.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000010', 'Adding the DMS angles 22°45′30″ and 17°20′40″ gives:', 'multiple_choice', '["40°06′10″","39°66′70″","40°05′10″","39°06′10″"]'::jsonb, '40°06′10″', '30″ + 40″ = 70″ = 1′10″; 45′ + 20′ + 1′ = 66′ = 1°06′; 22° + 17° + 1° = 40°. Result 40°06′10″. The calculator does this directly in DMS mode.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000011', 'Why is storing a running coordinate total with STO/RCL preferred over re-typing it on each traverse leg?', 'multiple_choice', '["It avoids re-keying errors (blunders) and saves time","It changes the angle mode automatically","It is required by NCEES rules","It increases the calculator''s display precision"]'::jsonb, 'It avoids re-keying errors (blunders) and saves time', 'Every re-typed number is a chance to introduce a blunder. Storing running Northing/Easting totals (and reused constants) in memory both prevents transcription errors and speeds up leg-by-leg traversing.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000012', 'On a single vertical photo problem you compute f/(H−h) = 1×10⁻⁴ and need the scale denominator. The fastest keystroke is:', 'multiple_choice', '["press the reciprocal x⁻¹ key to read 10,000","multiply by 12","convert to DMS","press R▸P"]'::jsonb, 'press the reciprocal x⁻¹ key to read 10,000', 'Scale is a ratio; pressing x⁻¹ turns 1×10⁻⁴ into 10,000, i.e., a scale of 1:10,000. The reciprocal key is also handy for relative-precision 1:N ratios.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000013', 'Which statement about programmable/graphing calculators on the FS exam is correct?', 'multiple_choice', '["They are prohibited; only models on the NCEES approved list may be used","Any calculator is allowed if its memory is cleared","Graphing calculators are allowed if they are not used for graphing","Programmable calculators are allowed if the programs are survey-related"]'::jsonb, 'They are prohibited; only models on the NCEES approved list may be used', 'NCEES bans programmable, graphing, and CAS calculators outright. Only models on the current approved list (Casio fx-115/991, HP 33s/35s, TI-30X/36X) are permitted, and memory should be cleared.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000014', 'Approximately how much time per question does the FS allow (110 questions in 5 h 20 min)?', 'multiple_choice', '["About 2.9 minutes","About 6 minutes","About 1 minute","About 5 minutes"]'::jsonb, 'About 2.9 minutes', '320 minutes ÷ 110 questions ≈ 2.9 minutes each. Banking quick boundary/ethics/definition points buys time for multi-step COGO problems.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000015', 'The best test-taking strategy when you reach a long multi-step COGO problem early in the exam is to:', 'multiple_choice', '["flag it, skip ahead to bank quick points, and return to it later","spend as long as needed before moving on","guess immediately without reading it","skip it permanently and leave it blank"]'::jsonb, 'flag it, skip ahead to bank quick points, and return to it later', 'Flag-and-return preserves momentum: answer the fast questions first, then come back to the time-consuming problem with the time you banked. Never leave it blank — there is no penalty for guessing.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000016', 'Because the FS has no penalty for wrong answers, you should:', 'multiple_choice', '["answer every question, guessing if necessary, before time expires","leave hard questions blank to avoid lowering your score","answer only the questions you are certain about","randomly fill all answers at the start"]'::jsonb, 'answer every question, guessing if necessary, before time expires', 'With no penalty for incorrect answers, a blank can only score zero while a guess has a chance. Always answer every question; eliminate wrong options first to improve guess odds.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000017', 'The electronic NCEES FS Reference Handbook is most efficiently used during the exam by:', 'multiple_choice', '["knowing in advance where each formula lives so you confirm rather than hunt","reading it cover-to-cover during the exam","ignoring it and working from memory only","searching it for every single question"]'::jsonb, 'knowing in advance where each formula lives so you confirm rather than hunt', 'The handbook is searchable but large. Practicing with the actual PDF beforehand so you know where the curve, area, inverse, and statistics formulas sit lets you confirm a formula in seconds instead of burning time hunting.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000018', 'A surveyor needs to area a simple 60 ft × 120 ft rectangle. The most efficient calculator approach is to:', 'multiple_choice', '["multiply the two sides directly","run a full coordinate (shoelace) routine on all four corners","use R▸P on each side","enter all corners into a stored AREA program"]'::jsonb, 'multiply the two sides directly', 'Part-D calculation discipline: use the simplest method. A rectangle''s area is just side × side — running a full traverse/area routine wastes time and invites entry errors.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000019', 'On the area-by-coordinates (shoelace) method, which variables are conventionally taken as X and Y?', 'multiple_choice', '["X = Easting, Y = Northing","X = Northing, Y = Easting","X = distance, Y = azimuth","X = latitude, Y = longitude"]'::jsonb, 'X = Easting, Y = Northing', 'In the coordinate (shoelace) area method, X is the Easting and Y is the Northing; you sum the cross-products Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ, halve, and take the absolute value.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000020', 'Which is the most reliable way to determine the correct quadrant of an inverse azimuth on the calculator?', 'multiple_choice', '["use atan2(ΔE, ΔN), or read the signs of ΔN and ΔE","always add 180°","always use the acute angle from atan","convert the distance to DMS"]'::jsonb, 'use atan2(ΔE, ΔN), or read the signs of ΔN and ΔE', 'atan2 returns the angle in the correct quadrant automatically. Equivalently, the signs of ΔN and ΔE place the line in NE/SE/SW/NW, to which you add the handbook quadrant constant. A bare atan loses the quadrant.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000021', 'True or False: For the curve-length quickie, when the degree of curve D is given, L = (I/D)·100 lets you avoid using π entirely.', 'true_false', '["True","False"]'::jsonb, 'True', 'True. With D known, L = (I/D)·100 gives the arc length directly in feet without π or radians — a faster keystroke chain than L = R·I·(π/180).', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000022', 'True or False: You may use a calculator with stored COGO programs (e.g., an HP traverse routine) on the FS exam as long as it is an HP 35s.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. The HP 35s is on the approved list, but NCEES expects calculator memory to be cleared and prohibits using stored programs/notes during the exam. The HP program books are study/field references, not exam tools.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000023', 'Convert 132°15′00″ to decimal degrees.', 'numeric_input', '[]'::jsonb, '132.25', 'dec = 132 + 15/60 + 0/3600 = 132 + 0.25 = 132.25°.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb093000-0000-0000-0000-000000000024', 'Express 1°30′45″ as a total number of seconds.', 'numeric_input', '[]'::jsonb, '5445', 'sec = 1·3600 + 30·60 + 45 = 3600 + 1800 + 45 = 5,445 seconds.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000001', 'CALCULATOR CHALLENGE — Express the angle {{D:f0}}°{{M:f0}}′{{S:f0}}″ as a TOTAL number of seconds.', 'numeric_input', '[]'::jsonb, '0', 'Total seconds = D·3600 + M·60 + S = {{D:f0}}·3600 + {{M:f0}}·60 + {{S:f0}} = {{_answer}} seconds. A fast mental/keystroke drill that underlies DMS arithmetic.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000001', 0.5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000002', 'CALCULATOR CHALLENGE — Add the two angles {{D1:f0}}°{{M1:f0}}′{{S1:f0}}″ and {{D2:f0}}°{{M2:f0}}′{{S2:f0}}″ and report the SUM in DECIMAL degrees.', 'numeric_input', '[]'::jsonb, '0', 'Enter both angles in DMS, press +, and the calculator returns the sum; here in decimal it is ({{D1:f0}}+{{M1:f0}}/60+{{S1:f0}}/3600) + ({{D2:f0}}+{{M2:f0}}/60+{{S2:f0}}/3600) = {{_answer}}°. Toggle ▸DMS for the field-book form.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000002', 0.001);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000003', 'CALCULATOR CHALLENGE (R▸P) — Point A is at (N {{nA:f2}}, E {{eA:f2}}) and point B is at (N {{nB:f2}}, E {{eB:f2}}). Using rectangular-to-polar, compute the horizontal DISTANCE A→B (ft).', 'numeric_input', '[]'::jsonb, '0', 'Compute ΔN = {{dN:f2}} and ΔE = {{dE:f2}}, feed them to R▸P, and read the distance r = hypot(ΔN, ΔE) = {{_answer}} ft. One R▸P replaces the separate √ and atan.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000003', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000004', 'CALCULATOR CHALLENGE (R▸P) — Point A is at (N {{nA:f2}}, E {{eA:f2}}) and point B is at (N {{nB:f2}}, E {{eB:f2}}). Using rectangular-to-polar, compute the AZIMUTH A→B in decimal degrees (0–360°).', 'numeric_input', '[]'::jsonb, '0', 'Azimuth is measured from north: Az = atan2(ΔE, ΔN) normalized to 0–360°. With ΔE = {{dE:f2}}, ΔN = {{dN:f2}}, Az = {{_answer}}°. On the calculator, R▸P returns this θ directly — read it with the swap key.', 'hard', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000004', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000005', 'CALCULATOR CHALLENGE (P▸R) — From point P (N {{nP:f2}}, E {{eP:f2}}) go azimuth {{az:f2}}° a distance of {{dist:f2}} ft. Using polar-to-rectangular, compute the NORTHING of the new point (ft).', 'numeric_input', '[]'::jsonb, '0', 'Feed distance {{dist:f2}} and azimuth {{az:f2}}° to P▸R; the latitude ΔN = D·cos(Az) = {{dN:f2}} ft. New Northing = {{nP:f2}} + {{dN:f2}} = {{_answer}} ft.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000005', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000006', 'CALCULATOR CHALLENGE — A line has the bearing S {{beta:f2}}° W. Compute its AZIMUTH (decimal degrees, 0–360°).', 'numeric_input', '[]'::jsonb, '0', 'A southwest bearing converts by Az = 180° + β = 180 + {{beta:f2}} = {{_answer}}°. (NE: β; SE: 180−β; SW: 180+β; NW: 360−β.)', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000006', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000007', 'CALCULATOR CHALLENGE — A triangular parcel has corners, in order, A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), and C (N {{nC:f2}}, E {{eC:f2}}). Using the coordinate (shoelace) method, compute the area in SQUARE FEET.', 'numeric_input', '[]'::jsonb, '0', 'Apply the shoelace sum with X = Easting, Y = Northing around A→B→C, halve the absolute value: A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| = {{_answer}} ft². Chain the three cross-products with memory/SUM to avoid re-keying.', 'medium', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000007', 1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb096000-0000-0000-0000-000000000008', 'CALCULATOR CHALLENGE — A circular curve has R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. In DEGREE mode, compute the tangent distance T (ft).', 'numeric_input', '[]'::jsonb, '0', 'In DEGREE mode, type I/2 straight into tan: T = R·tan(I/2) = {{R:f2}}·tan({{I:f2}}°/2) = {{_answer}} ft.', 'easy', 'f5000009-0000-0000-0000-000000000009', 'FS', ARRAY['fs-buildout','fs-m9','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb095000-0000-0000-0000-000000000008', 0.1);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000001', 'Which single calculator operation most directly returns both the distance and the azimuth between two coordinates?', 'multiple_choice', '["Rectangular-to-polar (R▸P)","Polar-to-rectangular (P▸R)","Decimal-to-DMS conversion","Reciprocal (x⁻¹)"]'::jsonb, 'Rectangular-to-polar (R▸P)', 'R▸P takes (ΔE, ΔN) and returns (distance r, direction θ) in one step — the inverse computation. P▸R does the reverse.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000002', 'To find the coordinates of a new point from a known azimuth and distance, the calculator operation is:', 'multiple_choice', '["Polar-to-rectangular (P▸R)","Rectangular-to-polar (R▸P)","DMS arithmetic","Statistics mode"]'::jsonb, 'Polar-to-rectangular (P▸R)', 'P▸R converts (distance, azimuth) to rectangular ΔE and ΔN, which add to the start coordinates — the forward computation ΔN = D·cos(Az), ΔE = D·sin(Az).', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000003', 'Adding 35°50′40″ and 12°15′30″ in DMS mode gives:', 'multiple_choice', '["48°06′10″","47°66′70″","48°05′10″","47°06′10″"]'::jsonb, '48°06′10″', '40″+30″ = 70″ = 1′10″; 50′+15′+1′ = 66′ = 1°06′; 35°+12°+1° = 48°. Result 48°06′10″ — the calculator does this directly in DMS.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000004', 'Converting the azimuth 215°00′ to a bearing gives:', 'multiple_choice', '["S 35°00′ W","N 35°00′ E","S 35°00′ E","N 35°00′ W"]'::jsonb, 'S 35°00′ W', '215° is in the SW quadrant (180–270). Bearing = S (Az − 180°) W = S (215 − 180)° W = S 35°00′ W.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000005', 'The single most important calculator setting to verify before any survey trig is:', 'multiple_choice', '["DEGREE (DEG) angle mode","Fix-3 decimal display","Scientific notation on","Fraction display on"]'::jsonb, 'DEGREE (DEG) angle mode', 'Survey angles are in degrees; a calculator in RAD or GRAD produces wildly wrong trig with no warning. Always confirm DEG before curve, inverse, or traverse work.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000006', 'Computing area from corner coordinates by the shoelace method, the cross-product to accumulate for each edge i is:', 'multiple_choice', '["Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ","Xᵢ·Yᵢ − X_{i+1}·Y_{i+1}","Xᵢ + Y_{i+1}","Xᵢ·X_{i+1} − Yᵢ·Y_{i+1}"]'::jsonb, 'Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ', 'Area = ½·|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| with X = Easting, Y = Northing. Accumulate each edge''s cross-product, halve, take the absolute value.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000007', 'A circular curve has R = 600 ft and I = 30°. Its tangent distance T = R·tan(I/2) is most nearly:', 'multiple_choice', '["160.77 ft","300.00 ft","321.54 ft","155.29 ft"]'::jsonb, '160.77 ft', 'T = 600·tan(15°) = 600·0.26795 = 160.77 ft. Type I/2 straight into tan in DEGREE mode.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000008', 'On the FS exam (110 questions in 5 h 20 min), the recommended pacing strategy is to:', 'multiple_choice', '["answer easy questions first, flag-and-skip hard ones, and return later","solve questions strictly in order regardless of difficulty","spend equal fixed time on every question","do all computational questions first, in full, before any others"]'::jsonb, 'answer easy questions first, flag-and-skip hard ones, and return later', 'At ~2.9 min/question, banking the quick boundary/ethics/definition points and flagging long COGO problems preserves momentum and protects time for multi-step items.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000009', 'Which calculator is NOT permitted on the FS exam under the 2026 approved list?', 'multiple_choice', '["A TI-84 Plus graphing calculator","A Casio fx-991EX","A TI-36X Pro","An HP 35s"]'::jsonb, 'A TI-84 Plus graphing calculator', 'Graphing (and programmable/CAS) calculators like the TI-84 are prohibited. The fx-991EX, TI-36X Pro, and HP 35s are all on the approved list.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000010', 'After an R▸P conversion shows the distance, the angle (azimuth) is read by:', 'multiple_choice', '["pressing the [x⇄y] swap key (or reading the θ field)","pressing x⁻¹","switching to RAD mode","re-entering ΔE and ΔN"]'::jsonb, 'pressing the [x⇄y] swap key (or reading the θ field)', 'R▸P outputs both r and θ; the swap key (or the second result field) shows the angle without re-keying the inputs.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000011', 'Because the FS imposes no penalty for wrong answers, the correct exam behavior is to:', 'multiple_choice', '["answer every question, guessing among remaining choices if unsure","leave uncertain questions blank","answer only questions you are fully confident about","guess all answers at the start to save time"]'::jsonb, 'answer every question, guessing among remaining choices if unsure', 'A blank scores zero; a guess (especially after eliminating wrong options) has a chance. Never leave a question unanswered.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000012', 'The most efficient way to use the searchable electronic FS Reference Handbook during the exam is to:', 'multiple_choice', '["know in advance where each formula section lives so you confirm, not hunt","read it fully during the exam","memorize it and never open it","search it from scratch for every question"]'::jsonb, 'know in advance where each formula section lives so you confirm, not hunt', 'The handbook is large but searchable; practicing with the real PDF so you know where curves, area, inverse, and statistics formulas sit turns a confirmation into seconds rather than a time-consuming hunt.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000013', 'The back azimuth of a line with forward azimuth 78°30′ is:', 'multiple_choice', '["258°30′","101°30′","281°30′","168°30′"]'::jsonb, '258°30′', 'Back azimuth = (Az + 180°) mod 360° = 78°30′ + 180° = 258°30′ (add 180° when Az < 180°).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb097000-0000-0000-0000-000000000014', 'To area a simple rectangular lot quickly, the best practice is to:', 'multiple_choice', '["multiply the two side lengths directly rather than run a full COGO/area routine","always run the stored AREA program","convert each corner with R▸P first","compute the diagonal and use Heron''s formula"]'::jsonb, 'multiply the two side lengths directly rather than run a full COGO/area routine', 'Calculation discipline: use the simplest method. A rectangle is side × side; running a full coordinate routine wastes time and invites entry errors.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m9','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO fs_study_modules (id, module_number, title, description, week_range, exam_weight_percent, key_topics, key_formulas, content_sections, prerequisite_module, passing_score, question_count, icon, xp_reward, is_published, review_status)
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000001', 'The NCEES Fundamentals of Surveying exam consists of how many questions, and how is it administered?', 'multiple_choice', '["110 questions, computer-based (CBT) and closed-book with an electronic reference handbook","80 questions, open-book paper-and-pencil","150 questions, take-home","110 questions, open-book with any personal references allowed"]'::jsonb, '110 questions, computer-based (CBT) and closed-book with an electronic reference handbook', 'The FS is a 110-question CBT delivered at Pearson VUE. It is closed-book, but examinees get the electronic NCEES FS Reference Handbook (and supplied standards) on screen the entire exam; no personal references are allowed.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000002', 'On the FS, the total exam time (after the agreement and tutorial) is 5 hours 20 minutes for 110 questions. The approximate time budget per question is:', 'multiple_choice', '["about 2.9 minutes","about 1.0 minute","about 5.0 minutes","about 8.0 minutes"]'::jsonb, 'about 2.9 minutes', '5 h 20 m = 320 minutes; 320 / 110 ≈ 2.9 minutes per question. Bank the quick boundary/ethics items and flag the long computations.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000003', 'Which knowledge area carries the single largest number of questions on the FS exam?', 'multiple_choice', '["Boundary Law and Real Property Principles","Applied Mathematics and Statistics","Business Concepts","Mapping Processes and Methods"]'::jsonb, 'Boundary Law and Real Property Principles', 'Boundary Law and Real Property Principles is the largest area (about 19–29 of the 110 questions), ahead of Survey Computations and Surveying Processes. The FS is as much a boundary exam as a math exam.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000004', 'In the hierarchy (dignity) of conflicting calls in a deed, which generally controls over the others?', 'multiple_choice', '["Calls for natural monuments","Calls for distance","Calls for area (quantity)","Calls for bearing"]'::jsonb, 'Calls for natural monuments', 'After senior rights and the written intent of the parties, calls for monuments control — natural monuments over artificial, and monuments over course and distance. Bearing controls over distance, and area (quantity) is the least reliable, controlling last.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000005', 'A line is measured 9 times with a standard deviation of a single measurement of 0.06 ft. The standard error of the mean is most nearly:', 'multiple_choice', '["0.020 ft","0.060 ft","0.180 ft","0.007 ft"]'::jsonb, '0.020 ft', 'σ_m = σ/√n = 0.06/√9 = 0.06/3 = 0.020 ft.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000006', 'Point A is (N 1,500.00, E 2,000.00) and point B is (N 1,800.00, E 2,400.00). The horizontal distance A→B is most nearly:', 'multiple_choice', '["500.00 ft","700.00 ft","300.00 ft","640.00 ft"]'::jsonb, '500.00 ft', 'D = hypot(ΔN, ΔE) = √(300² + 400²) = √(90,000 + 160,000) = √250,000 = 500.00 ft (a 3-4-5 triangle).', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000007', 'The azimuth of the line from A(N 1,500.00, E 2,000.00) to B(N 1,800.00, E 2,400.00) is most nearly:', 'multiple_choice', '["53°08′","36°52′","126°52′","233°08′"]'::jsonb, '53°08′', 'Both ΔN (+300) and ΔE (+400) are positive → Quadrant I (NE). Az = atan2(ΔE, ΔN) = atan(400/300) = 53.13° = 53°08′.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000008', 'A closed traverse has a perimeter of 2,400.00 ft and a linear misclosure of 0.24 ft. Its relative precision is:', 'multiple_choice', '["1:10,000","1:1,000","1:24,000","1:5,000"]'::jsonb, '1:10,000', 'Relative precision = misclosure/perimeter = 0.24/2,400 = 1/10,000.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000009', 'A backsight of 5.20 ft is taken on a benchmark at elevation 612.40 ft, then a foresight of 7.85 ft is read to a turning point. The turning-point elevation is:', 'multiple_choice', '["609.75 ft","615.05 ft","625.45 ft","604.55 ft"]'::jsonb, '609.75 ft', 'HI = Elev + BS = 612.40 + 5.20 = 617.60 ft. Elev = HI − FS = 617.60 − 7.85 = 609.75 ft.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000010', 'A simple circular curve has R = 800.00 ft and a central angle I = 40°00′. The tangent distance T is most nearly:', 'multiple_choice', '["291.21 ft","558.46 ft","320.00 ft","279.23 ft"]'::jsonb, '291.21 ft', 'T = R·tan(I/2) = 800·tan20° = 800·0.36397 = 291.21 ft.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000011', 'For the curve with R = 800.00 ft and I = 40°00′, the curve (arc) length L is most nearly:', 'multiple_choice', '["558.51 ft","582.41 ft","320.00 ft","547.23 ft"]'::jsonb, '558.51 ft', 'L = R·I·(π/180) = 800·(40·π/180) = 800·0.698132 = 558.51 ft.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000012', 'Which expression correctly relates orthometric height H, ellipsoidal height h, and geoid undulation N?', 'multiple_choice', '["H = h − N","H = h + N","N = h + H","H = N − h"]'::jsonb, 'H = h − N', 'Orthometric (elevation above the geoid) = ellipsoidal height − geoid undulation: H = h − N. GNSS gives h; subtract the geoid model N to get the elevation H.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000013', 'A ground distance of 4,000.00 ft is to be reduced to the state-plane grid using a combined factor of 0.9999200. The grid distance is most nearly:', 'multiple_choice', '["3,999.68 ft","4,000.32 ft","3,996.80 ft","4,003.20 ft"]'::jsonb, '3,999.68 ft', 'grid = ground × CF = 4,000.00 × 0.9999200 = 3,999.68 ft. Because the combined factor is less than 1, the grid distance is slightly shorter than the ground distance.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000014', 'A vertical aerial photo is taken at H = 5,000 ft above datum with a 6-in (0.5-ft) focal length camera over terrain at h = 1,000 ft. The photo scale is most nearly:', 'multiple_choice', '["1:8,000","1:10,000","1:12,000","1:6,000"]'::jsonb, '1:8,000', 'S = f/(H − h) = 0.5/(5,000 − 1,000) = 0.5/4,000 = 1/8,000.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000015', 'A four-corner lot has coordinates A(N 1,000, E 1,000), B(N 1,000, E 1,500), C(N 1,400, E 1,500), D(N 1,400, E 1,000). Its area in acres is most nearly:', 'multiple_choice', '["4.59 acres","2.30 acres","5.00 acres","3.44 acres"]'::jsonb, '4.59 acres', 'The lot is a 500 ft × 400 ft rectangle = 200,000 ft²; 200,000/43,560 = 4.59 acres. By the shoelace method the signed sum gives the same 200,000 ft².', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000016', 'In a SEQUENTIAL conveyance, when the total of all called parcels does not exactly fit the parent tract, the excess or deficiency is:', 'multiple_choice', '["absorbed entirely by the last (junior/remainder) parcel","prorated equally among all parcels","always given to the senior parcel","split by court order only"]'::jsonb, 'absorbed entirely by the last (junior/remainder) parcel', 'Senior rights govern sequential conveyances: each earlier grantee gets the full called area, and the remaining (junior) parcel absorbs any excess or deficiency. Proration applies to SIMULTANEOUS conveyances (e.g., a recorded plat).', 'hard', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000017', 'Under the surveyor''s ethical canons (NSPS / Model Rules), the surveyor''s first and foremost obligation is to:', 'multiple_choice', '["the safety, health, and welfare of the public","the client''s financial interest","the employer above all","other licensed surveyors"]'::jsonb, 'the safety, health, and welfare of the public', 'The Model Rules place duty to the public first and foremost. Surveyors also serve clients/employers honestly and deal fairly with other professionals, but public welfare comes first; sign and seal only work performed under your responsible charge and within your competence.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000018', 'The gradual, imperceptible build-up of land along a watercourse by natural deposition is called:', 'multiple_choice', '["accretion","avulsion","reliction","erosion"]'::jsonb, 'accretion', 'Accretion is the slow, imperceptible addition of soil; the boundary moves with it. Avulsion is a sudden change (boundary stays fixed); reliction is land exposed by receding water; erosion is gradual loss.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000019', 'An equal-tangent vertical curve has g₁ = +1.0%, g₂ = −3.0%, L = 400 ft, with the PVC at elevation 250.00 ft. The elevation on the curve 100 ft past the PVC is most nearly:', 'multiple_choice', '["250.50 ft","251.00 ft","249.50 ft","250.00 ft"]'::jsonb, '250.50 ft', 'Y = Y_PVC + g₁x + [(g₂−g₁)/(2L)]x² = 250 + 0.01·100 + [(−0.04)/(800)]·100² = 250 + 1.00 − 0.50 = 250.50 ft.', 'hard', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000020', 'A rectangular parcel is measured 200.00 ± 0.05 ft by 300.00 ± 0.05 ft. The standard error of the computed area is most nearly:', 'multiple_choice', '["±18.0 ft²","±0.05 ft²","±36.0 ft²","±2.5 ft²"]'::jsonb, '±18.0 ft²', 'σ_A = √[(L·σ_W)² + (W·σ_L)²] = √[(200·0.05)² + (300·0.05)²] = √(10² + 15²) = √325 = 18.03 ≈ ±18.0 ft².', 'hard', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000021', 'Which best describes an appurtenant easement?', 'multiple_choice', '["a non-possessory right that runs with the land and passes to subsequent owners of the dominant tract","a possessory ownership interest in the servient tract","a right that automatically terminates upon sale of either parcel","a right that exists only if separately recorded each year"]'::jsonb, 'a non-possessory right that runs with the land and passes to subsequent owners of the dominant tract', 'An appurtenant easement benefits a dominant tract and burdens a servient tract; it is a non-possessory interest that runs with the land and conveys automatically with the dominant parcel. It is not separable from the land it benefits.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000022', 'The station of the PT of a simple circular curve is found by:', 'multiple_choice', '["adding the curve length L to the PC station","adding the tangent distance T to the PC station","adding 2T to the PI station","subtracting L from the PI station"]'::jsonb, 'adding the curve length L to the PC station', 'PT = PC + L, using the arc (curve) length. PC = PI − T. Adding the tangent T instead of the arc L is the most common curve-stationing blunder.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000023', 'True or False: On the FS exam, examinees may bring and use their own printed reference books and notes.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. The FS is closed-book. The only references are the on-screen electronic NCEES FS Reference Handbook and the supplied standards; no personal references are permitted.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000024', 'Two adjacent cross-sections 100 ft apart have cut end areas of 80 ft² and 160 ft². The average-end-area volume between them, in cubic yards, is most nearly:', 'numeric_input', '[]'::jsonb, '444', 'V = L·(A₁+A₂)/2 = 100·(80+160)/2 = 100·120 = 12,000 ft³; 12,000/27 = 444.4 ≈ 444 yd³.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb103000-0000-0000-0000-000000000025', 'True or False: A surveyor may sign and seal a plat prepared entirely by another firm that was not under the surveyor''s responsible charge, as long as it appears correct.', 'true_false', '["True","False"]'::jsonb, 'False', 'False. Under the ethical canons a surveyor may sign and seal only work performed by the surveyor or under the surveyor''s direct responsible charge. Sealing another''s work not under your charge violates the Model Rules.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000001', 'A distance is measured {{n}} times. The standard deviation of a single measurement is σ = {{sigma:f3}} ft. Compute the standard error of the mean (ft).', 'numeric_input', '[]'::jsonb, '0', 'The standard error of the mean improves with the square root of the number of observations: σ_m = σ/√n = {{sigma:f3}}/√{{n}} = {{_answer}} ft.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000001', 0.0005);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000002', 'Point A is at (N {{nA:f2}}, E {{eA:f2}}). Point B is at (N {{nB:f2}}, E {{eB:f2}}). Compute the horizontal distance A→B (ft).', 'numeric_input', '[]'::jsonb, '0', 'Use rectangular→polar: enter ΔN and ΔE; the calculator returns distance = hypot(ΔN, ΔE) = {{_answer}} ft directly.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000002', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000003', 'From point A (N {{nA:f2}}, E {{eA:f2}}) to point B (N {{nB:f2}}, E {{eB:f2}}), compute the azimuth of line A→B (decimal degrees, 0–360°).', 'numeric_input', '[]'::jsonb, '0', 'Azimuth = atan2(ΔE, ΔN); add 360° if negative so the result lies in 0–360°. Here Az = {{_answer}}°. The signs of ΔN and ΔE place it in the correct quadrant automatically.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000003', 0.02);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000004', 'From point P (N {{nP:f2}}, E {{eP:f2}}), a line runs azimuth {{az:f2}}° for a distance of {{dist:f2}} ft to point Q. Compute the NORTHING of point Q (ft).', 'numeric_input', '[]'::jsonb, '0', 'The latitude is ΔN = L·cos(Az), so N_Q = N_P + L·cos(Az) = {{nP:f2}} + {{dist:f2}}·cos({{az:f2}}°) = {{_answer}} ft (calc: P▸R, read the latitude component).', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000004', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000005', 'A four-corner parcel has corners, in order, A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), C (N {{nC:f2}}, E {{eC:f2}}), and D (N {{nD:f2}}, E {{eD:f2}}). Compute the enclosed area by coordinates (shoelace) and report it in ACRES.', 'numeric_input', '[]'::jsonb, '0', 'Apply the shoelace formula with X = Easting, Y = Northing, vertices in order A→B→C→D, take the absolute value, then divide by 43,560 ft²/acre. Area = {{_answer}} acres.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000005', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000006', 'A simple circular curve has radius R = {{R:f2}} ft and deflection (central) angle I = {{I:f2}}°. Compute the tangent distance T (ft).', 'numeric_input', '[]'::jsonb, '0', 'The tangent distance from the PI to the PC (and to the PT) is T = R·tan(I/2) = {{R:f2}}·tan({{I:f2}}°/2) = {{_answer}} ft. Set the calculator to DEGREE mode and use I/2.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000006', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000007', 'A circular curve has radius R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. Compute the curve (arc) length L (ft).', 'numeric_input', '[]'::jsonb, '0', 'The arc length is L = R·I·(π/180) = {{R:f2}}·toRad({{I:f2}}°) = {{_answer}} ft. The PT is set by adding this arc length (not T) to the PC.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000007', 0.1);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000008', 'A backsight of {{bs:f2}} ft is taken on a benchmark at elevation {{elev:f2}} ft, then a foresight of {{fs:f2}} ft is read to a turning point. Compute the elevation of the turning point (ft).', 'numeric_input', '[]'::jsonb, '0', 'HI = Elev + BS = {{elev:f2}} + {{bs:f2}} = {{hi:f2}} ft; then Elev = HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft.', 'easy', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000008', 0.01);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000009', 'A vertical aerial photo is taken at flying height H = {{H:f1}} ft above datum with a focal length f = {{f:f3}} ft, over terrain at average ground height h = {{h:f1}} ft. Compute the scale denominator (the number S in 1:S).', 'numeric_input', '[]'::jsonb, '0', 'Photo scale S = f/(H − h); the denominator is (H − h)/f = ({{H:f1}} − {{h:f1}})/{{f:f3}} = {{_answer}}, i.e. a scale of 1:{{_answer}}.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000009', 5);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000010', 'A ground distance of {{ground:f2}} ft is to be reduced to the state-plane grid using a combined factor CF = {{cf:f7}}. Compute the grid distance (ft).', 'numeric_input', '[]'::jsonb, '0', 'To go from ground to grid, multiply by the combined factor (CF = scale factor × elevation factor): grid = {{ground:f2}} × {{cf:f7}} = {{_answer}} ft. (To reverse, divide grid by CF.)', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000010', 0.05);
INSERT INTO problem_templates (id, name, description, category, subcategory, question_type, difficulty, question_template, answer_formula, answer_format, parameters, computed_vars, solution_steps_template, options_generator, explanation_template, module_id, exam_category, tags, diagram, is_active, created_by) VALUES (
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, module_id, exam_category, tags, is_published, review_status, study_references, is_dynamic, template_id, tolerance) VALUES ('fb106000-0000-0000-0000-000000000011', 'Two adjacent cross-sections {{L:f1}} ft apart have end areas A₁ = {{a1:f1}} ft² and A₂ = {{a2:f1}} ft². Using the average-end-area method, compute the earthwork volume in CUBIC YARDS.', 'numeric_input', '[]'::jsonb, '0', 'Average end area: V = L·(A₁+A₂)/2 = {{L:f1}}·({{a1:f1}}+{{a2:f1}})/2 = {{vft3:f1}} ft³. Divide by 27 ft³/yd³ → {{_answer}} yd³.', 'medium', 'f500000a-0000-0000-0000-00000000000a', 'FS', ARRAY['fs-buildout','fs-m10','fs-dynamic']::text[], true, 'approved', '[]'::jsonb, true, 'fb105000-0000-0000-0000-000000000011', 0.5);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000001', 'A line is measured 16 times with a single-measurement standard deviation of 0.08 ft. The standard error of the mean is most nearly:', 'multiple_choice', '["0.020 ft","0.080 ft","0.005 ft","0.320 ft"]'::jsonb, '0.020 ft', 'σ_m = σ/√n = 0.08/√16 = 0.08/4 = 0.020 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000002', 'A distance is measured with a relative precision of 1:25,000 over a 1,500-ft line. The expected positional uncertainty is most nearly:', 'multiple_choice', '["0.06 ft","0.60 ft","0.006 ft","0.15 ft"]'::jsonb, '0.06 ft', 'Uncertainty = length × (1/precision) = 1,500 × (1/25,000) = 0.06 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000003', 'Under a normal distribution, approximately what percentage of observations fall within ±2 standard deviations of the mean?', 'multiple_choice', '["95%","68%","99.7%","50%"]'::jsonb, '95%', 'The empirical (68-95-99.7) rule: about 68% lie within ±1σ, 95% within ±2σ, and 99.7% within ±3σ of the mean.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-math']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000004', 'Point A is (N 2,000.00, E 3,000.00) and point B is (N 2,600.00, E 3,800.00). The distance A→B is most nearly:', 'multiple_choice', '["1,000.00 ft","1,400.00 ft","600.00 ft","800.00 ft"]'::jsonb, '1,000.00 ft', 'D = hypot(ΔN, ΔE) = √(600² + 800²) = √1,000,000 = 1,000.00 ft (a 6-8-10 triangle).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000005', 'The azimuth from A(N 2,000, E 3,000) to B(N 2,600, E 3,800) is most nearly:', 'multiple_choice', '["53°08′","36°52′","126°52′","233°08′"]'::jsonb, '53°08′', 'ΔN = +600, ΔE = +800 → Quadrant I. Az = atan(800/600) = 53.13° = 53°08′.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000006', 'A closed traverse has ΣLat = +0.12 ft and ΣDep = −0.16 ft. The linear misclosure is most nearly:', 'multiple_choice', '["0.20 ft","0.28 ft","0.04 ft","0.14 ft"]'::jsonb, '0.20 ft', 'misclosure = √(ΣLat² + ΣDep²) = √(0.12² + 0.16²) = √(0.0144 + 0.0256) = √0.04 = 0.20 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000007', 'A simple circular curve has R = 1,200.00 ft and I = 30°00′. Its tangent distance T is most nearly:', 'multiple_choice', '["321.54 ft","300.00 ft","600.00 ft","310.58 ft"]'::jsonb, '321.54 ft', 'T = R·tan(I/2) = 1,200·tan15° = 1,200·0.26795 = 321.54 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000008', 'A backsight of 6.40 ft is read on a benchmark at elevation 500.00 ft; the foresight to a turning point is 9.15 ft. The turning-point elevation is:', 'multiple_choice', '["497.25 ft","502.75 ft","515.55 ft","484.45 ft"]'::jsonb, '497.25 ft', 'HI = 500.00 + 6.40 = 506.40 ft; Elev = HI − FS = 506.40 − 9.15 = 497.25 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000009', 'An equal-tangent vertical curve has g₁ = +2.0%, g₂ = −2.0%, L = 500 ft, PVC elevation 800.00 ft. The elevation at the midpoint of the curve (x = 250 ft) is most nearly:', 'multiple_choice', '["802.50 ft","805.00 ft","800.00 ft","807.50 ft"]'::jsonb, '802.50 ft', 'Y = 800 + 0.02·250 + [(−0.04)/(1000)]·250² = 800 + 5.00 − 2.50 = 802.50 ft (the crest of a symmetric curve).', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-computations']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000010', 'A road measures 3.00 in on a 1:6,000 vertical aerial photo. Its ground length is most nearly:', 'multiple_choice', '["1,500 ft","18,000 ft","2,000 ft","750 ft"]'::jsonb, '1,500 ft', 'Ground = photo distance × scale denominator = 3.00 in × 6,000 = 18,000 in = 1,500 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000011', 'A drone camera with 24 mm focal length and 5.0 µm pixels flies 120 m above ground. The ground sample distance is most nearly:', 'multiple_choice', '["2.5 cm","5.0 cm","1.0 cm","25 cm"]'::jsonb, '2.5 cm', 'GSD = (pixel size × H)/f = (5.0 µm × 120 m)/24 mm. Using GSD_cm = (pixel_µm × H_m)/(f_mm × 10) = (5.0 × 120)/(24 × 10) = 600/240 = 2.5 cm.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000012', 'On a topographic map, contour lines that are spaced very close together indicate:', 'multiple_choice', '["steep terrain","flat terrain","a body of water","a survey monument"]'::jsonb, 'steep terrain', 'Contours represent equal-elevation lines at a fixed interval; the closer they are, the greater the elevation change over a short horizontal distance, i.e., steeper ground. Widely spaced contours indicate gentle slopes.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000013', 'In a GIS, the information describing the source, accuracy, projection, and date of a dataset is called:', 'multiple_choice', '["metadata","a legend","a raster","an attribute join"]'::jsonb, 'metadata', 'Metadata is ''data about the data'' — it documents lineage, accuracy, coordinate system, and currency, and is essential for responsibly sharing and using GIS datasets.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-mapping']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000014', 'When two deed calls conflict, which of the following normally controls over the others?', 'multiple_choice', '["a call for a natural monument","a call for distance","a call for area (quantity)","a call for bearing"]'::jsonb, 'a call for a natural monument', 'In the dignity of calls, after senior rights and the parties'' intent, natural monuments control over artificial monuments, and monuments control over course (bearing) and distance; area is least reliable.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000015', 'Five lots are created at once by a single recorded subdivision plat, but the block is found to be 1.0 ft longer than the platted total. How is the excess handled?', 'multiple_choice', '["prorated among the lots in proportion to their record dimensions","given entirely to the first lot","given entirely to the last lot","ignored because plats are exact"]'::jsonb, 'prorated among the lots in proportion to their record dimensions', 'Lots created simultaneously by a plat carry no seniority among them, so excess or deficiency is prorated proportionally. (In a sequential conveyance, by contrast, the junior/remainder parcel absorbs the difference.)', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000016', 'Title acquired by occupying land openly, notoriously, continuously, exclusively, and hostilely for the statutory period is acquired by:', 'multiple_choice', '["adverse possession","an easement by necessity","accretion","a quitclaim deed"]'::jsonb, 'adverse possession', 'Adverse possession transfers title when the possession satisfies the open, notorious, continuous, exclusive, and hostile elements for the jurisdiction''s statutory period.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000017', 'A right-of-way granted to a utility to cross another''s land for power lines is an example of:', 'multiple_choice', '["an easement","fee simple ownership","adverse possession","a deed restriction reverting title"]'::jsonb, 'an easement', 'An easement is a non-possessory right to use another''s land for a specific purpose (here, utility access). It does not convey ownership of the underlying land.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000018', 'In the PLSS, a standard township is divided into how many sections?', 'multiple_choice', '["36","16","100","640"]'::jsonb, '36', 'A standard township is 6 miles square, divided into 36 sections of (nominally) one square mile (640 acres) each, numbered 1–36 in a boustrophedonic pattern beginning at the northeast corner.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000019', 'A lost original PLSS corner that fell between two existing corners on a line is best restored by:', 'multiple_choice', '["proportionate (single or double) measurement","setting it at the record distance from the nearest corner only","placing it at the centroid of the section","GPS coordinates from the county GIS"]'::jsonb, 'proportionate (single or double) measurement', 'A truly lost corner is restored by proportionate measurement — single proportion along a line, double proportion at an interior corner controlled in two directions — distributing the discrepancy in proportion to the record distances.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000020', 'A warranty deed differs from a quitclaim deed in that the warranty deed:', 'multiple_choice', '["guarantees the grantor''s title against defects","conveys only whatever interest the grantor happens to have","transfers no interest at all","is valid only if the land is surveyed"]'::jsonb, 'guarantees the grantor''s title against defects', 'A warranty deed includes covenants guaranteeing good title and defending against claims. A quitclaim conveys only whatever interest (if any) the grantor holds, without warranties.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000021', 'Land lost suddenly and perceptibly when a river changes course in a single flood event is governed by the doctrine of:', 'multiple_choice', '["avulsion (boundary stays fixed)","accretion (boundary moves)","reliction","prescription"]'::jsonb, 'avulsion (boundary stays fixed)', 'Avulsion is a sudden, perceptible change in a watercourse; the boundary remains at its former location. Accretion (gradual, imperceptible) moves the boundary with the slowly changing bank.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-boundary']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000022', 'Which device achieves the highest absolute positional accuracy for establishing a geodetic control network?', 'multiple_choice', '["static GNSS observations processed against CORS","single-frequency handheld GPS","a hand compass and pacing","real-time autonomous (uncorrected) GNSS"]'::jsonb, 'static GNSS observations processed against CORS', 'Long static GNSS sessions post-processed against continuously operating reference stations (e.g., via OPUS) yield centimeter-level control, far better than autonomous or handheld positioning.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000023', 'OPUS (Online Positioning User Service) is used to:', 'multiple_choice', '["post-process a static GNSS occupation against the CORS network for accurate coordinates","drive a robotic total station","draft a final plat","compute earthwork volumes"]'::jsonb, 'post-process a static GNSS occupation against the CORS network for accurate coordinates', 'OPUS is an NGS service that processes a submitted static GNSS data file against nearby CORS stations and returns accurate NAD83 (and ellipsoidal/orthometric) coordinates for the occupied point.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000024', 'Why must field notes and raw data files be kept complete, legible, and unaltered?', 'multiple_choice', '["they are the original evidence of the survey and may be needed in court","they are required to be turned in to NCEES","they replace the recorded plat","they are only for billing purposes"]'::jsonb, 'they are the original evidence of the survey and may be needed in court', 'Field notes and raw data are the contemporaneous record of what was observed and are the surveyor''s evidence of the work — they may be examined in litigation or retracement and must never be falsified.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000025', 'For best accuracy when measuring a long distance with an EDM, the surveyor must account for:', 'multiple_choice', '["atmospheric temperature and pressure (the ppm correction)","the color of the prism pole","the time of day only","the operator''s height"]'::jsonb, 'atmospheric temperature and pressure (the ppm correction)', 'EDM measurements depend on the velocity of light through the atmosphere; temperature and pressure change the refractive index, requiring a parts-per-million correction (roughly 10 ppm per 10 °C or per 1 in Hg).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-processes']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000026', 'GNSS gives an ellipsoidal height h = 245.30 ft at a point where the geoid undulation N = −28.10 ft. The orthometric height (elevation) H is most nearly:', 'multiple_choice', '["273.40 ft","217.20 ft","245.30 ft","28.10 ft"]'::jsonb, '273.40 ft', 'H = h − N = 245.30 − (−28.10) = 245.30 + 28.10 = 273.40 ft.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000027', 'The geoid is best described as:', 'multiple_choice', '["an equipotential surface of the Earth''s gravity field, everywhere perpendicular to the plumb line","a perfect mathematical ellipsoid of revolution","the visible topographic surface of the Earth","the orbit plane of GPS satellites"]'::jsonb, 'an equipotential surface of the Earth''s gravity field, everywhere perpendicular to the plumb line', 'The geoid is the equipotential (level) surface of gravity that the plumb line is perpendicular to everywhere; it is the reference for orthometric heights. The ellipsoid is the smooth mathematical reference used for horizontal datums.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000028', 'For a long, narrow north-south state, the State Plane Coordinate System most commonly uses which projection?', 'multiple_choice', '["Transverse Mercator","Lambert Conformal Conic","Albers equal-area","Universal polar stereographic"]'::jsonb, 'Transverse Mercator', 'Transverse Mercator is used for zones that extend predominantly north-south, while Lambert Conformal Conic is used for east-west zones. Both are conformal projections used by SPCS.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000029', 'A grid distance of 5,280.00 ft is reduced from a ground distance using a combined factor of 0.9999000. The corresponding ground distance is most nearly:', 'multiple_choice', '["5,280.53 ft","5,279.47 ft","5,285.28 ft","5,274.72 ft"]'::jsonb, '5,280.53 ft', 'ground = grid / CF = 5,280.00 / 0.9999000 = 5,280.53 ft. With CF < 1, the ground distance is slightly longer than the grid distance.', 'hard', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-principles']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000030', 'Under the surveyor''s professional canons, a surveyor should accept assignments only when:', 'multiple_choice', '["they fall within the surveyor''s area of competence","the fee is highest","the client is a friend","no other surveyor is available"]'::jsonb, 'they fall within the surveyor''s area of competence', 'A core ethical canon requires practicing only within one''s area of competence and signing/sealing only work performed under one''s responsible charge, with the public''s welfare paramount.', 'easy', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-business']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000031', 'Which set of elements is required to form a valid contract?', 'multiple_choice', '["offer, acceptance, and consideration","a seal and a notary only","a verbal promise alone","a recorded plat"]'::jsonb, 'offer, acceptance, and consideration', 'A valid contract generally requires offer, acceptance, consideration, capacity of the parties, and a lawful purpose. Scope of work and specifications define the deliverable but are not the bare formation elements.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-business']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000032', 'Professional liability coverage that protects a surveyor against claims of negligent errors in professional work is commonly called:', 'multiple_choice', '["errors and omissions (E&O) insurance","workers'' compensation","title insurance","a performance bond"]'::jsonb, 'errors and omissions (E&O) insurance', 'Errors and omissions (professional liability) insurance covers claims arising from negligent acts, errors, or omissions in professional services — distinct from title insurance, which protects against defects in title.', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-business']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
INSERT INTO question_bank (id, question_text, question_type, options, correct_answer, explanation, difficulty, exam_category, tags, is_published, review_status, study_references, is_dynamic, tolerance) VALUES ('fb107000-0000-0000-0000-000000000033', 'A safety data sheet (SDS) under the GHS contains how many standardized sections?', 'multiple_choice', '["16","8","11","4"]'::jsonb, '16', 'An SDS has 16 sections in a fixed order; OSHA enforces sections 1–11 and 16 (sections 12–15 cover ecological, disposal, transport, and regulatory information not enforced by OSHA).', 'medium', 'FS-MOCK', ARRAY['fs-buildout','fs-m10','fs-mock-business']::text[], true, 'approved', '[]'::jsonb, false, 0.01);
