-- 368_fs_prep_buildout.sql (GENERATED) — comprehensive FS/SIT exam-prep buildout
-- 10 fs_study_modules (enrich 1-8, add 9 Calculator Mastery + 10 Review/Mock),
-- FS question bank, randomized problem_templates, and the FS-MOCK 110-q pool.
-- Namespaced by tag 'fs-buildout' / created_by 'fs:m<n>' — original 030_fs_prep rows untouched.
-- Depends on: 330 (question_bank dynamic cols).
BEGIN;

-- ===== FS Module 1: Fundamentals of Surveying =====
DELETE FROM question_bank WHERE module_id='f5000001-0000-0000-0000-000000000001' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m1' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m1';
VALUES ('f5000001-0000-0000-0000-000000000001', 1, 'Fundamentals of Surveying', 'The mathematical and measurement-science foundation for the entire FS exam: units and conversions, significant figures, error theory, statistics, error propagation, and probability. Master this before any COGO, leveling, or curve work.', 'Weeks 1-2', 15, ARRAY['Units and conversions (US survey foot vs international foot, chains, acres, metric)','Significant figures and rounding rules','Error types: gross/blunder, systematic, random','Accuracy vs precision','Most probable value (mean) and residuals','Sample standard deviation σ = √(Σv²/(n−1))','Standard error of the mean σ_m = σ/√n','Error propagation: sum √(Σe²), series e·√n, product','Relative precision / accuracy ratio','Normal distribution and the 68-95-99.7 rule','Weighted mean (weight ∝ 1/σ²)','Confidence intervals (Z-values)']::text[], '[{"name":"Sample Standard Deviation","formula":"σ = √(Σv² / (n − 1)),  v = xᵢ − x̄"},{"name":"Standard Error of the Mean","formula":"σ_m = σ / √n"},{"name":"Error Propagation — Sum","formula":"E_sum = √(E₁² + E₂² + … + Eₙ²)"},{"name":"Error Propagation — Series of n equal errors","formula":"E_series = E · √n"},{"name":"Error Propagation — Product (area)","formula":"σ_A = √((b·σ_a)² + (a·σ_b)²)"},{"name":"Most Probable Value (mean)","formula":"x̄ = Σxᵢ / n"},{"name":"Weighted Mean","formula":"x̄_w = Σ(wᵢ·xᵢ) / Σwᵢ,  wᵢ ∝ 1/σᵢ²"},{"name":"Relative Precision","formula":"1 : (distance / error)"},{"name":"Confidence Interval","formula":"x̄ ± Z·σ_m   (Z = 1.6449 @90%, 1.9600 @95%)"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Why this module matters\n\nThe NCEES FS exam blends two knowledge areas that this module covers head-on: **Applied Mathematics and Statistics** (10–15 questions) and **Surveying Principles** (13–20 questions, the measurement-theory half). Together with the measurement-science questions embedded in **Survey Computations** (17–26), the material here is worth roughly **15% of your score** and — just as important — underpins every other computation in the course. You cannot reduce a traverse, balance a level loop, or judge whether a measurement is acceptable without understanding error.\n\nEverything in surveying is a **measurement**, and every measurement carries error. The professional''s job is not to eliminate error (impossible) but to **understand, quantify, and bound** it. This module builds that mindset in five steps:\n\n- **Units & significant figures** — the bookkeeping that keeps answers honest. Watch the US survey foot vs international foot trap and never report more precision than you measured.\n- **Error classification** — gross (blunders), systematic (one-directional, correctable), and random (the irreducible scatter statistics actually describe).\n- **Statistics of a measurement set** — the most probable value (mean), residuals, and the **sample standard deviation** σ = √(Σv²/(n−1)).\n- **Error propagation** — how the uncertainty in inputs flows into a sum, a series of n repeated readings, or a product such as area.\n- **Probability** — the normal curve and the **68-95-99.7 rule**, weighted means, and confidence intervals.\n\nThe payoff: when the exam hands you ten distance observations, a ±tolerance on each side of a lot, or a 1:10,000 precision spec, you will know exactly which formula applies and how to key it on an NCEES-approved calculator. These are fast, high-yield points — drill them until they are reflexive."},{"type":"concepts","title":"Key Concepts","content":"## Accuracy vs precision\n\n**Accuracy** = closeness to the true value. **Precision** = closeness of repeated measurements to one another (repeatability). A total station can be precise (tight cluster) yet inaccurate (cluster centered on the wrong value because of an uncorrected systematic error). The classic image: tight grouping off the bullseye = precise but not accurate; scattered around the bullseye = accurate-on-average but not precise.\n\n## The three error types\n\n<table border=\"1\" cellpadding=\"6\">\n<tr><th>Type</th><th>Cause</th><th>Behavior</th><th>Treatment</th></tr>\n<tr><td><b>Gross (blunder/mistake)</b></td><td>Human error: transposed digits, wrong target, misread rod</td><td>Large, sporadic, not predictable</td><td><b>Detect &amp; remove</b> with redundancy/checks; never \"adjust\"</td></tr>\n<tr><td><b>Systematic</b></td><td>Physical/instrumental: tape too long, EDM scale, refraction</td><td><b>One-directional</b>, repeats in same sign/size, accumulates</td><td><b>Correct by formula or procedure</b> (e.g., temperature correction, reciprocal leveling)</td></tr>\n<tr><td><b>Random (accidental)</b></td><td>Irreducible limits of reading/pointing</td><td>Equally likely + or −, small, follows the normal curve</td><td><b>Treat with statistics</b> (mean, std dev, least squares)</td></tr>\n</table>\n\nOnly **random** error is what standard deviation and error propagation describe. Blunders must be found and thrown out first; systematic errors must be modeled/corrected first. Statistics applied to data still containing a blunder is meaningless.\n\n## Most probable value and residuals\n\nFor a set of equally-weighted direct observations, the **most probable value (MPV)** is the arithmetic mean x̄ = Σxᵢ/n. The **residual** of each observation is vᵢ = xᵢ − x̄ (observation minus the mean). Residuals are the raw material of every dispersion statistic.\n\n## Standard deviation and standard error\n\nThe **sample standard deviation** measures the scatter of a single observation about the mean:\n\nσ = √( Σv² / (n − 1) )\n\nWe divide by (n − 1), the **degrees of freedom**, not n — one degree of freedom was \"used up\" computing the mean. The **standard error (deviation) of the mean** measures how well the *mean itself* is known and is always smaller than σ:\n\nσ_m = σ / √n\n\nDoubling your confidence in the mean by halving σ_m requires **four times** as many observations (because of the √n).\n\n## Error propagation\n\nWhen a result is computed from several measured quantities, their individual random errors **combine in quadrature** (root-sum-square), not by simple addition, because random errors partly cancel:\n\n- **Sum/difference of independent quantities:** E = √(E₁² + E₂² + … )\n- **Series of n equal, independent errors** (e.g., n equal tape lengths each ±e): E = e·√n\n- **Product** such as area A = a·b: σ_A = √((b·σ_a)² + (a·σ_b)²)\n\n## Probability and the normal curve\n\nRandom errors follow the **normal (Gaussian) distribution**. The empirical **68-95-99.7 rule** states that about **68.3%** of observations fall within ±1σ of the mean, **95.4%** within ±2σ, and **99.7%** within ±3σ. The **probable error (E₅₀ = 0.6745σ)** is the bound containing 50% of errors. **Weights** are assigned inversely to variance, w ∝ 1/σ², so a more precise measurement (smaller σ) pulls the **weighted mean** more strongly."},{"type":"formulas","title":"Essential Formulas","content":"## From the NCEES FS Reference Handbook (Probability & Statistics)\n\n**Mean (most probable value):**\n\nx̄ = Σxᵢ / n\n\n**Residual:** vᵢ = xᵢ − x̄\n\n**Sample standard deviation:**\n\nσ = √( Σ(xᵢ − x̄)² / (n − 1) ) = √( Σv² / (n − 1) )\n\n**Standard error of the mean:**\n\nσ_m = σ / √n\n\n## Error propagation (handbook A17)\n\n<table border=\"1\" cellpadding=\"6\">\n<tr><th>Case</th><th>Formula</th></tr>\n<tr><td>Sum of independent errors</td><td>E_sum = √(E₁² + E₂² + … + Eₙ²)</td></tr>\n<tr><td>Series of n equal errors</td><td>E_series = E·√n</td></tr>\n<tr><td>Error in the mean</td><td>E_mean = E / √n</td></tr>\n<tr><td>Product A = a·b</td><td>σ_A = √((b·σ_a)² + (a·σ_b)²)</td></tr>\n</table>\n\n## Weighting & weighted mean\n\nWeight inversely proportional to variance: **wᵢ ∝ 1/σᵢ²**\n\nWeighted mean: **x̄_w = Σ(wᵢ·xᵢ) / Σwᵢ**\n\n## Relative precision (accuracy ratio)\n\nExpressed as 1:N, reduced so the numerator is 1:\n\n**Relative precision = 1 : (distance / error)**  →  e.g. error 0.08 ft over 800 ft = 1:10,000\n\n## Probability bounds (normal curve)\n\n<table border=\"1\" cellpadding=\"6\">\n<tr><th>Bound</th><th>Multiplier on σ</th><th>% of observations</th></tr>\n<tr><td>Probable error E₅₀</td><td>0.6745σ</td><td>50%</td></tr>\n<tr><td>1σ</td><td>1.000σ</td><td>68.3%</td></tr>\n<tr><td>90% (E₉₀)</td><td>1.6449σ</td><td>90%</td></tr>\n<tr><td>2σ (95.4%)</td><td>2.000σ</td><td>95.4%</td></tr>\n<tr><td>95% (E₉₅)</td><td>1.9600σ</td><td>95%</td></tr>\n<tr><td>3σ</td><td>3.000σ</td><td>99.7%</td></tr>\n</table>\n\n## Useful unit conversions (handbook A1)\n\n<ul>\n<li>1 chain = 100 links = 66 ft = 4 rods/poles/perches</li>\n<li>1 mile = 80 chains = 5,280 ft</li>\n<li>1 acre = 10 sq chains = 43,560 ft²</li>\n<li>1 US survey ft = 0.3048006096 m  (1 m = 3.2808333333 US ft)</li>\n<li>1 international ft = 0.3048 m exactly  (1 in = 25.4 mm exactly)</li>\n<li>1 rad = 180°/π ≈ 57.2957795°</li>\n</ul>"},{"type":"examples","title":"Worked Examples","content":"## Example 1 — Mean, standard deviation, and standard error of the mean\n\nA distance is measured 10 times (ft): 215.86, 215.80, 215.78, 215.84, 215.84, 215.83, 215.82, 215.86, 215.86, 215.81. Find the most probable value, the standard deviation, and the standard error of the mean.\n\n**Step 1 — Mean (MPV).** Σx = 2158.30, n = 10 → x̄ = 2158.30/10 = **215.830 ft**.\n\n**Step 2 — Residuals & Σv².** v = x − 215.830. Squaring and summing gives Σv² = 0.006600 ft².\n\n**Step 3 — Standard deviation.**\n\nσ = √(Σv²/(n−1)) = √(0.006600/9) = √0.0007333 = **±0.027 ft** (matches practice-exam Q6).\n\n**Step 4 — Standard error of the mean.**\n\nσ_m = σ/√n = 0.027/√10 = 0.027/3.1623 = **±0.0086 ft**.\n\n**Calculator — TI-36X Pro (stat mode):** press `data`, enter all ten values in L1, `2nd [data]` (stat) → `1-Var Stats`, select L1, `calc`. Read **x̄ = 215.83** and **Sx = 0.0271** (Sx is the sample σ; the screen also shows σx, the population value — use **Sx** for n−1). Then σ_m = Sx ÷ √10.\n\n**Calculator — Casio fx-991EX (ClassWiz):** `MENU` → `6 Statistics` → `1 (1-Variable)`, type the ten values, `AC`, then `OPTN` → `2 1-Variable Calc`. Read **x̄** and **sx** (sample std dev). HP-35S: enter values with `Σ+`, then `s` for sample std dev.\n\n## Example 2 — Error propagation of a sum (taping a line in segments)\n\nA line is taped in 6 equal segments; each segment''s length has a random error of ±0.010 ft. What is the expected error in the total length?\n\n**Series of n equal errors:** E = e·√n = 0.010·√6 = 0.010·2.449 = **±0.0245 ft ≈ ±0.024 ft.**\n\nNote it is **not** 6 × 0.010 = 0.060 ft — random errors partly cancel, so they add in quadrature. Equivalently E = √(0.010² × 6).\n\n**Calculator — TI-36X Pro:** `0.010 × √6 =` → 0.02449. (For unequal errors use √(e1²+e2²+…): square each, sum, `√`.)\n\n## Example 3 — Error propagation of a product (area of a lot)\n\nA rectangular lot measures 120.00 ± 0.04 ft by 144.00 ± 0.05 ft. State the area and its uncertainty.\n\n**Area:** A = 120.00 × 144.00 = 17,280 ft².\n\n**Propagation (product):** σ_A = √((b·σ_a)² + (a·σ_b)²) = √((144·0.04)² + (120·0.05)²) = √(5.76² + 6.00²) = √(33.18 + 36.00) = √69.18 = **±8.3 ft².**\n\nSo **A = 17,280 ± 8.3 ft²** (matches practice-exam Q2, choice B).\n\n**Calculator — TI-36X Pro:** compute `144×0.04 = 5.76` `[STO→ x]`, `120×0.05 = 6`, then `√(5.76² + 6²)` = 8.31.\n\n## Example 4 — Relative precision\n\nA traverse with perimeter 2,640 ft closes with a linear misclosure of 0.22 ft. Express the relative precision.\n\nRelative precision = misclosure / perimeter = 0.22 / 2640 = 1/12,000. **Report as 1:12,000** (always reduce numerator to 1: divide perimeter by misclosure → 2640/0.22 = 12,000).\n\n## Example 5 — Weighted mean of redundant length measurements\n\nA distance is measured three ways: tape 297.426 m (σ = ±0.070), EDM 297.155 m (σ = ±0.015), total-station inverse 297.209 m (σ = ±0.048). Find the most probable length.\n\n**Step 1 — Weights ∝ 1/σ².** w_tape = 1/0.070² = 204.1; w_EDM = 1/0.015² = 4444.4; w_inv = 1/0.048² = 434.0.\n\n**Step 2 — Weighted mean.**\n\nx̄_w = Σ(w·x)/Σw = (204.1·297.426 + 4444.4·297.155 + 434.0·297.209) / (204.1 + 4444.4 + 434.0)\n= (60,704.7 + 1,320,684.4 + 128,988.7) / 5082.5 = 1,510,377.8 / 5082.5 = **297.168 m.**\n\nThe high-precision EDM (smallest σ → largest weight) dominates, pulling the answer toward 297.155 m.\n\n**Calculator — TI-36X Pro (weighted stat):** in stat mode use the two-column (FRQ) layout — enter values in L1 and weights in L2, run `1-Var Stats` with **FRQ = L2**; the reported x̄ is the weighted mean.\n\n## Example 6 — The 68-95-99.7 rule\n\nAngles are observed with σ = 4″. Within what symmetric bound do 95.4% of observations fall? That is ±2σ = ±8″. About 68.3% fall within ±4″ (±1σ); 99.7% within ±12″ (±3σ)."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Exam strategy for this area\n\n- **These are fast points.** Stats and unit questions are usually one- or two-step. Bank them early; flag-and-skip long COGO problems. Budget ~2.9 min/question overall, but most of these take under a minute.\n- **Read the n−1 vs n choice carefully.** \"Standard deviation of the *set/observations*\" → use sample σ (n−1). The exam''s distractors almost always include the population value (÷n). On your calculator that is **Sx (TI) / sx (Casio)** for n−1 and **σx / xσn** for n.\n- **Standard error of the mean has the extra √n.** If a question asks how well the *mean* is known (vs a single observation), divide by √n. Forgetting this is the #1 trap.\n- **Errors add in quadrature, not linearly.** For a sum or a series, root-sum-square. If you see a clean linear sum among the choices, it is the distractor.\n- **Relative precision is reported 1:N.** Divide the distance by the error and round to a \"nice\" denominator (1:5,000, 1:10,000…).\n- **Watch the foot.** US survey foot (0.3048006096 m) vs international foot (0.3048 m exactly) differ by 2 ppm — on a state-plane coordinate that is feet of difference. The exam mixes SI and USCS; confirm units before keying.\n\n## Approved-calculator tricks (NCEES 2026 list)\n\nApproved: **TI-30X / TI-36X** (all), **Casio fx-115 / fx-991** (all), **HP 33s / 35s** only. No programmable/graphing/CAS models.\n\n- **TI-36X Pro stats:** `data` to enter L1 (and L2 for frequencies/weights), `2nd [data]` → `1-Var Stats`. Read **x̄** (mean) and **Sx** (sample σ, n−1). Compute σ_m = Sx ÷ √n by hand.\n- **Casio fx-991EX:** `MENU 6` Statistics → `1-Variable`; turn on the FREQ column via `SHIFT MENU (SETUP) → Statistics → Frequency On` to do weighted means. `OPTN → 1-Variable Calc` shows x̄ and **sx**.\n- **HP-35S:** enter each value `Σ+`; recall **x̄** with `[x̄,ŷ]`, sample std dev with `[s]`. RPN chaining is handy but optional here.\n- **Root-sum-square fast path:** `√( a x² + b x² + … )` — use the `x²` key on each term, sum, then `√`. Store an intermediate with `STO` to avoid re-keying.\n- **DMS for angle-error problems:** keep the calculator in degree mode and use the `°’”` (DMS) key so angular σ values combine correctly.\n\n## Common traps\n\n- Applying statistics to data that still contains a **blunder** (find/remove it first) or an uncorrected **systematic** error (model it first).\n- Confusing **accuracy** (closeness to truth) with **precision** (repeatability).\n- Using **n** instead of **n−1** in σ.\n- Adding tolerances linearly instead of in quadrature.\n- Reporting more **significant figures** than the measurement justifies — carry full precision through intermediate steps, round only at the end.\n\n## How the handbook helps\n\nThe FS Reference Handbook''s **Probability and Statistics** section gives σ = √(Σv²/(n−1)), the propagation formulas (sum, series, product, mean), weighted-mean relation w ∝ 1/σ², and the **Z-value / unit-normal table** (90% → 1.6449, 95% → 1.9600). Know *where* these live so you can confirm a formula in seconds rather than deriving it. The **Conversions** section up front has every unit factor you need — bookmark both pages mentally before exam day."}]'::jsonb, NULL, 70, 30, '📐', 400, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb015000-0000-0000-0000-000000000001', 'Standard error of the mean from n observations', 'Standard error of the mean from n observations', 'FS — Applied Mathematics and Statistics', 'Error analysis', 'numeric_input', 'medium', 'A distance is measured {{n}} times. The standard deviation of a single observation is σ = {{sigma:f3}} ft. Compute the standard error of the mean (ft).', 'sigma/sqrt(n)', '{"decimals":4,"unit":"ft","tolerance":0.0005}', '[{"name":"n","type":"integer","min":4,"max":36},{"name":"sigma","type":"float","min":0.01,"max":0.09,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply σ_m = σ/√n","calculation_template":"σ_m = {{sigma:f3}} / √{{n}}"},{"step_number":2,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The standard error of the mean is σ_m = σ/√n = {{sigma:f3}}/√{{n}} = {{_answer}} ft. It is always smaller than the single-observation σ by the factor √n.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');
  'fb015000-0000-0000-0000-000000000002', 'Error propagation — series of n equal errors', 'Error propagation — series of n equal errors', 'FS — Applied Mathematics and Statistics', 'Error propagation', 'numeric_input', 'medium', 'A line is taped in {{n}} equal segments. Each segment carries an independent random error of ±{{e:f3}} ft. Compute the expected random error in the total length (ft).', 'e*sqrt(n)', '{"decimals":4,"unit":"ft","tolerance":0.0005}', '[{"name":"n","type":"integer","min":3,"max":16},{"name":"e","type":"float","min":0.005,"max":0.03,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Series rule E = e·√n","calculation_template":"E = {{e:f3}} × √{{n}}"},{"step_number":2,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'For n equal independent errors, they combine in quadrature: E = e·√n = {{e:f3}}·√{{n}} = {{_answer}} ft. This is NOT the linear sum n·e.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');
  'fb015000-0000-0000-0000-000000000003', 'Error propagation — sum of three independent errors', 'Error propagation — sum of three independent errors', 'FS — Applied Mathematics and Statistics', 'Error propagation', 'numeric_input', 'medium', 'Three independent distances are added end to end. Their standard errors are ±{{e1:f3}} ft, ±{{e2:f3}} ft, and ±{{e3:f3}} ft. Compute the standard error of the total distance (ft).', 'sqrt(e1*e1 + e2*e2 + e3*e3)', '{"decimals":4,"unit":"ft","tolerance":0.0005}', '[{"name":"e1","type":"float","min":0.01,"max":0.06,"decimals":3},{"name":"e2","type":"float","min":0.01,"max":0.06,"decimals":3},{"name":"e3","type":"float","min":0.01,"max":0.06,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Root-sum-square","calculation_template":"E = √({{e1:f3}}² + {{e2:f3}}² + {{e3:f3}}²)"},{"step_number":2,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'For a sum of independent quantities, errors add in quadrature: E = √(e1²+e2²+e3²) = {{_answer}} ft.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');
  'fb015000-0000-0000-0000-000000000004', 'Relative precision of a traverse', 'Relative precision of a traverse', 'FS — Survey Computations', 'Traverse', 'numeric_input', 'easy', 'A traverse has a perimeter of {{perimeter:f2}} ft and a linear misclosure of {{misclosure:f3}} ft. Express the relative precision as 1:N — report N (rounded to the nearest whole number).', 'round(perimeter/misclosure,0)', '{"decimals":0,"unit":"","tolerance":1}', '[{"name":"perimeter","type":"float","min":1500,"max":5000,"decimals":2},{"name":"misclosure","type":"float","min":0.1,"max":0.6,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Divide perimeter by misclosure","calculation_template":"N = {{perimeter:f2}} / {{misclosure:f3}}"},{"step_number":2,"title":"Result","result_template":"1:{{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'Relative precision = misclosure/perimeter reduced to a unit numerator: N = perimeter/misclosure = {{perimeter:f2}}/{{misclosure:f3}} = {{_answer}}, reported as 1:{{_answer}}.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');
  'fb015000-0000-0000-0000-000000000005', 'Sample standard deviation from residual sum', 'Sample standard deviation from residual sum', 'FS — Applied Mathematics and Statistics', 'Statistics', 'numeric_input', 'medium', 'A quantity is observed {{n}} times. The sum of the squared residuals about the mean is Σv² = {{sv2:f4}}. Compute the sample standard deviation σ = √(Σv²/(n−1)).', 'sqrt(sv2/(n-1))', '{"decimals":4,"unit":"","tolerance":0.0005}', '[{"name":"n","type":"integer","min":5,"max":15},{"name":"sv2","type":"float","min":0.004,"max":0.02,"decimals":4}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Divide by degrees of freedom (n−1)","calculation_template":"{{sv2:f4}} / ({{n}} − 1)"},{"step_number":2,"title":"Take the square root","result_template":"σ = {{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'σ = √(Σv²/(n−1)) = √({{sv2:f4}}/({{n}}−1)) = {{_answer}}. Use n−1 (degrees of freedom) because the mean consumed one degree of freedom.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');
  'fb015000-0000-0000-0000-000000000006', 'Weighted mean of two measurements', 'Weighted mean of two measurements', 'FS — Applied Mathematics and Statistics', 'Weighted observations', 'numeric_input', 'hard', 'A distance is measured two ways: method 1 gives {{m1:f3}} ft with σ₁ = ±{{s1:f3}} ft; method 2 gives {{m2:f3}} ft with σ₂ = ±{{s2:f3}} ft. Compute the weighted mean (ft), using weights ∝ 1/σ².', '(w1*m1 + w2*m2)/(w1+w2)', '{"decimals":3,"unit":"ft","tolerance":0.005}', '[{"name":"m1","type":"float","min":250,"max":350,"decimals":3},{"name":"d","type":"float","min":0.05,"max":0.4,"decimals":3},{"name":"s1","type":"float","min":0.02,"max":0.08,"decimals":3},{"name":"s2","type":"float","min":0.008,"max":0.03,"decimals":3}]'::jsonb, '[{"name":"m2","formula":"m1+d"},{"name":"w1","formula":"1/(s1*s1)"},{"name":"w2","formula":"1/(s2*s2)"}]'::jsonb, '[{"step_number":1,"title":"Weights ∝ 1/σ²","calculation_template":"w1 = 1/{{s1:f3}}², w2 = 1/{{s2:f3}}²"},{"step_number":2,"title":"Weighted mean","calculation_template":"(w1·{{m1:f3}} + w2·{{m2:f3}})/(w1+w2)"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Weights are inverse variances: w1 = 1/σ₁², w2 = 1/σ₂². The weighted mean = Σ(w·x)/Σw = {{_answer}} ft, pulled toward the more precise (smaller-σ) measurement.', 'f5000001-0000-0000-0000-000000000001', 'FS', ARRAY['fs-buildout','fs-m1','fs-practice']::text[], NULL, true, 'fs:m1');

-- ===== FS Module 2: Leveling =====
DELETE FROM question_bank WHERE module_id='f5000002-0000-0000-0000-000000000002' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m2' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m2';
VALUES ('f5000002-0000-0000-0000-000000000002', 2, 'Leveling', 'Differential leveling by the height-of-instrument (HI) method, profile and trigonometric leveling, curvature & refraction, collimation/two-peg testing, and loop misclosure adjustment for vertical control. Covers the field data and computations an FS examinee must perform from benchmarks and datums.', 'Weeks 3-4', 12, ARRAY['Differential leveling (HI method)','Benchmarks, turning points, and datums (NAVD88)','Backsight / foresight bookkeeping and the arithmetic check','Profile and reciprocal leveling','Trigonometric leveling (Δelev = S·sin V = d·tan V)','Curvature and refraction correction','Collimation error and the two-peg test','Loop misclosure and adjustment / closure tolerances','Three-wire leveling']::text[], '[{"name":"Height of instrument","formula":"HI = Elev_BM + BS"},{"name":"Point elevation","formula":"Elev = HI − FS"},{"name":"Elevation difference (multi-setup)","formula":"ΔElev = ΣBS − ΣFS"},{"name":"Arithmetic check","formula":"Elev_last − Elev_first = ΣBS − ΣFS"},{"name":"Curvature & refraction (rod)","formula":"C_R = 0.0206·F²   (F in thousands of ft)"},{"name":"Curvature only (rod)","formula":"C = 0.0240·F²   (F in thousands of ft)"},{"name":"Trigonometric leveling","formula":"ΔElev = S·sin(V) = d·tan(V)  (+ hi − hr)"},{"name":"Loop misclosure","formula":"Misclosure = (ΣBS − ΣFS) − (Elev_known_end − Elev_known_start)"},{"name":"Reciprocal leveling Δh","formula":"Δh = ½[(a₁ − b₁) + (a₂ − b₂)]"},{"name":"Three-wire mean reading","formula":"Reading = (Upper + Middle + Lower)/3"},{"name":"Collimation correction","formula":"ΔC = (collimation rate)·(BS dist − FS dist)"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Leveling — the backbone of vertical control\n\n**Leveling** is the field operation that determines **elevations** of points relative to a **datum**. On the FS exam, leveling lives in Knowledge Area 5C (Survey Computations) with strong overlap into Area 1 (field procedures) and Area 7 (error/closure). Expect a handful of direct computational items: read a level note and find an elevation, compute a curvature-and-refraction correction, reduce a trigonometric-leveling sight, or distribute a loop misclosure.\n\nThe dominant field technique is **differential leveling** using the **height-of-instrument (HI) method**. A level set up between two points reads a **backsight (BS)** on a point of known elevation (a benchmark or turning point) and a **foresight (FS)** on the next point. Adding the BS to the known elevation gives the line-of-sight elevation, the **HI**; subtracting a FS from the HI gives the new point''s elevation. Repeating this from setup to setup carries elevation across long distances.\n\nThree relationships are non-negotiable: **HI = Elev + BS**, **Elev = HI − FS**, and the running check **ΣBS − ΣFS = Elev_last − Elev_first**. Beyond the bookkeeping you must handle systematic effects — **earth curvature and atmospheric refraction**, **instrument collimation** (line-of-sight not level, found by the **two-peg test**) — and quality control through **loop misclosure** against a known datum, then adjusting the observed elevations.\n\nThis module also covers **profile leveling** (elevations along a route for cross-sections and grades), **trigonometric leveling** (elevation from a slope distance and vertical angle), **reciprocal leveling** across obstacles, and **three-wire leveling** for higher precision. Datums you will see named: **NAVD88** (the current US vertical datum) and the older **NGVD29**; elevations are **orthometric heights (H)**, related to GPS ellipsoid heights by H = h − N."},{"type":"concepts","title":"Key Concepts","content":"## Datums, benchmarks, and the vertical reference\n\nA **datum** is the reference surface from which elevations are measured; in modern US practice that is the **geoid**, realized as **NAVD88**. A **benchmark (BM)** is a permanently monumented point of published, known elevation. A **turning point (TP)** is a temporary, well-defined point (e.g., a turning plate) used to transfer the line of sight from one instrument setup to the next; the rod is held on the same TP for the FS of one setup and the BS of the next.\n\n## Backsight, foresight, and the HI method\n\n- **Backsight (BS)** — also called a **plus sight (+)**. A rod reading taken on a point of *known* elevation. **HI = Elev + BS.**\n- **Foresight (FS)** — also called a **minus sight (−)**. A rod reading on a point whose elevation you are *determining*. **Elev = HI − FS.**\n- The **HI (height of instrument)** here is the *elevation of the line of sight*, not the height of the telescope above the ground.\n\n<table border=\"1\" cellpadding=\"4\">\n<tr><th>Station</th><th>BS (+)</th><th>HI</th><th>FS (−)</th><th>Elevation</th></tr>\n<tr><td>BM-A</td><td>3.21</td><td>503.21</td><td></td><td>500.00</td></tr>\n<tr><td>TP1</td><td>4.05</td><td>505.10</td><td>2.16</td><td>501.05</td></tr>\n<tr><td>BM-B</td><td></td><td></td><td>1.74</td><td>503.36</td></tr>\n</table>\n\n**Arithmetic check:** ΣBS = 3.21 + 4.05 = 7.26; ΣFS = 2.16 + 1.74 = 3.90; ΣBS − ΣFS = 3.36 = Elev_B − Elev_A = 503.36 − 500.00. The check confirms the *bookkeeping* (not blunders in the field).\n\n## Curvature and refraction\n\nOver a long sight the earth curves away from the level line of sight (**curvature**, makes rod readings read **too high**), and the line of sight bends downward through the atmosphere (**refraction**, partly offsetting curvature). Net, for rod readings in feet with the sight distance **F expressed in thousands of feet**:\n\n- Curvature only: **C = 0.0240·F²** ft\n- Combined curvature & refraction: **C_R = 0.0206·F²** ft\n\nBalancing BS and FS distances **cancels** curvature & refraction in differential leveling — a key reason to keep sight distances equal.\n\n## Collimation error and the two-peg test\n\n**Collimation error** is a line of sight that is not truly horizontal when the bubble is centered. The **two-peg test** detects it: set two pegs A and B a known distance apart; from the midpoint, equal sight distances cancel any collimation and give the *true* ΔElev; then set up near one peg (unequal distances) and re-read — the discrepancy is the collimation error per unit of distance difference. In differential leveling the residual collimation effect is **(collimation rate)·(ΣBS dist − ΣFS dist)**, again zeroed by balancing sights.\n\n## Trigonometric leveling\n\nWhen a slope distance **S** (or horizontal distance **d**) and a **vertical angle V** (above horizontal) are measured, the elevation difference is **ΔElev = S·sin V = d·tan V**, adjusted for instrument height (hi) and rod/target height (hr): ΔElev = S·sin V + hi − hr. For long sights add the C_R correction. (Note: if a **zenith angle z** is measured instead, ΔElev = S·cos z.)\n\n## Loop misclosure and adjustment\n\nA level **loop** returns to a benchmark of known elevation (or closes back on the start). The **misclosure** = observed (ΣBS − ΣFS) minus the known elevation difference. If within tolerance, distribute the correction in proportion to **distance leveled** (or number of setups). Federal/typical order-of-accuracy tolerances scale with √(distance): e.g., third-order ≈ 0.05·√(miles) ft. **Reciprocal leveling** (reading both ends from each bank) cancels curvature/refraction and collimation across rivers/canyons; **three-wire leveling** averages upper/middle/lower crosshair readings for precision and a built-in check."},{"type":"formulas","title":"Essential Formulas","content":"## Differential leveling (HI method)\n\n- **Height of instrument:** HI = Elev_BM + BS\n- **Point elevation:** Elev = HI − FS\n- **Net elevation change (multi-setup):** ΔElev = ΣBS − ΣFS\n- **Arithmetic (page) check:** Elev_last − Elev_first = ΣBS − ΣFS\n\n## Curvature & refraction (rod readings, USCS)\n\nWith sight distance **F in thousands of feet**:\n\n- Curvature only: **C = 0.0240·F²** ft\n- Curvature + refraction: **C_R = 0.0206·F²** ft\n- (Metric, K in km: C = 0.0785·K² m; C_R = 0.0675·K² m)\n- Vertical-angle form (handbook): c ≈ 4.905″/1000 ft; (c & r) ≈ 4.244″/1000 ft\n\n## Trigonometric leveling\n\n- **ΔElev = S·sin(V) = d·tan(V)**  (V = vertical angle above horizontal)\n- With instrument/rod heights: **ΔElev = S·sin(V) + hi − hr**\n- Zenith-angle form: ΔElev = S·cos(z)\n- New elevation: Elev_B = Elev_A + ΔElev\n\n## Loop / line misclosure & adjustment\n\n- **Misclosure** = (ΣBS − ΣFS)_observed − (Elev_known_end − Elev_known_start)\n- **Correction at a point** = −Misclosure × (distance to point / total distance)\n- Closure tolerance (typical 3rd order): allowable = 0.05·√(M) ft, M = miles leveled\n\n## Reciprocal & three-wire leveling\n\n- **Reciprocal Δh:** Δh = ½[(a₁ − b₁) + (a₂ − b₂)]\n- **Three-wire mean reading:** R = (Upper + Middle + Lower)/3; half-interval check: (U − M) ≈ (M − L)\n- **Stadia interval → distance:** D ≈ 100·(U − L)\n\n## Collimation\n\n- **Collimation correction:** ΔC = e·(ΣBS dist − ΣFS dist), where e = collimation rate (ft of error per ft of sight, e.g., 0.012/100)\n\n## Orthometric vs ellipsoid height\n\n- **H = h − N** (H orthometric/leveled elevation, h GPS ellipsoid height, N geoid height)"},{"type":"examples","title":"Worked Examples","content":"## Example 1 — HI and a point elevation (HI method)\n\n**Given:** BM-A elevation 642.18 ft. The level reads a backsight of **5.42 ft** on BM-A, then a foresight of **7.91 ft** on point P.\n\n**Solve:**\n1. HI = Elev_BM + BS = 642.18 + 5.42 = **647.60 ft**\n2. Elev_P = HI − FS = 647.60 − 7.91 = **639.69 ft**\n\n**Calculator (TI-36X Pro / Casio fx-991):** plain arithmetic — `642.18 + 5.42 =` gives HI, then `Ans − 7.91 =` gives Elev_P. Sanity check: FS > BS, so P is lower than BM-A (639.69 < 642.18). ✓\n\n## Example 2 — Multi-setup elevation and arithmetic check\n\n**Given:** Run from BM-12 (Elev 1004.55 ft) over two turning points to BM-13.\n\n<table border=\"1\" cellpadding=\"4\">\n<tr><th>Station</th><th>BS</th><th>FS</th></tr>\n<tr><td>BM-12</td><td>2.10</td><td></td></tr>\n<tr><td>TP1</td><td>6.34</td><td>1.55</td></tr>\n<tr><td>TP2</td><td>3.02</td><td>8.71</td></tr>\n<tr><td>BM-13</td><td></td><td>4.18</td></tr>\n</table>\n\n**Solve:**\n1. ΣBS = 2.10 + 6.34 + 3.02 = **11.46**; ΣFS = 1.55 + 8.71 + 4.18 = **14.44**\n2. ΔElev = ΣBS − ΣFS = 11.46 − 14.44 = **−2.98 ft**\n3. Elev_BM-13 = 1004.55 + (−2.98) = **1001.57 ft**\n4. **Arithmetic check:** Elev_last − Elev_first = 1001.57 − 1004.55 = −2.98 = ΣBS − ΣFS ✓\n\n**Calculator:** store ΣBS and ΣFS, subtract, add to start. Keep BS and FS columns aligned so you never mix a plus sight with a minus sight.\n\n## Example 3 — Curvature & refraction\n\n**Given:** A single sight of **2,800 ft**. Find the combined curvature-and-refraction correction to the rod reading.\n\n**Solve:** F = 2800/1000 = **2.8** (thousands of ft).\nC_R = 0.0206·F² = 0.0206 × 2.8² = 0.0206 × 7.84 = **0.1615 ft** (read too high; subtract from the rod reading).\n\nCurvature alone would be 0.0240 × 7.84 = 0.188 ft; refraction recovers ≈ 0.027 ft. **Calculator:** `2.8 x² × 0.0206 =`. Note balancing BS = FS distances cancels this entirely.\n\n## Example 4 — Trigonometric leveling\n\n**Given:** From station A (Elev 500.00 ft) a total station measures to a prism at B: horizontal distance **d = 620.0 ft**, vertical angle **V = +3°45′00″** above horizontal, instrument height hi = 5.30 ft, prism height hr = 5.30 ft (equal).\n\n**Solve:**\n1. Convert angle: 3°45′ = 3.75°. `3` `°’”` `45` `°’”` `=` on TI-36X gives 3.75°.\n2. ΔElev = d·tan(V) = 620.0 × tan(3.75°) = 620.0 × 0.065543 = **40.64 ft**\n3. Add hi − hr = 0, so Elev_B = 500.00 + 40.64 = **540.64 ft**\n\n**Check with slope form:** S = d/cos V = 620.0/0.99786 = 621.3 ft; ΔElev = S·sin V = 621.3 × 0.065399 = 40.63 ft ✓ (rounding). **Calculator:** put the calculator in DEG mode; for a zenith angle z use `S × cos(z)` instead.\n\n## Example 5 — Loop misclosure & adjustment\n\n**Given:** A level loop starts on BM-100 (Elev 250.000 ft) and is run through field points back to **BM-101 (published Elev 263.420 ft)**. The notes give ΣBS = 41.275 ft and ΣFS = 27.810 ft over **0.80 miles**.\n\n**Solve:**\n1. Observed ΔElev = ΣBS − ΣFS = 41.275 − 27.810 = **13.465 ft** → observed Elev_BM-101 = 250.000 + 13.465 = 263.465 ft\n2. Misclosure = observed − known = 263.465 − 263.420 = **+0.045 ft**\n3. Allowable (3rd order) = 0.05·√0.80 = 0.05 × 0.894 = 0.045 ft → **just within tolerance**\n4. Distribute −0.045 ft across the run in proportion to distance; the corrected closing elevation becomes the published **263.420 ft**.\n\n**Calculator:** `0.05 × 0.80 √ =` for the tolerance; sign of the misclosure tells you which way to push the elevations."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Strategy for leveling items\n\n- **Memorize the three core relations** so you never look them up: **HI = Elev + BS**, **Elev = HI − FS**, **ΣBS − ΣFS = ΔElev**. These solve the majority of leveling questions in seconds.\n- **BS is always a plus, FS is always a minus.** The single most common trap is swapping them. Write a tiny two-column BS/FS table in the margin even for a one-setup problem.\n- **Always run the arithmetic check** (ΣBS − ΣFS = last − first). If it fails, you mis-added a column — fix it before trusting the elevation.\n- **Watch the units of F in curvature & refraction.** The handbook constants 0.0240 and 0.0206 assume **F in *thousands* of feet**. A 3,000-ft sight is F = 3, not 3000. Forgetting this inflates the answer by 10⁶.\n- **Curvature reads the rod too HIGH; refraction lowers the apparent reading.** Net C_R = 0.0206·F² is *subtracted* from a long FS. Balancing BS and FS distances cancels both — a frequent \"why do we keep sights equal?\" concept question.\n- **Trig leveling:** confirm whether the angle is a **vertical angle** (from horizontal → use sin/tan) or a **zenith angle** (from vertical → use cos). Add hi, subtract hr. Put the calculator in **DEG** mode.\n- **Misclosure sign:** misclosure = observed − known. Corrections have the *opposite* sign and are spread by **distance or setup count**.\n\n## Approved-calculator tricks (TI-36X Pro / Casio fx-991 / HP 33s-35s)\n\n- **DMS entry:** TI-36X Pro — type the degrees, `°’”`, minutes, `°’”`, seconds, `°’”`, then `=`; Casio fx-991 uses the `°’”` key the same way. This converts 3°45′ to 3.75° for the tan() call. HP 35s: enter `3.4500` then `→HR`.\n- **Chaining a level run:** store ΣBS in memory A and ΣFS in memory B as you add the columns, then `RCL A − RCL B` for ΔElev — avoids re-keying.\n- **C_R fast path:** `(F) x² × 0.0206 =`. Keep F in thousands of feet.\n- **Reciprocal leveling:** compute Δh = ½[(a₁−b₁)+(a₂−b₂)] directly; the averaging cancels curvature/refraction and collimation.\n- **Three-wire:** mean = (U+M+L)/3 and check that (U−M) ≈ (M−L); distance ≈ 100·(U−L).\n\n## How the FS Reference Handbook helps\n\n- The handbook''s **Curvature and refraction** block gives the 0.0240/0.0206 (ft) and 0.0785/0.0675 (m) constants plus the arc-second forms — search \"curvature\" rather than re-deriving.\n- Leveling bookkeeping (HI, BS, FS) is **not** a boxed formula; you must know it cold. The handbook only supplies the constants and the trig.\n- For trig leveling, use the handbook''s **trigonometry / right-triangle** relations; for tolerances, leveling closure follows the supplied **FGCS Geodetic Leveling** standard logic (allowable ∝ √distance)."}]'::jsonb, 1, 70, 30, '📏', 400, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb025000-0000-0000-0000-000000000001', 'Height of instrument from a benchmark', 'Height of instrument from a benchmark', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'easy', 'A level is set up and reads a backsight of {{bs:f2}} ft on benchmark BM-A, whose elevation is {{elevBM:f2}} ft. Compute the height of instrument (HI), in ft.', 'elevBM + bs', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"elevBM","type":"float","min":100,"max":2000,"decimals":2},{"name":"bs","type":"float","min":0.5,"max":11.5,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"HI = Elev_BM + BS","calculation_template":"HI = {{elevBM:f2}} + {{bs:f2}}"},{"step_number":2,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The backsight is a plus sight added to the known benchmark elevation: HI = {{elevBM:f2}} + {{bs:f2}} = {{_answer}} ft.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], NULL, true, 'fs:m2');
  'fb025000-0000-0000-0000-000000000002', 'Point elevation from HI and foresight', 'Point elevation from HI and foresight', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'easy', 'Benchmark BM-A has elevation {{elevBM:f2}} ft. The level reads a backsight of {{bs:f2}} ft on BM-A, then a foresight of {{fs:f2}} ft on point P. Compute the elevation of point P, in ft.', 'elevBM + bs - fs', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"elevBM","type":"float","min":100,"max":2000,"decimals":2},{"name":"bs","type":"float","min":0.5,"max":11.5,"decimals":2},{"name":"fs","type":"float","min":0.5,"max":11.5,"decimals":2}]'::jsonb, '[{"name":"hi","formula":"elevBM + bs"}]'::jsonb, '[{"step_number":1,"title":"HI = Elev_BM + BS","calculation_template":"HI = {{elevBM:f2}} + {{bs:f2}} = {{hi:f2}} ft"},{"step_number":2,"title":"Elev_P = HI − FS","calculation_template":"Elev_P = {{hi:f2}} − {{fs:f2}}"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'HI = {{elevBM:f2}} + {{bs:f2}} = {{hi:f2}} ft, then Elev_P = HI − FS = {{hi:f2}} − {{fs:f2}} = {{_answer}} ft.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], '{"type":"leveling","bsVar":"bs","fsVar":"fs","title":"Differential leveling: HI − FS"}'::jsonb, true, 'fs:m2');
  'fb025000-0000-0000-0000-000000000003', 'Multi-setup closing elevation (ΣBS − ΣFS)', 'Multi-setup closing elevation (ΣBS − ΣFS)', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'medium', 'A differential level run starts on BM-1 (elevation {{elevBM:f2}} ft). Over the run the sum of backsights is ΣBS = {{sumBS:f2}} ft and the sum of foresights is ΣFS = {{sumFS:f2}} ft. Compute the elevation of the closing point, in ft.', 'elevBM + sumBS - sumFS', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"elevBM","type":"float","min":100,"max":1500,"decimals":2},{"name":"sumBS","type":"float","min":10,"max":40,"decimals":2},{"name":"sumFS","type":"float","min":10,"max":40,"decimals":2}]'::jsonb, '[{"name":"dElev","formula":"sumBS - sumFS"}]'::jsonb, '[{"step_number":1,"title":"Net change = ΣBS − ΣFS","calculation_template":"ΔElev = {{sumBS:f2}} − {{sumFS:f2}} = {{dElev:f2}} ft"},{"step_number":2,"title":"Add to starting elevation","calculation_template":"Elev = {{elevBM:f2}} + ({{dElev:f2}})"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'ΔElev = ΣBS − ΣFS = {{sumBS:f2}} − {{sumFS:f2}} = {{dElev:f2}} ft. Closing elevation = {{elevBM:f2}} + {{dElev:f2}} = {{_answer}} ft.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], NULL, true, 'fs:m2');
  'fb025000-0000-0000-0000-000000000004', 'Curvature & refraction correction', 'Curvature & refraction correction', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'medium', 'A level sight is {{distFt}} ft long. Using the combined curvature-and-refraction relation C_R = 0.0206·F² (F in thousands of feet), compute the correction to the rod reading, in ft.', '0.0206 * pow(distFt/1000, 2)', '{"decimals":3,"unit":"ft","tolerance":0.005}', '[{"name":"distFt","type":"integer","min":1000,"max":6000}]'::jsonb, '[{"name":"F","formula":"distFt/1000"}]'::jsonb, '[{"step_number":1,"title":"Express distance in thousands of feet","calculation_template":"F = {{distFt}} / 1000 = {{F:f2}}"},{"step_number":2,"title":"Apply C_R = 0.0206·F²","calculation_template":"C_R = 0.0206 × ({{F:f2}})²"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'With F = {{distFt}}/1000 = {{F:f2}} thousand ft, C_R = 0.0206·F² = {{_answer}} ft. This correction is subtracted from a long foresight; balancing BS and FS distances cancels it.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], NULL, true, 'fs:m2');
  'fb025000-0000-0000-0000-000000000005', 'Trigonometric leveling — elevation of target', 'Trigonometric leveling — elevation of target', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'medium', 'From station A (elevation {{elevA:f2}} ft) a total station measures a horizontal distance of {{dist:f1}} ft to a prism at a vertical angle of {{vAngle:dms}} above horizontal. Instrument and prism heights are equal. Compute the elevation of the prism point, in ft.', 'elevA + dist * tan(toRad(vAngle))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"elevA","type":"float","min":200,"max":1500,"decimals":2},{"name":"dist","type":"float","min":200,"max":900,"decimals":1},{"name":"vAngle","type":"angle_dms","min":1.5,"max":9.5}]'::jsonb, '[{"name":"dElev","formula":"dist * tan(toRad(vAngle))"}]'::jsonb, '[{"step_number":1,"title":"ΔElev = d·tan(V)","calculation_template":"ΔElev = {{dist:f1}} × tan({{vAngle:dms}}) = {{dElev:f2}} ft"},{"step_number":2,"title":"Add to station elevation (hi = hr)","calculation_template":"Elev = {{elevA:f2}} + {{dElev:f2}}"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft (calc: DEG mode, °’” key for the angle)"}]'::jsonb, '{"method":"none"}'::jsonb, 'With equal instrument and prism heights, ΔElev = d·tan(V) = {{dist:f1}} × tan({{vAngle:dms}}) = {{dElev:f2}} ft, so the prism elevation = {{elevA:f2}} + {{dElev:f2}} = {{_answer}} ft.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], NULL, true, 'fs:m2');
  'fb025000-0000-0000-0000-000000000006', 'Loop misclosure against a known benchmark', 'Loop misclosure against a known benchmark', 'FS — Survey Computations', 'Leveling', 'numeric_input', 'hard', 'A level loop starts on BM-100 (elevation {{elevStart:f3}} ft) and is run to BM-101, whose published elevation is {{elevKnown:f3}} ft. The notes give ΣBS = {{sumBS:f3}} ft and ΣFS = {{sumFS:f3}} ft. Compute the loop misclosure (observed closing elevation − published elevation), in ft.', '(elevStart + sumBS - sumFS) - (elevStart + sumBS - sumFS - misclose)', '{"decimals":3,"unit":"ft","tolerance":0.002}', '[{"name":"elevStart","type":"float","min":200,"max":600,"decimals":3},{"name":"sumBS","type":"float","min":20,"max":50,"decimals":3},{"name":"sumFS","type":"float","min":20,"max":50,"decimals":3},{"name":"misclose","type":"float","min":-0.08,"max":0.08,"decimals":3}]'::jsonb, '[{"name":"obsClose","formula":"elevStart + sumBS - sumFS"},{"name":"elevKnown","formula":"elevStart + sumBS - sumFS - misclose"}]'::jsonb, '[{"step_number":1,"title":"Observed closing elevation","calculation_template":"Elev_obs = {{elevStart:f3}} + {{sumBS:f3}} − {{sumFS:f3}} = {{obsClose:f3}} ft"},{"step_number":2,"title":"Misclosure = observed − published","calculation_template":"Misclosure = {{obsClose:f3}} − {{elevKnown:f3}}"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft (distribute the opposite correction by distance/setups)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Observed closing elevation = {{elevStart:f3}} + ΣBS − ΣFS = {{obsClose:f3}} ft. Misclosure = observed − published = {{obsClose:f3}} − {{elevKnown:f3}} = {{_answer}} ft; the correction (opposite sign) is distributed in proportion to distance leveled.', 'f5000002-0000-0000-0000-000000000002', 'FS', ARRAY['fs-buildout','fs-m2','fs-practice']::text[], NULL, true, 'fs:m2');

-- ===== FS Module 3: Distance and Angle Measurement =====
DELETE FROM question_bank WHERE module_id='f5000003-0000-0000-0000-000000000003' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m3' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m3';
VALUES ('f5000003-0000-0000-0000-000000000003', 3, 'Distance and Angle Measurement', 'Field acquisition of linear and angular data: taping with all standard corrections, EDM and total-station distance measurement, horizontal/vertical/zenith angles, direct-and-reverse observation, bearings vs azimuths, DMS arithmetic, magnetic declination, and the slope-to-horizontal reduction.', 'Weeks 5-6', 15, ARRAY['Taping corrections (temperature, tension/pull, sag, slope, standardization)','EDM principles and instrument-constant + ppm error','Total stations and robotic/reflectorless measurement','Horizontal, vertical, and zenith angles','Direct and reverse (face-left/face-right) observation','Bearings vs azimuths and quadrant conversion','Back-azimuth and back-bearing','DMS arithmetic and DMS↔decimal-degree conversion','Magnetic declination and the magnetic-to-true correction','Slope distance to horizontal distance (H = S·sin Z)']::text[], '[{"name":"Temperature (thermal) tape correction","formula":"Ct = 0.00000645 · (T − 68) · L"},{"name":"Slope (grade) tape correction","formula":"Ch ≈ −h² / (2L)  (subtract from slope length)"},{"name":"Sag correction","formula":"Cs = −w²·L³ / (24·P²)"},{"name":"Tension (pull) correction","formula":"Cp = (P − P0)·L / (A·E)"},{"name":"Horizontal distance from zenith angle","formula":"H = S · sin(Z)"},{"name":"Horizontal distance from vertical angle","formula":"H = S · cos(α)"},{"name":"EDM error (constant + ppm)","formula":"e = a_mm + b_ppm · D(km) · 1000   (mm)"},{"name":"DMS to decimal degrees","formula":"dd = D + M/60 + S/3600"},{"name":"Back-azimuth","formula":"Back-Az = Az ± 180°"},{"name":"True from magnetic (east declination)","formula":"True bearing = Magnetic bearing + East declination"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Field Data Acquisition: Distances and Angles\n\nEvery coordinate, traverse, and boundary computation on the FS exam ultimately rests on two raw field observations: a **distance** and a **direction (angle)**. This module covers how those observations are actually made and, more importantly for the exam, how they are **corrected and reduced** into the clean numbers you later feed into COGO.\n\nYou will work through three eras of distance measurement that the exam still tests:\n\n1. **Taping (chaining)** — and its five systematic corrections: temperature, tension/pull, sag, slope, and standardization. The exam loves a tape-correction problem because it isolates one concept and rewards careful sign handling.\n2. **EDM (electronic distance measurement)** — the phase/pulse principle, the **instrument (additive) constant**, and the **atmospheric ppm** correction tied to temperature and pressure.\n3. **Total stations** — which marry an EDM to an electronic theodolite, plus robotic and reflectorless variants.\n\nOn the angular side you will master **horizontal angles, vertical angles, and zenith angles**, the **direct-and-reverse** (face-left/face-right) procedure that cancels instrumental error, and the conversions that trip up examinees under time pressure: **DMS↔decimal degrees**, **azimuth↔bearing**, **back-azimuth**, and the **magnetic declination** correction for historical (record) bearings.\n\nFinally you will reduce a **slope distance to a horizontal distance** using the zenith angle — the single most common reduction in trigonometric field work: **H = S·sin(Z)**.\n\nBecause the NCEES calculator (TI-36X Pro / Casio fx-991) does DMS entry, DMS arithmetic, and rectangular↔polar conversion natively, this module pairs every worked example with the exact keystrokes so the conversions become reflexive on exam day."},{"type":"concepts","title":"Key Concepts","content":"## 1. Taping and its corrections\n\nA steel tape is standardized (calibrated) at a known **temperature (68°F / 20°C)**, a known **tension (pull)**, and a known **support condition** (fully supported on a flat surface, or supported only at the ends). When field conditions differ, the measured length is systematically wrong and must be corrected. The five standard corrections:\n\n- **Temperature** — steel expands when warm. `Ct = α·(T − Ts)·L` with the coefficient of thermal expansion for steel **α = 0.00000645 / °F** (i.e. 6.45×10⁻⁶ per °F) and standard temperature **Ts = 68°F**. Hot tape reads short (so the correction is positive when T > 68°F for a measured distance).\n- **Tension / pull** — pulling harder than standard stretches the tape: `Cp = (P − P0)·L / (A·E)`, where A = cross-sectional area, E = modulus of elasticity (≈29,000,000 psi for steel).\n- **Sag** — an unsupported tape hangs in a catenary and reads **long**, so the correction is always **negative**: `Cs = −w²·L³ / (24·P²)`, w = weight per foot, P = applied tension.\n- **Slope** — a tape stretched along a slope measures the slope distance, not the horizontal. The reduction `Ch ≈ −h²/(2L)` (h = elevation difference) or exactly `H = S·cos(vertical angle)`.\n- **Standardization** — the tape''s true length differs from its nominal length (e.g. a \"100 ft\" tape is actually 100.012 ft). Add the per-tape-length error proportionally.\n\n**Sign discipline is everything.** Decide whether you are (a) *measuring a distance in the field* or (b) *laying out a distance to set a point* — the sign of every correction flips between the two cases.\n\n## 2. EDM and total stations\n\nAn **EDM** transmits a modulated light/IR wave to a prism (or directly to a surface, *reflectorless*) and infers distance from the phase shift (or pulse time-of-flight). Two errors dominate exam problems:\n\n- **Instrument (additive/zero) constant** — a fixed offset `a` in mm, independent of distance.\n- **Scale / ppm error** — proportional to distance, expressed in **parts per million**. Atmospheric conditions matter: roughly a **10°C** temperature change **or** a **1 in Hg (≈25 mm Hg)** pressure change is about **10 ppm**. Total stated EDM precision is written as **±(a mm + b ppm)**.\n\nA **total station** combines an EDM with an electronic (digital) theodolite and an onboard processor, outputting horizontal angle, zenith angle, and slope distance — and computing H, V, and coordinates internally. **Robotic** total stations track a prism for one-person crews; **reflectorless** units measure to a surface without a prism.\n\n## 3. Angles: horizontal, vertical, zenith\n\n- **Horizontal angle** — measured in the horizontal plane between two directions; the basis of traverse turning angles and angles-to-the-right.\n- **Vertical angle (α)** — measured **up (+) or down (−) from the horizontal** (0° = level).\n- **Zenith angle (Z)** — measured **down from the upward vertical** (zenith). A level sight = **90°**. Relationship: **Z = 90° − α**. Most modern total stations read **zenith** angles.\n\n## 4. Direct and reverse (D&R)\n\nObserving an angle in both telescope positions — **direct (face left / face I)** and **reverse (face right / face II, telescope plunged)** — and **meaning** the two cancels instrumental errors (collimation, horizontal-axis tilt, vertical-circle index). The mean of D&R is the accepted angle; the **2C** (direct + reverse − 360°) checks collimation.\n\n## 5. Directions: azimuths, bearings, declination\n\n- **Azimuth** — clockwise angle from a reference meridian (usually north), **0°–360°**.\n- **Bearing** — acute angle (0°–90°) from north OR south, toward east or west, written as a quadrant call (e.g. **N42°15′E**, **S08°40′W**).\n- **Back-azimuth** = Az ± 180° (use + if Az < 180°, − if Az ≥ 180°). **Back-bearing** = same angle, opposite quadrant letters.\n- **Magnetic declination** — the angle between magnetic north and true (geodetic) north at a place and date. **East declination is added** to a magnetic bearing to get true; **west declination is subtracted**. Converting old magnetic deed calls to true direction (and accounting for *secular change* in declination between two dates) is a classic boundary/retracement question."},{"type":"formulas","title":"Essential Formulas","content":"## Taping corrections (apply to a measured length L)\n\n**Temperature (thermal):**\n\n`Ct = 0.00000645 · (T − 68) · L`   (L, Ct in ft; T in °F; α_steel = 6.45×10⁻⁶/°F)\n\nMetric form: `Ct = 0.0000116 · (T − 20) · L` (T in °C, α = 11.6×10⁻⁶/°C).\n\n**Tension / pull:**\n\n`Cp = (P − P0)·L / (A·E)`   (P, P0 in lb; A in in²; E ≈ 29,000,000 psi for steel)\n\n**Sag (always negative — tape reads long):**\n\n`Cs = − w²·L³ / (24·P²)`   (w = weight per ft; or `Cs = −W²·L/(24·P²)` with total weight W)\n\n**Slope reduction (slope length S → horizontal H):**\n\n`H = S · cos(α)`   (α = vertical angle)  •  `H = S · sin(Z)`   (Z = zenith angle)\n\nApproximate correction: `Ch ≈ − h² / (2L)`   (h = elevation difference over length L)\n\n**Standardization:** `Cstd = (actual tape length − nominal) · (measured / nominal)`\n\n**Corrected length:** `L_corrected = L_measured + Ct + Cp + Cs + Ch + Cstd`\n\n## EDM\n\n**Combined stated error / correction:**\n\n`e(mm) = a_mm + b_ppm · D_km · 1000`   ⇒ for D in km, ppm term in mm = `b · D_km`\n\nEquivalently, for D in meters: `e(mm) = a + b·(D/1,000,000)·... ` — simplest: ppm error (mm) = `b · D(km)`.\n\nAtmospheric rule of thumb: ≈ **10 ppm per 10°C** or per **1 in Hg** pressure difference.\n\n## Angles\n\n`Z = 90° − α`   (zenith ↔ vertical angle)\n\n`2C = (Direct + Reverse) − 360°`   (collimation check; mean angle = (D + (R−180°))/2)\n\n## DMS ↔ decimal degrees\n\n`dd = D + M/60 + S/3600`\n\n`D = trunc(dd)` ; `M = trunc((dd − D)·60)` ; `S = (((dd − D)·60) − M)·60`\n\nTotal seconds: `total\" = D·3600 + M·60 + S`\n\n## Azimuth ↔ bearing (by quadrant of the azimuth)\n\n| Quadrant | Azimuth range | Bearing | Az→Brg | Brg→Az |\n|---|---|---|---|---|\n| I — NE | 0°–90° | N (Az) E | brg = Az | Az = brg |\n| II — SE | 90°–180° | S (180−Az) E | brg = 180 − Az | Az = 180 − brg |\n| III — SW | 180°–270° | S (Az−180) W | brg = Az − 180 | Az = 180 + brg |\n| IV — NW | 270°–360° | N (360−Az) W | brg = 360 − Az | Az = 360 − brg |\n\n**Back-azimuth:** `Back-Az = Az + 180°` (if Az < 180°) or `Az − 180°` (if Az ≥ 180°).\n\n## Magnetic declination\n\n`True = Magnetic + East_declination`  •  `True = Magnetic − West_declination`\n\nSecular change between dates: apply the *difference* in declination to convert an old magnetic call to a present-day true (or current magnetic) direction."},{"type":"examples","title":"Worked Examples","content":"## Example 1 — Temperature tape correction\n\nA line is measured with a steel tape standardized at 68°F as **measured length = 842.60 ft**. The field temperature was **96°F**. What is the corrected horizontal length (tape fully supported, standard tension)?\n\n**Solution.** Use `Ct = 0.00000645·(T − 68)·L`:\n\n`Ct = 0.00000645 × (96 − 68) × 842.60 = 0.00000645 × 28 × 842.60 = +0.152 ft`\n\nThe tape was hot, so it read short; the true distance is longer:\n\n`L_corrected = 842.60 + 0.152 = 842.75 ft`\n\n**TI-36X Pro keystrokes:** `0.00000645 × ( 96 − 68 ) × 842.60 =` → 0.15225. Then `842.60 + 0.15225 =`. (Enter 6.45E-6 with the `×10ⁿ` / `EE` key: `6.45` `×10ⁿ` `(-) 6`.)\n\n**Casio fx-991:** identical; use the `×10ˣ` key for the exponent: `6.45` `×10ˣ` `(−)6`.\n\n---\n\n## Example 2 — Slope distance → horizontal distance (zenith angle)\n\nA total station reads a **slope distance S = 415.270 ft** to a prism with a **zenith angle Z = 87°12′30″**. What is the horizontal distance?\n\n**Solution.** `H = S · sin(Z)`. First get Z into the calculator in DMS:\n\nEnter `87°12′30″` using the DMS key, then `H = 415.270 × sin(Z)`.\n\n`sin(87°12′30″) = sin(87.20833°) = 0.998813`\n\n`H = 415.270 × 0.998813 = 414.777 ft`\n\n**TI-36X Pro keystrokes:** put calc in **DEG** mode. `415.270 × sin( 87 [°’”] 12 [°’”] 30 [°’”] ) =` → 414.777. The `[°’”]` key is `2nd` `[matrix/angle]` → `°’”` (the DMS template). You may also type 87 `°’”` 12 `°’”` 30 `°’”`.\n\n**Casio fx-991:** `415.270 × sin( 87 [°’’’] 12 [°’’’] 30 [°’’’] ) =`. The `°’’’` key enters and displays sexagesimal directly; pressing `=` then `°’’’` toggles a result between decimal and DMS.\n\n*Check with the vertical angle:* α = 90° − 87°12′30″ = 2°47′30″, and `H = S·cos(α) = 415.270 × cos(2.79167°) = 414.777 ft`. ✓\n\n---\n\n## Example 3 — DMS arithmetic and DMS↔decimal\n\n**(a)** Convert **218°43′52″** to decimal degrees.\n\n`dd = 218 + 43/60 + 52/3600 = 218 + 0.716667 + 0.014444 = 218.731111°`\n\n**(b)** Add two angles: **47°38′45″ + 22°51′30″**.\n\nSeconds: 45 + 30 = 75″ → 1′15″. Minutes: 38 + 51 + 1 = 90′ → 1°30′. Degrees: 47 + 22 + 1 = 70°. Result = **70°30′15″**.\n\n**TI-36X Pro:** `47 °’” 38 °’” 45 °’” + 22 °’” 51 °’” 30 °’” =` displays **70°30′15″** directly (the calculator carries the base-60 arithmetic). Press `2nd` `[°’”]` (the `▸DMS`/`▸DD` toggle) to flip the answer to decimal.\n\n**Casio fx-991:** `47°’’’38°’’’45°’’’ + 22°’’’51°’’’30°’’’ =` → `70°30′15″`. Press `°’’’` again to read 70.50416667°.\n\n---\n\n## Example 4 — Azimuth ↔ bearing and back-azimuth\n\nA line has **azimuth 218°43′52″**. Find its bearing and its back-azimuth.\n\n**Bearing:** azimuth is in **Quadrant III (180°–270°, SW)**, so `bearing = Az − 180° = 218°43′52″ − 180° = 38°43′52″`, written **S 38°43′52″ W**.\n\n**Back-azimuth:** Az ≥ 180°, so `Back-Az = 218°43′52″ − 180° = 38°43′52″`.\n\n*(Sanity check: the back-azimuth''s bearing is N 38°43′52″ E — the exact reverse quadrant of S 38°43′52″ W. ✓)*\n\n---\n\n## Example 5 — EDM constant + ppm error\n\nAn EDM is rated **±(2 mm + 2 ppm)**. For a measured distance **D = 1,850 m**, what is the worst-case standard error in mm?\n\n**Solution.** ppm term = `b · D(km) = 2 × 1.850 = 3.70 mm`. Constant term = 2 mm.\n\n`e = a + b·D(km) = 2 + 2(1.850) = 2 + 3.70 = 5.70 mm`\n\nSo the line is good to about **±5.7 mm** (≈ ±0.006 m).\n\n**Calculator:** trivial — `2 + 2 × 1.850 =`. The trap is unit handling: convert D to **km** before multiplying by the ppm figure (2 ppm of 1,850,000 mm = 3.7 mm).\n\n---\n\n## Example 6 — Magnetic declination (retracement)\n\nAn 1885 deed calls a line **N 12°30′ E (magnetic)**. The magnetic declination at that place and date was **8°15′ East**. What is the **true** bearing of the line?\n\n**Solution.** East declination is **added** to a magnetic bearing measured toward the east:\n\n`True = N (12°30′ + 8°15′) E = N 20°45′ E`\n\nIf you then needed to re-run the line today with a compass, you would apply the *present-day* declination (and its sign) instead, accounting for secular change."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Exam strategy for distance & angle items\n\n- **Read for the reduction asked.** Many problems give a slope distance and a zenith angle and ask for *horizontal distance* — that is just `H = S·sin(Z)`. Don''t over-build it.\n- **Sign of every correction.** Decide first: am I *measuring* (correcting a field reading) or *laying out* (setting a point)? Sag is **always negative**; temperature follows the sign of (T − 68); slope reduction always *shortens* slope to horizontal.\n- **Zenith vs vertical angle.** A level sight is **Z = 90°** and **α = 0°**. If a problem gives a \"vertical angle\" near 0° use `cos`; if it gives a \"zenith angle\" near 90° use `sin`. Mixing them is the #1 trap. `Z = 90° − α`.\n- **EDM ppm needs km.** Convert the distance to kilometers before multiplying by the ppm rating (2 ppm × 1.85 km = 3.7 mm). 10 ppm ≈ 10°C or 1 in Hg of atmosphere.\n- **Quadrant before conversion.** For azimuth↔bearing, identify the quadrant from the azimuth first, then apply the matching rule (NE: same; SE: 180−; SW: −180; NW: 360−). Back-azimuth is ±180°.\n- **Declination direction.** \"East is least, west is best\" is backwards for *magnetic→true*: for a true-from-magnetic conversion, **add east declination, subtract west**. Watch whether the problem wants magnetic→true or true→magnetic (the sign flips).\n\n## Approved-calculator tricks (TI-36X Pro / Casio fx-991)\n\n- **DMS entry & arithmetic:** Use the **°’”** (TI) / **°’’’** (Casio) key to enter angles directly as D°M''S\". The calculator does base-60 add/subtract/multiply for you — never convert to decimal by hand on the exam unless asked. Toggle a result between DMS and decimal with `2nd °’”` (TI) or by pressing `°’’’` again (Casio).\n- **DEG mode:** confirm the calculator is in **degrees** (not RAD/GRAD) before any trig — a wrong angle mode silently corrupts every answer.\n- **R▸P / P▸R (rectangular↔polar):** for inverse-type and forward-coordinate work, `R▸P` converts (ΔE, ΔN) → (distance, azimuth) in one step, and `P▸R` converts (distance, azimuth) → (ΔE, ΔN). On the TI-36X Pro these live under `2nd` `[R▸P]`/`[P▸R]`; on the Casio fx-991 use `Pol(` and `Rec(`. This is the fastest path for slope/azimuth bookkeeping and carries straight into the next module''s COGO.\n- **HP-33S/35S (RPN, if used):** `→POL`/`→REC` and `→HMS`/`→HR` give the same conversions; enter DMS as `D.MMSSss` and use `→HR` to decimalize.\n- **Store-and-recall:** stash a standardized-tape length or a declination value in memory so you don''t re-key it across a multi-part problem.\n\n## How the handbook helps\n\nThe NCEES FS Reference Handbook gives you the EDM relationship (V = c/n, λ = V/f), the curvature-&-refraction constants, the azimuth/bearing quadrant constants (C = 0/180/180/360), and the inverse/forward direction formulas verbatim. Know *where* taping corrections and the slope reduction live so you can confirm a coefficient under time pressure instead of trusting memory. Practice every conversion on the actual handbook PDF before exam day."}]'::jsonb, 2, 70, 34, '📐', 400, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb035000-0000-0000-0000-000000000001', 'DMS to decimal degrees', 'DMS to decimal degrees', 'FS — Field Data Acquisition', 'Angles', 'numeric_input', 'easy', 'Convert the angle {{D}}°{{M}}′{{S}}″ to decimal degrees.', 'D + M/60 + S/3600', '{"decimals":4,"unit":"°","tolerance":0.001}', '[{"name":"D","type":"integer","min":1,"max":359},{"name":"M","type":"integer","min":0,"max":59},{"name":"S","type":"integer","min":0,"max":59}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply dd = D + M/60 + S/3600","calculation_template":"{{D}} + {{M}}/60 + {{S}}/3600"},{"step_number":2,"title":"Result","result_template":"{{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'Decimal degrees = {{D}} + {{M}}/60 + {{S}}/3600 = {{_answer}}°. On the TI-36X Pro enter the angle with the °’” key and toggle to decimal with 2nd °’”.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000002', 'DMS to total seconds of arc', 'DMS to total seconds of arc', 'FS — Field Data Acquisition', 'Angles', 'numeric_input', 'easy', 'Express the angle {{D}}°{{M}}′{{S}}″ in total seconds of arc.', 'D*3600 + M*60 + S', '{"decimals":0,"unit":"\"","tolerance":1}', '[{"name":"D","type":"integer","min":1,"max":359},{"name":"M","type":"integer","min":0,"max":59},{"name":"S","type":"integer","min":0,"max":59}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Convert each part to seconds","calculation_template":"{{D}}·3600 + {{M}}·60 + {{S}}"},{"step_number":2,"title":"Sum","result_template":"{{_answer}}″"}]'::jsonb, '{"method":"none"}'::jsonb, 'Total seconds = {{D}}·3600 + {{M}}·60 + {{S}} = {{_answer}}″.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000003', 'Azimuth to bearing', 'Azimuth to bearing', 'FS — Field Data Acquisition', 'Directions', 'numeric_input', 'medium', 'A line has azimuth {{az:f4}}°, which lies in the SW quadrant. Give the bearing angle (degrees from south, toward west).', 'az - 180', '{"decimals":4,"unit":"°","tolerance":0.001}', '[{"name":"az","type":"float","min":180.5,"max":269.5,"decimals":4}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Identify quadrant","calculation_template":"Az = {{az:f4}}° is between 180° and 270° → Quadrant III (SW)"},{"step_number":2,"title":"Bearing = Az − 180°","result_template":"S {{_answer}}° W"}]'::jsonb, '{"method":"none"}'::jsonb, 'For an azimuth in the SW quadrant (180°–270°), bearing = Az − 180° = {{az:f4}} − 180 = {{_answer}}°, written S {{_answer}}° W.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], '{"type":"compass","azVar":"az","title":"Azimuth → bearing"}'::jsonb, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000004', 'Bearing to azimuth (NW quadrant)', 'Bearing to azimuth (NW quadrant)', 'FS — Field Data Acquisition', 'Directions', 'numeric_input', 'medium', 'A line bears N {{brg:f4}}° W. Compute its azimuth (clockwise from north, 0°–360°).', '360 - brg', '{"decimals":4,"unit":"°","tolerance":0.001}', '[{"name":"brg","type":"float","min":1,"max":89,"decimals":4}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Identify quadrant","calculation_template":"N __ W → Quadrant IV (NW)"},{"step_number":2,"title":"Azimuth = 360° − bearing","result_template":"{{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'For a NW-quadrant bearing, azimuth = 360° − bearing = 360 − {{brg:f4}} = {{_answer}}°.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000005', 'Back-azimuth', 'Back-azimuth', 'FS — Field Data Acquisition', 'Directions', 'numeric_input', 'easy', 'The forward azimuth of a line is {{az:f4}}°. Compute its back-azimuth (0°–360°).', 'az + 180 - 360*floor((az+180)/360)', '{"decimals":4,"unit":"°","tolerance":0.001}', '[{"name":"az","type":"float","min":0.5,"max":359.5,"decimals":4}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Apply ±180° rule","calculation_template":"If Az < 180°, add 180°; if Az ≥ 180°, subtract 180°"},{"step_number":2,"title":"Back-azimuth","result_template":"{{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'Back-azimuth = Az ± 180° = {{_answer}}° (add 180° when Az < 180°, subtract 180° when Az ≥ 180°).', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], '{"type":"compass","azVar":"az","title":"Forward azimuth"}'::jsonb, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000006', 'Temperature tape correction', 'Temperature tape correction', 'FS — Field Data Acquisition', 'Taping', 'numeric_input', 'medium', 'A distance of {{L:f2}} ft is measured with a steel tape standardized at 68°F. The field temperature is {{T}}°F. Compute the corrected length (ft). Use Ct = 0.00000645·(T − 68)·L.', 'L + 0.00000645*(T-68)*L', '{"decimals":3,"unit":"ft","tolerance":0.01}', '[{"name":"L","type":"float","min":200,"max":1500,"decimals":2},{"name":"T","type":"integer","min":20,"max":110}]'::jsonb, '[{"name":"Ct","formula":"0.00000645*(T-68)*L"}]'::jsonb, '[{"step_number":1,"title":"Temperature correction","calculation_template":"Ct = 0.00000645·({{T}} − 68)·{{L:f2}} = {{Ct:f3}} ft"},{"step_number":2,"title":"Corrected length","result_template":"{{L:f2}} + {{Ct:f3}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Ct = 0.00000645·({{T}}−68)·{{L:f2}} = {{Ct:f3}} ft; corrected length = {{L:f2}} + {{Ct:f3}} = {{_answer}} ft. The correction is positive when T > 68°F (hot tape reads short).', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000007', 'Horizontal distance from slope distance and zenith angle', 'Horizontal distance from slope distance and zenith angle', 'FS — Field Data Acquisition', 'Slope reduction', 'numeric_input', 'medium', 'A total station measures a slope distance of {{S:f3}} ft with a zenith angle of {{Zd}}°{{Zm}}′{{Zs}}″. Compute the horizontal distance (ft). Use H = S·sin(Z).', 'S*sin(toRad(Zd + Zm/60 + Zs/3600))', '{"decimals":3,"unit":"ft","tolerance":0.02}', '[{"name":"S","type":"float","min":150,"max":900,"decimals":3},{"name":"Zd","type":"integer","min":80,"max":99},{"name":"Zm","type":"integer","min":0,"max":59},{"name":"Zs","type":"integer","min":0,"max":59}]'::jsonb, '[{"name":"Zdd","formula":"Zd + Zm/60 + Zs/3600"}]'::jsonb, '[{"step_number":1,"title":"Zenith angle to decimal degrees","calculation_template":"Z = {{Zd}} + {{Zm}}/60 + {{Zs}}/3600 = {{Zdd:f4}}°"},{"step_number":2,"title":"Horizontal distance","result_template":"H = {{S:f3}}·sin({{Zdd:f4}}°) = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Convert the zenith angle to {{Zdd:f4}}°, then H = S·sin(Z) = {{S:f3}}·sin({{Zdd:f4}}°) = {{_answer}} ft. Enter the angle in DMS and keep the calculator in DEG mode.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');
  'fb035000-0000-0000-0000-000000000008', 'EDM constant + ppm error', 'EDM constant + ppm error', 'FS — Field Data Acquisition', 'EDM', 'numeric_input', 'medium', 'An EDM is rated ±({{a}} mm + {{b}} ppm). For a measured distance of {{Dm}} m, compute the worst-case standard error (mm).', 'a + b*Dm/1000', '{"decimals":2,"unit":"mm","tolerance":0.05}', '[{"name":"a","type":"integer","min":1,"max":5},{"name":"b","type":"integer","min":1,"max":5},{"name":"Dm","type":"integer","min":500,"max":5000}]'::jsonb, '[{"name":"Dkm","formula":"Dm/1000"},{"name":"ppmTerm","formula":"b*Dm/1000"}]'::jsonb, '[{"step_number":1,"title":"ppm term (convert D to km)","calculation_template":"{{b}} ppm × {{Dkm:f3}} km = {{ppmTerm:f2}} mm"},{"step_number":2,"title":"Add the constant term","result_template":"e = {{a}} + {{ppmTerm:f2}} = {{_answer}} mm"}]'::jsonb, '{"method":"none"}'::jsonb, 'ppm error (mm) = b·D(km) = {{b}}·{{Dkm:f3}} = {{ppmTerm:f2}} mm; total e = a + ppm term = {{a}} + {{ppmTerm:f2}} = {{_answer}} mm. Always convert the distance to km before multiplying by the ppm rating.', 'f5000003-0000-0000-0000-000000000003', 'FS', ARRAY['fs-buildout','fs-m3','fs-practice']::text[], NULL, true, 'fs:m3');

-- ===== FS Module 4: Traversing and COGO =====
DELETE FROM question_bank WHERE module_id='f5000004-0000-0000-0000-000000000004' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m4' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m4';
VALUES ('f5000004-0000-0000-0000-000000000004', 4, 'Traversing and COGO', 'Master the computational core of plane surveying: latitudes and departures, linear misclosure and relative precision, compass (Bowditch) and transit-rule traverse adjustment, coordinate geometry, the inverse problem, azimuth/bearing conversions, intersections, and area by coordinates (shoelace) — all with NCEES-approved calculator keystrokes.', 'Weeks 7-9', 18, ARRAY['Open, closed-loop, and closed-connecting (link) traverses','Latitude (ΔN) and departure (ΔE) of a course','Linear misclosure and relative precision','Compass (Bowditch) rule and transit rule adjustment','Coordinate computation by polar→rectangular (P▸R)','The inverse problem by rectangular→polar (R▸P)','Azimuth ↔ bearing conversion and back-azimuth','Bearing-bearing, bearing-distance, and distance-distance intersections','Area by coordinates (shoelace / coordinate method)','DMS ↔ decimal degrees on the approved calculator']::text[], '[{"name":"Latitude of a course","formula":"Lat = L·cos(Az)"},{"name":"Departure of a course","formula":"Dep = L·sin(Az)"},{"name":"Inverse distance","formula":"D = √(ΔN² + ΔE²)"},{"name":"Inverse azimuth","formula":"Az = atan2(ΔE, ΔN), normalized 0–360°"},{"name":"Forward coordinates","formula":"N₂ = N₁ + L·cos(Az);  E₂ = E₁ + L·sin(Az)"},{"name":"Linear misclosure","formula":"e = √((ΣLat)² + (ΣDep)²)"},{"name":"Relative precision","formula":"RP = perimeter / e  (reported 1:RP)"},{"name":"Compass (Bowditch) lat correction","formula":"C_lat,i = −(ΣLat)·(Lᵢ / perimeter)"},{"name":"Compass (Bowditch) dep correction","formula":"C_dep,i = −(ΣDep)·(Lᵢ / perimeter)"},{"name":"Transit-rule lat correction","formula":"C_lat,i = −(ΣLat)·(|Latᵢ| / Σ|Lat|)"},{"name":"Area by coordinates (shoelace)","formula":"A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|"},{"name":"Bearing→azimuth","formula":"NE: Az=β; SE: Az=180−β; SW: Az=180+β; NW: Az=360−β"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Why this module is the heart of the FS exam\n\n**Survey Computations and Computer Applications** is one of the two largest computational areas on the NCEES FS exam (17–26 of 110 questions), and **traversing and coordinate geometry (COGO) sit at its center**. Nearly every applied surveying problem — boundary, control, construction, topographic, route — eventually reduces to the same handful of operations you will drill here: turn a **bearing and distance** into a **latitude and departure**, accumulate them into **coordinates**, check the **closure**, **adjust** the traverse, and compute **area**.\n\nA **traverse** is a series of connected lines (courses) whose lengths and directions are measured, used to establish horizontal control and to locate boundaries. The three families are:\n\n- **Open traverse** — starts at a known point but ends at an unknown point; no closure check possible (avoid for control).\n- **Closed-loop (polygon) traverse** — returns to its starting point; the latitudes must sum to zero and the departures must sum to zero, giving a closure check.\n- **Closed-connecting (link) traverse** — starts and ends on two *different* known control points; closure is checked against the known coordinate difference.\n\nThe **two reciprocal operations** you must perform reflexively on the calculator are the **forward computation** (azimuth + distance → ΔN, ΔE → new coordinates, done with **polar→rectangular, P▸R**) and the **inverse** (two coordinates → distance + azimuth, done with **rectangular→polar, R▸P**). Master these two, plus the **shoelace** area formula, and you can solve the majority of the computational items on the exam.\n\nThis module assumes Module 3 (angles, bearings, azimuths, and DMS arithmetic). Here we put those directions to work building and adjusting traverses and computing coordinates and areas. **Every formula matches the NCEES FS Reference Handbook v2.5** so the on-screen exam reference will look familiar."},{"type":"concepts","title":"Key Concepts","content":"## Latitude and departure\n\nEvery course has a **length L** and a **direction** (azimuth Az measured clockwise from north, or a quadrant bearing). Resolve the course onto the coordinate axes:\n\n- **Latitude** = the north–south component = the change in **Northing**: `Lat = ΔN = L·cos(Az)`\n- **Departure** = the east–west component = the change in **Easting**: `Dep = ΔE = L·sin(Az)`\n\n**Sign convention is automatic when you use azimuth** (0°–360°): cos and sin already deliver the correct signs. North latitudes are +, south −; east departures +, west −. If you work with quadrant bearings, apply the sign by quadrant (N+/S−, E+/W−).\n\n## Building coordinates (the forward computation)\n\nStarting from a known point (N₁, E₁), the next point is:\n\n`N₂ = N₁ + L·cos(Az)`   `E₂ = E₁ + L·sin(Az)`\n\nWalk the traverse course by course, accumulating coordinates. On the calculator this is **polar→rectangular (P▸R)**: enter (L, Az) and read back (ΔN, ΔE) — note the surveying convention puts the **angle from north**, so the *x*-result is the departure and the *y*-result is the latitude.\n\n## Closure of a traverse\n\nFor a **closed-loop** traverse the course components must close on themselves: ideally **ΣLat = 0** and **ΣDep = 0**. Measurement error makes them small nonzero values — the **closure in latitude** (`C_N = ΣLat`) and **closure in departure** (`C_E = ΣDep`). Combine them into the **linear misclosure**:\n\n`e = √((ΣLat)² + (ΣDep)²)`\n\nThe quality of the work is the **relative precision** (precision ratio):\n\n`RP = perimeter / e`, reported as **1:RP** (e.g., 1:12,000). Higher is better; boundary and control work commonly require 1:5,000 to 1:10,000 or better.\n\n## Traverse adjustment\n\nIf the misclosure is acceptable, distribute it to force the traverse to close:\n\n- **Compass (Bowditch) rule** — the most common. The correction to each course''s latitude/departure is proportional to that course''s **length** relative to the perimeter:\n  - `C_lat,i = −(ΣLat)·(Lᵢ / P)`   `C_dep,i = −(ΣDep)·(Lᵢ / P)`\n  - Assumes angles and distances are of comparable precision (typical of total-station work).\n- **Transit rule** — the correction is proportional to the **magnitude of the latitude (or departure)** of the course rather than its length:\n  - `C_lat,i = −(ΣLat)·(|Latᵢ| / Σ|Lat|)`   `C_dep,i = −(ΣDep)·(|Depᵢ| / Σ|Dep|)`\n  - Used (historically) when angles are more precise than distances.\n- **Least squares** — the rigorous method (Module on adjustments); compass/transit are the hand methods the FS tests.\n\nAfter adjustment, the corrected latitudes sum to zero and corrected departures sum to zero, so the adjusted coordinates close.\n\n## The inverse problem\n\nGiven two coordinates, recover the **distance and direction** between them:\n\n- `ΔN = N₂ − N₁`, `ΔE = E₂ − E₁`\n- **Distance** `D = √(ΔN² + ΔE²)`\n- **Azimuth** `Az = atan2(ΔE, ΔN)` normalized to 0°–360° (or `Az = arctan(ΔE/ΔN) + C`, with the handbook quadrant constant C: 0° in NE, 180° in SE and SW, 360° in NW).\n\nOn the calculator this is **rectangular→polar (R▸P)**: enter (ΔE, ΔN), read distance and angle.\n\n## Intersections\n\n- **Bearing–bearing**: two lines of known direction from two known points; solve the two `(E − E₀) = (N − N₀)·tan(Az)` equations for the common point.\n- **Bearing–distance**: a direction from one point and a radius (distance) from another (one or two solutions).\n- **Distance–distance**: two radii (circle–circle); two possible intersection points.\n\n## Area by coordinates (shoelace)\n\nOnce every corner has coordinates, the enclosed area is, for points numbered in order around the polygon:\n\n`A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|`\n\nequivalently `A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|`. Divide ft² by **43,560** to get acres. This is the modern replacement for the legacy **DMD (double meridian distance)** method, which is still occasionally tested but gives the same result."},{"type":"formulas","title":"Essential Formulas","content":"## Components of a course\n\n| Quantity | Formula | Notes |\n|---|---|---|\n| Latitude (ΔN) | `Lat = L·cos(Az)` | + north, − south (automatic with azimuth) |\n| Departure (ΔE) | `Dep = L·sin(Az)` | + east, − west (automatic with azimuth) |\n| Course length (from components) | `L = √(Lat² + Dep²)` | the inverse distance |\n| Course azimuth (from components) | `Az = atan2(Dep, Lat)`, normalize 0–360° | quadrant from signs of Lat, Dep |\n\n## Forward (coordinates of a new point)\n\n`N₂ = N₁ + L·cos(Az)`     `E₂ = E₁ + L·sin(Az)`\n\n## Closure and precision (closed-loop)\n\n| Quantity | Formula |\n|---|---|\n| Closure in latitude | `C_N = ΣLat` |\n| Closure in departure | `C_E = ΣDep` |\n| Linear misclosure | `e = √((ΣLat)² + (ΣDep)²)` |\n| Relative precision | `RP = P / e` → report **1:RP** |\n| Azimuth of misclosure | `Az_e = atan2(−ΣDep, −ΣLat)` |\n\n(P = perimeter = ΣL.)\n\n## Compass (Bowditch) rule\n\n`C_lat,i = −C_N·(Lᵢ / P)`     `C_dep,i = −C_E·(Lᵢ / P)`\n\nAdjusted latitude = `Latᵢ + C_lat,i`; adjusted departure = `Depᵢ + C_dep,i`.\n\n## Transit rule\n\n`C_lat,i = −C_N·(|Latᵢ| / Σ|Lat|)`     `C_dep,i = −C_E·(|Depᵢ| / Σ|Dep|)`\n\n## Inverse (rectangular → polar)\n\n`ΔN = N₂ − N₁`,  `ΔE = E₂ − E₁`\n\n`D = √(ΔN² + ΔE²) = hypot(ΔN, ΔE)`\n\n`Az = atan2(ΔE, ΔN)`, then add 360° if negative → 0°–360°.\n\nHandbook quadrant form: `θ = arctan(ΔE/ΔN) + C`, with **C = 0° (NE), 180° (SE), 180° (SW), 360° (NW)**.\n\n## Bearing ↔ azimuth\n\n| Quadrant | Bearing → Azimuth | Azimuth → Bearing |\n|---|---|---|\n| NE | Az = β | β = Az |\n| SE | Az = 180° − β | β = 180° − Az |\n| SW | Az = 180° + β | β = Az − 180° |\n| NW | Az = 360° − β | β = 360° − Az |\n\n**Back-azimuth** = Az ± 180°.\n\n## Area by coordinates (shoelace)\n\n`A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|`   (close the polygon: last point connects to first)\n\nAcres = A(ft²) / 43,560."},{"type":"examples","title":"Worked Examples","content":"## A labeled 4-leg closed traverse\n\nThe traverse **A → B → C → D → A** below is computed throughout these examples. Bearings/azimuths and distances are labeled on each leg.\n\n<svg width=\"460\" height=\"360\" viewBox=\"0 0 460 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"background:#fff;border:1px solid #ccc\">\n  <defs>\n    <marker id=\"arrow\" markerWidth=\"8\" markerHeight=\"8\" refX=\"6\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"#1a5\"/></marker>\n  </defs>\n  <!-- north arrow -->\n  <line x1=\"40\" y1=\"60\" x2=\"40\" y2=\"20\" stroke=\"#333\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/>\n  <text x=\"33\" y=\"16\" font-size=\"13\" font-family=\"sans-serif\">N</text>\n  <!-- traverse polygon: A bottom-left, B bottom-right, C upper-right, D upper-left -->\n  <polygon points=\"90,300 360,300 410,110 140,150\" fill=\"#eef6ff\" stroke=\"#1c4e80\" stroke-width=\"2\"/>\n  <!-- vertices -->\n  <circle cx=\"90\" cy=\"300\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"360\" cy=\"300\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"410\" cy=\"110\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"140\" cy=\"150\" r=\"4\" fill=\"#c0392b\"/>\n  <text x=\"72\" y=\"318\" font-size=\"14\" font-weight=\"bold\">A</text>\n  <text x=\"364\" y=\"318\" font-size=\"14\" font-weight=\"bold\">B</text>\n  <text x=\"416\" y=\"108\" font-size=\"14\" font-weight=\"bold\">C</text>\n  <text x=\"118\" y=\"146\" font-size=\"14\" font-weight=\"bold\">D</text>\n  <!-- leg labels -->\n  <text x=\"190\" y=\"320\" font-size=\"12\" fill=\"#1c4e80\">A→B: N 90°00′ E (Az 90°), 600.00 ft</text>\n  <text x=\"372\" y=\"210\" font-size=\"12\" fill=\"#1c4e80\">B→C: N 14°02′ W</text>\n  <text x=\"372\" y=\"226\" font-size=\"12\" fill=\"#1c4e80\">(Az 345°57′47″), 412.31 ft</text>\n  <text x=\"150\" y=\"230\" font-size=\"12\" fill=\"#1c4e80\">C→D: S 81°28′ W</text>\n  <text x=\"150\" y=\"246\" font-size=\"12\" fill=\"#1c4e80\">(Az 261°28′, 273.0 ft)</text>\n  <text x=\"50\" y=\"230\" font-size=\"12\" fill=\"#1c4e80\">D→A:</text>\n  <text x=\"30\" y=\"246\" font-size=\"12\" fill=\"#1c4e80\">S 18°26′ E,</text>\n  <text x=\"30\" y=\"262\" font-size=\"12\" fill=\"#1c4e80\">158.1 ft</text>\n</svg>\n\nFor clean arithmetic we use these legs (azimuths from north):\n\n| Leg | Azimuth | Distance L (ft) |\n|---|---|---|\n| A→B | 90°00′00″ | 600.00 |\n| B→C | 345°57′45″ | 412.31 |\n| C→D | 261°52′12″ | 282.84 |\n| D→A | 198°26′06″ | 316.23 |\n\n---\n\n## Example 1 — Latitude & departure of each leg\n\n**`Lat = L·cos(Az)`, `Dep = L·sin(Az)`.**\n\n- **A→B** (Az 90°): Lat = 600·cos 90° = **0.00**; Dep = 600·sin 90° = **+600.00**\n- **B→C** (Az 345.9625°): Lat = 412.31·cos 345.9625° = **+400.00**; Dep = 412.31·sin 345.9625° = **−100.00**\n- **C→D** (Az 261.8700°): Lat = 282.84·cos 261.87° = **−40.00**; Dep = 282.84·sin 261.87° = **−280.00**\n- **D→A** (Az 198.4350°): Lat = 316.23·cos 198.435° = **−300.00**; Dep = 316.23·sin 198.435° = **−100.00**\n\n**Check:** ΣLat = 0 + 400 − 40 − 300 = **+60.00 ft**; ΣDep = 600 − 100 − 280 − 100 = **+120.00 ft** (these are the misclosures used in Example 4).\n\n**Calculator (TI-36X Pro):** put the calc in DEGREE mode. For a leg, key `L  ×  cos(  Az  )  =` for the latitude and `L  ×  sin(  Az  )  =` for the departure. Convert a DMS azimuth first with the `°’”` (DMS) entry, e.g. `345°57′45″` entered directly, then `cos`. **Casio fx-991:** identical; enter the DMS angle with the `°’”` key. **HP-35S:** `345.5745  →HR` converts H.MMSS to decimal degrees, then `COS` / `SIN`.\n\n---\n\n## Example 2 — The inverse: distance & azimuth between two points (R▸P)\n\nPoint P1 = (N 5,000.00, E 5,000.00); Point P2 = (N 5,400.00, E 4,900.00). Find distance and azimuth P1→P2.\n\n1. `ΔN = 5400 − 5000 = +400.00`;  `ΔE = 4900 − 5000 = −100.00`\n2. **Distance** `D = √(400² + 100²) = √170000 = 412.31 ft`\n3. **Azimuth** `Az = atan2(ΔE, ΔN) = atan2(−100, +400) = −14.036° → +345.96°` (i.e. **345°57′45″**). ΔN +, ΔE − ⇒ NW quadrant, so bearing **N 14°02′15″ W**.\n\n**Calculator R▸P (TI-36X Pro):** `2nd [R▸P]` opens `R▸Pr(` and `R▸Pθ(`. Key `R▸Pr( ΔE , ΔN )` → **412.31** (distance); `R▸Pθ( ΔE , ΔN )` → **−14.04°**, add 360° → 345.96°, then `▸DMS`. (Enter ΔE first as *x*, ΔN as *y* per the surveying convention.) **Casio fx-991:** `Pol(ΔE, ΔN)` returns r→variable X and θ→variable Y in one step. **HP-35S:** enter ΔN, ΔE and press `→POL`.\n\n---\n\n## Example 3 — Coordinates of a point from azimuth + distance (P▸R)\n\nFrom A = (N 5,000.00, E 5,000.00), run **Az 198°26′06″ for 316.23 ft** to point D. Find D''s coordinates.\n\n1. `ΔN (Lat) = 316.23·cos 198.435° = −300.00`;  `ΔE (Dep) = 316.23·sin 198.435° = −100.00`\n2. `N_D = 5000 + (−300.00) = 4,700.00`;  `E_D = 5000 + (−100.00) = 4,900.00`\n\n**Calculator P▸R (TI-36X Pro):** `2nd [P▸R]` gives `P▸Rx(` and `P▸Ry(`. Key `P▸Rx( L , Az )` → **departure −100.00** (the *x* result); `P▸Ry( L , Az )` → **latitude −300.00** (the *y* result). Add to the start coordinates. **Casio fx-991:** `Rec(L, Az)` returns x (=ΔE) and y (=ΔN). **HP-35S:** enter L, Az; `→REC`.\n\n---\n\n## Example 4 — Misclosure & relative precision\n\nFrom Example 1, ΣLat = +60.00 ft, ΣDep = +120.00 ft, perimeter P = 600.00 + 412.31 + 282.84 + 316.23 = 1,611.38 ft.\n\n1. **Linear misclosure** `e = √(60² + 120²) = √(3600 + 14400) = √18000 = 134.16 ft` (this exaggerated example shows the method; real misclosures are tenths of a foot).\n2. **Relative precision** `RP = P / e = 1611.38 / 134.16 = 12.01` → **≈ 1:12**. (A real 0.13-ft misclosure on this perimeter would give 1611/0.13 ≈ **1:12,400**.)\n\n**Calculator:** misclosure is just `hypot(ΣLat, ΣDep)` — on the TI use `R▸Pr(ΣDep, ΣLat)` to get e in one keystroke. Report relative precision by dividing and rounding to a clean 1:N.\n\n---\n\n## Example 5 — Area by coordinates (shoelace)\n\nFour corners (closed-loop): A(N 5000, E 5000), B(N 5000, E 5600), C(N 5400, E 5500), D(N 4700, E 4900). Using X = Easting, Y = Northing, and the cross form `A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|`:\n\n| i | Xᵢ (E) | Yᵢ (N) | X_{i+1} | Y_{i+1} | Xᵢ·Y_{i+1} | X_{i+1}·Yᵢ |\n|---|---|---|---|---|---|---|\n| A | 5000 | 5000 | 5600 | 5000 | 25,000,000 | 28,000,000 |\n| B | 5600 | 5000 | 5500 | 5400 | 30,240,000 | 27,500,000 |\n| C | 5500 | 5400 | 4900 | 4700 | 25,850,000 | 29,160,000 |\n| D | 4900 | 4700 | 5000 | 5000 | 24,500,000 | 23,500,000 |\n\nΣ(Xᵢ·Y_{i+1}) = 105,590,000; Σ(X_{i+1}·Yᵢ) = 108,160,000. Difference = −2,570,000.\n\n`A = ½·|−2,570,000| = 1,285,000 ft²`  → **÷ 43,560 = 29.50 acres.**\n\n**Calculator tip:** there is no one-button shoelace on the TI/Casio — set it up as a running sum in the home screen, or use the matrix/list features to enter the products. The HP-35S survey program book includes a stored **AREA** routine that accepts sequential N,E inputs and returns acreage directly."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Strategy for the computations area\n\n- **COGO is the most learnable, highest-density point source on the FS.** The same two operations (forward P▸R, inverse R▸P) plus shoelace area cover most items. Drill them until they are reflexive — you should not be *thinking* about which key, only about the geometry.\n- **Pace:** ~2.9 min/question overall. A clean inverse or a single latitude/departure should take under a minute; flag a long multi-leg traverse-adjustment problem and bank quick ones first.\n- **Sketch first.** A 30-second vicinity sketch with the rough azimuth of each leg catches sign and quadrant errors before they cost you.\n\n## Approved-calculator tricks (TI-36X Pro / Casio fx-991 / HP-35S)\n\n- **Always confirm DEGREE mode** before any trig. A traverse in radian mode is the classic silent blunder.\n- **R▸P does the inverse in two keystrokes:** distance = `R▸Pr(ΔE, ΔN)`, azimuth = `R▸Pθ(ΔE, ΔN)`. On Casio, `Pol(ΔE, ΔN)` returns both r and θ at once (stored in X and Y).\n- **P▸R does the forward computation:** departure = `P▸Rx(L, Az)`, latitude = `P▸Ry(L, Az)`. On Casio, `Rec(L, Az)`.\n- **Surveying convention:** enter ΔE (departure) as *x* and ΔN (latitude) as *y*, because azimuth is measured from **north (the y-axis)**. Get this backwards and your azimuth is reflected.\n- **Normalize azimuth:** if R▸Pθ / atan2 returns a negative angle, **add 360°**; if it exceeds 360°, subtract 360°.\n- **DMS ↔ decimal:** TI uses `°’”` for entry and `▸DMS` for output; Casio the same; HP-35S uses `→HR` (to decimal) and `→HMS` (to D.MMSS). Convert *before* trig and back *after* an inverse.\n- **Store and recall** running northing/easting totals (TI `STO`/`RCL`, HP register chaining) so you don''t re-key coordinates leg to leg — this both saves time and prevents transcription blunders.\n- **Misclosure in one shot:** `e = R▸Pr(ΣDep, ΣLat)`.\n\n## Common traps\n\n- **Latitude uses cosine, departure uses sine** — memorize \"**L**atitude–co**s**, **D**eparture–**s**in.\" Swapping them is the #1 COGO error.\n- **Bowditch vs. transit:** Bowditch weights by **course length**; transit weights by **latitude/departure magnitude**. The exam may name the rule — use the one asked.\n- **Sign of the correction:** the correction is the **negative** of the closure distributed out (you are removing the misclosure).\n- **Relative precision is reported as 1:N**, with the **larger** number being **better**. Don''t invert it.\n- **Area sign:** the shoelace sum is negative for clockwise vertex order — always take the **absolute value**, then divide by 43,560 for acres.\n- **Units:** watch ft vs. m and US survey-foot vs. international foot when a problem mixes systems.\n\n## How the handbook helps\n\nThe NCEES FS Reference Handbook v2.5 gives the **inverse** (distance + the quadrant-constant azimuth form), **area by coordinates**, **straight-line / coordinate-geometry** relations, and the **bearing/azimuth** conventions verbatim. Know *where* each lives (Mathematical & Surveying-Related Formulas → Area formulas, and the Coordinate Geometry section) so you can confirm a formula in seconds instead of deriving it under time pressure."}]'::jsonb, 3, 70, 36, '🧭', 600, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb045000-0000-0000-0000-000000000001', 'Latitude of a course', 'Latitude of a course', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'easy', 'A traverse course has a length of {{dist:f2}} ft and an azimuth of {{az:f2}}° (measured clockwise from north). Compute the LATITUDE (ΔN, north–south component) of the course in feet.', 'dist*cos(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"dist","type":"float","min":120,"max":900,"decimals":2},{"name":"az","type":"float","min":1,"max":359,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Latitude = L·cos(azimuth)","formula":"Lat = L·cos(Az)","calculation_template":"{{dist:f2}} × cos({{az:f2}}°)"},{"step_number":2,"title":"Result","result_template":"Lat = {{_answer}} ft (+ = north, − = south)"}]'::jsonb, '{"method":"none"}'::jsonb, 'The latitude is the north–south component of the course: Lat = L·cos(Az) = {{dist:f2}} × cos({{az:f2}}°) = {{_answer}} ft. Use the cosine for latitude (sine gives the departure). The sign is automatic from the azimuth.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"traverse","legs":[{"azVar":"az","distVar":"dist","label":"course"}],"title":"Course (latitude)"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000002', 'Departure of a course', 'Departure of a course', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'easy', 'A traverse course has a length of {{dist:f2}} ft and an azimuth of {{az:f2}}° (clockwise from north). Compute the DEPARTURE (ΔE, east–west component) of the course in feet.', 'dist*sin(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"dist","type":"float","min":120,"max":900,"decimals":2},{"name":"az","type":"float","min":1,"max":359,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Departure = L·sin(azimuth)","formula":"Dep = L·sin(Az)","calculation_template":"{{dist:f2}} × sin({{az:f2}}°)"},{"step_number":2,"title":"Result","result_template":"Dep = {{_answer}} ft (+ = east, − = west)"}]'::jsonb, '{"method":"none"}'::jsonb, 'The departure is the east–west component of the course: Dep = L·sin(Az) = {{dist:f2}} × sin({{az:f2}}°) = {{_answer}} ft. Use the sine for departure (cosine gives the latitude). The sign follows from the azimuth automatically.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"traverse","legs":[{"azVar":"az","distVar":"dist","label":"course"}],"title":"Course (departure)"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000003', 'Inverse between two points (distance)', 'Inverse between two points (distance)', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'medium', 'Point A is at (N {{nA:f2}}, E {{eA:f2}}). Point B is at (N {{nB:f2}}, E {{eB:f2}}). Compute the horizontal distance A→B (ft).', 'hypot(dN,dE)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"nA","type":"float","min":1000,"max":5000,"decimals":2},{"name":"eA","type":"float","min":1000,"max":5000,"decimals":2},{"name":"dN","type":"float","min":-1500,"max":1500,"decimals":2},{"name":"dE","type":"float","min":-1500,"max":1500,"decimals":2}]'::jsonb, '[{"name":"nB","formula":"nA+dN"},{"name":"eB","formula":"eA+dE"}]'::jsonb, '[{"step_number":1,"title":"Latitude & departure","calculation_template":"ΔN = {{nB:f2}} − {{nA:f2}} = {{dN:f2}};  ΔE = {{eB:f2}} − {{eA:f2}} = {{dE:f2}}"},{"step_number":2,"title":"Distance = √(ΔN² + ΔE²)","result_template":"{{_answer}} ft (calculator: R▸Pr(ΔE, ΔN))"}]'::jsonb, '{"method":"none"}'::jsonb, 'Use rectangular→polar. ΔN = {{dN:f2}}, ΔE = {{dE:f2}}; the distance is √(ΔN² + ΔE²) = {{_answer}} ft. On the TI, R▸Pr(ΔE, ΔN) returns this in one keystroke.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"inverse","aNVar":"nA","aEVar":"eA","bNVar":"nB","bEVar":"eB","aLabel":"A","bLabel":"B","title":"Inverse A→B (distance)"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000004', 'Inverse between two points (azimuth)', 'Inverse between two points (azimuth)', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'medium', 'Point A is at (N {{nA:f2}}, E {{eA:f2}}). Point B is at (N {{nB:f2}}, E {{eB:f2}}). Compute the azimuth (clockwise from north, 0°–360°) of the line A→B, in decimal degrees.', '(toDeg(atan2(dE,dN))+360)%360', '{"decimals":2,"unit":"°","tolerance":0.05}', '[{"name":"nA","type":"float","min":1000,"max":5000,"decimals":2},{"name":"eA","type":"float","min":1000,"max":5000,"decimals":2},{"name":"dN","type":"float","min":-1500,"max":1500,"decimals":2},{"name":"dE","type":"float","min":-1500,"max":1500,"decimals":2}]'::jsonb, '[{"name":"nB","formula":"nA+dN"},{"name":"eB","formula":"eA+dE"},{"name":"azRaw","formula":"toDeg(atan2(dE,dN))"}]'::jsonb, '[{"step_number":1,"title":"Latitude & departure","calculation_template":"ΔN = {{dN:f2}}, ΔE = {{dE:f2}}"},{"step_number":2,"title":"Azimuth = atan2(ΔE, ΔN), normalized","result_template":"{{_answer}}° (add 360° if the raw angle is negative)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Azimuth = atan2(ΔE, ΔN) referenced to north. Raw value = {{azRaw:f2}}°; normalized to 0°–360° gives {{_answer}}°. The signs of ΔN ({{dN:f2}}) and ΔE ({{dE:f2}}) place the line in its quadrant. On the TI, R▸Pθ(ΔE, ΔN) then add 360° if negative.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"inverse","aNVar":"nA","aEVar":"eA","bNVar":"nB","bEVar":"eB","aLabel":"A","bLabel":"B","title":"Inverse A→B (azimuth)"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000005', 'Coordinates of a point from azimuth + distance', 'Coordinates of a point from azimuth + distance', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'medium', 'Starting at point P (N {{n1:f2}}, E {{e1:f2}}), a course of azimuth {{az:f2}}° (clockwise from north) and length {{dist:f2}} ft is run to point Q. Compute the NORTHING (N) of point Q (ft).', 'n1 + dist*cos(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"n1","type":"float","min":2000,"max":6000,"decimals":2},{"name":"e1","type":"float","min":2000,"max":6000,"decimals":2},{"name":"az","type":"float","min":1,"max":359,"decimals":2},{"name":"dist","type":"float","min":150,"max":800,"decimals":2}]'::jsonb, '[{"name":"lat","formula":"dist*cos(toRad(az))"}]'::jsonb, '[{"step_number":1,"title":"Latitude of the course","formula":"Lat = L·cos(Az)","calculation_template":"{{dist:f2}} × cos({{az:f2}}°) = {{lat:f2}} ft"},{"step_number":2,"title":"New northing","result_template":"N_Q = {{n1:f2}} + {{lat:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Forward (polar→rectangular) computation: the latitude is L·cos(Az) = {{dist:f2}} × cos({{az:f2}}°) = {{lat:f2}} ft. Add to the starting northing: N_Q = {{n1:f2}} + {{lat:f2}} = {{_answer}} ft. (The easting would use L·sin(Az).)', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"traverse","startNVar":"n1","startEVar":"e1","legs":[{"azVar":"az","distVar":"dist","label":"P→Q"}],"title":"Forward: coordinates of Q"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000006', 'Coordinates of a point — easting from azimuth + distance', 'Coordinates of a point — easting from azimuth + distance', 'FS — Plane Survey Computations', 'COGO', 'numeric_input', 'medium', 'Starting at point P (N {{n1:f2}}, E {{e1:f2}}), a course of azimuth {{az:f2}}° (clockwise from north) and length {{dist:f2}} ft is run to point Q. Compute the EASTING (E) of point Q (ft).', 'e1 + dist*sin(toRad(az))', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"n1","type":"float","min":2000,"max":6000,"decimals":2},{"name":"e1","type":"float","min":2000,"max":6000,"decimals":2},{"name":"az","type":"float","min":1,"max":359,"decimals":2},{"name":"dist","type":"float","min":150,"max":800,"decimals":2}]'::jsonb, '[{"name":"dep","formula":"dist*sin(toRad(az))"}]'::jsonb, '[{"step_number":1,"title":"Departure of the course","formula":"Dep = L·sin(Az)","calculation_template":"{{dist:f2}} × sin({{az:f2}}°) = {{dep:f2}} ft"},{"step_number":2,"title":"New easting","result_template":"E_Q = {{e1:f2}} + {{dep:f2}} = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Forward (polar→rectangular) computation: the departure is L·sin(Az) = {{dist:f2}} × sin({{az:f2}}°) = {{dep:f2}} ft. Add to the starting easting: E_Q = {{e1:f2}} + {{dep:f2}} = {{_answer}} ft. (The northing would use L·cos(Az).)', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"traverse","startNVar":"n1","startEVar":"e1","legs":[{"azVar":"az","distVar":"dist","label":"P→Q"}],"title":"Forward: coordinates of Q"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000007', 'Linear misclosure of a closed traverse', 'Linear misclosure of a closed traverse', 'FS — Plane Survey Computations', 'Traverse Closure', 'numeric_input', 'medium', 'A closed-loop traverse has a closure in latitude ΣLat = {{sumLat:f3}} ft and a closure in departure ΣDep = {{sumDep:f3}} ft. Compute the linear misclosure (ft).', 'hypot(sumLat,sumDep)', '{"decimals":3,"unit":"ft","tolerance":0.005}', '[{"name":"sumLat","type":"float","min":-0.6,"max":0.6,"decimals":3},{"name":"sumDep","type":"float","min":-0.6,"max":0.6,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Misclosure = √((ΣLat)² + (ΣDep)²)","calculation_template":"√(({{sumLat:f3}})² + ({{sumDep:f3}})²)"},{"step_number":2,"title":"Result","result_template":"e = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The linear misclosure is the magnitude of the closure vector: e = √((ΣLat)² + (ΣDep)²) = √(({{sumLat:f3}})² + ({{sumDep:f3}})²) = {{_answer}} ft. On the TI this is R▸Pr(ΣDep, ΣLat).', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], NULL, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000008', 'Relative precision of a traverse', 'Relative precision of a traverse', 'FS — Plane Survey Computations', 'Traverse Closure', 'numeric_input', 'medium', 'A closed traverse has a perimeter of {{perim:f2}} ft and a linear misclosure of {{misc:f3}} ft. Express the relative precision as 1:N — report the value of N (rounded to the nearest whole number).', 'round(perim/misc,0)', '{"decimals":0,"unit":"","tolerance":1}', '[{"name":"perim","type":"float","min":1500,"max":6000,"decimals":2},{"name":"misc","type":"float","min":0.08,"max":0.9,"decimals":3}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Relative precision = perimeter / misclosure","calculation_template":"{{perim:f2}} / {{misc:f3}}"},{"step_number":2,"title":"Result","result_template":"1:{{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'Relative precision = perimeter / misclosure = {{perim:f2}} / {{misc:f3}} = {{_answer}}, reported as 1:{{_answer}}. A larger N indicates better (tighter) work.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], NULL, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000009', 'Area by coordinates (triangle, shoelace)', 'Area by coordinates (triangle, shoelace)', 'FS — Plane Survey Computations', 'Area', 'numeric_input', 'medium', 'A triangular parcel has corners A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), and C (N {{nC:f2}}, E {{eC:f2}}), taken in order. Compute the enclosed area by coordinates (shoelace), in square feet.', 'abs((eA*nB-eB*nA)+(eB*nC-eC*nB)+(eC*nA-eA*nC))/2', '{"decimals":2,"unit":"ft²","tolerance":1}', '[{"name":"nA","type":"float","min":1000,"max":1200,"decimals":2},{"name":"eA","type":"float","min":1000,"max":1200,"decimals":2},{"name":"dNB","type":"float","min":200,"max":700,"decimals":2},{"name":"dEB","type":"float","min":200,"max":700,"decimals":2},{"name":"dNC","type":"float","min":200,"max":700,"decimals":2},{"name":"dEC","type":"float","min":-700,"max":-200,"decimals":2}]'::jsonb, '[{"name":"nB","formula":"nA+dNB"},{"name":"eB","formula":"eA+dEB"},{"name":"nC","formula":"nA+dNC"},{"name":"eC","formula":"eA+dEC"}]'::jsonb, '[{"step_number":1,"title":"Use X = Easting, Y = Northing","calculation_template":"A({{eA:f2}},{{nA:f2}}), B({{eB:f2}},{{nB:f2}}), C({{eC:f2}},{{nC:f2}})"},{"step_number":2,"title":"Shoelace cross-products","formula":"A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|","calculation_template":"Sum the three cross-products, halve the absolute value"},{"step_number":3,"title":"Result","result_template":"{{_answer}} ft² (÷ 43,560 for acres)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Apply the shoelace formula with X = Easting, Y = Northing, vertices in order A→B→C: A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)| = {{_answer}} ft². Divide by 43,560 to convert to acres. The absolute value handles clockwise vs. counterclockwise ordering.', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], '{"type":"triangle","vertices":[{"nVar":"nA","eVar":"eA","label":"A"},{"nVar":"nB","eVar":"eB","label":"B"},{"nVar":"nC","eVar":"eC","label":"C"}],"title":"Area by coordinates"}'::jsonb, true, 'fs:m4');
  'fb045000-0000-0000-0000-000000000010', 'Bearing to azimuth conversion', 'Bearing to azimuth conversion', 'FS — Plane Survey Computations', 'Azimuth/Bearing', 'numeric_input', 'easy', 'A line has the quadrant bearing S {{beta:f2}}° W. Express this as an azimuth (clockwise from north, 0°–360°), in decimal degrees.', '180+beta', '{"decimals":2,"unit":"°","tolerance":0.02}', '[{"name":"beta","type":"float","min":1,"max":89,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"SW quadrant: Az = 180° + bearing angle","calculation_template":"180° + {{beta:f2}}°"},{"step_number":2,"title":"Result","result_template":"Az = {{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'For a SW-quadrant bearing, the azimuth = 180° + the bearing angle = 180° + {{beta:f2}}° = {{_answer}}°. (NE: Az = β; SE: 180 − β; SW: 180 + β; NW: 360 − β.)', 'f5000004-0000-0000-0000-000000000004', 'FS', ARRAY['fs-buildout','fs-m4','fs-practice']::text[], NULL, true, 'fs:m4');

-- ===== FS Module 5: Areas, Volumes and Curves =====
DELETE FROM question_bank WHERE module_id='f5000005-0000-0000-0000-000000000005' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m5' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m5';
VALUES ('f5000005-0000-0000-0000-000000000005', 5, 'Areas, Volumes and Curves', 'Compute parcel areas (coordinate/shoelace and DMD methods, plus trapezoidal and Simpson''s rule from field offsets), earthwork volumes by average-end-area and the prismoidal formula, and the full geometry of horizontal and vertical curves — all with NCEES-approved calculator keystrokes.', 'Weeks 10-12', 15, ARRAY['Area by coordinates (shoelace) and the DMD/DPD method','Area from field offsets: trapezoidal rule and Simpson''s 1/3 rule','Partitioning and converting between ft², acres, and hectares','Earthwork volume by average end area (V = L·(A₁+A₂)/2)','Earthwork volume by the prismoidal formula (V = L·(A₁+4Aₘ+A₂)/6)','Cubic-yard conversion (÷27) and shrinkage/swell','Horizontal curve elements: T, L, R, D (degree of curve), M, E, LC','Curve stationing: PC = PI − T, PT = PC + L, and deflection angles','Vertical (parabolic) curve elevations on the curve and on the tangents','High/low point of a vertical curve and rate of grade change']::text[], '[{"name":"Area by coordinates (shoelace)","formula":"A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|"},{"name":"Acres from square feet","formula":"acres = A(ft²) / 43,560"},{"name":"Trapezoidal rule","formula":"A = w·[(h₁ + hₙ)/2 + h₂ + h₃ + … + hₙ₋₁]"},{"name":"Simpson''s 1/3 rule","formula":"A = (w/3)·[h₁ + hₙ + 4·Σ(odd-index h) + 2·Σ(even-index h)]"},{"name":"Average end area volume","formula":"V = L·(A₁ + A₂)/2"},{"name":"Prismoidal formula","formula":"V = L·(A₁ + 4·Aₘ + A₂)/6"},{"name":"Cubic yards","formula":"V(yd³) = V(ft³) / 27"},{"name":"Degree of curve (arc def.)","formula":"D = 5,729.58 / R   →   R = 5,729.58 / D"},{"name":"Tangent distance","formula":"T = R·tan(I/2)"},{"name":"Curve length","formula":"L = R·I·(π/180) = (I/D)·100"},{"name":"Long chord","formula":"LC = 2R·sin(I/2)"},{"name":"Middle ordinate","formula":"M = R·[1 − cos(I/2)]"},{"name":"External distance","formula":"E = R·[1/cos(I/2) − 1] = R·[sec(I/2) − 1]"},{"name":"Curve stationing","formula":"PC = PI − T;   PT = PC + L"},{"name":"Vertical curve elevation","formula":"Y = Y_PVC + g₁·x + [(g₂−g₁)/(2L)]·x²"},{"name":"Rate of grade change","formula":"r = (g₂ − g₁)/L"},{"name":"High/low point station","formula":"x_m = −g₁·L/(g₂ − g₁)"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Closing the loop: from coordinates to acreage, dirt, and alignment\n\nModule 4 turned bearings and distances into coordinates and closed traverses. This module puts those coordinates to work on the three remaining staples of the **Survey Computations** area (17–26 of the 110 FS questions): **areas**, **volumes**, and **curves**. Together they account for a large, very learnable share of the computational points on the exam.\n\n**Area** is what most boundary and subdivision work ultimately reports. You will compute it two ways: from **coordinates** (the shoelace / coordinate method, equivalent to the legacy double-meridian-distance approach) when every corner is known, and from a series of **field offsets** along a baseline (the **trapezoidal** and **Simpson''s 1/3** rules) when the boundary is an irregular line — a stream bank, a road edge, a tract front. You will also **partition** parcels and move fluently between **square feet, acres, and hectares**.\n\n**Volume** is the heart of construction-survey earthwork. Cross-sectional **end areas** taken at regular stations are combined by the **average-end-area** formula (and refined by the **prismoidal** formula), then divided by **27** to report **cubic yards** for cut/fill and haul.\n\n**Curves** — both **horizontal** (circular) and **vertical** (parabolic) — define route alignments. For horizontal curves you will compute the interlocking elements **T, L, R, D, M, E, LC**, lay out stationing (**PC = PI − T**, **PT = PC + L**), and set points by **deflection angle**. For vertical curves you will compute **elevations** anywhere on an equal-tangent parabola and locate its **high or low point**.\n\n**Every formula matches the NCEES FS Reference Handbook v2.5** (Area formulas, Earthwork, Horizontal circular curves, Vertical curves), so the on-screen exam reference will look exactly like what you drill here."},{"type":"concepts","title":"Key Concepts","content":"## Area by coordinates (shoelace)\n\nWhen every corner of a parcel has coordinates (Northing, Easting), the enclosed area for vertices numbered **in order** around the polygon is:\n\n`A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|`  (handbook form), equivalently the cross-product form `A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|`.\n\nUse **X = Easting, Y = Northing**, close the polygon (the last vertex connects back to the first), and take the **absolute value** — a clockwise vertex order makes the signed sum negative. Divide ft² by **43,560** for acres. This is the modern equivalent of the legacy **DMD (double meridian distance)** method, which sums each course''s DMD × latitude and gives the same answer; the FS may name either.\n\n## Area from field offsets — irregular boundaries\n\nWhen one side of a parcel is an irregular line, you run a straight **baseline** and measure **perpendicular offsets** hᵢ to the boundary at a **constant interval w**. Two integration rules then give the area between the baseline and the boundary:\n\n- **Trapezoidal rule** (any number of offsets): treats the boundary as straight between offsets.\n  `A = w·[(h₁ + hₙ)/2 + h₂ + h₃ + … + hₙ₋₁]`\n- **Simpson''s 1/3 rule** (needs an **odd number of offsets / even number of intervals**): fits parabolas through successive triples, more accurate for curving boundaries.\n  `A = (w/3)·[h₁ + hₙ + 4·(sum of odd-position offsets) + 2·(sum of even-position offsets)]`\n  where, counting offsets 1…n, the **interior odd-position** offsets (2nd, 4th, …) get the **×4** weight and the **interior even-position** offsets (3rd, 5th, …) get the **×2** weight. (If n is even, apply Simpson to the first n−1 offsets and add the last strip as a trapezoid.)\n\n## Partitioning and unit conversions\n\n- 1 acre = 43,560 ft² = 10 square chains; 1 acre = 0.404687 hectare; 1 hectare = 10,000 m².\n- **Partition** problems split a parcel along a line of given direction or through a given point so the pieces have target areas — you set the area equation equal to the target and solve for the unknown dimension.\n\n## Earthwork volumes\n\nCross-sections are cut at regular stations; each has a **cut or fill end area** A (ft²). Between two adjacent sections a distance **L** apart:\n\n- **Average end area:** `V = L·(A₁ + A₂)/2` — the workhorse; slightly **over**estimates when sections taper.\n- **Prismoidal formula:** `V = L·(A₁ + 4·Aₘ + A₂)/6`, where **Aₘ is the area of the section midway between** (computed from the *mid dimensions*, **not** the average of A₁ and A₂). More accurate; the difference is the **prismoidal correction**.\n- **Cubic yards:** divide ft³ by **27**. Apply **shrinkage** (compacted fill needs more bank volume) or **swell** (excavated rock bulks up) factors when the problem gives them.\n\n## Horizontal (circular) curves\n\nA simple circular curve connects two tangents that meet at the **PI** (point of intersection) with **deflection/central angle I (or Δ)**. Key points: **PC** (point of curvature, where the curve begins), **PT** (point of tangency, where it ends), radius **R**. The interlocking elements:\n\n- **Degree of curve (arc def.):** `D = 5,729.58/R` — the central angle subtending a 100-ft arc.\n- **Tangent:** `T = R·tan(I/2)` (PI to PC = PI to PT).\n- **Length:** `L = R·I·(π/180) = (I/D)·100` (along the arc).\n- **Long chord:** `LC = 2R·sin(I/2)`; **Middle ordinate:** `M = R·(1 − cos(I/2))`; **External:** `E = R·(sec(I/2) − 1)`.\n- **Stationing:** `PC = PI − T`, then `PT = PC + L` (note PT is found by adding the *arc length*, never by adding T twice).\n- **Deflection angle** to any point on the curve = half the central angle subtended from the PC: for an arc length ℓ, deflection δ = (ℓ/L)·(I/2); the total deflection from PC to PT is exactly I/2.\n\n## Vertical (parabolic) curves\n\nAn **equal-tangent parabola** joins a back grade **g₁** to a forward grade **g₂** over horizontal length **L**, beginning at the **PVC** and ending at the **PVT**, with the grades meeting at the **PVI**. Grades are decimals (e.g. +2% = +0.02). Measuring **x horizontally from the PVC**:\n\n- **Elevation on the curve:** `Y = Y_PVC + g₁·x + [(g₂−g₁)/(2L)]·x²`\n- **Tangent (grade-line) elevation:** `Y_PVC + g₁·x`; the **tangent offset** is `y = [(g₂−g₁)/(2L)]·x²`.\n- **Rate of grade change:** `r = (g₂−g₁)/L` (per station or per foot, matching x''s units).\n- **High/low point:** where the curve grade is zero, at `x_m = −g₁/r = −g₁·L/(g₂−g₁)` from the PVC. A **crest** (high point) occurs when g₁ > g₂; a **sag** (low point) when g₁ < g₂. The high/low point exists on the curve only when g₁ and g₂ have **opposite signs**."},{"type":"formulas","title":"Essential Formulas","content":"## Area\n\n| Method | Formula | Notes |\n|---|---|---|\n| Coordinates (shoelace) | `A = ½·|Σ (Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|` | X = E, Y = N; close the polygon; take \\|·\\| |\n| Handbook form | `A = ½·|Σ Xᵢ(Y_{i+1} − Y_{i−1})|` | identical result |\n| DMD method | `2A = Σ (DMDᵢ · Latᵢ)` | DMDᵢ = DMDᵢ₋₁ + Depᵢ₋₁ + Depᵢ; first DMD = first Dep |\n| Trapezoidal rule | `A = w·[(h₁ + hₙ)/2 + Σ(interior h)]` | w = offset interval |\n| Simpson''s 1/3 rule | `A = (w/3)·[h₁ + hₙ + 4·Σ(h_odd) + 2·Σ(h_even)]` | needs odd # of offsets |\n\n**Conversions:** 1 acre = 43,560 ft²; acres = ft²/43,560; 1 hectare = 10,000 m² = 2.47105 acres.\n\n## Earthwork volume\n\n| Method | Formula |\n|---|---|\n| Average end area | `V = L·(A₁ + A₂)/2` |\n| Prismoidal | `V = L·(A₁ + 4·Aₘ + A₂)/6` |\n| Pyramid / cone | `V = L·A/3` (one end area zero) |\n| Cubic yards | `V(yd³) = V(ft³)/27` |\n\n(L = distance between sections, ft; A = end area, ft²; Aₘ = mid-section area from mid dimensions.)\n\n## Horizontal circular curve\n\nGiven any two of {R, D, I} plus stationing, everything follows:\n\n| Element | Formula |\n|---|---|\n| Degree of curve (arc) | `D = 5,729.58/R` ; `R = 5,729.58/D` |\n| Tangent | `T = R·tan(I/2)` |\n| Length | `L = R·I·(π/180) = (I/D)·100` |\n| Long chord | `LC = 2R·sin(I/2)` |\n| Middle ordinate | `M = R·(1 − cos(I/2))` |\n| External | `E = R·(sec(I/2) − 1) = R·(1/cos(I/2) − 1)` |\n| Stationing | `PC = PI − T` ; `PT = PC + L` |\n| Deflection to a point | `δ = (ℓ/L)·(I/2)` (total PC→PT deflection = I/2) |\n\n(I in degrees; convert to radians for the length formula: L = R·toRad(I).)\n\n## Vertical (equal-tangent parabolic) curve\n\n| Quantity | Formula |\n|---|---|\n| Elevation on curve | `Y = Y_PVC + g₁·x + [(g₂−g₁)/(2L)]·x²` |\n| Tangent (grade) elevation | `Y_PVC + g₁·x` |\n| Tangent offset | `y = [(g₂−g₁)/(2L)]·x²` ; at PVI: `E = [(g₂−g₁)/(2L)]·(L/2)²` |\n| Rate of grade change | `r = (g₂ − g₁)/L` |\n| High/low point from PVC | `x_m = −g₁/r = −g₁·L/(g₂ − g₁)` |\n\n(Grades as decimals: +2% → +0.02. x and L in the same horizontal unit — feet, or stations.)"},{"type":"examples","title":"Worked Examples","content":"## A labeled horizontal circular curve\n\nThe figure shows a simple circular curve: the back tangent and forward tangent meet at **PI** with deflection angle **I**; the curve runs from **PC** to **PT** with radius **R** and tangent length **T**.\n\n<svg width=\"500\" height=\"360\" viewBox=\"0 0 500 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"background:#fff;border:1px solid #ccc\">\n  <!-- tangents meeting at PI (top) -->\n  <line x1=\"60\" y1=\"300\" x2=\"260\" y2=\"60\" stroke=\"#333\" stroke-width=\"2\"/>\n  <line x1=\"260\" y1=\"60\" x2=\"460\" y2=\"300\" stroke=\"#333\" stroke-width=\"2\"/>\n  <!-- the curve arc from PC to PT, center O below PI -->\n  <path d=\"M 130 215 A 210 210 0 0 1 390 215\" fill=\"none\" stroke=\"#1c4e80\" stroke-width=\"3\"/>\n  <!-- radii from center O to PC and PT -->\n  <line x1=\"260\" y1=\"335\" x2=\"130\" y2=\"215\" stroke=\"#1a5\" stroke-width=\"1.3\" stroke-dasharray=\"5,4\"/>\n  <line x1=\"260\" y1=\"335\" x2=\"390\" y2=\"215\" stroke=\"#1a5\" stroke-width=\"1.3\" stroke-dasharray=\"5,4\"/>\n  <!-- long chord PC-PT -->\n  <line x1=\"130\" y1=\"215\" x2=\"390\" y2=\"215\" stroke=\"#c0392b\" stroke-width=\"1.2\" stroke-dasharray=\"3,3\"/>\n  <!-- points -->\n  <circle cx=\"260\" cy=\"60\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"130\" cy=\"215\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"390\" cy=\"215\" r=\"4\" fill=\"#c0392b\"/>\n  <circle cx=\"260\" cy=\"335\" r=\"4\" fill=\"#1a5\"/>\n  <text x=\"268\" y=\"58\" font-size=\"14\" font-weight=\"bold\">PI</text>\n  <text x=\"96\" y=\"212\" font-size=\"14\" font-weight=\"bold\">PC</text>\n  <text x=\"398\" y=\"212\" font-size=\"14\" font-weight=\"bold\">PT</text>\n  <text x=\"268\" y=\"345\" font-size=\"13\" fill=\"#1a5\">O (center)</text>\n  <!-- labels -->\n  <text x=\"150\" y=\"140\" font-size=\"13\" fill=\"#333\">T (tangent)</text>\n  <text x=\"330\" y=\"140\" font-size=\"13\" fill=\"#333\">T</text>\n  <text x=\"180\" y=\"285\" font-size=\"13\" fill=\"#1a5\">R</text>\n  <text x=\"330\" y=\"285\" font-size=\"13\" fill=\"#1a5\">R</text>\n  <text x=\"246\" y=\"205\" font-size=\"13\" fill=\"#c0392b\">LC</text>\n  <text x=\"238\" y=\"95\" font-size=\"13\" fill=\"#333\">I = Δ</text>\n  <text x=\"150\" y=\"175\" font-size=\"12\" fill=\"#1c4e80\">curve (arc length L)</text>\n</svg>\n\n---\n\n## Example 1 — Full horizontal curve from R and I\n\nGiven **R = 1,145.92 ft**, deflection **I = 24°00′00″**, and **PI at station 42+50.00**. Find D, T, L, LC, M, E, and the stationing of PC and PT.\n\n1. **Degree of curve:** `D = 5,729.58/R = 5,729.58/1,145.92 = 5.0000°` (a 5° curve).\n2. **Tangent:** `T = R·tan(I/2) = 1,145.92·tan(12°) = 1,145.92·0.21256 = 243.57 ft`.\n3. **Length:** `L = R·I·(π/180) = 1,145.92·(24·π/180) = 1,145.92·0.418879 = 480.00 ft` (check: (I/D)·100 = (24/5)·100 = 480.00 ✓).\n4. **Long chord:** `LC = 2R·sin(I/2) = 2·1,145.92·sin12° = 2,291.84·0.20791 = 476.50 ft`.\n5. **Middle ordinate:** `M = R·(1 − cos12°) = 1,145.92·(1 − 0.97815) = 25.04 ft`.\n6. **External:** `E = R·(sec12° − 1) = 1,145.92·(1.02234 − 1) = 25.60 ft`.\n7. **Stationing:** `PC = PI − T = (42+50.00) − 243.57 = station 40+06.43`. `PT = PC + L = (40+06.43) + 480.00 = station 44+86.43`.\n\n**Calculator (TI-36X Pro):** DEGREE mode. `1145.92 × tan( 12 ) =` → 243.57. For L either `1145.92 × 24 × π ÷ 180 =` or simply `(24 ÷ 5) × 100`. For E: `1145.92 × ( 1 ÷ cos(12) − 1 ) =`. **Casio fx-991:** identical keystrokes; the `×10ˣ`/`Ans` keys help chain. **HP-35S (RPN):** `12 TAN 1145.92 × ` gives T; enter I as 24, `→RAD`, `× R` for L.\n\n---\n\n## Example 2 — Deflection angle for staking the curve\n\nUsing the curve above (L = 480.00 ft, I = 24°), find the **deflection angle from the PC** to the curve point at the half-station **42+00**, and the chord from PC to it.\n\n1. Arc from PC to 42+00: `ℓ = (42+00) − (40+06.43) = 193.57 ft`.\n2. **Deflection:** `δ = (ℓ/L)·(I/2) = (193.57/480.00)·12° = 0.40327·12° = 4.839° = 4°50′21″`.\n3. **Chord (from PC):** `c = 2R·sin(δ) = 2·1,145.92·sin(4.839°) = 2,291.84·0.08436 = 193.34 ft` (slightly less than the arc, as expected).\n\n**Check:** the deflection from PC all the way to PT must be **I/2 = 12°00′00″** — a built-in field check. **Calculator:** compute δ in decimal degrees, then `▸DMS` for the field book.\n\n---\n\n## Example 3 — Vertical curve elevation and low point\n\nA sag vertical curve has back grade **g₁ = −3.00%**, forward grade **g₂ = +2.00%**, length **L = 600.00 ft**, with **PVC at station 25+00, elevation 842.00 ft**. Find the elevation at station 28+00 and the station/elevation of the low point.\n\n1. Grades as decimals: g₁ = −0.03, g₂ = +0.02. `x` at 28+00 = (28+00) − (25+00) = **300.00 ft**.\n2. **Elevation on curve:** `Y = 842.00 + (−0.03)(300) + [(0.02 − (−0.03))/(2·600)]·300²`\n   = 842.00 − 9.00 + [0.05/1200]·90,000 = 842.00 − 9.00 + 3.75 = **836.75 ft**.\n3. **Low point from PVC:** `x_m = −g₁·L/(g₂ − g₁) = −(−0.03)(600)/(0.05) = 18/0.05 = 360.00 ft` → station **28+60**.\n4. **Low-point elevation:** `Y = 842.00 + (−0.03)(360) + [0.05/1200]·360² = 842.00 − 10.80 + 5.40 = 836.60 ft`.\n\n**Calculator:** store `a = (g₂−g₁)/(2L) = 0.05/1200 = 4.1667e−5` in memory, then `Y = 842 + (−0.03)x + a·x²` for any x. **Casio fx-991:** use the table (TABLE) mode with f(x) = 842 − 0.03x + 4.1667e−5·x² to print elevations at each station automatically.\n\n---\n\n## Example 4 — Area by coordinates (quad → acres)\n\nA four-corner lot, vertices in order: A(N 1,000.00, E 1,000.00), B(N 1,000.00, E 1,400.00), C(N 1,300.00, E 1,400.00), D(N 1,300.00, E 1,000.00). Find the area in acres (X = E, Y = N).\n\n| i | Xᵢ (E) | Yᵢ (N) | X_{i+1} | Y_{i+1} | Xᵢ·Y_{i+1} | X_{i+1}·Yᵢ |\n|---|---|---|---|---|---|---|\n| A | 1000 | 1000 | 1400 | 1000 | 1,400,000 | 1,400,000 |\n| B | 1400 | 1000 | 1400 | 1300 | 1,820,000 | 1,400,000 |\n| C | 1400 | 1300 | 1000 | 1300 | 1,820,000 | 1,300,000 |\n| D | 1000 | 1300 | 1000 | 1000 | 1,000,000 | 1,300,000 |\n\nΣ(Xᵢ·Y_{i+1}) = 6,040,000; Σ(X_{i+1}·Yᵢ) = 5,400,000. Difference = 640,000.\n`A = ½·|640,000| = 120,000 ft²` → **÷ 43,560 = 2.755 acres** (a 400 × 300 rectangle, as a sanity check).\n\n---\n\n## Example 5 — Average end area earthwork volume\n\nTwo adjacent cross-sections, 100.00 ft apart (one full station), have cut end areas **A₁ = 120.0 ft²** and **A₂ = 180.0 ft²**. Find the cut volume in cubic yards.\n\n1. **Average end area:** `V = L·(A₁ + A₂)/2 = 100·(120 + 180)/2 = 100·150 = 15,000 ft³`.\n2. **Cubic yards:** `V = 15,000 / 27 = 555.6 yd³`.\n\nIf the mid-section area were measured (say Aₘ = 148.0 ft²), the **prismoidal** volume would be `V = 100·(120 + 4·148 + 180)/6 = 100·892/6 = 14,866.7 ft³ = 550.6 yd³` — the **prismoidal correction** of about 5 yd³ less. **Calculator:** `100 × (120 + 180) ÷ 2 ÷ 27 =` → 555.6. Always divide ft³ by 27 last to report yards."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Strategy for areas, volumes, and curves\n\n- **These are high-yield, formula-lookup points.** Every formula you need is in the handbook (Area formulas, Earthwork, Horizontal circular curves, Vertical curves). Know *where* each lives so you confirm rather than derive. Curves alone reliably appear several times.\n- **Pace:** a single curve element (T, L, M, E) or one average-end-area volume is a sub-minute calculation; a full curve layout with stationing is a flag-and-return item. Bank the one-formula questions first.\n- **Sketch the curve.** A quick PI–PC–PT sketch with I marked prevents the classic error of adding T (a straight distance) instead of L (the arc) when stationing the PT.\n\n## Approved-calculator tricks (TI-36X Pro / Casio fx-991 / HP-35S)\n\n- **Confirm DEGREE mode** before any curve trig. Then I/2 is just `I ÷ 2`; feed it straight into tan/cos/sin.\n- **External and middle ordinate** both use I/2: `E = R(1/cos(I/2) − 1)`, `M = R(1 − cos(I/2))`. There is no `sec` key — type `1/cos(...)`.\n- **Curve length two ways:** `L = R·toRad(I)` (radians) OR the cleaner `(I/D)·100`. Use the second when D is given — it avoids π entirely.\n- **Vertical curves:** put grades in as **decimals** (+2% → 0.02). Store the constant `a = (g₂−g₁)/(2L)` once; then any elevation is `Y_PVC + g₁x + a·x²`. The Casio **TABLE** mode and TI **table** print a full elevation column in one setup.\n- **Stationing arithmetic:** a station is just feet (42+50 = 4,250 ft). Do the math in feet, then re-split into stations (÷100 for the station number, remainder for the plus).\n- **Volume:** keep everything in ft² and ft, then **÷27 at the very end** for cubic yards. Mixing the /27 in early is a common slip.\n- **Area by offsets:** Simpson needs an **odd number of offsets**; if you''re given an even number, Simpson the first n−1 and add the last strip as a trapezoid, or just use the trapezoidal rule.\n\n## Common traps\n\n- **PT = PC + L, not PC + 2T or PI + T.** The curve length is the arc; T is a straight tangent distance. This is the single most common curve blunder.\n- **Degree of curve uses 5,729.58, not 5,730.** Arc definition. R = 5,729.58/D.\n- **Prismoidal Aₘ** is computed from the **mid-section''s own dimensions**, *not* the average (A₁+A₂)/2 — using the average just reproduces the end-area answer.\n- **High/low point only exists when g₁ and g₂ have opposite signs.** A grade that goes −1% to −3% (both negative) has no turning point on the curve.\n- **Average end area slightly over-estimates** volume for tapering sections; the prismoidal value is smaller (the correction). Know which the question wants.\n- **Acres vs. square feet:** divide by **43,560**. Hectares: 1 ha = 10,000 m² = 2.47105 acres — watch SI vs. USCS.\n- **Simpson weighting:** ends ×1, interior **odd-position** offsets ×4, interior **even-position** ×2 — miscounting the weights is the usual error.\n\n## How the handbook helps\n\nThe NCEES FS Reference Handbook v2.5 gives the **horizontal circular curve** set (D, T, L, LC, M, E, stationing), the **vertical curve** parabola (elevation, tangent offset, rate r, high/low x_m), the **area formulas** (coordinates, trapezoidal, Simpson''s 1/3), and **earthwork** (average end area, prismoidal) verbatim. Practice pulling each up by name so that on exam day the formula is a confirmation, not a recall test."}]'::jsonb, 4, 70, 36, '📊', 600, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb055000-0000-0000-0000-000000000001', 'Area by coordinates (quadrilateral) → acres', 'Area by coordinates (quadrilateral) → acres', 'FS — Plane Survey Computations', 'Area', 'numeric_input', 'medium', 'A four-corner parcel has corners, in order, A (N {{nA:f2}}, E {{eA:f2}}), B (N {{nB:f2}}, E {{eB:f2}}), C (N {{nC:f2}}, E {{eC:f2}}), and D (N {{nD:f2}}, E {{eD:f2}}). Compute the enclosed area by coordinates (shoelace) and report it in ACRES.', 'abs((eA*nB-eB*nA)+(eB*nC-eC*nB)+(eC*nD-eD*nC)+(eD*nA-eA*nD))/2/43560', '{"decimals":3,"unit":"acres","tolerance":0.01}', '[{"name":"nA","type":"float","min":1000,"max":1100,"decimals":2},{"name":"eA","type":"float","min":1000,"max":1100,"decimals":2},{"name":"w","type":"float","min":300,"max":700,"decimals":2},{"name":"h","type":"float","min":300,"max":700,"decimals":2}]'::jsonb, '[{"name":"eB","formula":"eA+w"},{"name":"nB","formula":"nA"},{"name":"eC","formula":"eA+w"},{"name":"nC","formula":"nA+h"},{"name":"eD","formula":"eA"},{"name":"nD","formula":"nA+h"}]'::jsonb, '[{"step_number":1,"title":"Use X = Easting, Y = Northing","calculation_template":"A({{eA:f2}},{{nA:f2}}), B({{eB:f2}},{{nB:f2}}), C({{eC:f2}},{{nC:f2}}), D({{eD:f2}},{{nD:f2}})"},{"step_number":2,"title":"Shoelace sum, halved, absolute value","formula":"A = ½|Σ(Xᵢ·Y_{i+1} − X_{i+1}·Yᵢ)|","calculation_template":"Sum the four cross-products, halve the absolute value → ft²"},{"step_number":3,"title":"Convert to acres","result_template":"{{_answer}} acres (= ft² ÷ 43,560)"}]'::jsonb, '{"method":"none"}'::jsonb, 'Apply the shoelace formula with X = Easting, Y = Northing, vertices in order A→B→C→D, take the absolute value, then divide by 43,560 ft²/acre. Area = {{_answer}} acres.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], '{"type":"triangle","vertices":[{"nVar":"nA","eVar":"eA","label":"A"},{"nVar":"nB","eVar":"eB","label":"B"},{"nVar":"nC","eVar":"eC","label":"C"},{"nVar":"nD","eVar":"eD","label":"D"}],"title":"Parcel by coordinates"}'::jsonb, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000002', 'Area from field offsets (trapezoidal rule)', 'Area from field offsets (trapezoidal rule)', 'FS — Plane Survey Computations', 'Area', 'numeric_input', 'medium', 'Perpendicular offsets from a straight baseline to an irregular boundary are measured at a constant interval of {{w:f1}} ft: h₁={{h1:f1}}, h₂={{h2:f1}}, h₃={{h3:f1}}, h₄={{h4:f1}}, h₅={{h5:f1}} ft. Using the TRAPEZOIDAL rule, compute the area (ft²) between the baseline and the boundary.', 'w*((h1+h5)/2 + h2 + h3 + h4)', '{"decimals":1,"unit":"ft²","tolerance":0.5}', '[{"name":"w","type":"float","min":20,"max":60,"decimals":1},{"name":"h1","type":"float","min":5,"max":25,"decimals":1},{"name":"h2","type":"float","min":5,"max":25,"decimals":1},{"name":"h3","type":"float","min":5,"max":25,"decimals":1},{"name":"h4","type":"float","min":5,"max":25,"decimals":1},{"name":"h5","type":"float","min":5,"max":25,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Trapezoidal rule","formula":"A = w·[(h₁+hₙ)/2 + Σ interior]","calculation_template":"{{w:f1}}·[({{h1:f1}}+{{h5:f1}})/2 + {{h2:f1}} + {{h3:f1}} + {{h4:f1}}]"},{"step_number":2,"title":"Result","result_template":"A = {{_answer}} ft²"}]'::jsonb, '{"method":"none"}'::jsonb, 'The trapezoidal rule averages the two end offsets and adds the interior offsets, all times the interval: A = w·[(h₁+hₙ)/2 + Σinterior] = {{w:f1}}·[({{h1:f1}}+{{h5:f1}})/2 + {{h2:f1}}+{{h3:f1}}+{{h4:f1}}] = {{_answer}} ft².', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000003', 'Area from field offsets (Simpson''s 1/3 rule)', 'Area from field offsets (Simpson''s 1/3 rule)', 'FS — Plane Survey Computations', 'Area', 'numeric_input', 'hard', 'Five offsets at a constant interval of {{w:f1}} ft are h₁={{h1:f1}}, h₂={{h2:f1}}, h₃={{h3:f1}}, h₄={{h4:f1}}, h₅={{h5:f1}} ft. Using SIMPSON''S 1/3 rule, compute the area (ft²) between the baseline and the boundary.', '(w/3)*(h1 + h5 + 4*(h2+h4) + 2*h3)', '{"decimals":1,"unit":"ft²","tolerance":0.5}', '[{"name":"w","type":"float","min":20,"max":50,"decimals":1},{"name":"h1","type":"float","min":5,"max":25,"decimals":1},{"name":"h2","type":"float","min":5,"max":25,"decimals":1},{"name":"h3","type":"float","min":5,"max":25,"decimals":1},{"name":"h4","type":"float","min":5,"max":25,"decimals":1},{"name":"h5","type":"float","min":5,"max":25,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Simpson''s 1/3 rule (5 offsets, even intervals)","formula":"A = (w/3)·[h₁ + hₙ + 4·Σodd + 2·Σeven]","calculation_template":"(w/3)·[{{h1:f1}} + {{h5:f1}} + 4({{h2:f1}}+{{h4:f1}}) + 2({{h3:f1}})]"},{"step_number":2,"title":"Result","result_template":"A = {{_answer}} ft²"}]'::jsonb, '{"method":"none"}'::jsonb, 'Simpson''s 1/3 rule weights the ends ×1, the interior odd-position offsets (2nd, 4th) ×4, and the interior even-position offset (3rd) ×2, all times w/3: A = ({{w:f1}}/3)·[{{h1:f1}}+{{h5:f1}} + 4({{h2:f1}}+{{h4:f1}}) + 2({{h3:f1}})] = {{_answer}} ft².', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000004', 'Average-end-area volume → cubic yards', 'Average-end-area volume → cubic yards', 'FS — Plane Survey Computations', 'Volume', 'numeric_input', 'medium', 'Two adjacent cross-sections {{L:f1}} ft apart have end areas A₁ = {{a1:f1}} ft² and A₂ = {{a2:f1}} ft². Using the average-end-area method, compute the earthwork volume in CUBIC YARDS.', 'L*(a1+a2)/2/27', '{"decimals":1,"unit":"yd³","tolerance":0.5}', '[{"name":"L","type":"float","min":50,"max":150,"decimals":1},{"name":"a1","type":"float","min":60,"max":300,"decimals":1},{"name":"a2","type":"float","min":60,"max":300,"decimals":1}]'::jsonb, '[{"name":"vft3","formula":"L*(a1+a2)/2"}]'::jsonb, '[{"step_number":1,"title":"Average end area","formula":"V = L·(A₁+A₂)/2","calculation_template":"{{L:f1}}·({{a1:f1}}+{{a2:f1}})/2 = {{vft3:f1}} ft³"},{"step_number":2,"title":"Convert to cubic yards (÷27)","result_template":"{{_answer}} yd³"}]'::jsonb, '{"method":"none"}'::jsonb, 'Average end area: V = L·(A₁+A₂)/2 = {{L:f1}}·({{a1:f1}}+{{a2:f1}})/2 = {{vft3:f1}} ft³. Divide by 27 ft³/yd³ → {{_answer}} yd³.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000005', 'Horizontal curve tangent distance T', 'Horizontal curve tangent distance T', 'FS — Plane Survey Computations', 'Horizontal Curves', 'numeric_input', 'medium', 'A simple circular curve has radius R = {{R:f2}} ft and deflection (central) angle I = {{I:f2}}°. Compute the tangent distance T (ft).', 'R*tan(toRad(I/2))', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"float","min":400,"max":2000,"decimals":2},{"name":"I","type":"float","min":8,"max":75,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Tangent = R·tan(I/2)","formula":"T = R·tan(I/2)","calculation_template":"{{R:f2}}·tan({{I:f2}}/2°)"},{"step_number":2,"title":"Result","result_template":"T = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The tangent distance from the PI to the PC (and to the PT) is T = R·tan(I/2) = {{R:f2}}·tan({{I:f2}}°/2) = {{_answer}} ft. Set the calculator to DEGREE mode and use I/2.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], '{"type":"curve","rVar":"R","iVar":"I","title":"Horizontal curve: tangent T"}'::jsonb, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000006', 'Horizontal curve length L', 'Horizontal curve length L', 'FS — Plane Survey Computations', 'Horizontal Curves', 'numeric_input', 'medium', 'A circular curve has radius R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. Compute the curve (arc) length L (ft).', 'R*toRad(I)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"float","min":400,"max":2000,"decimals":2},{"name":"I","type":"float","min":8,"max":75,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Length = R·I (radians)","formula":"L = R·I·(π/180)","calculation_template":"{{R:f2}}·({{I:f2}}°·π/180)"},{"step_number":2,"title":"Result","result_template":"L = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The arc length is L = R·I·(π/180) = {{R:f2}}·toRad({{I:f2}}°) = {{_answer}} ft. Equivalently, L = (I/D)·100 if the degree of curve D is known.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], '{"type":"curve","rVar":"R","iVar":"I","title":"Horizontal curve: length L"}'::jsonb, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000007', 'Degree of curve from radius', 'Degree of curve from radius', 'FS — Plane Survey Computations', 'Horizontal Curves', 'numeric_input', 'easy', 'A circular curve has radius R = {{R:f2}} ft. Compute the degree of curve D (arc definition), in decimal degrees.', '5729.58/R', '{"decimals":3,"unit":"°","tolerance":0.01}', '[{"name":"R","type":"float","min":500,"max":3000,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Degree of curve (arc def.)","formula":"D = 5,729.58 / R","calculation_template":"5,729.58 / {{R:f2}}"},{"step_number":2,"title":"Result","result_template":"D = {{_answer}}°"}]'::jsonb, '{"method":"none"}'::jsonb, 'The arc-definition degree of curve is D = 5,729.58/R = 5,729.58/{{R:f2}} = {{_answer}}°. It is the central angle that subtends a 100-ft arc.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000008', 'Horizontal curve external distance E', 'Horizontal curve external distance E', 'FS — Plane Survey Computations', 'Horizontal Curves', 'numeric_input', 'medium', 'A circular curve has radius R = {{R:f2}} ft and deflection angle I = {{I:f2}}°. Compute the external distance E (ft) from the PI to the midpoint of the curve.', 'R*(1/cos(toRad(I/2))-1)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"R","type":"float","min":400,"max":2000,"decimals":2},{"name":"I","type":"float","min":8,"max":75,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"External = R·(sec(I/2) − 1)","formula":"E = R·(1/cos(I/2) − 1)","calculation_template":"{{R:f2}}·(1/cos({{I:f2}}°/2) − 1)"},{"step_number":2,"title":"Result","result_template":"E = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The external distance is E = R·(sec(I/2) − 1) = R·(1/cos(I/2) − 1) = {{R:f2}}·(1/cos({{I:f2}}°/2) − 1) = {{_answer}} ft. There is no sec key — type 1/cos(I/2).', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], '{"type":"curve","rVar":"R","iVar":"I","title":"Horizontal curve: external E"}'::jsonb, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000009', 'Vertical curve elevation', 'Vertical curve elevation', 'FS — Plane Survey Computations', 'Vertical Curves', 'numeric_input', 'medium', 'An equal-tangent vertical curve of length L = {{L:f1}} ft has back grade g₁ = {{g1:f2}}% and forward grade g₂ = {{g2:f2}}%. The PVC is at elevation {{ypvc:f2}} ft. Compute the elevation on the curve at a distance x = {{x:f1}} ft from the PVC (ft).', 'ypvc + (g1/100)*x + ((g2/100-g1/100)/(2*L))*x*x', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"L","type":"float","min":300,"max":800,"decimals":1},{"name":"g1","type":"float","min":-5,"max":5,"decimals":2},{"name":"g2","type":"float","min":-5,"max":5,"decimals":2},{"name":"ypvc","type":"float","min":500,"max":1200,"decimals":2},{"name":"x","type":"float","min":50,"max":300,"decimals":1}]'::jsonb, '[{"name":"a","formula":"(g2/100-g1/100)/(2*L)"}]'::jsonb, '[{"step_number":1,"title":"Grades to decimals; parabola constant","formula":"a = (g₂−g₁)/(2L)","calculation_template":"g₁={{g1:f2}}%→{{g1:f2}}/100; g₂={{g2:f2}}%→{{g2:f2}}/100; a = {{a}}"},{"step_number":2,"title":"Curve elevation","formula":"Y = Y_PVC + g₁·x + a·x²","calculation_template":"{{ypvc:f2}} + (g₁)({{x:f1}}) + a·({{x:f1}})²"},{"step_number":3,"title":"Result","result_template":"Y = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Convert grades to decimals, then Y = Y_PVC + g₁·x + [(g₂−g₁)/(2L)]·x². With g₁={{g1:f2}}%, g₂={{g2:f2}}%, L={{L:f1}} ft, x={{x:f1}} ft: Y = {{_answer}} ft.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');
  'fb055000-0000-0000-0000-000000000010', 'Vertical curve high/low point station', 'Vertical curve high/low point station', 'FS — Plane Survey Computations', 'Vertical Curves', 'numeric_input', 'medium', 'An equal-tangent vertical curve of length L = {{L:f1}} ft has back grade g₁ = {{g1:f2}}% and forward grade g₂ = {{g2:f2}}% (opposite signs, so a turning point exists). Compute the distance x from the PVC to the high/low point (ft).', '(-g1)*L/(g2-g1)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"L","type":"float","min":300,"max":800,"decimals":1},{"name":"g1","type":"float","min":-4,"max":-1,"decimals":2},{"name":"g2","type":"float","min":1,"max":4,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Turning point from PVC","formula":"x_m = −g₁·L/(g₂ − g₁)","calculation_template":"−({{g1:f2}})·{{L:f1}} / ({{g2:f2}} − {{g1:f2}})"},{"step_number":2,"title":"Result","result_template":"x_m = {{_answer}} ft from the PVC"}]'::jsonb, '{"method":"none"}'::jsonb, 'The high/low point is where the curve grade is zero: x_m = −g₁·L/(g₂ − g₁). The percent signs cancel in the ratio, so x_m = −({{g1:f2}})·{{L:f1}}/({{g2:f2}} − {{g1:f2}}) = {{_answer}} ft from the PVC.', 'f5000005-0000-0000-0000-000000000005', 'FS', ARRAY['fs-buildout','fs-m5','fs-practice']::text[], NULL, true, 'fs:m5');

-- ===== FS Module 6: GNSS/GPS and Geodesy =====
DELETE FROM question_bank WHERE module_id='f5000006-0000-0000-0000-000000000006' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m6' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m6';
VALUES ('f5000006-0000-0000-0000-000000000006', 6, 'GNSS/GPS and Geodesy', 'GNSS positioning fundamentals and field methods (static, RTK, PPK, OPUS/PPP, RTN), error sources and DOP, the geoid–ellipsoid relationship (H = h − N), datums (NAD83, WGS84, NATRF2022), map projections, the State Plane Coordinate System, grid vs. ground distances via the combined scale factor, convergence, and UTM — all matched to the NCEES FS Reference Handbook v2.5.', 'Weeks 12-13', 14, ARRAY['GNSS constellations (GPS, GLONASS, Galileo, BeiDou) and signal structure','Positioning methods: autonomous, DGPS, static, fast-static, RTK, PPK, OPUS/PPP','Real-time networks (RTN / VRS) and base–rover differential positioning','GNSS error sources: ionosphere, troposphere, multipath, clock, ephemeris','Dilution of precision (DOP) and UERE → position error','Geoid vs. ellipsoid vs. orthometric height: H = h − N','Datums: NAD83, WGS84, NAVD88, GRS80, and the 2022 NATRF/NAPGD reference frames','Map projections: Lambert Conformal Conic vs. Transverse Mercator','State Plane Coordinate System (SPCS) and zone selection','Grid vs. ground: scale factor, elevation factor, combined factor','Convergence (mapping angle) and UTM']::text[], '[{"name":"Orthometric / ellipsoidal / geoid height","formula":"H = h − N   (equivalently h = H + N)"},{"name":"Elevation factor","formula":"EF = R / (R + H + N) ≈ R / (R + h),  R ≈ 20,906,000 ft"},{"name":"Combined factor","formula":"CSF = SF × EF   (scale factor × elevation factor)"},{"name":"Ground → grid distance","formula":"D_grid = D_ground × CSF"},{"name":"Grid → ground distance","formula":"D_ground = D_grid / CSF"},{"name":"Baseline error budget","formula":"σ = a (mm) + b (ppm) × L (km)"},{"name":"Position error from DOP","formula":"σ_pos = UERE × DOP"},{"name":"Geometric range from satellite","formula":"ρ = √((Xs−Xr)² + (Ys−Yr)² + (Zs−Zr)²)"},{"name":"Convergence (grid azimuth ↔ geodetic azimuth)","formula":"Az_grid = Az_geodetic − γ + (t−T)   (γ = convergence/mapping angle)"},{"name":"Arc-to-chord (t−T) correction","formula":"AR − CH = CH³ / (24R²)"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## Where geodesy and GNSS sit on the FS\n\nThe NCEES FS exam tests geodesy and GNSS under **Surveying Principles** (Area 4: basic surveying, geodesy, and *applied* geodesy — datums, datum conversions, SPCS, map projections, satellite coordinate systems) and under **Surveying Processes and Methods** (Area 1: GNSS/GPS surveys — static, kinematic, OPUS, real-time networks). Together these are roughly an eighth of the exam, and they are conceptually rich rather than calculation-heavy: most points come from *understanding* how a satellite position becomes a grid coordinate on a map.\n\nThis module follows the **measurement → reference frame → projection** chain that every modern survey rides:\n\n1. **GNSS measures** a three-dimensional position relative to an **ellipsoid** (a smooth mathematical earth) in a global datum (WGS84 / NAD83 / the 2022 frames).\n2. The height it returns is an **ellipsoidal height h**, not the **orthometric height H** (elevation above the **geoid**, the equipotential ''mean sea level'' surface). The two are tied by the **geoid undulation N**: `H = h − N`.\n3. To put the position on a flat **map** we apply a **projection** — Lambert Conformal Conic for east–west states, Transverse Mercator for north–south states — producing **State Plane** (or UTM) **grid coordinates**.\n4. Grid coordinates are not ground distances. The **combined factor** (scale factor × elevation factor) converts between **grid** and **ground**, and **convergence** relates grid north to geodetic north.\n\nMaster the vocabulary (geoid vs. ellipsoid, datum vs. projection, grid vs. ground), the one essential height equation **H = h − N**, and the one essential distance chain **grid = ground × CSF**, and you will pick up most of the available points. Every formula here matches the **NCEES FS Reference Handbook v2.5** (Geodesy, State Plane Coordinates, and Conversions sections) so the on-screen reference will look familiar."},{"type":"concepts","title":"Key Concepts","content":"## GNSS fundamentals\n\n**GNSS** (Global Navigation Satellite System) is the umbrella term; **GPS** is the U.S. constellation. The four major constellations are **GPS (USA)**, **GLONASS (Russia)**, **Galileo (EU)**, and **BeiDou (China)**. A receiver computes position by measuring **ranges** to satellites whose orbital positions are known from the broadcast **ephemeris**. Each constellation has three segments: **space** (satellites), **control** (ground monitoring/upload stations), and **user** (receivers).\n\nTwo observable types:\n\n- **Code (pseudorange)** — fast to acquire, meter-level; the basis of autonomous and DGPS navigation.\n- **Carrier phase** — uses the wavelength of the carrier (~19 cm L1); millimeter-to-centimeter precision once the integer **ambiguity** is resolved. All high-accuracy surveying is carrier-phase.\n\nA single receiver positioning by itself is **autonomous** (a few meters). Accuracy improves through **differencing** against a reference of known coordinates, which cancels common errors.\n\n## Positioning (field) methods\n\n| Method | Observable | Typical accuracy | When used |\n|---|---|---|---|\n| **Autonomous** | code | 2–5 m | navigation, recon |\n| **DGPS / SBAS (WAAS)** | code (differential) | sub-meter to ~1 m | GIS, mapping-grade |\n| **Static** | carrier, long occupation (20 min–hours) | mm–cm | control, long baselines |\n| **Fast/rapid static** | carrier, short occupation | cm | densifying control |\n| **RTK (real-time kinematic)** | carrier, base→rover radio | 1–3 cm | layout, topo, boundary |\n| **PPK (post-processed kinematic)** | carrier, processed later | 1–3 cm | when no real-time link |\n| **RTN / VRS (network RTK)** | carrier, modeled from a CORS network | 1–3 cm | RTK without your own base |\n| **OPUS / PPP** | carrier, processed against CORS / precise orbits | cm | single-receiver static positioning |\n\n**OPUS** (Online Positioning User Service, NGS) post-processes a single static occupation against the **CORS** (Continuously Operating Reference Stations) network and returns published NAD83 and ITRF coordinates. **PPP** (precise point positioning) uses precise satellite orbit/clock products to position a single receiver without a local base.\n\n## GNSS error sources\n\n- **Ionospheric delay** — frequency-dependent; largely removed by **dual-frequency** (L1/L2) receivers; the largest natural error.\n- **Tropospheric delay** — modeled (not frequency-dependent); worse at low elevation angles.\n- **Satellite clock & ephemeris (orbit) errors** — corrected by broadcast/precise products; differenced out over short baselines.\n- **Multipath** — signal reflecting off nearby surfaces; mitigated by choke-ring antennas, siting, and avoiding reflective surfaces. **Not** reduced by differencing (it is site-specific).\n- **Receiver noise** and **antenna phase-center variation**.\n- **Cycle slips** — loss of carrier lock that must be repaired in processing.\n\n## Dilution of Precision (DOP)\n\n**DOP** quantifies how satellite *geometry* amplifies ranging error into position error. **Lower DOP is better** (well-spread satellites). Position error ≈ **UERE × DOP**, where **UERE** is the user-equivalent range error.\n\n- **GDOP** (geometric, 3D + time), **PDOP** (position, 3D), **HDOP** (horizontal), **VDOP** (vertical), **TDOP** (time).\n- VDOP is typically worse than HDOP because all satellites are above the horizon (no satellites ''below'' to balance the vertical).\n\n## Heights: geoid, ellipsoid, orthometric — H = h − N\n\nThree surfaces:\n\n- **Ellipsoid** — the smooth mathematical reference (GRS80 for NAD83). GNSS heights are **ellipsoidal heights h** measured along the ellipsoid normal.\n- **Geoid** — the equipotential gravity surface approximating mean sea level; the reference for **orthometric height H** (the ''elevation'' a level gives).\n- **Geoid undulation N** — the separation between geoid and ellipsoid (negative across most of the conterminous U.S.).\n\n**The single most-tested geodesy relationship:**\n\n`H = h − N`   (equivalently `h = H + N`)\n\nA **geoid model** (e.g., GEOID18, and the upcoming **GEOID2022**) supplies N so GNSS ellipsoidal heights can be converted to usable orthometric elevations.\n\n## Datums and reference frames\n\n- **NAD83** — the horizontal datum for U.S. surveying (uses the **GRS80** ellipsoid). Realized through CORS/HARN.\n- **WGS84** — the GPS broadcast datum; now essentially coincident with ITRF at the ~cm level (NAD83 differs from WGS84/ITRF by 1–2 m due to plate motion and origin definition).\n- **NAVD88** — the current vertical datum (orthometric).\n- **GRS80** — the reference ellipsoid (a = 6,378,137 m, 1/f = 298.257222101).\n- **2022 modernization (NGS)** — replaces NAD83 and NAVD88 with the **terrestrial reference frames** of the **North American Terrestrial Reference Frame of 2022 (NATRF2022)** (plus Pacific/Caribbean/Mariana frames) for horizontal and the **North American–Pacific Geopotential Datum of 2022 (NAPGD2022)** for vertical, with **GEOID2022** providing N. These are plate-fixed, time-dependent (epoch) frames aligned to the ITRF and realized largely by GNSS/CORS rather than passive marks.\n\n## Map projections and SPCS\n\nA **projection** flattens the curved ellipsoid onto a plane, introducing **distortion**; surveying uses **conformal** projections (angles preserved locally). Two families dominate U.S. State Plane:\n\n- **Lambert Conformal Conic (LCC)** — a cone; best for zones that are **long east–west** (e.g., Texas zones, Pennsylvania).\n- **Transverse Mercator (TM)** — a cylinder; best for zones **long north–south** (e.g., Illinois, New Jersey).\n- (**Oblique Mercator** is used for the Alaska panhandle Zone 1.)\n\nThe **State Plane Coordinate System (SPCS)** divides each state into zones sized so the **scale distortion stays within about 1:10,000**. **UTM** (Universal Transverse Mercator) is a global TM system in 6°-wide zones; its central-meridian scale factor is fixed at **0.9996** (larger distortion than SPCS, so SPCS is preferred for local surveying).\n\n## Grid vs. ground, and convergence\n\n**Grid** distances/coordinates live on the projection; **ground** distances are what you measure with an EDM. Convert with the **combined factor**:\n\n- **Scale factor (SF)** — projection distortion (ellipsoid → grid); near 1 (e.g., 0.9999).\n- **Elevation (sea-level) factor (EF)** — reduces a ground distance to the ellipsoid: `EF = R/(R + H + N) ≈ R/(R + h)`, R ≈ 20,906,000 ft.\n- **Combined scale factor:** `CSF = SF × EF`.\n- **`grid = ground × CSF`**, and **`ground = grid / CSF`**.\n\n**Convergence γ** (the **mapping angle**) is the angle between **grid north** and **geodetic (true) north** at a point; it grows with distance from the zone''s central meridian. Grid azimuth = geodetic azimuth − γ + the small **arc-to-chord (t−T)** correction."},{"type":"formulas","title":"Essential Formulas","content":"## Heights (NCEES Handbook — Geodesy)\n\n| Quantity | Formula | Notes |\n|---|---|---|\n| Height relationship | `h = H + N`  →  `H = h − N` | h = ellipsoidal, H = orthometric, N = geoid undulation |\n| Geoid undulation | `N = h − H` | from a geoid model (GEOID18 / GEOID2022) |\n\n**Memory hook:** ellipsoidal (GNSS) is ''higher up the alphabet'' — `h = H + N`. To get the elevation you *subtract* the (usually negative) undulation: `H = h − N`.\n\n## Distance reduction chain (SPCS — Handbook State Plane section)\n\n| Step | Formula |\n|---|---|\n| Elevation (sea-level) factor | `EF = R / (R + H + N) ≈ R / (R + h)`,  R ≈ 20,906,000 ft |\n| Projection scale factor | `SF` (from the zone''s projection / published value) |\n| Combined scale factor | `CSF = SF × EF` |\n| Ground → grid | `D_grid = D_ground × CSF` |\n| Grid → ground | `D_ground = D_grid / CSF` |\n| Ellipsoid (geodetic) distance | `D_E = D_ground × EF` (ground → ellipsoid) |\n| Arc-to-chord (t−T) | `AR − CH = CH³ / (24R²)` |\n\n(For precision looser than ~1:200,000 you may use R ≈ 20,906,000 ft and neglect N, so `EF ≈ R/(R+H)`.)\n\n## GNSS error budget and DOP\n\n| Quantity | Formula |\n|---|---|\n| Baseline error budget | `σ = a + b·L`  (a in mm, b in ppm, L in km) |\n| Position error from DOP | `σ_pos = UERE × DOP`  (use HDOP, VDOP, or PDOP for the matching component) |\n| Geometric range, satellite→receiver | `ρ = √((Xs−Xr)² + (Ys−Yr)² + (Zs−Zr)²)` |\n\n## Ellipsoid geometry (Handbook — Geodesy)\n\n| Quantity | Formula |\n|---|---|\n| Flattening | `f = (a − b)/a`  (published as 1/f) |\n| Eccentricity² | `e² = (a² − b²)/a²` |\n| Radius in the meridian | `M = a(1 − e²)/(1 − e²·sin²φ)^{3/2}` |\n| Radius in the prime vertical | `N_pv = a/(1 − e²·sin²φ)^{1/2}` |\n| GRS80 ellipsoid | a = 6,378,137.0 m, 1/f = 298.257222101 |\n| Orthometric correction | `−0.005288·sin 2φ·Δφ·(arc 1′)` |\n\n## Convergence / azimuth\n\n`Az_grid = Az_geodetic − γ + (t − T)`\n\nγ = convergence (mapping angle, grid north relative to geodetic north); (t − T) = arc-to-chord correction (small, often negligible for short lines)."},{"type":"examples","title":"Worked Examples","content":"## The measurement-to-map chain, illustrated\n\n<svg width=\"480\" height=\"260\" viewBox=\"0 0 480 260\" xmlns=\"http://www.w3.org/2000/svg\" style=\"background:#fff;border:1px solid #ccc\">\n  <!-- terrain -->\n  <path d=\"M20,70 Q140,40 260,75 T460,70\" fill=\"none\" stroke=\"#7a5230\" stroke-width=\"2\"/>\n  <text x=\"24\" y=\"62\" font-size=\"12\" fill=\"#7a5230\">Ground (terrain), height H above geoid</text>\n  <!-- geoid -->\n  <path d=\"M20,150 Q140,140 260,152 T460,150\" fill=\"none\" stroke=\"#1c4e80\" stroke-width=\"2\"/>\n  <text x=\"24\" y=\"168\" font-size=\"12\" fill=\"#1c4e80\">Geoid (≈ MSL) — datum for orthometric H</text>\n  <!-- ellipsoid -->\n  <line x1=\"20\" y1=\"200\" x2=\"460\" y2=\"200\" stroke=\"#888\" stroke-width=\"2\" stroke-dasharray=\"6 4\"/>\n  <text x=\"24\" y=\"218\" font-size=\"12\" fill=\"#555\">Ellipsoid (GRS80) — datum for ellipsoidal h (GNSS)</text>\n  <!-- vertical ties at x=300 -->\n  <line x1=\"300\" y1=\"73\" x2=\"300\" y2=\"200\" stroke=\"#333\" stroke-width=\"1\"/>\n  <line x1=\"300\" y1=\"73\" x2=\"300\" y2=\"152\" stroke=\"#c0392b\" stroke-width=\"3\"/>\n  <text x=\"305\" y=\"120\" font-size=\"12\" fill=\"#c0392b\">H (orthometric)</text>\n  <line x1=\"300\" y1=\"152\" x2=\"300\" y2=\"200\" stroke=\"#1c4e80\" stroke-width=\"3\"/>\n  <text x=\"305\" y=\"180\" font-size=\"12\" fill=\"#1c4e80\">N (undulation)</text>\n  <text x=\"360\" y=\"140\" font-size=\"12\" fill=\"#333\">h = H + N</text>\n  <circle cx=\"300\" cy=\"73\" r=\"3\" fill=\"#000\"/>\n  <text x=\"308\" y=\"70\" font-size=\"11\">survey point</text>\n</svg>\n\n---\n\n## Example 1 — Orthometric height from a GNSS observation (H = h − N)\n\nA GNSS survey gives an **ellipsoidal height h = 1,250.00 ft** at a station. The geoid model returns a **geoid undulation N = −29.50 ft** there. Find the **orthometric height (elevation) H**.\n\n`H = h − N = 1,250.00 − (−29.50) = 1,279.50 ft`\n\n**Why it''s larger:** N is negative across most of the lower-48, so the ellipsoid sits *above* the geoid; subtracting a negative undulation *adds* to the elevation. **Calculator (any approved model):** simply `1250 − (−29.5) =`. The only trap is the **sign of N** — read it off the geoid model exactly.\n\n---\n\n## Example 2 — Geoid undulation from known h and H\n\nA benchmark has a published **orthometric elevation H = 612.40 ft** (NAVD88). A static GNSS occupation gives **h = 587.10 ft**. Find the **geoid undulation N** at the mark.\n\n`N = h − H = 587.10 − 612.40 = −25.30 ft`\n\nThis is exactly how a GNSS-on-benchmarks campaign *measures* the geoid to validate a model. **Sanity check:** N is negative (typical for the conterminous U.S.), and |N| is a few tens of feet — reasonable.\n\n---\n\n## Example 3 — Combined factor and ground → grid distance\n\nAt a project site the **projection scale factor SF = 0.9999012** and the station elevation is **H = 4,500 ft** (geoid undulation small, neglected). Reduce a measured **ground distance of 2,456.78 ft** to a **grid distance** for State Plane.\n\n1. **Elevation factor** `EF = R/(R + H) = 20,906,000 / (20,906,000 + 4,500) = 0.9997848`.\n2. **Combined factor** `CSF = SF × EF = 0.9999012 × 0.9997848 = 0.9996860`.\n3. **Grid distance** `D_grid = D_ground × CSF = 2,456.78 × 0.9996860 = 2,456.01 ft`.\n\n**Calculator (TI-36X Pro / Casio fx-991):** compute EF, store it (`STO`), multiply by SF for CSF, then multiply the ground distance. The grid distance is **shorter** here because both factors are < 1 (elevation > sea level *and* this zone projects slightly small). **Trap:** at high elevations EF can dominate; near the standard parallels SF can exceed 1.\n\n---\n\n## Example 4 — Grid → ground (the reverse reduction)\n\nState Plane inversed a line as **grid distance 2,456.78 ft**. The combined factor for the area is **CSF = 0.9998765**. What **ground distance** would you stake?\n\n`D_ground = D_grid / CSF = 2,456.78 / 0.9998765 = 2,457.08 ft`\n\nTo go from grid back to ground you **divide** by the combined factor (the inverse of grid = ground × CSF). The ground distance is slightly **longer**, by about 0.30 ft over this line — exactly the kind of error that shows up when crews stake grid coordinates without applying the factor.\n\n---\n\n## Example 5 — Baseline error budget and DOP\n\n**(a) Baseline accuracy.** A receiver pair is specified at **a = 5 mm + 1 ppm**. For a **12.34 km** baseline, the expected horizontal uncertainty is:\n\n`σ = a + b·L = 5 mm + (1 ppm)(12.34 km) = 5 + 1×12.34 = 17.34 mm` (≈ 0.017 m).\n\n(1 ppm = 1 mm per km, so b·L = 12.34 mm.)\n\n**(b) Position error from DOP.** If the **UERE ≈ 2.5 m** and the current **PDOP = 3.2**, the expected 3-D position error is:\n\n`σ_pos = UERE × PDOP = 2.5 × 3.2 = 8.0 m`.\n\n**Takeaway:** wait for a **low DOP** window — the same ranging error produces far smaller position error when the satellite geometry is strong. **Calculator:** both are one-line multiplications; the only skill is matching the right DOP (HDOP/VDOP/PDOP) to the component asked.\n\n---\n\n## Example 6 — Convergence and grid azimuth (concept-to-number)\n\nAt a station the **convergence (mapping angle) γ = +1°12′30″** and the (t−T) arc-to-chord correction is negligible. A line has a **geodetic azimuth of 87°45′00″**. The **grid azimuth** is:\n\n`Az_grid = Az_geodetic − γ = 87°45′00″ − 1°12′30″ = 86°32′30″`.\n\nConvergence is **positive east of the central meridian** (grid north lies west of true north there), so grid azimuths come out *smaller* than geodetic. **Calculator:** subtract in DMS mode (TI/Casio `°’”`)."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Strategy for the geodesy / GNSS area\n\n- **This is a vocabulary-and-concept area first, a math area second.** Most points come from knowing *which surface, datum, projection, or method* is correct — fast questions you should bank early in the exam. The few calculations (H = h − N, grid = ground × CSF) are one-liners.\n- **Lock down the three surfaces.** Ellipsoid (GNSS h), geoid (orthometric H, ≈ MSL), and the undulation N between them. If you can recite `H = h − N` and explain why N is usually negative in the U.S., you own the most-tested item.\n- **Datum vs. projection vs. coordinate system** are different things: a *datum* (NAD83) defines the reference frame; a *projection* (Lambert / Transverse Mercator) flattens it; SPCS/UTM are *coordinate systems* built on a projection. Watch questions that swap these.\n- **Know the projection-to-state shape rule:** **Lambert Conformal Conic for east–west zones, Transverse Mercator for north–south zones.** Texas (wide E–W) uses Lambert.\n- **Currency:** the FS still references NAD83/NAVD88, but be ready for one item on the **2022 modernization** — NATRF2022 (horizontal), NAPGD2022 (vertical), GEOID2022 — which replaces passive monuments with GNSS/CORS-realized, time-dependent frames.\n\n## Approved-calculator tricks (TI-36X Pro / Casio fx-991 / HP-35S)\n\n- **EF and CSF are short chains — store intermediates.** Compute `EF = R/(R+H)`, `STO` it, multiply by SF for CSF, then by the distance. Re-keying R = 20,906,000 ft each time invites blunders; store it once.\n- **Direction of the factor:** **ground → grid = multiply; grid → ground = divide.** Sanity-check: at elevation, ground is longer than grid, so the ground number should be the bigger one.\n- **DMS for convergence:** enter γ and azimuths with the `°’”` (TI/Casio) key; HP-35S uses `→HR`/`→HMS`. Keep the calculator in **DEGREE** mode.\n- **ppm is mm-per-km:** `b ppm × L km` gives millimeters directly — no unit gymnastics. Add the constant term `a` (also mm).\n- **DOP is a pure multiplier:** `σ_pos = UERE × DOP`. Match HDOP to horizontal, VDOP to vertical, PDOP to 3-D.\n\n## Common traps\n\n- **Sign of N:** `H = h − N`. With N negative (typical U.S.), the orthometric height ends up *larger* than the ellipsoidal height. Flip the sign and you lose the point.\n- **Multiply vs. divide the combined factor:** grid = ground × CSF; ground = grid ÷ CSF.\n- **Lower DOP is better.** A ''high DOP'' (poor geometry) inflates position error — don''t pick it as the ''good'' condition.\n- **Multipath is not removed by differencing** (it is site-specific); the dual-frequency cure is for the *ionosphere*.\n- **UTM scale factor is fixed 0.9996** at the central meridian; SPCS zones are tighter (~1:10,000), which is *why* SPCS is preferred for local work.\n- **Ellipsoidal height ≠ elevation.** A GNSS ''height'' is not an orthometric elevation until you apply the geoid model.\n- **WGS84 vs. NAD83** differ by 1–2 m — they are not interchangeable for survey-grade work even though both use ~GRS80-class ellipsoids.\n\n## How the handbook helps\n\nThe NCEES FS Reference Handbook v2.5 gives, verbatim: the **height relationship h = H + N** and ellipsoid constants (Geodesy section); the **State Plane** distance-reduction chain (`EF = R/(R+H+N)`, combined factor, arc-to-chord); GRS80/Clarke-1866 ellipsoid parameters; and the unit conversions (R ≈ 20,906,000 ft ≈ 6,372,000 m). Know *where* each lives so you can confirm a factor in seconds instead of deriving it under time pressure."}]'::jsonb, 5, 70, 35, '🛰️', 550, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb065000-0000-0000-0000-000000000001', 'Orthometric height from GNSS (H = h − N)', 'Orthometric height from GNSS (H = h − N)', 'FS — Surveying Principles / Geodesy', 'Heights', 'numeric_input', 'easy', 'A GNSS survey returns an ellipsoidal height h = {{h:f2}} ft at a station. The geoid model gives a geoid undulation N = {{N:f2}} ft. Compute the orthometric height (elevation) H, in feet.', 'h - N', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"h","type":"float","min":300,"max":6000,"decimals":2},{"name":"N","type":"float","min":-35,"max":-15,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Height relationship","formula":"H = h − N","calculation_template":"{{h:f2}} − ({{N:f2}})"},{"step_number":2,"title":"Result","result_template":"H = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'The orthometric height is H = h − N = {{h:f2}} − ({{N:f2}}) = {{_answer}} ft. Because the geoid undulation N is negative, subtracting it makes H larger than the ellipsoidal height h.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000002', 'Geoid undulation from h and H (N = h − H)', 'Geoid undulation from h and H (N = h − H)', 'FS — Surveying Principles / Geodesy', 'Heights', 'numeric_input', 'easy', 'A benchmark has a published orthometric elevation H = {{H:f2}} ft. A static GNSS occupation gives an ellipsoidal height h = {{h:f2}} ft. Compute the geoid undulation N at the mark, in feet.', 'h - H', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"H","type":"float","min":400,"max":5000,"decimals":2},{"name":"dN","type":"float","min":-35,"max":-15,"decimals":2}]'::jsonb, '[{"name":"h","formula":"H + dN"}]'::jsonb, '[{"step_number":1,"title":"Rearrange the height relationship","formula":"N = h − H","calculation_template":"{{h:f2}} − {{H:f2}}"},{"step_number":2,"title":"Result","result_template":"N = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'From h = H + N, the geoid undulation is N = h − H = {{h:f2}} − {{H:f2}} = {{_answer}} ft. A negative N (typical of the conterminous U.S.) means the geoid lies below the ellipsoid here.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000003', 'Elevation factor at a station', 'Elevation factor at a station', 'FS — Surveying Principles / Geodesy', 'State Plane', 'numeric_input', 'medium', 'A station is at elevation H = {{H:f2}} ft (geoid undulation neglected). Using a mean earth radius R = 20,906,000 ft, compute the elevation (sea-level) factor EF = R/(R + H). Report to 6 decimal places.', '20906000/(20906000+H)', '{"decimals":6,"unit":"","tolerance":0.000002}', '[{"name":"H","type":"float","min":500,"max":9000,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Elevation factor","formula":"EF = R/(R + H)","calculation_template":"20,906,000 / (20,906,000 + {{H:f2}})"},{"step_number":2,"title":"Result","result_template":"EF = {{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'EF = R/(R + H) = 20,906,000 / (20,906,000 + {{H:f2}}) = {{_answer}}. A higher elevation gives a smaller EF, reducing the ground distance toward the ellipsoid.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000004', 'Combined factor (scale × elevation)', 'Combined factor (scale × elevation)', 'FS — Surveying Principles / Geodesy', 'State Plane', 'numeric_input', 'medium', 'At a project site the projection scale factor SF = {{SF:f7}} and the station elevation is H = {{H:f2}} ft (geoid undulation neglected, R = 20,906,000 ft). Compute the combined scale factor CSF. Report to 7 decimal places.', 'SF*(20906000/(20906000+H))', '{"decimals":7,"unit":"","tolerance":5e-7}', '[{"name":"SF","type":"float","min":0.9998,"max":1.0001,"decimals":7},{"name":"H","type":"float","min":500,"max":8000,"decimals":2}]'::jsonb, '[{"name":"EF","formula":"20906000/(20906000+H)"}]'::jsonb, '[{"step_number":1,"title":"Elevation factor","formula":"EF = R/(R + H)","calculation_template":"20,906,000 / (20,906,000 + {{H:f2}}) = {{EF:f7}}"},{"step_number":2,"title":"Combined factor","formula":"CSF = SF × EF","calculation_template":"{{SF:f7}} × {{EF:f7}}"},{"step_number":3,"title":"Result","result_template":"CSF = {{_answer}}"}]'::jsonb, '{"method":"none"}'::jsonb, 'First EF = R/(R + H) = {{EF:f7}}. Then CSF = SF × EF = {{SF:f7}} × {{EF:f7}} = {{_answer}}. Multiply a ground distance by this combined factor to obtain the State Plane grid distance.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000005', 'Ground distance reduced to grid', 'Ground distance reduced to grid', 'FS — Surveying Principles / Geodesy', 'Grid vs Ground', 'numeric_input', 'medium', 'A ground distance of {{dist:f2}} ft is to be placed on the State Plane grid where the combined scale factor CSF = {{csf:f7}}. Compute the grid distance, in feet.', 'dist*csf', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"dist","type":"float","min":800,"max":6000,"decimals":2},{"name":"csf","type":"float","min":0.9996,"max":1.0001,"decimals":7}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Ground → grid","formula":"D_grid = D_ground × CSF","calculation_template":"{{dist:f2}} × {{csf:f7}}"},{"step_number":2,"title":"Result","result_template":"D_grid = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'To go from ground to grid, multiply by the combined factor: D_grid = {{dist:f2}} × {{csf:f7}} = {{_answer}} ft. With CSF < 1 the grid distance is shorter than the measured ground distance.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000006', 'Grid distance reduced to ground', 'Grid distance reduced to ground', 'FS — Surveying Principles / Geodesy', 'Grid vs Ground', 'numeric_input', 'medium', 'A State Plane inverse gives a grid distance of {{dist:f2}} ft. The combined scale factor for the area is CSF = {{csf:f7}}. Compute the ground distance to stake, in feet.', 'dist/csf', '{"decimals":2,"unit":"ft","tolerance":0.02}', '[{"name":"dist","type":"float","min":800,"max":6000,"decimals":2},{"name":"csf","type":"float","min":0.9996,"max":1.0001,"decimals":7}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Grid → ground","formula":"D_ground = D_grid / CSF","calculation_template":"{{dist:f2}} / {{csf:f7}}"},{"step_number":2,"title":"Result","result_template":"D_ground = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'To recover the ground distance, divide the grid distance by the combined factor: D_ground = {{dist:f2}} / {{csf:f7}} = {{_answer}} ft. With CSF < 1 the ground distance is longer than the grid distance.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000007', 'GNSS baseline error budget (a + b·ppm)', 'GNSS baseline error budget (a + b·ppm)', 'FS — Surveying Processes / GNSS', 'GNSS Accuracy', 'numeric_input', 'easy', 'A GNSS receiver pair is specified at {{a:f1}} mm + {{b:f1}} ppm. For a baseline of {{km:f2}} km, compute the expected horizontal uncertainty, in millimeters.', 'a + b*km', '{"decimals":2,"unit":"mm","tolerance":0.05}', '[{"name":"a","type":"float","min":2,"max":8,"decimals":1},{"name":"b","type":"float","min":0.5,"max":2,"decimals":1},{"name":"km","type":"float","min":3,"max":30,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Error budget","formula":"σ = a + b·L","calculation_template":"{{a:f1}} + {{b:f1}} × {{km:f2}}"},{"step_number":2,"title":"Result","result_template":"σ = {{_answer}} mm"}]'::jsonb, '{"method":"none"}'::jsonb, 'The baseline error is σ = a + b·L = {{a:f1}} mm + {{b:f1}} ppm × {{km:f2}} km = {{_answer}} mm. One ppm equals 1 mm per km, so the distance-dependent term is b·L millimeters.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');
  'fb065000-0000-0000-0000-000000000008', 'Position error from DOP (σ = UERE × DOP)', 'Position error from DOP (σ = UERE × DOP)', 'FS — Surveying Processes / GNSS', 'GNSS Accuracy', 'numeric_input', 'easy', 'A GNSS observation has a user-equivalent range error UERE = {{uere:f2}} m and a PDOP of {{pdop:f2}}. Compute the expected 3-D position error, in meters.', 'uere*pdop', '{"decimals":2,"unit":"m","tolerance":0.02}', '[{"name":"uere","type":"float","min":1,"max":4,"decimals":2},{"name":"pdop","type":"float","min":1.5,"max":6,"decimals":2}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Position error from DOP","formula":"σ_pos = UERE × DOP","calculation_template":"{{uere:f2}} × {{pdop:f2}}"},{"step_number":2,"title":"Result","result_template":"σ_pos = {{_answer}} m"}]'::jsonb, '{"method":"none"}'::jsonb, 'Position error scales the ranging error by the geometry: σ_pos = UERE × PDOP = {{uere:f2}} × {{pdop:f2}} = {{_answer}} m. A lower DOP (stronger geometry) gives a smaller position error.', 'f5000006-0000-0000-0000-000000000006', 'FS', ARRAY['fs-buildout','fs-m6','fs-practice']::text[], NULL, true, 'fs:m6');

-- ===== FS Module 7: Boundary Law and Public Lands =====
DELETE FROM question_bank WHERE module_id='f5000007-0000-0000-0000-000000000007' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m7' = ANY(tags);
DELETE FROM problem_templates WHERE created_by='fs:m7';
VALUES ('f5000007-0000-0000-0000-000000000007', 7, 'Boundary Law and Public Lands', 'The largest knowledge area on the FS exam: the Public Land Survey System (townships, ranges, sections, aliquot parts, section subdivision, and lost/obliterated-corner restoration by single and double proportionate measurement), the three systems of legal description (metes-and-bounds, lot-and-block, PLSS), the dignity/priority of calls and the footsteps doctrine, senior/junior rights, simultaneous vs. sequential conveyances, riparian/littoral water boundaries, adverse possession, easements, recording, and boundary-related ethics — with Texas (GLO grant, vara, no-PLSS) callouts throughout.', 'Weeks 13-16', 20, ARRAY['PLSS framework: principal meridian/base line, townships, ranges, sections','Numbering and acreage of sections (1 section = 640 acres = 1 sq mile)','Aliquot parts and section subdivision (quarters, quarter-quarters, half-quarters)','Lost vs. obliterated vs. existent corners; corner accessories and bearing trees','Single proportionate measurement (corner on a single line)','Double proportionate measurement (corner controlled in two directions)','Legal descriptions: metes-and-bounds, lot-and-block (platted), PLSS aliquot','Dignity/priority of calls and the footsteps-of-the-original-surveyor doctrine','Senior/junior rights; simultaneous vs. sequential conveyances; excess & deficiency','Riparian/littoral boundaries; accretion, reliction, erosion, avulsion; navigable beds','Adverse possession elements and easements (express, implied, prescriptive)','Recording acts (notice/race/race-notice), chain of title, BFP doctrine','Texas specifics: GLO original-survey/abstract system, no PLSS grid, the vara','Boundary-related professional ethics and the surveyor''s duty in retracement']::text[], '[{"name":"Area of a standard section","formula":"1 section = 1 sq mile = 640 acres"},{"name":"Aliquot part area","formula":"A = (product of the aliquot fractions) × 640 acres"},{"name":"Quarter section","formula":"¼ × 640 = 160 acres"},{"name":"Quarter-quarter (forty)","formula":"¼ × ¼ × 640 = 40 acres"},{"name":"Half of a quarter","formula":"½ × ¼ × 640 = 80 acres"},{"name":"Acre definition","formula":"1 acre = 43,560 ft² = 10 sq chains"},{"name":"Chain / mile","formula":"1 chain = 66 ft; 1 mile = 80 chains = 5,280 ft"},{"name":"Single proportion (corrected interval)","formula":"d'' = D_record × (L_measured / L_record)"},{"name":"Single proportion (restored coordinate)","formula":"C = C₁ + (C₂ − C₁) × (record dist to corner / total record dist)"},{"name":"Texas vara","formula":"1 vara = 33⅓ in = 2.7778 ft;  ft = vrs × 2.7778 = vrs ÷ 0.36"},{"name":"Texas labor / league","formula":"1 labor ≈ 177.1 ac; 1 league (sitio) = 25 labors ≈ 4,428 ac"}]'::jsonb, '[{"type":"overview","title":"Module Overview","content":"## The heaviest area on the FS exam\n\n**Boundary Law and Real Property Principles is the single largest knowledge area on the NCEES FS exam — 19 to 29 of the 110 questions (roughly 17–26%).** Do not treat the FS as a pure math test: more points live here than in any computational area, and most boundary questions are conceptual, fast to answer, and high-return. A candidate who masters this module banks a large block of quick points while others burn time on long COGO problems.\n\nBoundary law answers one question: **where is the line, and who owns the land?** It is answered with three intertwined systems:\n\n1. **The Public Land Survey System (PLSS)** — the federal rectangular grid of townships, ranges, sections, and **aliquot parts** that organizes most of the 30 \"public-land states.\" You must be able to number a section, subdivide it, compute aliquot-part acreage, and **restore a lost corner** by single or double proportionate measurement using the BLM *Manual of Surveying Instructions*.\n\n2. **Legal descriptions** — **metes-and-bounds** (a perimeter of bearings, distances, and monuments), **lot-and-block** (reference to a recorded subdivision plat), and **PLSS aliquot** (e.g., the *NE¼ of the SW¼ of Sec. 14*). Each must unambiguously locate one closed parcel.\n\n3. **Common-law boundary doctrine** — the **dignity (priority) of calls**, the **footsteps of the original surveyor**, **senior/junior rights**, **simultaneous vs. sequential** conveyances, **water boundaries** (riparian/littoral, accretion/avulsion), **adverse possession**, **easements**, and **recording/chain of title**.\n\nThroughout, watch for **Texas specifics**: Texas was **never federal public domain**, so **most of Texas has no PLSS township-range grid** — Texas land is metes-and-bounds keyed to an **original General Land Office (GLO) survey + abstract number**, measured historically in **varas**. These Texas-vs-PLSS distinctions are flagged in callouts and appear on the Texas SIT. Every concept here is exam-aligned to the NCEES FS specification (Area 3) and the supplied standards."},{"type":"concepts","title":"Key Concepts","content":"## 1. The Public Land Survey System (PLSS)\n\nThe PLSS (begun under the Land Ordinance of 1785, administered today by the **BLM**, successor to the federal **General Land Office**) lays a **rectangular grid** over the public domain. It is built from an **initial point**, from which run a **principal meridian** (north–south) and a **base line** (east–west).\n\n- **Township strips** run east–west, numbered north or south of the base line: **T2N, T3S**, etc.\n- **Range strips** run north–south, numbered east or west of the principal meridian: **R4E, R1W**, etc.\n- A **township** is the 6 mi × 6 mi square at the intersection of a township row and a range column — nominally **36 sq miles**, containing **36 sections**.\n\n**Section numbering is a boustrophedon (\"ox-plow\") serpentine:** Section 1 is in the **NE corner**, numbering runs **west** across the top to 6, **drops down** to 7, runs **east** to 12, drops to 13, and so on, ending at **Section 36 in the SE corner**.\n\n```\n  6  5  4  3  2  1\n  7  8  9 10 11 12\n 18 17 16 15 14 13\n 19 20 21 22 23 24\n 30 29 28 27 26 25\n 31 32 33 34 35 36\n```\n\nA **standard section is 1 mile square = 640 acres.** Because the Earth converges toward the poles, the grid cannot be perfectly square: **standard parallels (correction lines)** and **guide meridians** periodically reset the grid, and the resulting deficiency or surplus is thrown into the **west and north tiers** of the township as irregular **government lots** (e.g., along a meander line or the township''s NW corner). Sections 6 and along the north/west edges therefore commonly contain fractional government lots rather than clean aliquot parts.\n\n## 2. Aliquot parts and section subdivision\n\nA section is subdivided by repeated halving and quartering into **aliquot parts**. The acreage of any aliquot part is simply the **product of its fractions times 640 acres**:\n\n- **Quarter section** (NE¼) = ¼ × 640 = **160 acres**\n- **Quarter-quarter** (NE¼ of the NW¼), the classic **\"forty\"** = ¼ × ¼ × 640 = **40 acres**\n- **Half of a quarter** (N½ of the NW¼) = ½ × ¼ × 640 = **80 acres**\n- **Half-half-quarter** (S½ of the NE¼ of the SW¼) = ½ × ¼ × ¼ × 640 = **20 acres**\n\n**Read the description right-to-left** to nest the parts: \"the *NE¼ of the SW¼*\" means *take the SW quarter (160 ac), then its NE quarter (40 ac)*. The center-quarter corners and quarter-quarter corners are set by **straight lines connecting opposite quarter and sixteenth corners** on the section boundary (the BLM \"3-3 rule\" of subdivision), **not** by measuring nominal 1,320-ft distances — found original corners control, and any excess/deficiency falls into the northern/western lots.\n\n## 3. Existent, obliterated, and lost corners\n\nWhen retracing a PLSS line you must classify each original corner:\n\n- **Existent corner** — its position can be recovered from the original monument or undisturbed accessories, beyond reasonable doubt. **It controls; never disturb it.**\n- **Obliterated corner** — no trace of the monument remains, **but its position can be recovered from collateral evidence** (testimony, fences/occupation lines, bearing trees, found accessories, adjoiner deeds). An obliterated corner is **not** lost.\n- **Lost corner** — its position **cannot be recovered from any acceptable evidence**, original or collateral, and can be restored **only by proportionate measurement** from surrounding existent corners. Proportioning is a **last resort.**\n\n**Corner accessories** — **bearing trees** (scribed trees with recorded bearings/distances to the corner), **mounds, pits, and memorial objects** — are the surveyor''s primary collateral evidence for recovering an obliterated corner.\n\n## 4. Proportionate measurement\n\nProportionate measurement restores a **lost** corner so the restored point bears the **same ratio to the corrected whole as the record interval bears to the record whole**, distributing the accumulated discrepancy uniformly.\n\n- **Single proportionate measurement (\"two-way\")** — for a corner that lies on **one line** between two found corners (e.g., a quarter corner between two section corners, or a lost corner on a township exterior). Distribute the measured-vs-record difference along that single line:  `d'' = D_record × (L_measured / L_record)`.\n- **Double proportionate measurement** — for a corner **controlled in two directions** (the typical **interior section corner**, common to four sections, controlled by the nearest found corners **north, south, east, and west**). Proportion **independently** in the N–S direction and the E–W direction to get two trial positions, then the corner is set at the intersection (the latitudinal value from the E–W proportion, the longitudinal value from the N–S proportion).\n\n**Order of precedence is the exam point:** existent monuments → obliterated corners recovered by collateral evidence → **only then** lost-corner proportioning. A gross **blunder** is placed where it belongs; only ordinary distributed error is proportioned.\n\n## 5. Legal descriptions\n\n- **Metes-and-bounds** — a perimeter run: a **point of beginning (POB)**, a series of **calls** (bearing + distance), **monuments**, and closure back to the POB. The original system of the 13 colonies and of Texas.\n- **Lot-and-block (platted)** — references a **recorded subdivision plat**: \"Lot 7, Block 3, of Sunset Addition, recorded in Vol. __, Pg. __.\" The plat (a **simultaneous** conveyance) controls; lots have no seniority among themselves.\n- **PLSS aliquot** — \"the SE¼ of the NW¼ of Sec. 14, T2N, R3E, [meridian].\" Compact and self-locating within the grid.\n\n## 6. Dignity (priority) of calls and footsteps\n\nWhen the calls in one description **conflict**, they are ranked by relative reliability (\"dignity\"), highest to lowest:\n\n1. **Calls for natural monuments** (rivers, lakes, established trees, rock outcrops)\n2. **Calls for artificial monuments** (set iron, stakes, marked trees, fences, road ROW)\n3. **Calls for adjoinder** (an adjacent, already-established survey line)\n4. **Course** (bearing/direction)\n5. **Distance**\n6. **Quantity / area / acreage** (the **weakest** — a check, not a control)\n\nThis hierarchy is **only a rule of construction** — a set of rebuttable presumptions — that **always yields to (i) the intent of the parties** (read within the four corners of the instrument) **and (ii) the footsteps of the original surveyor**: the line is located **where it was actually run on the ground**, even against later \"more accurate\" measurements. A found, identifiable original monument controls over conflicting course-and-distance calls.\n\n## 7. Senior/junior rights; simultaneous vs. sequential\n\n- **Sequential conveyances** (parcels carved off one at a time over time): **senior rights govern.** The **senior** (earlier) deed takes the full measure of its description; the **junior** (later) takes only the **remainder** — it absorbs any excess and eats any deficiency. **No proration.**\n- **Simultaneous conveyances** (all parcels created at one instant — classically, lots in a recorded plat): **no lot is senior.** Excess or deficiency found between controlling monuments is **apportioned proportionately** among the affected lots by their record dimensions. The order lots later *sold* is immaterial.\n\n## 8. Water boundaries\n\n- **Riparian** rights attach to land along a **flowing watercourse**; **littoral** rights attach to land along a **static body** (lake, sea).\n- On a **non-navigable** stream, the abutting owner generally takes to the **center thread**; on a **navigable** stream the bed below the ordinary high-water mark is **State-owned** (public-trust).\n- **Accretion** (gradual deposit) and **reliction** (gradual uncovering) **move the boundary** — the owner gains. **Erosion** moves it landward — the owner loses. **Avulsion** (a **sudden**, perceptible change — a flood cutting a new channel) **FIXES the boundary** at its former location.\n\n## 9. Adverse possession, easements, recording\n\n- **Adverse possession** matures title in a trespasser whose possession is **actual, open and notorious, exclusive, hostile (under a claim of right), and continuous** for the statutory period. (Texas instead runs a **statutory multi-track** 3/5/10/25-year scheme in Civ. Prac. & Rem. Code Ch. 16.)\n- **Easements** are **non-possessory** rights to use another''s land — created **expressly** (writing), by **implication/prior use**, by **necessity**, or by **prescription** (adverse use for the statutory period). An **appurtenant** easement runs with the land; an **easement in gross** is personal.\n- **Recording acts** give later purchasers notice and set priority. Three regimes: **race** (first to record wins), **notice** (a later bona-fide purchaser without notice wins, recording order irrelevant), and **race-notice** (later BFP wins only if without notice **and** records first). A **bona-fide purchaser (BFP)** pays value, in good faith, without actual or constructive notice."},{"type":"formulas","title":"Essential Formulas & Reference Facts","content":"## PLSS dimensions and acreage\n\n| Quantity | Value |\n|---|---|\n| Township | 6 mi × 6 mi = 36 sq mi = **36 sections** |\n| Standard section | 1 mi × 1 mi = **640 acres** |\n| Half section (N½, E½, …) | ½ × 640 = **320 acres** |\n| Quarter section (NE¼, …) | ¼ × 640 = **160 acres** |\n| Half-quarter (N½ of NW¼) | ½ × ¼ × 640 = **80 acres** |\n| Quarter-quarter (\"forty\") | ¼ × ¼ × 640 = **40 acres** |\n| Quarter-quarter-quarter (S½ of NE¼ of SW¼) | ½ × ¼ × ¼ × 640 = **20 acres** |\n\n**General aliquot rule:**  `Area (acres) = (product of all the aliquot fractions) × 640`.\n\n**Linear:** 1 section side = 1 mile = **80 chains = 5,280 ft**; a quarter-section side = ½ mile = 40 chains = **2,640 ft**; a quarter-quarter side = ¼ mile = 20 chains = **1,320 ft**.\n\n## Units (NCEES handbook v2.5)\n\n| Conversion | Value |\n|---|---|\n| 1 acre | **43,560 ft²** = 10 sq chains |\n| 1 chain | 100 links = **66 ft** = 4 rods/poles/perches |\n| 1 mile | 80 chains = **5,280 ft** |\n| 1 acre | 0.40469 hectare |\n| 1 sq mile | 640 acres |\n\n## Single proportionate measurement\n\nA lost corner on a single line between two found corners (1 and 2). Let `L_record` = total record distance 1→2, `L_measured` = total measured distance 1→2, `D_record` = record distance from corner 1 to the lost corner. The corrected (restored) distance from corner 1 is:\n\n`d'' = D_record × (L_measured / L_record)`\n\nEquivalently, restore each coordinate of the lost corner by linear interpolation between the found corners'' coordinates in proportion to the record distances:\n\n`C_restored = C₁ + (C₂ − C₁) × (D_record / L_record)`\n\n## Double proportionate measurement\n\nFor an interior corner controlled in two directions, proportion **separately**:\n- **Latitude (N–S) value** from the nearest found corners **N and S**, by their record N–S distances.\n- **Departure (E–W) value** from the nearest found corners **E and W**, by their record E–W distances.\n\nThe corner is set at the point having the proportioned **latitude** (from the N–S line) and the proportioned **departure** (from the E–W line). (A small final adjustment for the cardinal-offset is made per the BLM Manual; for FS purposes the two-direction proportion is the key idea.)\n\n## Dignity of calls (memorize the order)\n\n`Natural monuments  >  Artificial monuments  >  Adjoinder  >  Course  >  Distance  >  Quantity/area`\n\nAll subordinate to **(i) intent of the parties** and **(ii) footsteps of the original surveyor.**\n\n## Water-boundary changes\n\n| Process | Speed | Effect on boundary |\n|---|---|---|\n| **Accretion** | gradual addition | boundary **moves** (owner gains) |\n| **Reliction** | gradual uncovering | boundary **moves** (owner gains) |\n| **Erosion** | gradual loss | boundary **moves** (owner loses) |\n| **Avulsion** | **sudden** change | boundary **FIXED** at former line |\n\n## Texas conversions (callout)\n\n| Unit | Value |\n|---|---|\n| **1 vara** | 33⅓ in = **2.7778 ft** (36 varas = exactly 100 ft) |\n| Vara → feet | × 2.7778  (equivalently **÷ 0.36**) |\n| Feet → vara | × **0.36** |\n| 1 labor | 1,000,000 sq varas ≈ **177.1 acres** |\n| 1 league (sitio) | 25,000,000 sq varas = 25 labors ≈ **4,428 acres** |\n| League + labor | ≈ **4,605.5 acres** (standard married-head grant) |\n\n> **⚠️ Texas vs. PLSS:** Most of Texas has **no township-range grid.** Texas grants are **metes-and-bounds keyed to an original GLO survey + abstract number**, measured in varas. Do not read a Texas description in T/R/Section terms, and do not apply a non-Texas vara value to a Texas grant."},{"type":"examples","title":"Worked Examples","content":"## A labeled section with aliquot subdivision\n\nThe figure shows one **640-acre section** subdivided into quarters and the NW¼ further into quarter-quarters. Acreages are labeled; use it for Examples 1–3.\n\n<svg width=\"440\" height=\"440\" viewBox=\"0 0 440 440\" xmlns=\"http://www.w3.org/2000/svg\" style=\"background:#fff;border:1px solid #ccc\">\n  <defs>\n    <marker id=\"narr\" markerWidth=\"8\" markerHeight=\"8\" refX=\"6\" refY=\"3\" orient=\"auto\"><path d=\"M0,0 L6,3 L0,6 Z\" fill=\"#333\"/></marker>\n  </defs>\n  <line x1=\"22\" y1=\"60\" x2=\"22\" y2=\"24\" stroke=\"#333\" stroke-width=\"1.5\" marker-end=\"url(#narr)\"/>\n  <text x=\"15\" y=\"20\" font-size=\"12\" font-family=\"sans-serif\">N</text>\n  <!-- outer section 360x360 from (60,40) -->\n  <rect x=\"60\" y=\"40\" width=\"360\" height=\"360\" fill=\"#f7faf7\" stroke=\"#1c4e80\" stroke-width=\"2.5\"/>\n  <!-- quarter lines -->\n  <line x1=\"240\" y1=\"40\" x2=\"240\" y2=\"400\" stroke=\"#1c4e80\" stroke-width=\"1.5\"/>\n  <line x1=\"60\" y1=\"220\" x2=\"420\" y2=\"220\" stroke=\"#1c4e80\" stroke-width=\"1.5\"/>\n  <!-- NW quarter subdivided into 4 forties -->\n  <line x1=\"150\" y1=\"40\" x2=\"150\" y2=\"220\" stroke=\"#8a8a8a\" stroke-width=\"1\"/>\n  <line x1=\"60\" y1=\"130\" x2=\"240\" y2=\"130\" stroke=\"#8a8a8a\" stroke-width=\"1\"/>\n  <!-- labels -->\n  <text x=\"95\" y=\"92\" font-size=\"11\">NW¼NW¼</text>\n  <text x=\"100\" y=\"106\" font-size=\"10\" fill=\"#c0392b\">40 ac</text>\n  <text x=\"175\" y=\"92\" font-size=\"11\">NE¼NW¼</text>\n  <text x=\"182\" y=\"106\" font-size=\"10\" fill=\"#c0392b\">40 ac</text>\n  <text x=\"95\" y=\"182\" font-size=\"11\">SW¼NW¼</text>\n  <text x=\"100\" y=\"196\" font-size=\"10\" fill=\"#c0392b\">40 ac</text>\n  <text x=\"175\" y=\"182\" font-size=\"11\">SE¼NW¼</text>\n  <text x=\"182\" y=\"196\" font-size=\"10\" fill=\"#c0392b\">40 ac</text>\n  <text x=\"300\" y=\"135\" font-size=\"13\" font-weight=\"bold\">NE¼</text>\n  <text x=\"300\" y=\"152\" font-size=\"11\" fill=\"#c0392b\">160 ac</text>\n  <text x=\"120\" y=\"315\" font-size=\"13\" font-weight=\"bold\">SW¼</text>\n  <text x=\"120\" y=\"332\" font-size=\"11\" fill=\"#c0392b\">160 ac</text>\n  <text x=\"300\" y=\"315\" font-size=\"13\" font-weight=\"bold\">SE¼</text>\n  <text x=\"300\" y=\"332\" font-size=\"11\" fill=\"#c0392b\">160 ac</text>\n  <text x=\"150\" y=\"420\" font-size=\"11\" fill=\"#555\">1 section = 1 mi × 1 mi = 640 acres</text>\n</svg>\n\n---\n\n## Example 1 — Acreage of an aliquot part\n\n**Find the area of the *S½ of the NE¼ of the SW¼* of a regular section.**\n\nMultiply the fractions, then × 640:\n\n`A = ½ × ¼ × ¼ × 640 = (1/32) × 640 = 20.00 acres.`\n\n**Method:** read right-to-left — the SW¼ (160 ac), its NE¼ (40 ac), the S½ of that (20 ac). A clean way to do it on the calculator: `640 ÷ 2 ÷ 4 ÷ 4 =` → **20**. (Each \"half\" divides by 2, each \"quarter\" divides by 4.)\n\n**Calculator (TI-36X Pro / Casio fx-991):** `640 ÷ 2 ÷ 4 ÷ 4 =` returns **20**. No mode setting needed — this is pure arithmetic.\n\n---\n\n## Example 2 — A compound description\n\n**Find the area of the *N½ of the NW¼* plus the *SE¼ of the NW¼*.**\n\n- N½ of NW¼ = ½ × ¼ × 640 = **80 acres**\n- SE¼ of NW¼ = ¼ × ¼ × 640 = **40 acres**\n- **Total = 80 + 40 = 120 acres.**\n\nNote the whole NW¼ is 160 ac; this description takes the north half (80) plus one of the two southern forties (40) = 120, leaving the SW¼NW¼ (40 ac) out.\n\n---\n\n## Example 3 — Dimensions of a forty\n\n**A quarter-quarter (40-acre \"forty\") of a regular section is nominally how many feet on a side, and how many square feet?**\n\n- Side = ¼ mile = 20 chains = 20 × 66 = **1,320 ft.**\n- Area = 1,320 × 1,320 = 1,742,400 ft²; ÷ 43,560 = **40.00 acres** ✓ (the check).\n\n**Calculator:** `1320 x² =` → 1,742,400, then `÷ 43560 =` → **40**. (Remember a forty is a square 1,320 ft on a side only in the *ideal* regular section; found original corners govern the real dimensions.)\n\n---\n\n## Example 4 — Single proportionate measurement (lost corner on one line)\n\nA **quarter corner** is recorded **40.00 chains** from each adjacent **section corner** (record line length 80.00 ch). The quarter corner is **lost**. You remeasure the full line between the two **existent section corners** and get **80.40 chains** (40-link surplus). Where do you set the restored quarter corner?\n\n1. **Proportion the record distance:** `d'' = D_record × (L_measured / L_record) = 40.00 × (80.40 / 80.00) = 40.00 × 1.005 = 40.20 chains` from the first section corner.\n2. So the restored quarter corner is **40.20 ch** from each section corner — the **0.40-ch surplus is split equally** (0.20 ch to each half), exactly because the record split was 40/40.\n\n**Why proportion, not hold record?** The corner is *lost*, so no monument controls; single proportion distributes the accumulated surplus uniformly along the single line so neither half absorbs it all.\n\n**Calculator:** `40 × ( 80.40 ÷ 80 ) =` → **40.20**. (In coordinates: restored N,E = section-corner-1 coordinates + 0.5 × (corner-2 − corner-1), since the record fraction is 40/80 = 0.5.)\n\n---\n\n## Example 5 — Coordinate form of single proportion (unequal record split)\n\nFound corner **1** is at (N 1,000.00, E 1,000.00); found corner **2** is at (N 1,000.00, E 6,000.00) — a measured 5,000.00-ft line. The lost intermediate corner has a **record distance of 2,000.00 ft from corner 1** on a record line total of 5,000.00 ft. Restore its easting.\n\n1. **Record fraction:** `2,000 / 5,000 = 0.40`.\n2. **Restored E:** `E = E₁ + (E₂ − E₁) × 0.40 = 1,000 + (6,000 − 1,000) × 0.40 = 1,000 + 2,000 = 3,000.00 ft.`\n3. Northing is unchanged here (the line is due east), so the restored corner is **(N 1,000.00, E 3,000.00).**\n\n**Calculator:** `1000 + ( 6000 − 1000 ) × ( 2000 ÷ 5000 ) =` → **3,000**. This linear-interpolation form generalizes single proportion to any coordinate.\n\n---\n\n## Example 6 — Texas vara conversion (callout problem)\n\nA Texas GLO field note calls **\"S 45°00′ E, 950 vrs\"** to a corner. Convert the distance to feet, and give the latitude/departure.\n\n1. **Distance in feet:** `950 × 2.7778 = 2,638.9 ft` (or 950 ÷ 0.36 = 2,638.9 ft).\n2. **Bearing S 45°00′ E → azimuth** = 180° − 45° = **135°**. Lat = 2,638.9 × cos135° = **−1,866.1 ft** (south); Dep = 2,638.9 × sin135° = **+1,866.1 ft** (east).\n\n**Calculator:** `950 × 2.7778 =` → 2,638.9; then `× cos(135) =` → −1,866.1 and `× sin(135) =` → +1,866.1 (DEGREE mode). **Texas note:** the historic bearing is likely magnetic/assumed — a retracing surveyor must reconcile it to a modern datum (State Plane, NAD83) before plotting."},{"type":"tips","title":"Exam Tips & Calculator Strategy","content":"## Strategy for the boundary area (the biggest block of points)\n\n- **Treat Boundary Law as your point bank.** It is the **largest area (19–29 questions)** and most items are **definitions and short reasoning** you can answer in under a minute. On preview, sweep these first and bank them before the long COGO problems.\n- **Memorize the dignity of calls cold:** *natural > artificial > adjoinder > course > distance > quantity*, **all yielding to intent and the original surveyor''s footsteps.** Many questions are a single application of this ladder (e.g., \"a call to a blazed oak controls over a conflicting bearing/distance\").\n- **Know the PLSS section snake (1 in the NE, 36 in the SE) and the aliquot acreage shortcuts** (forty = 40, quarter = 160, eighty = 80). These are guaranteed quick points.\n- **Classify the corner before you act:** existent → obliterated (collateral evidence) → lost (proportion). Proportioning is **always a last resort**; the most-common trap answer says \"immediately proportion\" when an obliterated corner is recoverable from a bearing tree, fence, or testimony.\n- **Match the discrepancy rule to the conveyance type:** **sequential → senior/junior (no proration)**; **simultaneous (platted) → apportion excess/deficiency.** Reversing these is the classic boundary trap.\n\n## Aliquot / acreage calculator tricks\n\n- **Aliquot area = chain-divide 640.** Each \"half\" = `÷ 2`, each \"quarter\" = `÷ 4`. So *S½ of NE¼ of SW¼* = `640 ÷ 2 ÷ 4 ÷ 4 = 20`. Faster and less error-prone than multiplying fractions.\n- **Acre ↔ ft²:** divide ft² by **43,560** for acres; a forty checks as 1,320 × 1,320 = 1,742,400 ft² = 40 ac.\n- **Chains:** keep work in chains when the record is in chains (1 ch = 66 ft; 10 sq ch = 1 ac) — it avoids large numbers, then convert at the end.\n\n## Proportionate-measurement tricks\n\n- **Single proportion is one multiply:** `d'' = D_record × (L_measured / L_record)` — set up the ratio once, multiply each record interval. In coordinates it is **linear interpolation** between the two found corners by the record fraction — do it as `C₁ + (C₂ − C₁) × fraction` on the calculator.\n- **Double proportion = do it twice** (N–S, then E–W) and combine. Recognize it whenever the lost corner is an **interior section corner controlled in four directions**.\n- **Sanity-check direction:** the restored corner must fall *between* the controlling monuments and the surplus/deficiency must split per the record ratio — if a half ends up longer than the whole, you inverted the ratio.\n\n## Texas (SIT) callouts\n\n- **No PLSS in most of Texas** — Texas grants are **metes-and-bounds keyed to a GLO survey + abstract**, measured in **varas** (1 vara = 33⅓ in = 2.7778 ft; ÷0.36 for ft→vara). Convert varas before any COGO.\n- **Footsteps doctrine is strong in Texas** (*Stafford v. King*): follow the original surveyor''s monuments over inconsistent field-note calls. **Adverse possession in Texas is statutory** (Civ. Prac. & Rem. Code Ch. 16, the 3/5/10/25-year tracks), **not** the single common-law test — and the **§16.025 five-year track requires paying taxes.**\n\n## Common traps\n\n- **Quantity/area is the weakest call** — \"containing 5.00 acres more or less\" never controls over a monument or a course-and-distance.\n- **Avulsion fixes, accretion moves** — a sudden flood does **not** shift the boundary; gradual accretion does.\n- **A quitclaim conveys only what the grantor has** (no warranty); a **warranty deed** guarantees title.\n- **Recording acts:** a **notice** state lets a later BFP-without-notice win even if recorded second; **race-notice** requires the BFP to also record first. Texas is a **pure notice** state.\n- **Easements are non-possessory** and (if appurtenant) **pass with the land** — they cannot be conveyed separately from the dominant estate.\n\n## How the handbook helps\n\nThe NCEES FS Reference Handbook v2.5 gives the **Land Description (PLSS) diagram**, the **unit conversions** (acre = 43,560 ft²; chain = 66 ft; mile = 80 chains), and the **area-by-coordinates** formula. Most boundary-law questions, though, are **conceptual** and not in the handbook — they reward *prepared knowledge* of the dignity of calls, senior/junior rights, water-boundary doctrine, and the BLM corner-restoration rules. Study those cold; use the handbook only for the conversions and the PLSS diagram."}]'::jsonb, 6, 70, 37, '⚖️', 800, true, 'approved')
ON CONFLICT (module_number) DO UPDATE SET title=EXCLUDED.title, description=EXCLUDED.description, week_range=EXCLUDED.week_range, exam_weight_percent=EXCLUDED.exam_weight_percent, key_topics=EXCLUDED.key_topics, key_formulas=EXCLUDED.key_formulas, content_sections=EXCLUDED.content_sections, prerequisite_module=EXCLUDED.prerequisite_module, question_count=EXCLUDED.question_count, icon=EXCLUDED.icon, xp_reward=EXCLUDED.xp_reward, is_published=true, review_status='approved', updated_at=now();
  'fb075000-0000-0000-0000-000000000001', 'Area of an aliquot part (fraction × 640)', 'Area of an aliquot part (fraction × 640)', 'FS — Boundary Law and Public Lands', 'PLSS', 'numeric_input', 'easy', 'A regular PLSS section contains 640 acres. Compute the area, in acres, of an aliquot part formed by applying a {{f1:choice}}, then a {{f2:choice}}, then a {{f3:choice}} (e.g., ''the {{f3:choice}} of the {{f2:choice}} of the {{f1:choice}}''). Each ''half'' divides the area by 2 and each ''quarter'' divides it by 4.', '640/(d1*d2*d3)', '{"decimals":2,"unit":"acres","tolerance":0.05}', '[{"name":"f1","type":"choice","choices":["half","quarter"]},{"name":"f2","type":"choice","choices":["half","quarter"]},{"name":"f3","type":"choice","choices":["half","quarter"]},{"name":"d1","type":"computed"},{"name":"d2","type":"computed"},{"name":"d3","type":"computed"}]'::jsonb, '[{"name":"d1","formula":"f1==''half''?2:4"},{"name":"d2","formula":"f2==''half''?2:4"},{"name":"d3","formula":"f3==''half''?2:4"}]'::jsonb, '[{"step_number":1,"title":"Each fraction divides 640","calculation_template":"640 ÷ {{d1}} ÷ {{d2}} ÷ {{d3}}"},{"step_number":2,"title":"Result","result_template":"{{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'Aliquot area = 640 ÷ (product of the divisors). A ''half'' divides by 2, a ''quarter'' by 4. Here 640 ÷ {{d1}} ÷ {{d2}} ÷ {{d3}} = {{_answer}} acres. Read the description right-to-left to nest the parts.', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');
  'fb075000-0000-0000-0000-000000000002', 'Acreage of a quarter-fraction of a section', 'Acreage of a quarter-fraction of a section', 'FS — Boundary Law and Public Lands', 'PLSS', 'numeric_input', 'easy', 'Compute the area, in acres, of {{frac:choice}} of a regular 640-acre section.', '640/div', '{"decimals":2,"unit":"acres","tolerance":0.05}', '[{"name":"frac","type":"choice","choices":["a quarter section (e.g., the NE¼)","a half section (e.g., the N½)","a quarter-quarter (e.g., the NE¼ of the SW¼)","a half of a quarter (e.g., the N½ of the NW¼)"]},{"name":"div","type":"computed"}]'::jsonb, '[{"name":"div","formula":"frac==''a quarter section (e.g., the NE¼)''?4:(frac==''a half section (e.g., the N½)''?2:(frac==''a quarter-quarter (e.g., the NE¼ of the SW¼)''?16:8))"}]'::jsonb, '[{"step_number":1,"title":"Divide 640 by the part''s denominator","calculation_template":"640 ÷ {{div}}"},{"step_number":2,"title":"Result","result_template":"{{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'A quarter = 640/4 = 160 ac; a half = 640/2 = 320 ac; a quarter-quarter = 640/16 = 40 ac; a half-quarter = 640/8 = 80 ac. For this part, 640 ÷ {{div}} = {{_answer}} acres.', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');
  'fb075000-0000-0000-0000-000000000003', 'Single proportionate measurement — corrected distance to a lost corner', 'Single proportionate measurement — corrected distance to a lost corner', 'FS — Boundary Law and Public Lands', 'Corner Restoration', 'numeric_input', 'medium', 'A lost corner lies on a single straight line between two existent corners. Its RECORD distance from the first corner is {{dRec:f2}} ft on a RECORD total line length of {{lRec:f2}} ft. You remeasure the full line between the two existent corners and obtain {{lMeas:f2}} ft. By single proportionate measurement, compute the CORRECTED distance (ft) from the first corner at which to set the restored corner.', 'dRec*(lMeas/lRec)', '{"decimals":2,"unit":"ft","tolerance":0.05}', '[{"name":"lRec","type":"float","min":2640,"max":5400,"decimals":2},{"name":"fRac","type":"float","min":0.3,"max":0.7,"decimals":3},{"name":"delta","type":"float","min":-2.5,"max":2.5,"decimals":2}]'::jsonb, '[{"name":"dRec","formula":"round(lRec*fRac,2)"},{"name":"lMeas","formula":"round(lRec+delta,2)"}]'::jsonb, '[{"step_number":1,"title":"Proportion ratio","formula":"d'' = D_record × (L_measured / L_record)","calculation_template":"{{dRec:f2}} × ({{lMeas:f2}} ÷ {{lRec:f2}})"},{"step_number":2,"title":"Result","result_template":"d'' = {{_answer}} ft from the first existent corner"}]'::jsonb, '{"method":"none"}'::jsonb, 'Single proportion distributes the measured-vs-record difference uniformly along the single line: d'' = D_record × (L_measured / L_record) = {{dRec:f2}} × ({{lMeas:f2}} ÷ {{lRec:f2}}) = {{_answer}} ft. The restored corner keeps the same record fraction of the corrected line.', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');
  'fb075000-0000-0000-0000-000000000004', 'Single proportion in coordinates (linear interpolation)', 'Single proportion in coordinates (linear interpolation)', 'FS — Boundary Law and Public Lands', 'Corner Restoration', 'numeric_input', 'medium', 'Existent corner 1 is at (N {{n1:f2}}, E {{e1:f2}}) and existent corner 2 is at (N {{n2:f2}}, E {{e2:f2}}). A lost corner lies between them on the line, with a RECORD distance of {{dRec:f2}} ft from corner 1 on a record line total of {{lRec:f2}} ft. By single proportion (linear interpolation), compute the restored EASTING (ft) of the lost corner.', 'e1+(e2-e1)*(dRec/lRec)', '{"decimals":2,"unit":"ft","tolerance":0.1}', '[{"name":"n1","type":"float","min":1000,"max":3000,"decimals":2},{"name":"e1","type":"float","min":1000,"max":3000,"decimals":2},{"name":"dN","type":"float","min":1500,"max":4000,"decimals":2},{"name":"dE","type":"float","min":1500,"max":4000,"decimals":2},{"name":"fRac","type":"float","min":0.3,"max":0.7,"decimals":3}]'::jsonb, '[{"name":"n2","formula":"n1+dN"},{"name":"e2","formula":"e1+dE"},{"name":"lRec","formula":"round(hypot(dN,dE),2)"},{"name":"dRec","formula":"round(hypot(dN,dE)*fRac,2)"}]'::jsonb, '[{"step_number":1,"title":"Record fraction along the line","calculation_template":"f = {{dRec:f2}} ÷ {{lRec:f2}}"},{"step_number":2,"title":"Interpolate the easting","formula":"E = E₁ + (E₂ − E₁)·f","calculation_template":"{{e1:f2}} + ({{e2:f2}} − {{e1:f2}}) × ({{dRec:f2}} ÷ {{lRec:f2}})"},{"step_number":3,"title":"Result","result_template":"E = {{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, 'Single proportion in coordinate form is a linear interpolation by the record fraction f = D_record/L_record = {{dRec:f2}}/{{lRec:f2}}. Restored easting E = E₁ + (E₂ − E₁)·f = {{e1:f2}} + ({{e2:f2}} − {{e1:f2}})·f = {{_answer}} ft. (The northing interpolates the same way.)', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');
  'fb075000-0000-0000-0000-000000000005', 'Acreage of a metes-and-bounds parcel (rectangle by sides)', 'Acreage of a metes-and-bounds parcel (rectangle by sides)', 'FS — Boundary Law and Public Lands', 'Area / Description', 'numeric_input', 'medium', 'A described rectangular parcel measures {{a:f2}} ft along its north and south lines and {{b:f2}} ft along its east and west lines. Compute the parcel''s area in ACRES (1 acre = 43,560 ft²).', '(a*b)/43560', '{"decimals":3,"unit":"acres","tolerance":0.01}', '[{"name":"a","type":"float","min":200,"max":1400,"decimals":2},{"name":"b","type":"float","min":200,"max":1400,"decimals":2}]'::jsonb, '[{"name":"sqft","formula":"a*b"}]'::jsonb, '[{"step_number":1,"title":"Area in square feet","calculation_template":"{{a:f2}} × {{b:f2}} = {{sqft:f2}} ft²"},{"step_number":2,"title":"Convert to acres","formula":"acres = ft² ÷ 43,560","result_template":"{{_answer}} acres"}]'::jsonb, '{"method":"none"}'::jsonb, 'Area = length × width = {{a:f2}} × {{b:f2}} = {{sqft:f2}} ft². Divide by 43,560 ft²/acre: {{_answer}} acres. (For a non-rectangular described parcel, reduce the corners to coordinates and use the shoelace area, then convert.)', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');
  'fb075000-0000-0000-0000-000000000006', 'Texas vara ↔ feet conversion (grant call)', 'Texas vara ↔ feet conversion (grant call)', 'FS — Boundary Law and Public Lands', 'Texas / Units', 'numeric_input', 'easy', 'A Texas GLO field note gives a call of {{vrs:f1}} varas. Using the Texas legal vara of 33⅓ in = 2.7778 ft, convert the distance to FEET.', 'vrs*2.7778', '{"decimals":2,"unit":"ft","tolerance":0.2}', '[{"name":"vrs","type":"float","min":150,"max":2000,"decimals":1}]'::jsonb, '[]'::jsonb, '[{"step_number":1,"title":"Multiply by feet-per-vara","formula":"ft = vrs × 2.7778","calculation_template":"{{vrs:f1}} × 2.7778"},{"step_number":2,"title":"Result","result_template":"{{_answer}} ft"}]'::jsonb, '{"method":"none"}'::jsonb, '1 vara = 33⅓ in = 2.7778 ft (equivalently feet = varas ÷ 0.36). So {{vrs:f1}} vrs × 2.7778 = {{_answer}} ft. Recall 36 varas = exactly 100 ft. A retracing surveyor must also reconcile the historic (often magnetic) bearing basis to a modern datum.', 'f5000007-0000-0000-0000-000000000007', 'FS', ARRAY['fs-buildout','fs-m7','fs-practice']::text[], NULL, true, 'fs:m7');

-- ===== FS Module 8: Photogrammetry, GIS and Construction =====
DELETE FROM question_bank WHERE module_id='f5000008-0000-0000-0000-000000000008' AND 'fs-buildout' = ANY(tags);
DELETE FROM question_bank WHERE exam_category='FS-MOCK' AND 'fs-m8' = ANY(tags);
